namespace Kappa.Compiler

open System
open System.Numerics
open System.Security.Cryptography
open System.Text
open System.Threading
open Kappa.Compiler.ResourceModel

// Elaborates resolved surface modules into KCore while preserving observability metadata.
module SurfaceElaboration =
    open TypeSignatures

    type private TraitMemberInfo =
        { Name: string
          Scheme: TypeScheme
          DefaultDefinition: LetDefinition option }

    type private TraitInfo =
        { ModuleName: string
          Name: string
          TypeParameters: string list
          Supertraits: TraitConstraint list
          Members: Map<string, TraitMemberInfo> }

    type private InstanceInfo =
        { ModuleName: string
          TraitName: string
          InstanceKey: string
          Constraints: TraitConstraint list
          HeadTypes: TypeExpr list
          Members: Map<string, LetDefinition> }

    type private TypeAliasInfo =
        { ModuleName: string
          Name: string
          IsOpaque: bool
          Parameters: string list
          Body: TypeExpr
          TerminationCertified: bool
          ConversionReducible: bool }

    type private TypeFacetKind =
        | TypeAliasFacet
        | DataFacet
        | EffectFacet
        | AbstractFacet

    type private TypeFacetInfo =
        { ModuleName: string
          Name: string
          FacetKind: TypeFacetKind
          IsOpaque: bool
          Scheme: TypeScheme }

    type private StaticObjectKind =
        | StaticTypeObject
        | StaticTraitObject
        | StaticEffectLabelObject
        | StaticModuleObject

    type private StaticObjectInfo =
        { ObjectKind: StaticObjectKind
          NameSegments: string list
          Scheme: TypeScheme option
          ScopedEffect: EffectSemanticDeclaration option
          TypeFacet: TypeFacetInfo option }

    type private RecordSurfaceFieldInfo =
        { Name: string
          IsOpaque: bool
          IsImplicit: bool
          TypeTokens: Token list }

    type private RecordSurfaceInfo =
        { Fields: RecordSurfaceFieldInfo list
          RowTail: string option }

    type private BindingSchemeInfo =
        { ModuleName: string
          Name: string
          IsPattern: bool
          Scheme: TypeScheme
          TypeTokens: Token list
          ParameterLayouts: Parameter list option
          ConstructorTypeName: string option
          DefaultArguments: Map<string, SurfaceExpression> }

    type private ProjectionInfo =
        { ModuleName: string
          Name: string
          Binders: ProjectionBinder list
          ReturnType: TypeExpr
          Body: SurfaceProjectionBody option }

    type private OrdinaryVisibleTermCandidate =
        | OrdinaryVisibleBindingCandidate of BindingSchemeInfo
        | OrdinaryVisibleExportedBindingCandidate of string * string
        | OrdinaryVisibleConstructorCandidate of BindingSchemeInfo
        | OrdinaryVisibleModuleCandidate of string

    let private renderOrdinaryVisibleTermCandidate candidate =
        match candidate with
        | OrdinaryVisibleBindingCandidate info when info.IsPattern ->
            $"pattern term '{info.Name}' from module '{info.ModuleName}'"
        | OrdinaryVisibleBindingCandidate info ->
            $"term '{info.Name}' from module '{info.ModuleName}'"
        | OrdinaryVisibleExportedBindingCandidate(moduleName, name) ->
            $"term '{name}' from module '{moduleName}'"
        | OrdinaryVisibleConstructorCandidate info ->
            $"constructor '{info.Name}' from module '{info.ModuleName}'"
        | OrdinaryVisibleModuleCandidate moduleName ->
            $"module '{moduleName}'"

    let private ordinaryNameAmbiguityMessage name candidates =
        let candidateText =
            candidates
            |> List.map renderOrdinaryVisibleTermCandidate
            |> String.concat ", "

        $"Name '{name}' is ambiguous between {candidateText}. Use an explicit import item, module alias, or qualification."

    type private ProjectionDescriptorAliasInfo =
        { Projection: ProjectionInfo
          RemainingPlaceBinders: ProjectionPlaceBinder list }

    type private TermNamespaceContributor =
        | TermSignatureContributor
        | TermLetContributor
        | TermProjectionContributor
        | TermExpectationContributor

    type private TypeNamespaceContributor =
        | ExpectTypeContributor
        | OrdinaryTypeContributor
        | EffectTypeContributor

    type private TraitNamespaceContributor =
        | ExpectTraitContributor
        | OrdinaryTraitContributor

    type private ModuleSurfaceInfo =
        { TypeAliases: Map<string, TypeAliasInfo>
          TypeFacets: Map<string, TypeFacetInfo>
          RecordTypes: Map<string, RecordSurfaceInfo>
          BindingSchemes: Map<string, BindingSchemeInfo>
          Constructors: Map<string, BindingSchemeInfo>
          Projections: Map<string, ProjectionInfo>
          Traits: Map<string, TraitInfo>
          Instances: InstanceInfo list
          Imports: ImportSpec list
          ExportedTerms: Set<string>
          ExportedConstructors: Set<string>
          ExportedConstructorsByType: Map<string, Set<string>>
          ExportedTypes: Set<string>
          ExportedTraits: Set<string> }

    type private BindingLoweringEnvironment =
        { CurrentModuleName: string
          SurfaceIndex: Map<string, ModuleSurfaceInfo>
          VisibleTypeAliases: Map<string, TypeAliasInfo>
          VisibleTypeFacets: Map<string, TypeFacetInfo>
          VisibleStaticObjects: Map<string, StaticObjectInfo>
          VisibleModules: Set<string>
          VisibleRecordTypes: Map<string, RecordSurfaceInfo>
          VisibleBindings: Map<string, BindingSchemeInfo>
          VisibleConstructors: Map<string, BindingSchemeInfo>
          AmbiguousVisibleOrdinaryTerms: Map<string, OrdinaryVisibleTermCandidate list>
          VisibleProjections: Map<string, ProjectionInfo>
          VisibleTraits: Map<string, TraitInfo>
          VisibleInstances: InstanceInfo list
          ElaborationAvailableBindings: Set<string>
          ConstraintDictionaries: Map<string, KCoreExpression>
          ConstrainedMembers: Map<string, string * string> }

    type private PreparedCallArgument =
        | ExplicitArgument of SurfaceExpression
        | ImplicitArgument of KCoreExpression

    type private PreparedCallParameter =
        { Layout: Parameter option
          ParameterType: TypeExpr
          AssignedArgument: PreparedCallArgument option }

    type private PreparedBindingCall =
        { InstantiatedScheme: TypeScheme
          ResultType: TypeExpr
          Parameters: PreparedCallParameter list
          Arguments: PreparedCallArgument list }

    type private SyntheticRecordLayout =
        { TypeKey: string
          TypeExpr: TypeExpr
          TypeName: string
          ConstructorName: string
          TypeParameters: string list
          Fields: RecordField list
          Provenance: KCoreOrigin }

    type private ConstraintResolutionResult =
        | ConstraintUnresolved
        | ConstraintResolved of InstanceInfo * Map<string, TypeExpr>
        | ConstraintAmbiguous of TraitConstraint * InstanceInfo list

    let private tokensText (tokens: Token list) =
        tokens
        |> List.map (fun token -> token.Text)
        |> String.concat " "

    let private tryParseTypeText (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        let lexResult = Lexer.tokenize source

        if not (List.isEmpty lexResult.Diagnostics) then
            None
        else
            TypeSignatures.parseType lexResult.Tokens

    let private tryParseSchemeText (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        let lexResult = Lexer.tokenize source

        if not (List.isEmpty lexResult.Diagnostics) then
            None
        else
            TypeSignatures.parseScheme lexResult.Tokens

    let private typeTextTokens (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        Lexer.tokenize source
        |> fun lexResult -> lexResult.Tokens
        |> List.filter (fun token -> token.Kind <> EndOfFile)

    let private significantTokens (tokens: Token list) =
        tokens
        |> List.filter (fun token ->
            match token.Kind with
            | Newline
            | Indent
            | Dedent
            | EndOfFile -> false
            | _ -> true)

    let private moduleNameText moduleName =
        moduleName
        |> Option.map SyntaxFacts.moduleNameToText
        |> Option.defaultValue "<unknown>"

    let private declarationName (declaration: TopLevelDeclaration) =
        match declaration with
        | SignatureDeclaration declaration -> Some declaration.Name
        | LetDeclaration declaration -> declaration.Name
        | DataDeclarationNode declaration -> Some declaration.Name
        | TypeAliasNode declaration -> Some declaration.Name
        | TraitDeclarationNode declaration -> Some declaration.Name
        | InstanceDeclarationNode declaration -> Some declaration.TraitName
        | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> Some declaration.Name
        | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> Some declaration.Name
        | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> Some declaration.Name
        | _ -> None

    let private declarationOrigin filePath moduleName declaration =
        { FilePath = filePath
          ModuleName = moduleName
          DeclarationName = declarationName declaration
          IntroductionKind = "source" }

    let private syntheticOrigin filePath moduleName declarationName introductionKind =
        { FilePath = filePath
          ModuleName = moduleName
          DeclarationName = Some declarationName
          IntroductionKind = introductionKind }

    let private stableSyntheticSuffix (value: string) =
        let bytes = Encoding.UTF8.GetBytes(value)
        let hash = SHA256.HashData(bytes)

        hash
        |> Seq.take 10
        |> Seq.map (fun value -> value.ToString("x2"))
        |> String.concat ""

    let private syntheticRecordTypeName recordKey =
        "__kappa_record_" + stableSyntheticSuffix recordKey

    let private syntheticRecordConstructorName recordKey =
        syntheticRecordTypeName recordKey

    let private syntheticLetSource name =
        LetDeclaration
            { Visibility = Some Visibility.Private
              IsOpaque = false
              TotalityAssertion = None
              IsPattern = false
              Name = Some name
              Parameters = []
              HeaderTokens = []
              ReturnTypeTokens = None
              BodyTokens = []
              Body = None }

    let private lowerKCoreParameter (parameter: Parameter) (parameterType: TypeExpr option) : KCoreParameter =
        { Name = parameter.Name
          Quantity = parameter.Quantity
          IsImplicit = parameter.IsImplicit
          Type = parameterType
          TypeText =
            parameterType
            |> Option.map TypeSignatures.toText
            |> Option.orElseWith (fun () -> parameter.TypeTokens |> Option.map tokensText) }

    let private lowerSyntheticKCoreParameter
        (name: string)
        (quantity: Quantity option)
        (isImplicit: bool)
        (parameterType: TypeExpr option)
        : KCoreParameter =
        { Name = name
          Quantity = quantity
          IsImplicit = isImplicit
          Type = parameterType
          TypeText = parameterType |> Option.map TypeSignatures.toText }

    let private explicitKCoreArgument expression =
        { ArgumentKind = KCoreExplicitArgument
          Expression = expression }

    let private implicitKCoreArgument expression =
        { ArgumentKind = KCoreImplicitArgument
          Expression = expression }

    let private inoutKCoreArgument expression =
        { ArgumentKind = KCoreInoutArgument
          Expression = expression }

    let rec private lowerKCorePattern (pattern: SurfacePattern) =
        match pattern with
        | WildcardPattern ->
            KCoreWildcardPattern
        | NamePattern name ->
            KCoreNamePattern name
        | AsPattern(_, inner) ->
            lowerKCorePattern inner
        | TypedPattern(inner, _) ->
            lowerKCorePattern inner
        | LiteralPattern literal ->
            KCoreLiteralPattern literal
        | ConstructorPattern(name, arguments) ->
            KCoreConstructorPattern(name, arguments |> List.map lowerKCorePattern)
        | NamedConstructorPattern(name, fields) ->
            KCoreConstructorPattern(name, fields |> List.map (fun field -> lowerKCorePattern field.Pattern))
        | TuplePattern _ ->
            KCoreWildcardPattern
        | VariantPattern(BoundVariantPattern(name, _))
        | VariantPattern(RestVariantPattern name) ->
            KCoreNamePattern name
        | VariantPattern(WildcardVariantPattern _) ->
            KCoreWildcardPattern
        | OrPattern alternatives ->
            KCoreOrPattern(alternatives |> List.map lowerKCorePattern)
        | AnonymousRecordPattern _ ->
            KCoreWildcardPattern

    let private collectPatternNames (pattern: SurfacePattern) =
        let rec loop current =
            seq {
                match current with
                | NamePattern name -> yield name
                | AsPattern(name, inner) ->
                    yield name
                    yield! loop inner
                | TypedPattern(inner, _) ->
                    yield! loop inner
                | ConstructorPattern(_, arguments) ->
                    for argument in arguments do
                        yield! loop argument
                | NamedConstructorPattern(_, fields) ->
                    for field in fields do
                        yield! loop field.Pattern
                | TuplePattern elements ->
                    for element in elements do
                        yield! loop element
                | VariantPattern(BoundVariantPattern(name, _))
                | VariantPattern(RestVariantPattern name) ->
                    yield name
                | VariantPattern(WildcardVariantPattern _) ->
                    ()
                | OrPattern alternatives ->
                    match alternatives with
                    | first :: _ ->
                        yield! loop first
                    | [] ->
                        ()
                | AnonymousRecordPattern(fields, rest) ->
                    for field in fields do
                        yield! loop field.Pattern
                    match rest with
                    | Some(BindRecordPatternRest name) -> yield name
                    | _ -> ()
                | WildcardPattern
                | LiteralPattern _ -> ()
            }

        loop pattern |> Seq.toList

    let private isOmegaText text =
        String.Equals(text, "\u03c9", StringComparison.Ordinal)
        || String.Equals(text, "omega", StringComparison.Ordinal)

    let private isQuantityVariableToken (token: Token) =
        if token.Kind <> Identifier then
            false
        else
            let text = SyntaxFacts.trimIdentifierQuotes token.Text
            not (String.IsNullOrEmpty text) && not (Char.IsUpper text[0])

    let private tryParseQuantityPrefix (tokens: Token list) =
        match tokens with
        | { Kind = IntegerLiteral; Text = "0" } :: rest ->
            Some(QuantityZero, rest)
        | { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityOne, rest)
        | { Kind = Operator; Text = "&" } :: { Kind = LeftBracket } :: regionToken :: { Kind = RightBracket } :: rest
            when Token.isName regionToken ->
            Some(QuantityBorrow(Some(SyntaxFacts.trimIdentifierQuotes regionToken.Text)), rest)
        | { Kind = Operator; Text = "&" } :: rest ->
            Some(QuantityBorrow None, rest)
        | { Kind = Operator; Text = "<=" } :: { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityAtMostOne, rest)
        | { Kind = Operator; Text = ">=" } :: { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityAtLeastOne, rest)
        | head :: rest when Token.isName head && isOmegaText head.Text ->
            Some(QuantityOmega, rest)
        | head :: rest when isQuantityVariableToken head ->
            match rest with
            | next :: _ when Token.isName next ->
                Some(QuantityVariable(SyntaxFacts.trimIdentifierQuotes head.Text), rest)
            | _ ->
                None
        | _ ->
            None

    let private tryParseSuspensionMarker (tokens: Token list) =
        match tokens with
        | head :: rest when Token.isKeyword Keyword.Thunk head ->
            Some({ head with Kind = Identifier; Text = "Thunk" }, rest)
        | head :: rest when Token.isKeyword Keyword.Lazy head ->
            Some({ head with Kind = Identifier; Text = "Need" }, rest)
        | _ ->
            None

    let private splitTopLevelCommaGroups (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let groups = ResizeArray<Token list>()
        let current = ResizeArray<Token>()
        let mutable depth = 0

        for token in tokenArray do
            match token.Kind with
            | LeftParen
            | LeftBracket
            | LeftBrace
            | LeftSetBrace ->
                depth <- depth + 1
                current.Add(token)
            | RightParen
            | RightBracket
            | RightBrace
            | RightSetBrace ->
                depth <- max 0 (depth - 1)
                current.Add(token)
            | Comma when depth = 0 ->
                groups.Add(List.ofSeq current)
                current.Clear()
            | _ ->
                current.Add(token)

        if current.Count > 0 then
            groups.Add(List.ofSeq current)

        groups |> Seq.toList

    let private tryFindTopLevelToken predicate (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let mutable depth = 0
        let mutable index = 0
        let mutable result = None

        while index < tokenArray.Length && result.IsNone do
            match tokenArray[index].Kind with
            | LeftParen
            | LeftBracket
            | LeftBrace
            | LeftSetBrace ->
                depth <- depth + 1
            | RightParen
            | RightBracket
            | RightBrace
            | RightSetBrace ->
                depth <- max 0 (depth - 1)
            | _ when depth = 0 && predicate tokenArray[index] ->
                result <- Some index
            | _ ->
                ()

            index <- index + 1

        result

    let private stripOuterParens (tokens: Token list) =
        let trimmed = significantTokens tokens

        match trimmed with
        | { Kind = LeftParen } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightParen ->
            Some(rest |> List.take (List.length rest - 1))
        | _ ->
            None

    let private tryParseRecordSurfaceField (tokens: Token list) =
        let tokens = significantTokens tokens

        let isOpaque, afterOpaque =
            match tokens with
            | head :: rest when Token.isKeyword Keyword.Opaque head -> true, rest
            | _ -> false, tokens

        let isImplicit, afterImplicit =
            match afterOpaque with
            | { Kind = AtSign } :: rest -> true, rest
            | _ -> false, afterOpaque

        let afterQuantity =
            match tryParseQuantityPrefix afterImplicit with
            | Some(_, rest) -> rest
            | None -> afterImplicit

        let suspensionTypeToken, afterSuspension =
            match tryParseSuspensionMarker afterQuantity with
            | Some(typeToken, rest) -> Some typeToken, rest
            | None -> None, afterQuantity

        tryFindTopLevelToken (fun token -> token.Kind = Colon) afterSuspension
        |> Option.bind (fun colonIndex ->
            let tokenArray = afterSuspension |> List.toArray
            let binderTokens = tokenArray[0 .. colonIndex - 1] |> Array.toList
            let rawTypeTokens = tokenArray[colonIndex + 1 ..] |> Array.toList
            let typeTokens =
                match suspensionTypeToken with
                | Some typeToken -> typeToken :: rawTypeTokens
                | None -> rawTypeTokens

            match binderTokens, typeTokens with
            | [ nameToken ], _ when Token.isName nameToken && not (List.isEmpty typeTokens) ->
                Some
                    { Name = SyntaxFacts.trimIdentifierQuotes nameToken.Text
                      IsOpaque = isOpaque
                      IsImplicit = isImplicit
                      TypeTokens = typeTokens }
            | _ ->
                None)

    let private tryParseRecordSurfaceInfo (tokens: Token list) =
        stripOuterParens tokens
        |> Option.bind (fun innerTokens ->
            let fieldGroups = splitTopLevelCommaGroups innerTokens |> List.filter (List.isEmpty >> not)
            let fields = ResizeArray<RecordSurfaceFieldInfo>()
            let mutable rowTail = None
            let mutable valid = true

            for group in fieldGroups do
                let fieldTokens, tailTokens =
                    match tryFindTopLevelToken (fun token -> token.Kind = Operator && token.Text = "|") group with
                    | Some pipeIndex ->
                        let tokenArray = group |> List.toArray
                        tokenArray[0 .. pipeIndex - 1] |> Array.toList,
                        Some(tokenArray[pipeIndex + 1 ..] |> Array.toList)
                    | None ->
                        group, None

                match tailTokens with
                | Some tokens ->
                    match significantTokens tokens with
                    | [ rowToken ] when Token.isName rowToken ->
                        rowTail <- Some(SyntaxFacts.trimIdentifierQuotes rowToken.Text)
                    | _ ->
                        valid <- false
                | None ->
                    ()

                if not (List.isEmpty (significantTokens fieldTokens)) then
                    match tryParseRecordSurfaceField fieldTokens with
                    | Some field -> fields.Add(field)
                    | None -> valid <- false

            if valid && (fields.Count > 0 || rowTail.IsSome) then
                Some
                    { Fields = List.ofSeq fields
                      RowTail = rowTail }
            else
                None)

    let private recordSurfaceFieldNames (recordInfo: RecordSurfaceInfo) =
        recordInfo.Fields |> List.map (fun field -> field.Name) |> Set.ofList

    let private tokenText (tokens: Token list) =
        tokens
        |> significantTokens
        |> List.map (fun token -> token.Text)
        |> String.concat " "

    let private stripDelimitedParameterTokens tokens =
        match tokens with
        | { Kind = LeftParen } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightParen ->
            Some(false, rest |> List.take (List.length rest - 1))
        | { Kind = LeftBrace } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightBrace ->
            Some(true, rest |> List.take (List.length rest - 1))
        | _ ->
            None

    let private tryParseSignatureParameterLayout (tokens: Token list) =
        stripDelimitedParameterTokens tokens
        |> Option.bind (fun (delimiterImplicit, innerTokens) ->
            let isImplicit, innerTokens =
                match innerTokens with
                | { Kind = AtSign } :: rest -> true, rest
                | _ -> delimiterImplicit, innerTokens

            let isInout, remainingTokens =
                match innerTokens with
                | head :: rest when Token.isKeyword Keyword.Inout head -> true, rest
                | _ -> false, innerTokens

            let quantity, bodyTokens =
                if isInout then
                    Some QuantityOne, remainingTokens
                else
                    match tryParseQuantityPrefix remainingTokens with
                    | Some(parsedQuantity, rest) -> Some parsedQuantity, rest
                    | None -> None, remainingTokens

            let suspensionTypeToken, bodyTokens =
                match tryParseSuspensionMarker bodyTokens with
                | Some(typeToken, rest) -> Some typeToken, rest
                | None -> None, bodyTokens

            match bodyTokens with
            | { Kind = Underscore } as underscoreToken :: { Kind = Colon } :: typeTokens when not (List.isEmpty typeTokens) ->
                Some
                    { Name = $"__kappa_signature_wildcard_{underscoreToken.Span.Start}"
                      TypeTokens =
                        Some(suspensionTypeToken |> Option.map (fun typeToken -> typeToken :: typeTokens) |> Option.defaultValue typeTokens)
                      Quantity = quantity
                      IsImplicit = isImplicit
                      IsInout = isInout
                      IsReceiver = false }
            | nameToken :: { Kind = Colon } :: typeTokens when Token.isName nameToken && not (List.isEmpty typeTokens) ->
                Some
                    { Name = SyntaxFacts.trimIdentifierQuotes nameToken.Text
                      TypeTokens =
                        Some(suspensionTypeToken |> Option.map (fun typeToken -> typeToken :: typeTokens) |> Option.defaultValue typeTokens)
                      Quantity = quantity
                      IsImplicit = isImplicit
                      IsInout = isInout
                      IsReceiver = false }
            | _ ->
                None)

    let private bindingSignatureBodyTokens (tokens: Token list) =
        let tokenArray = significantTokens tokens |> List.toArray
        let mutable parenDepth = 0
        let mutable braceDepth = 0
        let mutable bracketDepth = 0
        let mutable bodyStart = 0

        for index = 0 to tokenArray.Length - 1 do
            match tokenArray[index].Kind with
            | LeftParen -> parenDepth <- parenDepth + 1
            | RightParen -> parenDepth <- max 0 (parenDepth - 1)
            | LeftBrace -> braceDepth <- braceDepth + 1
            | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
            | LeftBracket -> bracketDepth <- bracketDepth + 1
            | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
            | Operator when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 && String.Equals(tokenArray[index].Text, "=>", StringComparison.Ordinal) ->
                bodyStart <- index + 1
            | Equals when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 && index + 1 < tokenArray.Length ->
                match tokenArray[index + 1] with
                | { Kind = Operator; Text = ">" } ->
                    bodyStart <- index + 2
                | _ ->
                    ()
            | _ ->
                ()

        let stripLeadingForall startIndex =
            if startIndex >= tokenArray.Length then
                startIndex
            else
                match tokenArray[startIndex] with
                | token when Token.isKeyword Keyword.Forall token ->
                    let mutable index = startIndex + 1
                    let mutable parsed = true
                    let mutable bodyIndex = startIndex
                    let mutable foundDot = false

                    while parsed && not foundDot && index < tokenArray.Length do
                        match tokenArray[index] with
                        | token when Token.isName token ->
                            index <- index + 1
                        | { Kind = LeftParen } ->
                            let mutable depth = 1
                            let mutable innerIndex = index + 1

                            while depth > 0 && innerIndex < tokenArray.Length do
                                match tokenArray[innerIndex].Kind with
                                | LeftParen -> depth <- depth + 1
                                | RightParen -> depth <- depth - 1
                                | _ -> ()

                                innerIndex <- innerIndex + 1

                            if depth = 0 then
                                index <- innerIndex
                            else
                                parsed <- false
                        | { Kind = Dot } ->
                            bodyIndex <- index + 1
                            foundDot <- true
                        | _ ->
                            parsed <- false

                    if parsed && foundDot then bodyIndex else startIndex
                | _ ->
                    startIndex

        bodyStart <- stripLeadingForall bodyStart
        List.ofArray tokenArray[bodyStart..]

    let private splitSignatureParameterTokens (tokens: Token list) =
        let bodyTokens = bindingSignatureBodyTokens tokens
        let tokenArray = bodyTokens |> List.toArray
        let segments = ResizeArray<Token list>()
        let mutable parenDepth = 0
        let mutable braceDepth = 0
        let mutable bracketDepth = 0
        let mutable segmentStart = 0

        for index = 0 to tokenArray.Length - 1 do
            match tokenArray[index].Kind with
            | LeftParen -> parenDepth <- parenDepth + 1
            | RightParen -> parenDepth <- max 0 (parenDepth - 1)
            | LeftBrace -> braceDepth <- braceDepth + 1
            | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
            | LeftBracket -> bracketDepth <- bracketDepth + 1
            | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
            | Arrow when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 ->
                if index > segmentStart then
                    segments.Add(List.ofArray tokenArray[segmentStart .. index - 1])

                segmentStart <- index + 1
            | _ ->
                ()

        segments |> Seq.toList

    let private mergeParameterLayouts
        (signatureLayouts: Parameter option list option)
        (definitionLayouts: Parameter list option)
        =
        match signatureLayouts, definitionLayouts with
        | Some signatureParameters, Some definitionParameters ->
            let mergeResolvedParameter (signatureParameter: Parameter) (definitionParameter: Parameter) =
                { definitionParameter with
                    Name = signatureParameter.Name
                    TypeTokens = signatureParameter.TypeTokens |> Option.orElse definitionParameter.TypeTokens
                    Quantity = signatureParameter.Quantity |> Option.orElse definitionParameter.Quantity
                    IsImplicit = signatureParameter.IsImplicit
                    IsInout = signatureParameter.IsInout }

            let rec mergeAligned
                (signatureParameters: Parameter option list)
                (definitionParameters: Parameter list)
                (merged: Parameter list)
                =
                match signatureParameters with
                | [] ->
                    if List.isEmpty definitionParameters then
                        Some(List.rev merged)
                    else
                        None
                | signatureParameter :: restSignatureParameters ->
                    match signatureParameter, definitionParameters with
                    | Some signatureParameter, definitionParameter :: restDefinitionParameters
                        when String.Equals(signatureParameter.Name, definitionParameter.Name, StringComparison.Ordinal) ->
                        mergeAligned
                            restSignatureParameters
                            restDefinitionParameters
                            (mergeResolvedParameter signatureParameter definitionParameter :: merged)
                    | Some signatureParameter, _ ->
                        mergeAligned restSignatureParameters definitionParameters (signatureParameter :: merged)
                    | None, definitionParameter :: restDefinitionParameters ->
                        mergeAligned restSignatureParameters restDefinitionParameters (definitionParameter :: merged)
                    | None, [] ->
                        mergeAligned restSignatureParameters [] merged

            match mergeAligned signatureParameters definitionParameters [] with
            | Some merged ->
                Some merged
            | None when List.length signatureParameters = List.length definitionParameters ->
                List.zip signatureParameters definitionParameters
                |> List.map (fun (signatureParameter, definitionParameter) ->
                    match signatureParameter with
                    | Some signatureParameter -> mergeResolvedParameter signatureParameter definitionParameter
                    | None -> definitionParameter)
                |> Some
            | None ->
                definitionLayouts
        | Some signatureParameters, None when signatureParameters |> List.forall Option.isSome ->
            signatureParameters |> List.choose id |> Some
        | _ ->
            definitionLayouts

    let private stripForallOnlyParameterLayouts
        (scheme: TypeScheme)
        (parameterLayouts: Parameter list option)
        =
        parameterLayouts
        |> Option.map (fun layouts ->
            let rec stripLeadingForallLayouts
                (remainingBinders: TypeSignatures.ForallBinder list)
                (remainingLayouts: Parameter list)
                =
                match remainingBinders, remainingLayouts with
                | binder :: restBinders, layout :: restLayouts
                    when String.Equals(binder.Name, layout.Name, StringComparison.Ordinal) ->
                    stripLeadingForallLayouts restBinders restLayouts
                | _ ->
                    remainingLayouts

            stripLeadingForallLayouts scheme.Forall layouts)

    let private parameterLayoutNeedsApplicationMetadata (parameter: Parameter) =
        parameter.IsImplicit
        || parameter.IsInout
        || (parameter.TypeTokens
            |> Option.bind TypeSignatures.parseType
            |> Option.exists (function
                | TypeUniverse _ -> true
                | TypeIntrinsic _ -> true
                | TypeName([ "Type" ], []) -> true
                | _ -> false))

    let private annotateLambdaWithTypeTokens typeTokens value =
        let signatureParameterLayouts =
            typeTokens
            |> splitSignatureParameterTokens
            |> function
                | [] -> None
                | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

        match TypeSignatures.parseScheme typeTokens, value with
        | Some signatureScheme, Lambda(lambdaParameters, lambdaBody) ->
            let parameterTypes, _ = TypeSignatures.schemeParts signatureScheme

            if List.length parameterTypes = List.length lambdaParameters then
                let annotatedParameters =
                    List.zip lambdaParameters parameterTypes
                    |> List.mapi (fun index (parameter, parameterType) ->
                        let signatureLayout =
                            signatureParameterLayouts
                            |> Option.bind (List.tryItem index)
                            |> Option.bind id

                        { parameter with
                            TypeTokens =
                                parameter.TypeTokens
                                |> Option.orElseWith (fun () ->
                                    Some(typeTextTokens (TypeSignatures.toText parameterType)))
                            Quantity = parameter.Quantity |> Option.orElseWith (fun () -> signatureLayout |> Option.bind (fun layout -> layout.Quantity))
                            IsImplicit = parameter.IsImplicit || (signatureLayout |> Option.exists (fun layout -> layout.IsImplicit))
                            IsInout = parameter.IsInout || (signatureLayout |> Option.exists (fun layout -> layout.IsInout)) })

                Lambda(annotatedParameters, lambdaBody)
            else
                value
        | _ ->
            value

    let private tryResolveVisibleConstructorInfo
        (environment: BindingLoweringEnvironment)
        nameSegments
        =
        match List.rev nameSegments with
        | [] ->
            None
        | constructorName :: reversedModuleSegments ->
            environment.VisibleConstructors
            |> Map.tryFind constructorName
            |> Option.filter (fun constructorInfo ->
                match reversedModuleSegments with
                | [] ->
                    true
                | _ ->
                    String.Equals(
                        constructorInfo.ModuleName,
                        SyntaxFacts.moduleNameToText (List.rev reversedModuleSegments),
                        StringComparison.Ordinal
                    ))

    let private typeObjectType =
        TypeUniverse None

    let private constraintObjectType =
        TypeIntrinsic ConstraintClassifier

    let private effectLabelObjectType =
        TypeIntrinsic EffLabelClassifier

    let private staticObjectTypeText (info: StaticObjectInfo) =
        info.Scheme
        |> Option.map (fun scheme -> TypeSignatures.toText scheme.Body)

    let private traitFacetScheme (traitInfo: TraitInfo) =
        let body =
            traitInfo.TypeParameters
            |> List.rev
            |> List.fold (fun current _ -> TypeArrow(QuantityOmega, typeObjectType, current)) constraintObjectType

        { Forall = []
          Constraints = []
          Body = body }

    let private typeFacetStaticObject (typeFacetInfo: TypeFacetInfo) =
        { ObjectKind = StaticTypeObject
          NameSegments = [ typeFacetInfo.Name ]
          Scheme = Some typeFacetInfo.Scheme
          ScopedEffect = None
          TypeFacet = Some typeFacetInfo }

    let private scopedEffectLabelNameSegments (declaration: EffectSemanticDeclaration) =
        EffectSemantics.labelNameSegments declaration

    let private scopedEffectInterfaceNameSegments (declaration: EffectSemanticDeclaration) =
        EffectSemantics.interfaceNameSegments declaration

    let private scopedEffectTypeStaticObject (declaration: EffectSemanticDeclaration) =
        { ObjectKind = StaticTypeObject
          NameSegments = scopedEffectInterfaceNameSegments declaration
          Scheme =
            Some
                { Forall = []
                  Constraints = []
                  Body = typeObjectType }
          ScopedEffect = Some declaration
          TypeFacet = None }

    let private scopedEffectLabelStaticObject (declaration: EffectSemanticDeclaration) =
        { ObjectKind = StaticEffectLabelObject
          NameSegments = scopedEffectLabelNameSegments declaration
          Scheme =
            Some
                { Forall = []
                  Constraints = []
                  Body = effectLabelObjectType }
          ScopedEffect = Some declaration
          TypeFacet = None }

    let private traitStaticObject (traitInfo: TraitInfo) =
        { ObjectKind = StaticTraitObject
          NameSegments = [ traitInfo.Name ]
          Scheme = Some(traitFacetScheme traitInfo)
          ScopedEffect = None
          TypeFacet = None }

    let private tryResolveVisibleTypeFacetInfo
        (environment: BindingLoweringEnvironment)
        nameSegments
        =
        match List.rev nameSegments with
        | [] ->
            None
        | typeName :: reversedModuleSegments ->
            environment.VisibleTypeFacets
            |> Map.tryFind typeName
            |> Option.filter (fun typeFacetInfo ->
                match reversedModuleSegments with
                | [] ->
                    true
                | _ ->
                    String.Equals(
                        typeFacetInfo.ModuleName,
                        SyntaxFacts.moduleNameToText (List.rev reversedModuleSegments),
                        StringComparison.Ordinal
                    ))

    let private tryResolveStaticObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        match expression with
        | KindQualifiedName(TypeKind, nameSegments) ->
            tryResolveVisibleTypeFacetInfo environment nameSegments
            |> Option.map typeFacetStaticObject
        | KindQualifiedName(TraitKind, nameSegments) ->
            match List.rev nameSegments with
            | [] -> None
            | traitName :: _ ->
                environment.VisibleTraits
                |> Map.tryFind traitName
                |> Option.map traitStaticObject
        | KindQualifiedName(EffectLabelKind, _) ->
            None
        | KindQualifiedName(ModuleKind, nameSegments) ->
            let moduleName = SyntaxFacts.moduleNameToText nameSegments

            if environment.VisibleModules.Contains moduleName then
                Some
                    { ObjectKind = StaticModuleObject
                      NameSegments = nameSegments
                      Scheme = None
                      ScopedEffect = None
                      TypeFacet = None }
            else
                None
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            let aliasName = SyntaxFacts.moduleNameToText nameSegments

            environment.VisibleStaticObjects
            |> Map.tryFind aliasName
            |> Option.orElseWith (fun () ->
                match nameSegments with
                | [ root ]
                    when not (environment.VisibleBindings.ContainsKey root)
                         && Option.isNone (tryResolveVisibleConstructorInfo environment [ root ]) ->
                    environment.VisibleTypeFacets
                    |> Map.tryFind root
                    |> Option.map typeFacetStaticObject
                    |> Option.orElseWith (fun () ->
                        environment.VisibleTraits
                        |> Map.tryFind root
                        |> Option.map traitStaticObject)
                | _ ->
                    None)
        | _ ->
            None

    let private tryResolveStaticReceiverObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        match expression with
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            let aliasName = SyntaxFacts.moduleNameToText nameSegments

            environment.VisibleStaticObjects
            |> Map.tryFind aliasName
            |> Option.orElseWith (fun () ->
                match nameSegments with
                | [ root ] ->
                    environment.VisibleTypeFacets
                    |> Map.tryFind root
                    |> Option.map typeFacetStaticObject
                | _ ->
                    None)
        | _ ->
            tryResolveStaticObject environment expression

    let private scopedEffects = AsyncLocal<Map<string, EffectSemanticDeclaration> option>()
    let private scopedEffectDeclarations = AsyncLocal<EffectSemanticDeclaration list option>()
    let private scopedEffectIdentityCounter = AsyncLocal<int option>()

    let private currentScopedEffects () =
        scopedEffects.Value |> Option.defaultValue Map.empty

    let private currentScopedEffectDeclarations () =
        scopedEffectDeclarations.Value |> Option.defaultValue []

    let private currentScopedEffectNames () =
        currentScopedEffects () |> Map.keys |> Set.ofSeq

    let private tryFindScopedEffectDeclaration name =
        currentScopedEffects () |> Map.tryFind name

    let private tryFindScopedEffectDeclarationByStaticSegments segments =
        let visibleNameSegments (declaration: EffectSemanticDeclaration) =
            declaration.VisibleName.Split('.') |> Array.toList

        currentScopedEffectDeclarations ()
        |> List.tryFind (fun declaration ->
            segments = visibleNameSegments declaration
            || segments = scopedEffectLabelNameSegments declaration
            || segments = scopedEffectInterfaceNameSegments declaration)

    let private nextScopedEffectIdentitySeed () =
        let current = scopedEffectIdentityCounter.Value |> Option.defaultValue 0
        scopedEffectIdentityCounter.Value <- Some(current + 1)
        $"surface-elaboration|{current}"

    let private ensureScopedEffectDeclarationIdentity (declaration: EffectDeclaration) =
        if declaration.EffectInterfaceId.IsSome && declaration.EffectLabelId.IsSome && (declaration.Operations |> List.forall (fun operation -> operation.OperationId.IsSome)) then
            declaration
        else
            EffectSemantics.ensureLocal (nextScopedEffectIdentitySeed ()) declaration

    let private scopedEffectOperationMetadata (declaration: EffectSemanticDeclaration) =
        declaration.Operations
        |> List.map (fun operation ->
            { KCoreEffectOperation.OperationId = operation.OperationId
              Name = operation.Name
              ResumptionQuantity = operation.ResumptionQuantity |> Option.orElse (Some QuantityOne)
              ParameterArity = operation.ParameterArity })

    let private scopedRuntimeEffectOperationMetadata (declaration: EffectSemanticDeclaration) =
        declaration.Operations
        |> List.map (fun operation ->
            { KRuntimeEffectOperation.OperationId = operation.OperationId
              Name = operation.Name
              ResumptionQuantity = operation.ResumptionQuantity |> Option.orElse (Some QuantityOne)
              ParameterArity = operation.ParameterArity })

    let private scopedKCoreEffectLabel (declaration: EffectSemanticDeclaration) =
        KCoreEffectLabel(
            declaration.VisibleName,
            declaration.InterfaceId,
            declaration.LabelId,
            scopedEffectOperationMetadata declaration
        )

    let private scopedKRuntimeEffectLabel (declaration: EffectSemanticDeclaration) =
        KRuntimeEffectLabel(
            declaration.VisibleName,
            declaration.InterfaceId,
            declaration.LabelId,
            scopedRuntimeEffectOperationMetadata declaration
        )

    let private tryFindScopedEffectOperation effectName operationName =
        tryFindScopedEffectDeclaration effectName
        |> Option.bind (fun declaration -> EffectSemantics.tryFindOperation operationName declaration |> Option.map (fun operation -> declaration, operation))

    let private significantEffectHandlerTokens tokens =
        tokens
        |> List.filter (fun token ->
            match token.Kind with
            | Newline
            | Indent
            | Dedent
            | EndOfFile -> false
            | _ -> true)

    let private tryParseEffectHandlerArgumentName tokens =
        match significantEffectHandlerTokens tokens with
        | [ token ] when Token.isName token ->
            let name = SyntaxFacts.trimIdentifierQuotes token.Text

            if String.Equals(name, "_", StringComparison.Ordinal) then
                None
            else
                Some name
        | leftParen :: nameToken :: colonToken :: _
            when leftParen.Kind = LeftParen && Token.isName nameToken && colonToken.Kind = Colon ->
            let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

            if String.Equals(name, "_", StringComparison.Ordinal) then
                None
            else
                Some name
        | _ ->
            None

    let private scopedEffectTypeParameters (declaration: EffectSemanticDeclaration) =
        TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens

    let private scopedEffectLabelType (declaration: EffectSemanticDeclaration) =
        TypeName(scopedEffectLabelNameSegments declaration, [])

    let private scopedEffectInterfaceType (declaration: EffectSemanticDeclaration) =
        TypeName(
            scopedEffectInterfaceNameSegments declaration,
            scopedEffectTypeParameters declaration
            |> List.map TypeVariable
        )

    let private scopedEffectRowType (declaration: EffectSemanticDeclaration) =
        TypeEffectRow(
            [
                { Label = scopedEffectLabelType declaration
                  Effect = scopedEffectInterfaceType declaration }
            ],
            None
        )

    let private withScopedEffectDeclaration (declaration: EffectDeclaration) work =
        let declaration = ensureScopedEffectDeclarationIdentity declaration |> EffectSemantics.toSemantic
        let saved = currentScopedEffects ()
        let savedDeclarations = currentScopedEffectDeclarations ()
        let savedCounter = scopedEffectIdentityCounter.Value
        scopedEffects.Value <- Some(Map.add declaration.VisibleName declaration saved)
        scopedEffectDeclarations.Value <- Some(declaration :: savedDeclarations)

        try
            work ()
        finally
            scopedEffects.Value <- Some saved
            scopedEffectDeclarations.Value <- Some savedDeclarations
            scopedEffectIdentityCounter.Value <- savedCounter

    let private withScopedEffectDeclarations (declarations: EffectDeclaration list) work =
        let saved = currentScopedEffects ()
        let savedDeclarations = currentScopedEffectDeclarations ()
        let savedCounter = scopedEffectIdentityCounter.Value

        let semanticDeclarations =
            declarations
            |> List.map ensureScopedEffectDeclarationIdentity
            |> List.map EffectSemantics.toSemantic

        let merged =
            semanticDeclarations
            |> List.fold (fun state declaration -> Map.add declaration.VisibleName declaration state) saved

        scopedEffects.Value <- Some merged
        scopedEffectDeclarations.Value <- Some(semanticDeclarations @ savedDeclarations)

        try
            work ()
        finally
            scopedEffects.Value <- Some saved
            scopedEffectDeclarations.Value <- Some savedDeclarations
            scopedEffectIdentityCounter.Value <- savedCounter

    let private tryResolveScopedStaticObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        let scopedEffectNames = currentScopedEffectNames ()

        match expression with
        | Name [ name ] when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectLabelStaticObject
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectLabelStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | KindQualifiedName(TypeKind, [ name ]) when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectTypeStaticObject
        | KindQualifiedName(TypeKind, nameSegments) when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectTypeStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | KindQualifiedName(EffectLabelKind, [ name ]) when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectLabelStaticObject
        | KindQualifiedName(EffectLabelKind, nameSegments) when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectLabelStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | _ ->
            tryResolveStaticObject environment expression

    let rec private tryResolveHandledEffectName
        (environment: BindingLoweringEnvironment)
        expression
        =
        tryResolveHandledEffectDeclaration environment expression
        |> Option.map (fun declaration -> declaration.VisibleName)

    and private tryResolveHandledEffectDeclaration
        (environment: BindingLoweringEnvironment)
        expression
        =
        tryResolveScopedStaticObject environment expression
        |> Option.bind (fun staticObject ->
            match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
            | StaticEffectLabelObject, Some declaration, _ -> Some declaration
            | StaticEffectLabelObject, None, [ effectName ] -> tryFindScopedEffectDeclaration effectName
            | _ -> None)

    let private tryResolveEffectOperationNamePath
        (environment: BindingLoweringEnvironment)
        (nameSegments: string list)
        =
        match List.rev nameSegments with
        | operationName :: reversedPrefix when not (List.isEmpty reversedPrefix) ->
            let prefix = List.rev reversedPrefix

            tryResolveScopedStaticObject environment (Name prefix)
            |> Option.bind (fun staticObject ->
                match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
                | StaticEffectLabelObject, Some declaration, _ ->
                    EffectSemantics.tryFindOperation operationName declaration
                    |> Option.map (fun operation -> declaration.VisibleName, declaration, operation)
                | StaticEffectLabelObject, None, [ effectName ] ->
                    tryFindScopedEffectOperation effectName operationName
                    |> Option.map (fun (declaration, operation) -> effectName, declaration, operation)
                | _ ->
                    None)
        | _ ->
            None

    let private effectResolutionCallbacks environment : EffectSemantics.EffectResolutionCallbacks =
        { TryResolveHandledEffectDeclaration = tryResolveHandledEffectDeclaration environment
          TryResolveEffectOperationNamePath =
            fun nameSegments ->
                tryResolveEffectOperationNamePath environment nameSegments
                |> Option.map (fun (_, declaration, operation) -> declaration, operation) }

    let private kindSelectorText selector =
        match selector with
        | TypeKind -> "type"
        | TraitKind -> "trait"
        | EffectLabelKind -> "effect-label"
        | ModuleKind -> "module"

    let private staticObjectExpression (staticObject: StaticObjectInfo) =
        let selector =
            match staticObject.ObjectKind with
            | StaticTypeObject -> TypeKind
            | StaticTraitObject -> TraitKind
            | StaticEffectLabelObject -> EffectLabelKind
            | StaticModuleObject -> ModuleKind

        KindQualifiedName(selector, staticObject.NameSegments)

    let private rewriteStaticObjectAliasUse aliasName staticObject expression =
        let aliasIsBoundByPattern pattern =
            collectPatternNames pattern
            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

        let aliasIsBoundByParameters (parameters: Parameter list) =
            parameters
            |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal))

        let aliasIsBoundByName name =
            String.Equals(name, aliasName, StringComparison.Ordinal)

        let rec rewrite current =
            match current with
            | Name [ root ] when aliasIsBoundByName root ->
                staticObjectExpression staticObject
            | Name(root :: path) when aliasIsBoundByName root ->
                Name(staticObject.NameSegments @ path)
            | Name _ ->
                current
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | LocalLet(binding, value, body) ->
                let rewrittenValue = rewrite value

                if aliasIsBoundByPattern binding.Pattern then
                    LocalLet(binding, rewrittenValue, body)
                else
                    LocalLet(binding, rewrittenValue, rewrite body)
            | LocalSignature(declaration, body) ->
                if aliasIsBoundByName declaration.Name then
                    LocalSignature(declaration, body)
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if aliasIsBoundByName declaration.Name then
                    LocalScopedEffect(declaration, body)
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Lambda(parameters, body) ->
                if aliasIsBoundByParameters parameters then
                    Lambda(parameters, body)
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        if aliasIsBoundByPattern caseClause.Pattern then
                            caseClause
                        else
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map rewrite
                                Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteStatements remaining =
                    match remaining with
                    | [] -> []
                    | statement :: rest ->
                        match statement with
                        | DoLet(binding, value) ->
                            let rewritten = DoLet(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoLetQuestion(binding, value, failure) ->
                            let rewrittenFailure =
                                failure
                                |> Option.map (fun failureClause ->
                                    if aliasIsBoundByPattern failureClause.ResiduePattern.Pattern then
                                        failureClause
                                    else
                                        { failureClause with Body = rewriteStatements failureClause.Body })

                            let rewritten = DoLetQuestion(binding, rewrite value, rewrittenFailure)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoBind(binding, value) ->
                            let rewritten = DoBind(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoUsing(binding, value) ->
                            let rewritten = DoUsing(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoVar(name, value) ->
                            let rewritten = DoVar(name, rewrite value)
                            if aliasIsBoundByName name then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoAssign(name, value) ->
                            DoAssign(name, rewrite value) :: rewriteStatements rest
                        | DoDefer value ->
                            DoDefer(rewrite value) :: rewriteStatements rest
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(condition |> rewrite, whenTrue |> rewriteStatements, whenFalse |> rewriteStatements)
                            :: rewriteStatements rest
                        | DoWhile(condition, body) ->
                            DoWhile(rewrite condition, rewriteStatements body) :: rewriteStatements rest
                        | DoReturn value ->
                            DoReturn(rewrite value) :: rest
                        | DoExpression value ->
                            DoExpression(rewrite value) :: rewriteStatements rest

                Do(rewriteStatements statements)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, operand) ->
                Unary(operatorName, rewrite operand)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _ ->
                current

        rewrite expression

    let private rewriteNamedApplicationAliasUse
        aliasName
        (parameters: Parameter list)
        expression
        =
        let supportedParameters =
            parameters
            |> List.forall (fun parameter -> not parameter.IsImplicit && not parameter.IsInout && not parameter.IsReceiver)

        let tryReorder arguments =
            match supportedParameters, arguments with
            | true, [ NamedApplicationBlock fields ] ->
                let fieldMap =
                    fields
                    |> List.map (fun field -> field.Name, field.Value)
                    |> Map.ofList

                if parameters |> List.forall (fun parameter -> fieldMap.ContainsKey(parameter.Name)) then
                    parameters
                    |> List.map (fun parameter -> fieldMap[parameter.Name])
                    |> Some
                else
                    None
            | _ ->
                None

        let rec rewrite current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                match tryReorder arguments with
                | Some reorderedArguments ->
                    Apply(Name [ name ], reorderedArguments |> List.map rewrite)
                | None ->
                    Apply(Name [ name ], arguments |> List.map rewrite)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | LocalLet(binding, value, body) ->
                let shadowsAlias =
                    collectPatternNames binding.Pattern
                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
            | LocalSignature(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Lambda(parameters, body) ->
                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                    current
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                Do statements
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | TypeSyntaxTokens _
            | Name _ ->
                current

        rewrite expression

    let private rewriteDirectAliasUse aliasName targetName expression =
        let rec rewrite current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                Apply(Name [ targetName ], arguments |> List.map rewrite)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | LocalLet(binding, value, body) ->
                let shadowsAlias =
                    collectPatternNames binding.Pattern
                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
            | LocalSignature(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Lambda(parameters, body) ->
                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                    current
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                Do statements
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                current

        rewrite expression

    let private rewriteStaticObjectPathAliasUses (aliases: Map<string list, StaticObjectInfo>) expression =
        let sortedAliases =
            aliases
            |> Map.toList
            |> List.sortByDescending (fun (segments, _) -> List.length segments)

        let shadowsAnyAlias names (activeAliases: Map<string list, StaticObjectInfo>) =
            if Set.isEmpty names then
                false
            else
                activeAliases
                |> Map.exists (fun segments _ ->
                    match segments with
                    | root :: _ -> Set.contains root names
                    | [] -> false)

        let withoutShadowedAliases names (activeAliases: Map<string list, StaticObjectInfo>) =
            if Set.isEmpty names then
                activeAliases
            else
                activeAliases
                |> Map.filter (fun segments _ ->
                    match segments with
                    | root :: _ -> not (Set.contains root names)
                    | [] -> true)

        let tryRewriteName activeAliases segments =
            let candidates =
                activeAliases
                |> Map.toList
                |> List.sortByDescending (fun (aliasSegments, _) -> List.length aliasSegments)

            candidates
            |> List.tryPick (fun (aliasSegments, staticObject) ->
                if List.length aliasSegments <= List.length segments
                   && (segments |> List.take (List.length aliasSegments)) = aliasSegments then
                    let rest = segments |> List.skip (List.length aliasSegments)

                    if List.isEmpty rest then
                        Some(staticObjectExpression staticObject)
                    else
                        Some(Name(staticObject.NameSegments @ rest))
                else
                    None)

        let rec rewrite activeAliases current =
            match current with
            | Name segments ->
                tryRewriteName activeAliases segments
                |> Option.defaultValue current
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite activeAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite activeAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite activeAliases inner)
            | CodeQuote inner ->
                CodeQuote(rewrite activeAliases inner)
            | CodeSplice inner ->
                CodeSplice(rewrite activeAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite activeAliases clause.Body }

                Handle(
                    isDeep,
                    rewrite activeAliases label,
                    rewrite activeAliases body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | LocalLet(binding, value, body) ->
                let rewrittenValue = rewrite activeAliases value
                let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList
                let bodyAliases = withoutShadowedAliases shadowedNames activeAliases

                LocalLet(binding, rewrittenValue, rewrite bodyAliases body)
            | LocalSignature(declaration, body) ->
                LocalSignature(declaration, rewrite (withoutShadowedAliases (Set.singleton declaration.Name) activeAliases) body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite activeAliases body)
            | LocalScopedEffect(declaration, body) ->
                let bodyAliases = withoutShadowedAliases (Set.singleton declaration.Name) activeAliases
                LocalScopedEffect(declaration, rewrite bodyAliases body)
            | Lambda(parameters, body) ->
                let shadowedNames = parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList
                Lambda(parameters, rewrite (withoutShadowedAliases shadowedNames activeAliases) body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite activeAliases condition, rewrite activeAliases whenTrue, rewrite activeAliases whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite activeAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        let shadowedNames = collectPatternNames caseClause.Pattern |> Set.ofList
                        let caseAliases = withoutShadowedAliases shadowedNames activeAliases

                        { caseClause with
                            Guard = caseClause.Guard |> Option.map (rewrite caseAliases)
                            Body = rewrite caseAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite activeAliases value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite activeAliases receiver, fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite activeAliases receiver, segments, arguments |> List.map (rewrite activeAliases))
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite activeAliases receiver, { navigation with Arguments = navigation.Arguments |> List.map (rewrite activeAliases) })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite activeAliases receiver, constructorName)
            | Do statements ->
                let rec rewriteStatements activeAliases remaining =
                    match remaining with
                    | [] -> []
                    | statement :: rest ->
                        match statement with
                        | DoLet(binding, value) ->
                            let rewritten = DoLet(binding, rewrite activeAliases value)
                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList

                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoLetQuestion(binding, value, failure) ->
                            let rewrittenFailure =
                                failure
                                |> Option.map (fun failureClause ->
                                    let shadowedNames = collectPatternNames failureClause.ResiduePattern.Pattern |> Set.ofList

                                    { failureClause with
                                        Body = rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) failureClause.Body })

                            let rewritten = DoLetQuestion(binding, rewrite activeAliases value, rewrittenFailure)
                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList

                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            let rewrittenValue = rewrite activeAliases value
                            let rewritten =
                                match statement with
                                | DoBind _ -> DoBind(binding, rewrittenValue)
                                | _ -> DoUsing(binding, rewrittenValue)

                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList
                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoVar(name, value) ->
                            DoVar(name, rewrite activeAliases value)
                            :: rewriteStatements (withoutShadowedAliases (Set.singleton name) activeAliases) rest
                        | DoAssign(name, value) ->
                            DoAssign(name, rewrite activeAliases value) :: rewriteStatements activeAliases rest
                        | DoDefer value ->
                            DoDefer(rewrite activeAliases value) :: rewriteStatements activeAliases rest
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(
                                rewrite activeAliases condition,
                                rewriteStatements activeAliases whenTrue,
                                rewriteStatements activeAliases whenFalse
                            )
                            :: rewriteStatements activeAliases rest
                        | DoWhile(condition, body) ->
                            DoWhile(rewrite activeAliases condition, rewriteStatements activeAliases body)
                            :: rewriteStatements activeAliases rest
                        | DoReturn value ->
                            DoReturn(rewrite activeAliases value) :: rest
                        | DoExpression value ->
                            DoExpression(rewrite activeAliases value) :: rewriteStatements activeAliases rest

                Do(rewriteStatements activeAliases statements)
            | MonadicSplice inner ->
                MonadicSplice(rewrite activeAliases inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite activeAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | Apply(callee, arguments) ->
                Apply(rewrite activeAliases callee, arguments |> List.map (rewrite activeAliases))
            | InoutArgument inner ->
                InoutArgument(rewrite activeAliases inner)
            | Unary(operatorName, operand) ->
                Unary(operatorName, rewrite activeAliases operand)
            | Binary(left, operatorName, right) ->
                Binary(rewrite activeAliases left, operatorName, rewrite activeAliases right)
            | Elvis(left, right) ->
                Elvis(rewrite activeAliases left, rewrite activeAliases right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite activeAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite activeAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _ ->
                current

        if List.isEmpty sortedAliases then
            expression
        else
            rewrite aliases expression

    let rec private rewriteEffectOperationPathAliasUses
        (environment: BindingLoweringEnvironment)
        (aliases: Map<string list, EffectSemantics.ResolvedEffectOperation>)
        expression
        =
        EffectSemantics.rewriteOperationAliasUses (effectResolutionCallbacks environment) aliases expression

    and private collectScopedPatternEffectOperationAliases
        (environment: BindingLoweringEnvironment)
        pattern
        value
        =
        EffectSemantics.collectPatternOperationAliases (effectResolutionCallbacks environment) pattern value

    let private collectScopedPatternStaticAliases
        (environment: BindingLoweringEnvironment)
        pattern
        value
        =
        let rec collectExpression prefix expression aliases =
            match tryResolveScopedStaticObject environment expression with
            | Some staticObject ->
                Map.add prefix staticObject aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectExpression (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(inner, _) ->
                    collectExpression prefix inner aliases
                | _ ->
                    aliases

        let rec collectPattern pattern value aliases =
            match pattern with
            | NamePattern name ->
                collectExpression [ name ] value aliases
            | AsPattern(name, inner) ->
                collectPattern inner value (collectExpression [ name ] value aliases)
            | TypedPattern(inner, _) ->
                collectPattern inner value aliases
            | AnonymousRecordPattern(fields, rest) ->
                fields
                |> List.fold (fun current field ->
                    let fieldExpression =
                        match value with
                        | Name segments -> Name(segments @ [ field.Name ])
                        | _ -> MemberAccess(value, [ field.Name ], [])

                    collectPattern field.Pattern fieldExpression current) aliases
                |> fun current ->
                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        collectExpression [ name ] value current
                    | _ ->
                        current
            | ConstructorPattern(_, arguments) ->
                arguments |> List.fold (fun current argument -> collectPattern argument value current) aliases
            | NamedConstructorPattern(_, fields) ->
                fields |> List.fold (fun current field -> collectPattern field.Pattern value current) aliases
            | TuplePattern elements ->
                elements |> List.fold (fun current element -> collectPattern element value current) aliases
            | VariantPattern(BoundVariantPattern(name, _))
            | VariantPattern(RestVariantPattern name) ->
                collectExpression [ name ] value aliases
            | VariantPattern(WildcardVariantPattern _) ->
                aliases
            | OrPattern alternatives ->
                alternatives
                |> List.tryHead
                |> Option.map (fun first -> collectPattern first value aliases)
                |> Option.defaultValue aliases
            | WildcardPattern
            | LiteralPattern _ ->
                aliases

        collectPattern pattern value Map.empty

    let private unitType =
        TypeName([ "Unit" ], [])

    let private voidType =
        TypeName([ "Void" ], [])

    let private boolType =
        TypeName([ "Bool" ], [])

    let private intType =
        TypeName([ "Int" ], [])

    let private integerType =
        TypeName([ "Integer" ], [])

    let private floatType =
        TypeName([ "Float" ], [])

    let private doubleType =
        TypeName([ "Double" ], [])

    let private stringType =
        TypeName([ "String" ], [])

    let private unicodeScalarType =
        TypeName([ "UnicodeScalar" ], [])

    let private graphemeType =
        TypeName([ "Grapheme" ], [])

    let private byteType =
        TypeName([ "Byte" ], [])

    let private syntaxType argumentType =
        TypeName([ "Syntax" ], [ argumentType ])

    let private elabType argumentType =
        TypeName([ "Elab" ], [ argumentType ])

    let private codeType argumentType =
        TypeName([ "Code" ], [ argumentType ])

    let private ioType argumentType =
        TypeName([ "IO" ], [ argumentType ])

    let private effType effectRow payloadType =
        TypeName([ "Eff" ], [ effectRow; payloadType ])

    let private refType argumentType =
        TypeName([ "Ref" ], [ argumentType ])

    let private dictionaryType traitName argumentTypes =
        TypeName([ TraitRuntime.dictionaryTypeName traitName ], argumentTypes)

    let private unwrapIoType typeExpr =
        match typeExpr with
        | TypeName([ "IO" ], [ inner ]) -> inner
        | TypeName([ "IO" ], [ _; inner ]) -> inner
        | TypeName([ "UIO" ], [ inner ]) -> inner
        | other -> other

    let private tryUnwrapEffType typeExpr =
        match typeExpr with
        | TypeName([ "Eff" ], [ effectRow; inner ]) -> Some(effectRow, inner)
        | _ -> None

    let rec private tryUnwrapComputationPayloadType typeExpr =
        match typeExpr with
        | TypeCapture(inner, _) -> tryUnwrapComputationPayloadType inner
        | TypeName([ "Eff" ], [ _; inner ]) -> Some inner
        | TypeName([ "IO" ], [ inner ]) -> Some inner
        | TypeName([ "IO" ], [ _; inner ]) -> Some inner
        | TypeName([ "UIO" ], [ inner ]) -> Some inner
        | _ -> None

    let rec private unwrapBindPayloadType typeExpr =
        match typeExpr with
        | TypeCapture(inner, _) -> unwrapBindPayloadType inner
        | TypeName([ "Eff" ], [ _; inner ]) -> inner
        | TypeName(_, [ inner ]) -> inner
        | other -> unwrapIoType other

    let private typeTextOf typeExpr =
        typeExpr
        |> unwrapIoType
        |> TypeSignatures.toText

    let private tryParseParameterType (parameter: Parameter) =
        parameter.TypeTokens |> Option.bind TypeSignatures.parseType

    let private tryParseReturnTypeType tokens =
        tokens |> Option.bind TypeSignatures.parseType

    let private tryParseReturnTypeTokens tokens =
        tryParseReturnTypeType tokens |> Option.map typeTextOf

    let private freshUnknownLocalType (freshCounter: int ref) =
        let name = $"__kappa_local_t{freshCounter.Value}"
        freshCounter.Value <- freshCounter.Value + 1
        TypeVariable name

    let private inferFallbackLocalType (freshCounter: int ref) expression =
        match expression with
        | Lambda(parameters, _) ->
            let resultType = freshUnknownLocalType freshCounter

            parameters
            |> List.rev
            |> List.fold
                (fun current parameter ->
                    let parameterType =
                        tryParseParameterType parameter
                        |> Option.defaultValue (freshUnknownLocalType freshCounter)

                    TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current))
                resultType
        | _ ->
            freshUnknownLocalType freshCounter

    let private tryParseLetDefinitionScheme (definition: LetDefinition) =
        match definition.ReturnTypeTokens |> Option.bind TypeSignatures.parseType with
        | Some returnType ->
            let parameterTypes =
                definition.Parameters
                |> List.map tryParseParameterType

            if parameterTypes |> List.forall Option.isSome then
                let body =
                    List.zip definition.Parameters (parameterTypes |> List.choose id)
                    |> List.rev
                    |> List.fold (fun current (parameter, parameterType) ->
                        TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current)) returnType

                Some
                    { Forall = []
                      Constraints = []
                      Body = body }
            else
                None
        | None ->
            None

    let private tryParseTraitMemberSignatureNameAndScheme (memberDeclaration: TraitMember) =
        let tokens = significantTokens memberDeclaration.Tokens

        let tryParseNamedSignature name schemeTokens =
            TypeSignatures.parseScheme schemeTokens
            |> Option.map (fun scheme ->
                name,
                { Name = name
                  Scheme = scheme
                  DefaultDefinition = memberDeclaration.DefaultDefinition })

        match tokens with
        | head :: colon :: schemeTokens when Token.isName head && colon.Kind = Colon ->
            tryParseNamedSignature (SyntaxFacts.trimIdentifierQuotes head.Text) schemeTokens
        | { Kind = LeftParen } :: { Kind = Operator; Text = operatorName } :: { Kind = RightParen } :: colon :: schemeTokens
            when colon.Kind = Colon ->
            tryParseNamedSignature operatorName schemeTokens
        | _ ->
            None

    let private tryParseTraitMemberInfo (memberDeclaration: TraitMember) =
        tryParseTraitMemberSignatureNameAndScheme memberDeclaration

    let rec private rewriteAssociatedTraitMembersInType
        (traitName: string)
        (traitTypeParameters: string list)
        (associatedStaticMembers: Set<string>)
        typeExpr
        =
        let traitHead =
            TypeName([ traitName ], traitTypeParameters |> List.map TypeVariable)

        let rewrite = rewriteAssociatedTraitMembersInType traitName traitTypeParameters associatedStaticMembers

        match typeExpr with
        | TypeName([ memberName ], []) when associatedStaticMembers.Contains memberName ->
            TypeProject(traitHead, memberName)
        | TypeApply(callee, arguments) ->
            TypeApply(rewrite callee, arguments |> List.map rewrite)
        | TypeLambda(parameterName, parameterSort, body) ->
            TypeLambda(parameterName, rewrite parameterSort, rewrite body)
        | TypeDelay inner ->
            TypeDelay(rewrite inner)
        | TypeMemo inner ->
            TypeMemo(rewrite inner)
        | TypeForce inner ->
            TypeForce(rewrite inner)
        | TypeProject(target, fieldName) ->
            TypeProject(rewrite target, fieldName)
        | TypeArrow(quantity, parameterType, resultType) ->
            TypeArrow(quantity, rewrite parameterType, rewrite resultType)
        | TypeEquality(left, right) ->
            TypeEquality(rewrite left, rewrite right)
        | TypeCapture(inner, captures) ->
            TypeCapture(rewrite inner, captures)
        | TypeEffectRow(entries, tail) ->
            TypeEffectRow(
                entries
                |> List.map (fun entry ->
                    { Label = rewrite entry.Label
                      Effect = rewrite entry.Effect }),
                tail |> Option.map rewrite
            )
        | TypeRecord fields ->
            TypeRecord(fields |> List.map (fun field -> { field with Type = rewrite field.Type }))
        | TypeUnion members ->
            TypeUnion(members |> List.map rewrite)
        | _ ->
            typeExpr

    let private rewriteAssociatedTraitMembersInScheme
        (traitName: string)
        (traitTypeParameters: string list)
        (associatedStaticMembers: Set<string>)
        (scheme: TypeScheme)
        =
        let rewriteType = rewriteAssociatedTraitMembersInType traitName traitTypeParameters associatedStaticMembers

        { scheme with
            Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = rewriteType binder.Sort })
            Constraints =
                scheme.Constraints
                |> List.map (fun constraintInfo ->
                    { constraintInfo with
                        Arguments = constraintInfo.Arguments |> List.map rewriteType })
            Body = rewriteType scheme.Body }

    let private splitTopLevelConstraintGroups (tokens: Token list) =
        let significant = significantTokens tokens

        let stripSingleOuterParens current =
            match current with
            | { Kind = LeftParen } :: rest ->
                let tokenArray = current |> List.toArray
                let mutable depth = 0
                let mutable closesAtEnd = false
                let mutable index = 0

                while index < tokenArray.Length do
                    match tokenArray[index].Kind with
                    | LeftParen ->
                        depth <- depth + 1
                    | RightParen ->
                        depth <- depth - 1

                        if depth = 0 then
                            closesAtEnd <- index = tokenArray.Length - 1
                    | _ ->
                        ()

                    index <- index + 1

                if closesAtEnd then
                    rest |> List.take (rest.Length - 1)
                else
                    current
            | _ ->
                current

        let flattened = stripSingleOuterParens significant
        let groups = ResizeArray<Token list>()
        let currentGroup = ResizeArray<Token>()
        let mutable parenDepth = 0
        let mutable bracketDepth = 0
        let mutable braceDepth = 0
        let mutable setBraceDepth = 0

        for token in flattened do
            match token.Kind with
            | LeftParen ->
                parenDepth <- parenDepth + 1
                currentGroup.Add(token)
            | RightParen ->
                parenDepth <- max 0 (parenDepth - 1)
                currentGroup.Add(token)
            | LeftBracket
            | LeftEffectRow ->
                bracketDepth <- bracketDepth + 1
                currentGroup.Add(token)
            | RightBracket
            | RightEffectRow ->
                bracketDepth <- max 0 (bracketDepth - 1)
                currentGroup.Add(token)
            | LeftBrace ->
                braceDepth <- braceDepth + 1
                currentGroup.Add(token)
            | RightBrace ->
                braceDepth <- max 0 (braceDepth - 1)
                currentGroup.Add(token)
            | LeftSetBrace ->
                setBraceDepth <- setBraceDepth + 1
                currentGroup.Add(token)
            | RightSetBrace ->
                setBraceDepth <- max 0 (setBraceDepth - 1)
                currentGroup.Add(token)
            | Comma when parenDepth = 0 && bracketDepth = 0 && braceDepth = 0 && setBraceDepth = 0 ->
                if currentGroup.Count > 0 then
                    groups.Add(List.ofSeq currentGroup)
                    currentGroup.Clear()
            | _ ->
                currentGroup.Add(token)

        if currentGroup.Count > 0 then
            groups.Add(List.ofSeq currentGroup)

        groups |> Seq.toList

    let private trySplitTraitHeaderTokens (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let mutable parenDepth = 0
        let mutable bracketDepth = 0
        let mutable braceDepth = 0
        let mutable setBraceDepth = 0
        let mutable headStart = 0
        let mutable constraintEnd = 0
        let mutable index = 0

        while index < tokenArray.Length do
            match tokenArray[index].Kind with
            | LeftParen ->
                parenDepth <- parenDepth + 1
            | RightParen ->
                parenDepth <- max 0 (parenDepth - 1)
            | LeftBracket
            | LeftEffectRow ->
                bracketDepth <- bracketDepth + 1
            | RightBracket
            | RightEffectRow ->
                bracketDepth <- max 0 (bracketDepth - 1)
            | LeftBrace ->
                braceDepth <- braceDepth + 1
            | RightBrace ->
                braceDepth <- max 0 (braceDepth - 1)
            | LeftSetBrace ->
                setBraceDepth <- setBraceDepth + 1
            | RightSetBrace ->
                setBraceDepth <- max 0 (setBraceDepth - 1)
            | Operator
                when parenDepth = 0
                     && bracketDepth = 0
                     && braceDepth = 0
                     && setBraceDepth = 0
                     && String.Equals(tokenArray[index].Text, "=>", StringComparison.Ordinal) ->
                headStart <- index + 1
                constraintEnd <- index
            | Equals
                when parenDepth = 0
                     && bracketDepth = 0
                     && braceDepth = 0
                     && setBraceDepth = 0
                     && index + 1 < tokenArray.Length
                     && tokenArray[index + 1].Kind = Operator
                     && String.Equals(tokenArray[index + 1].Text, ">", StringComparison.Ordinal) ->
                headStart <- index + 2
                constraintEnd <- index
                index <- index + 1
            | _ ->
                ()

            index <- index + 1

        if headStart <= 0 then
            [], tokens
        else
            tokenArray[..constraintEnd - 1] |> Array.toList, tokenArray[headStart..] |> Array.toList

    let private tryParseTraitConstraintTokens tokens =
        TypeSignatures.parseType tokens
        |> Option.bind (function
            | TypeName(nameSegments, arguments) ->
                Some
                    { TraitName =
                        match nameSegments with
                        | [ singleName ] -> singleName
                        | _ -> SyntaxFacts.moduleNameToText nameSegments
                      Arguments = arguments }
            | _ ->
                None)

    let private parseTraitSupertraits (declaration: TraitDeclaration) =
        let supertraitTokens, _ = trySplitTraitHeaderTokens declaration.FullHeaderTokens

        splitTopLevelConstraintGroups supertraitTokens
        |> List.choose tryParseTraitConstraintTokens


    let private tryParseInstanceHeader (declaration: InstanceDeclaration) =
        declaration.FullHeaderTokens
        |> TypeSignatures.parseScheme
        |> Option.bind (fun scheme ->
            match scheme.Body with
            | TypeName(name, headTypes) ->
                let traitName =
                    match name with
                    | [ singleName ] -> singleName
                    | _ -> SyntaxFacts.moduleNameToText name

                Some(traitName, scheme.Constraints, headTypes)
            | _ ->
                None)

    let private tryParseTypeAliasInfo moduleName (declaration: TypeAlias) =
        declaration.BodyTokens
        |> Option.bind TypeSignatures.parseType
        |> Option.map (fun body ->
            declaration.Name,
            { ModuleName = moduleName
              Name = declaration.Name
              IsOpaque = declaration.IsOpaque
              Parameters = TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens
              Body = body
              TerminationCertified = true
              ConversionReducible = true })

    let private splitHeaderKindTokens (tokens: Token list) =
        let rec loop depth index =
            if index >= tokens.Length then
                tokens, []
            else
                match tokens[index].Kind with
                | LeftParen
                | LeftBracket
                | LeftBrace
                | LeftSetBrace ->
                    loop (depth + 1) (index + 1)
                | RightParen
                | RightBracket
                | RightBrace
                | RightSetBrace ->
                    loop (max 0 (depth - 1)) (index + 1)
                | Colon when depth = 0 ->
                    List.take index tokens, List.skip (index + 1) tokens
                | _ ->
                    loop depth (index + 1)

        loop 0 0

    let private findMatchingRightParen (tokens: Token list) =
        let rec loop depth index =
            if index >= tokens.Length then
                None
            else
                match tokens[index].Kind with
                | LeftParen ->
                    loop (depth + 1) (index + 1)
                | RightParen when depth = 1 ->
                    Some index
                | RightParen ->
                    loop (max 0 (depth - 1)) (index + 1)
                | _ ->
                    loop depth (index + 1)

        loop 0 0

    let private parseBinderTypeOrDefault (binderTokens: Token list) =
        let _, typeTokens = splitHeaderKindTokens binderTokens

        match significantTokens typeTokens with
        | [] -> typeObjectType
        | tokens -> TypeSignatures.parseType tokens |> Option.defaultValue typeObjectType

    let private typeFacetParameterTypes (tokens: Token list) =
        let rec loop remaining acc =
            match significantTokens remaining with
            | [] ->
                List.rev acc
            | head :: rest when Token.isName head ->
                loop rest (typeObjectType :: acc)
            | { Kind = LeftParen } :: _ as current ->
                match findMatchingRightParen current with
                | Some rightParenIndex ->
                    let binderTokens =
                        current
                        |> List.skip 1
                        |> List.take (rightParenIndex - 1)

                    let next =
                        current |> List.skip (rightParenIndex + 1)

                    loop next (parseBinderTypeOrDefault binderTokens :: acc)
                | None ->
                    List.rev acc
            | _ :: rest ->
                loop rest acc

        loop tokens []

    let private buildTypeFacetInfo moduleName name kind isOpaque headerTokens =
        let parameterTokens, kindTokens = splitHeaderKindTokens headerTokens

        let resultType =
            match significantTokens kindTokens with
            | [] -> typeObjectType
            | tokens -> TypeSignatures.parseType tokens |> Option.defaultValue typeObjectType

        let body =
            parameterTokens
            |> typeFacetParameterTypes
            |> List.rev
            |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) resultType

        name,
        { ModuleName = moduleName
          Name = name
          FacetKind = kind
          IsOpaque = isOpaque
          Scheme =
            { Forall = []
              Constraints = []
              Body = body } }

    let private isPrivateByDefault (frontendModule: KFrontIRModule) =
        frontendModule.ModuleAttributes
        |> List.exists (fun attributeName -> String.Equals(attributeName, ModuleAttribute.PrivateByDefault, StringComparison.Ordinal))

    let private moduleHasAttribute (frontendModule: KFrontIRModule) (attributeName: string) =
        frontendModule.ModuleAttributes
        |> List.exists (fun current -> String.Equals(current, attributeName, StringComparison.Ordinal))

    let private itemHasModifier modifier (item: ImportItem) =
        item.Modifiers |> List.exists ((=) modifier)

    let private itemRequestsUnhide item =
        itemHasModifier Unhide item

    let private itemRequestsClarify item =
        itemHasModifier Clarify item

    let private isExportedVisibility isPrivateByDefault visibility =
        match visibility with
        | Some Visibility.Public -> true
        | Some Visibility.Private -> false
        | None -> not isPrivateByDefault

    let private backendSupportsMultishotEffects backendProfile =
        match backendProfile with
        | BackendProfile.Interpreter
        | BackendProfile.DotNet
        | BackendProfile.Zig -> true
        | BackendProfile.Unknown _ -> false

    let private quantityPermitsMultipleResumptions quantity =
        match quantity |> Option.defaultValue QuantityOne with
        | QuantityOmega
        | QuantityAtLeastOne
        | QuantityVariable _ ->
            true
        | QuantityZero
        | QuantityOne
        | QuantityBorrow _
        | QuantityAtMostOne ->
            false

    let private borrowedEffectResumptionQuantityDiagnostics makeDiagnostic (declaration: EffectDeclaration) =
        declaration.Operations
        |> List.choose (fun operation ->
            match operation.ResumptionQuantity with
            | Some(QuantityBorrow _ as quantity) ->
                Some(
                    makeDiagnostic
                        DiagnosticCode.EffectResumptionQuantityBorrowed
                        $"Effect operation '{declaration.Name}.{operation.Name}' declares borrowed resumption quantity '{Quantity.toSurfaceText quantity}'. Resumption quantities quantify the handler-bound resumption value itself, and borrowed resumptions are not part of the language."
                )
            | _ ->
                None)

    let private itemImportsTermName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Term

    let private itemImportsTypeName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Type

    let private itemImportsTraitName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Trait

    let private itemImportsConstructorName (item: ImportItem) =
        item.Namespace = Some ImportNamespace.Constructor

    let private itemImportsConstructorsOfType typeName (item: ImportItem) =
        item.IncludeConstructors
        && item.Namespace = Some ImportNamespace.Type
        && String.Equals(item.Name, typeName, StringComparison.Ordinal)

    let private importedItemLocalName (item: ImportItem) =
        item.Alias |> Option.defaultValue item.Name

    let private itemExportsTermName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Term

    let private itemExportsTypeName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Type

    let private itemExportsTraitName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Trait

    let private itemExportsConstructorName (item: ImportItem) =
        item.Namespace = Some ImportNamespace.Constructor

    let private tryParseConstructorScheme (dataDeclaration: DataDeclaration) (constructor: DataConstructor) =
        let significantConstructorTokens = significantTokens constructor.Tokens

        let signatureScheme =
            match significantConstructorTokens with
            | _ :: { Kind = Colon } :: typeTokens ->
                TypeSignatures.parseScheme typeTokens
            | _ ->
                None

        let parameterLayouts, defaultArguments =
            match constructor.Parameters with
            | Some parameters when parameters |> List.forall (fun parameter -> parameter.ParameterName.IsSome) ->
                let layouts =
                    parameters
                    |> List.map (fun parameter ->
                        { Name = parameter.ParameterName.Value
                          TypeTokens = Some parameter.ParameterTypeTokens
                          Quantity = parameter.ParameterQuantity
                          IsImplicit = parameter.ParameterIsImplicit
                          IsInout = false
                          IsReceiver = false })

                let defaults =
                    parameters
                    |> List.choose (fun parameter ->
                        match parameter.ParameterName, parameter.DefaultValue with
                        | Some name, Some defaultValue -> Some(name, defaultValue)
                        | _ -> None)
                    |> Map.ofList

                Some layouts, defaults
            | _ ->
                None, Map.empty

        let scheme =
            match signatureScheme with
            | Some scheme ->
                scheme
            | None ->
                let typeParameters = TypeSignatures.collectLeadingTypeParameters dataDeclaration.HeaderTokens
                let resultType = TypeName([ dataDeclaration.Name ], typeParameters |> List.map TypeVariable)

                let body =
                    constructor
                    |> TypeSignatures.constructorFieldTypes
                    |> List.rev
                    |> List.fold (fun state fieldType -> TypeArrow(QuantityOmega, fieldType, state)) resultType

                { Forall = TypeSignatures.inferredTypeForallBinders typeParameters
                  Constraints = []
                  Body = body }

        Some
            (constructor.Name,
             { ModuleName = ""
               Name = constructor.Name
               IsPattern = false
               Scheme = scheme
               TypeTokens = []
               ParameterLayouts = parameterLayouts
               ConstructorTypeName = Some dataDeclaration.Name
               DefaultArguments = defaultArguments })

    let private exceptMatches namespaceName name (item: ExceptItem) =
        String.Equals(item.Name, name, StringComparison.Ordinal)
        && (item.Namespace.IsNone || item.Namespace = Some namespaceName)

    let private selectionImportedName
        namespaceName
        (exportedNames: Set<string>)
        itemSelector
        (selection: ImportSelection)
        (name: string)
        =
        let exported = Set.contains name exportedNames

        match selection with
        | QualifiedOnly ->
            None
        | Items items ->
            if not exported then
                None
            else
                items
                |> List.tryFind (fun item ->
                    String.Equals(item.Name, name, StringComparison.Ordinal)
                    && itemSelector item)
                |> Option.map importedItemLocalName
        | All ->
            if exported then Some name else None
        | AllExcept excludedItems ->
            if exported && not (excludedItems |> List.exists (exceptMatches namespaceName name)) then
                Some name
            else
                None

    let private selectionImportedNameWithExplicitAccess
        namespaceName
        (exportedNames: Set<string>)
        itemSelector
        itemAccessAllowed
        (selection: ImportSelection)
        (name: string)
        =
        let exported = Set.contains name exportedNames

        match selection with
        | QualifiedOnly ->
            None
        | Items items ->
            items
            |> List.tryPick (fun item ->
                if String.Equals(item.Name, name, StringComparison.Ordinal)
                   && itemSelector item
                   && itemAccessAllowed item then
                    Some(importedItemLocalName item)
                else
                    None)
        | All ->
            if exported then Some name else None
        | AllExcept excludedItems ->
            if exported && not (excludedItems |> List.exists (exceptMatches namespaceName name)) then
                Some name
            else
                None

    let private buildModuleSurfaceInfo (frontendModule: KFrontIRModule) =
        let moduleName = moduleNameText frontendModule.ModuleIdentity
        let privateByDefault = isPrivateByDefault frontendModule

        let typeAliases =
            frontendModule.Declarations
            |> List.choose (function
                | TypeAliasNode declaration -> tryParseTypeAliasInfo moduleName declaration
                | _ -> None)
            |> Map.ofList

        let typeFacets =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration ->
                    buildTypeFacetInfo moduleName declaration.Name DataFacet declaration.IsOpaque declaration.HeaderTokens
                    |> Some
                | EffectDeclarationNode declaration ->
                    buildTypeFacetInfo moduleName declaration.Name EffectFacet false declaration.HeaderTokens
                    |> Some
                | TypeAliasNode declaration ->
                    buildTypeFacetInfo moduleName declaration.Name TypeAliasFacet declaration.IsOpaque declaration.HeaderTokens
                    |> Some
                | _ ->
                    None)
            |> Map.ofList

        let recordTypes =
            frontendModule.Declarations
            |> List.choose (function
                | TypeAliasNode declaration ->
                    declaration.BodyTokens
                    |> Option.bind tryParseRecordSurfaceInfo
                    |> Option.map (fun recordInfo -> declaration.Name, recordInfo)
                | _ ->
                    None)
            |> Map.ofList

        let bindingSchemes =
            let signatureNames =
                frontendModule.Declarations
                |> List.choose (function
                    | SignatureDeclaration declaration -> Some declaration.Name
                    | _ -> None)
                |> Set.ofList

            let bindingDefinitions =
                frontendModule.Declarations
                |> List.choose (function
                    | LetDeclaration definition when definition.Name.IsSome ->
                        Some(definition.Name.Value, definition)
                    | _ ->
                        None)
                |> Map.ofList

            frontendModule.Declarations
            |> List.choose (function
                | SignatureDeclaration declaration ->
                    let signatureParameterLayouts =
                        declaration.TypeTokens
                        |> splitSignatureParameterTokens
                        |> function
                            | [] -> None
                            | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                    TypeSignatures.parseScheme declaration.TypeTokens
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            bindingDefinitions
                            |> Map.tryFind declaration.Name
                            |> Option.map (fun definition -> definition.Parameters)
                            |> mergeParameterLayouts signatureParameterLayouts
                            |> stripForallOnlyParameterLayouts scheme

                        declaration.Name,
                        { ModuleName = moduleName
                          Name = declaration.Name
                          IsPattern =
                            bindingDefinitions
                              |> Map.tryFind declaration.Name
                              |> Option.exists (fun definition -> definition.IsPattern)
                          Scheme = scheme
                          TypeTokens = declaration.TypeTokens
                          ParameterLayouts = parameterLayouts
                          ConstructorTypeName = None
                          DefaultArguments = Map.empty })
                | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                    let signatureParameterLayouts =
                        declaration.TypeTokens
                        |> splitSignatureParameterTokens
                        |> function
                            | [] -> None
                            | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                    TypeSignatures.parseScheme declaration.TypeTokens
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            mergeParameterLayouts signatureParameterLayouts None
                            |> stripForallOnlyParameterLayouts scheme
                            |> Option.bind (fun layouts ->
                                if layouts |> List.exists parameterLayoutNeedsApplicationMetadata then
                                    Some layouts
                                else
                                    None)

                        declaration.Name,
                        { ModuleName = moduleName
                          Name = declaration.Name
                          IsPattern = false
                          Scheme = scheme
                          TypeTokens = declaration.TypeTokens
                          ParameterLayouts = parameterLayouts
                          ConstructorTypeName = None
                          DefaultArguments = Map.empty })
                | LetDeclaration definition
                    when definition.Name.IsSome
                         && not (Set.contains definition.Name.Value signatureNames)
                         && (definition.IsPattern || (definition.Parameters |> List.exists (fun parameter -> parameter.IsReceiver))) ->
                    tryParseLetDefinitionScheme definition
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            Some definition.Parameters
                            |> stripForallOnlyParameterLayouts scheme

                        definition.Name.Value,
                        { ModuleName = moduleName
                          Name = definition.Name.Value
                          IsPattern = definition.IsPattern
                          Scheme = scheme
                          TypeTokens = definition.ReturnTypeTokens |> Option.defaultValue []
                          ParameterLayouts = parameterLayouts
                          ConstructorTypeName = None
                          DefaultArguments = Map.empty })
                | _ ->
                    None)
            |> Map.ofList

        let constructors =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode dataDeclaration ->
                    dataDeclaration.Constructors
                    |> List.choose (fun constructor ->
                        tryParseConstructorScheme dataDeclaration constructor
                        |> Option.map (fun (name, info) ->
                            name,
                            { info with
                                ModuleName = moduleName }))
                    |> Some
                | _ ->
                    None)
            |> List.concat
            |> Map.ofList

        let projections =
            frontendModule.Declarations
            |> List.choose (function
                | ProjectionDeclarationNode declaration ->
                    TypeSignatures.parseType declaration.ReturnTypeTokens
                    |> Option.map (fun returnType ->
                        declaration.Name,
                        { ModuleName = moduleName
                          Name = declaration.Name
                          Binders = declaration.Binders
                          ReturnType = returnType
                          Body = declaration.Body })
                | _ ->
                    None)
            |> Map.ofList

        let exportedTerms =
            frontendModule.Declarations
            |> List.choose (function
                | SignatureDeclaration declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | LetDeclaration definition when isExportedVisibility privateByDefault definition.Visibility ->
                    definition.Name
                | ProjectionDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let exportedTypes =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | EffectDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | TypeAliasNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTypeDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let exportedConstructors =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration
                    when isExportedVisibility privateByDefault declaration.Visibility && not declaration.IsOpaque ->
                    Some(declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                | _ ->
                    None)
            |> List.concat
            |> Set.ofList

        let exportedConstructorsByType =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration
                    when isExportedVisibility privateByDefault declaration.Visibility && not declaration.IsOpaque ->
                    Some(
                        declaration.Name,
                        declaration.Constructors |> List.map (fun constructor -> constructor.Name) |> Set.ofList
                    )
                | _ ->
                    None)
            |> Map.ofList

        let exportedTraits =
            frontendModule.Declarations
            |> List.choose (function
                | TraitDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTraitDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let traits =
            frontendModule.Declarations
            |> List.choose (function
                | TraitDeclarationNode declaration ->
                    let supertraits = parseTraitSupertraits declaration
                    let traitTypeParameters = TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens
                    let isTraitAssociatedCompileTimeType typeExpr =
                        match typeExpr with
                        | TypeUniverse _
                        | TypeIntrinsic UniverseClassifier
                        | TypeIntrinsic ConstraintClassifier
                        | TypeIntrinsic QuantityClassifier
                        | TypeIntrinsic RegionClassifier
                        | TypeIntrinsic RecRowClassifier
                        | TypeIntrinsic VarRowClassifier
                        | TypeIntrinsic EffRowClassifier
                        | TypeIntrinsic LabelClassifier
                        | TypeIntrinsic EffLabelClassifier
                        | TypeName([ "Type" ], [])
                        | TypeName([ "Constraint" ], [])
                        | TypeName([ "Quantity" ], [])
                        | TypeName([ "Region" ], [])
                        | TypeName([ "RecRow" ], [])
                        | TypeName([ "VarRow" ], [])
                        | TypeName([ "EffRow" ], [])
                        | TypeName([ "Label" ], [])
                        | TypeName([ "EffLabel" ], []) ->
                            true
                        | _ ->
                            false

                    let associatedStaticMembers =
                        declaration.Members
                        |> List.choose (fun memberDeclaration ->
                            tryParseTraitMemberSignatureNameAndScheme memberDeclaration
                            |> Option.bind (fun (memberName, memberInfo) ->
                                if isTraitAssociatedCompileTimeType memberInfo.Scheme.Body then
                                    Some memberName
                                else
                                    None))
                        |> Set.ofList

                    let members =
                        declaration.Members
                        |> List.fold (fun state memberDeclaration ->
                            match tryParseTraitMemberInfo memberDeclaration with
                            | Some(memberName, memberInfo) ->
                                let memberInfo =
                                    { memberInfo with
                                        Scheme =
                                            rewriteAssociatedTraitMembersInScheme
                                                declaration.Name
                                                traitTypeParameters
                                                associatedStaticMembers
                                                memberInfo.Scheme }

                                let mergedInfo =
                                    match Map.tryFind memberName state with
                                    | Some existingInfo ->
                                        { memberInfo with
                                            DefaultDefinition =
                                                memberInfo.DefaultDefinition
                                                |> Option.orElse existingInfo.DefaultDefinition }
                                    | None ->
                                        memberInfo

                                Map.add memberName mergedInfo state
                            | None ->
                                match memberDeclaration.Name, memberDeclaration.DefaultDefinition with
                                | Some memberName, Some defaultDefinition ->
                                    match Map.tryFind memberName state, tryParseLetDefinitionScheme defaultDefinition with
                                    | Some existingInfo, _ ->
                                        state
                                        |> Map.add memberName { existingInfo with DefaultDefinition = Some defaultDefinition }
                                    | None, Some scheme ->
                                        state
                                        |> Map.add
                                            memberName
                                            { Name = memberName
                                              Scheme = scheme
                                              DefaultDefinition = Some defaultDefinition }
                                    | None, None ->
                                        state
                                | _ ->
                                    state) Map.empty

                    Some(
                        declaration.Name,
                        { ModuleName = moduleName
                          Name = declaration.Name
                          TypeParameters = traitTypeParameters
                          Supertraits = supertraits
                          Members = members }
                    )
                | _ ->
                    None)
            |> Map.ofList

        let instances =
            frontendModule.Declarations
            |> List.choose (function
                | InstanceDeclarationNode declaration ->
                    tryParseInstanceHeader declaration
                    |> Option.map (fun (traitName, constraints, headTypes) ->
                        { ModuleName = moduleName
                          TraitName = traitName
                          InstanceKey = TraitRuntime.instanceKeyFromTokens declaration.HeaderTokens
                          Constraints = constraints
                          HeadTypes = headTypes
                          Members =
                            declaration.Members
                            |> List.choose (fun memberDeclaration ->
                                memberDeclaration.Name
                                |> Option.map (fun memberName -> memberName, memberDeclaration))
                            |> Map.ofList })
                | _ ->
                    None)

        { TypeAliases = typeAliases
          TypeFacets = typeFacets
          RecordTypes = recordTypes
          BindingSchemes = bindingSchemes
          Constructors = constructors
          Projections = projections
          Traits = traits
          Instances = instances
          Imports = frontendModule.Imports
          ExportedTerms = exportedTerms
          ExportedConstructors = exportedConstructors
          ExportedConstructorsByType = exportedConstructorsByType
          ExportedTypes = exportedTypes
          ExportedTraits = exportedTraits }

    let private buildEffectDeclarationIndex (frontendModules: KFrontIRModule list) =
        frontendModules
        |> List.groupBy (fun frontendModule -> moduleNameText frontendModule.ModuleIdentity)
        |> List.map (fun (moduleName, fragments) ->
            moduleName,
            (fragments
             |> List.collect (fun fragment ->
                 fragment.Declarations
                 |> List.choose (function
                     | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleName declaration)
                     | _ -> None))))
        |> Map.ofList

    let private buildHostModuleSurfaceInfo (description: HostBindings.HostModuleDescription) =
        let bindingSchemes =
            description.Terms
            |> List.choose (fun binding ->
                let parameterTypes =
                    binding.Parameters
                    |> List.map (fun parameter -> tryParseTypeText parameter.TypeText)

                let returnType = tryParseTypeText binding.ReturnTypeText

                if parameterTypes |> List.forall Option.isSome && returnType.IsSome then
                    let schemeBody =
                        (parameterTypes |> List.choose id)
                        |> List.rev
                        |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) returnType.Value

                    let parameterLayouts =
                        binding.Parameters
                        |> List.map (fun parameter ->
                            { Name = parameter.Name
                              TypeTokens = Some(typeTextTokens parameter.TypeText)
                              Quantity = None
                              IsImplicit = false
                              IsInout = false
                              IsReceiver = parameter.IsReceiver })

                    Some(
                        binding.Name,
                        { ModuleName = description.ModuleName
                          Name = binding.Name
                          IsPattern = false
                          Scheme =
                            { Forall = []
                              Constraints = []
                              Body = schemeBody }
                          TypeTokens = typeTextTokens binding.ReturnTypeText
                          ParameterLayouts = Some parameterLayouts
                          ConstructorTypeName = None
                          DefaultArguments = Map.empty }
                    )
                else
                    None)
            |> Map.ofList

        let typeFacets =
            description.Types
            |> List.map (fun exportedType ->
                exportedType.Name,
                { ModuleName = description.ModuleName
                  Name = exportedType.Name
                  FacetKind = AbstractFacet
                  IsOpaque = false
                  Scheme =
                    { Forall = []
                      Constraints = []
                      Body = typeObjectType } })
            |> Map.ofList

        { TypeAliases = Map.empty
          TypeFacets = typeFacets
          RecordTypes = Map.empty
          BindingSchemes = bindingSchemes
          Constructors = Map.empty
          Projections = Map.empty
          Traits = Map.empty
          Instances = []
          Imports = []
          ExportedTerms = description.Terms |> List.map (fun binding -> binding.Name) |> Set.ofList
          ExportedConstructors = Set.empty
          ExportedConstructorsByType = Map.empty
          ExportedTypes = description.Types |> List.map (fun exportedType -> exportedType.Name) |> Set.ofList
          ExportedTraits = Set.empty }

    let private buildStandardModuleSurfaceInfo (description: StandardModules.StandardModuleDescription) =
        let bindingSchemes =
            description.Terms
            |> List.choose (fun binding ->
                tryParseSchemeText binding.TypeText
                |> Option.map (fun scheme ->
                    binding.Name,
                    { ModuleName = description.ModuleName
                      Name = binding.Name
                      IsPattern = false
                      Scheme = scheme
                      TypeTokens = typeTextTokens binding.TypeText
                      ParameterLayouts = None
                      ConstructorTypeName = None
                      DefaultArguments = Map.empty }))
            |> Map.ofList

        let typeFacets =
            description.Types
            |> List.map (fun typeName ->
                typeName,
                { ModuleName = description.ModuleName
                  Name = typeName
                  FacetKind = AbstractFacet
                  IsOpaque = false
                  Scheme =
                    { Forall = []
                      Constraints = []
                      Body = typeObjectType } })
            |> Map.ofList

        let traits =
            description.Traits
            |> List.map (fun traitInfo ->
                let members =
                    traitInfo.Members
                    |> List.choose (fun memberInfo ->
                        TypeSignatures.parseScheme (typeTextTokens memberInfo.TypeText)
                        |> Option.map (fun scheme ->
                            memberInfo.Name,
                            { Name = memberInfo.Name
                              Scheme = scheme
                              DefaultDefinition = None }))
                    |> Map.ofList

                traitInfo.Name,
                { ModuleName = description.ModuleName
                  Name = traitInfo.Name
                  TypeParameters = [ for index in 1 .. traitInfo.TypeParameterCount -> $"t{index}" ]
                  Supertraits = []
                  Members = members })
            |> Map.ofList

        { TypeAliases = Map.empty
          TypeFacets = typeFacets
          RecordTypes = Map.empty
          BindingSchemes = bindingSchemes
          Constructors = Map.empty
          Projections = Map.empty
          Traits = traits
          Instances = []
          Imports = []
          ExportedTerms = description.Terms |> List.map (fun binding -> binding.Name) |> Set.ofList
          ExportedConstructors = Set.empty
          ExportedConstructorsByType = Map.empty
          ExportedTypes = description.Types |> Set.ofList
          ExportedTraits = description.Traits |> List.map (fun traitInfo -> traitInfo.Name) |> Set.ofList }

    let private mergeSurfaceInfoMaps
        (left: Map<string, 'value>)
        (right: Map<string, 'value>)
        =
        right |> Map.fold (fun state name info -> Map.add name info state) left

    let private mergeSurfaceInfoSetMaps
        (left: Map<string, Set<string>>)
        (right: Map<string, Set<string>>)
        =
        right
        |> Map.fold (fun state name values ->
            let mergedValues =
                state
                |> Map.tryFind name
                |> Option.map (Set.union values)
                |> Option.defaultValue values

            Map.add name mergedValues state) left

    let private mergeModuleSurfaceInfo (left: ModuleSurfaceInfo) (right: ModuleSurfaceInfo) =
        { TypeAliases = mergeSurfaceInfoMaps left.TypeAliases right.TypeAliases
          TypeFacets = mergeSurfaceInfoMaps left.TypeFacets right.TypeFacets
          RecordTypes = mergeSurfaceInfoMaps left.RecordTypes right.RecordTypes
          BindingSchemes = mergeSurfaceInfoMaps left.BindingSchemes right.BindingSchemes
          Constructors = mergeSurfaceInfoMaps left.Constructors right.Constructors
          Projections = mergeSurfaceInfoMaps left.Projections right.Projections
          Traits = mergeSurfaceInfoMaps left.Traits right.Traits
          Instances = left.Instances @ right.Instances
          Imports = left.Imports @ right.Imports
          ExportedTerms = Set.union left.ExportedTerms right.ExportedTerms
          ExportedConstructors = Set.union left.ExportedConstructors right.ExportedConstructors
          ExportedConstructorsByType =
            mergeSurfaceInfoSetMaps left.ExportedConstructorsByType right.ExportedConstructorsByType
          ExportedTypes = Set.union left.ExportedTypes right.ExportedTypes
          ExportedTraits = Set.union left.ExportedTraits right.ExportedTraits }

    let private buildSurfaceIndex
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<string, HostBindings.HostModuleDescription>)
        =
        let moduleGroups =
            frontendModules
            |> List.groupBy (fun moduleDump -> moduleNameText moduleDump.ModuleIdentity)
            |> Map.ofList

        let directUserSurfaceIndex =
            moduleGroups
            |> Map.map (fun _ moduleDumps ->
                moduleDumps
                |> List.map buildModuleSurfaceInfo
                |> List.reduce mergeModuleSurfaceInfo)

        let hostSurfaceIndex =
            hostModules |> Map.map (fun _ description -> buildHostModuleSurfaceInfo description)

        let standardSurfaceIndex =
            StandardModules.byName |> Map.map (fun _ description -> buildStandardModuleSurfaceInfo description)

        let directIndex =
            directUserSurfaceIndex
            |> fun state -> standardSurfaceIndex |> Map.fold (fun current moduleName moduleInfo -> Map.add moduleName moduleInfo current) state
            |> fun state -> hostSurfaceIndex |> Map.fold (fun current moduleName moduleInfo -> Map.add moduleName moduleInfo current) state

        let addReexportedItem (importedModule: ModuleSurfaceInfo) (moduleInfo: ModuleSurfaceInfo) (item: ImportItem) =
            let exportedName = item.Name
            let localName = importedItemLocalName item
            let exportsType = Set.contains exportedName importedModule.ExportedTypes && itemExportsTypeName item
            let exportsTerm = Set.contains exportedName importedModule.ExportedTerms && itemExportsTermName item
            let exportsTrait = Set.contains exportedName importedModule.ExportedTraits && itemExportsTraitName item
            let exportsConstructor = Set.contains exportedName importedModule.ExportedConstructors && itemExportsConstructorName item
            let exportsBundledConstructors = itemImportsConstructorsOfType exportedName item
            let exportsSameSpellingConstructor =
                item.Namespace.IsNone
                && Set.contains exportedName importedModule.ExportedTypes
                && Set.contains exportedName importedModule.ExportedConstructors

            let moduleInfo =
                { moduleInfo with
                    ExportedTerms =
                        if exportsTerm then Set.add localName moduleInfo.ExportedTerms else moduleInfo.ExportedTerms
                    ExportedTypes =
                        if exportsType then Set.add localName moduleInfo.ExportedTypes else moduleInfo.ExportedTypes
                    ExportedTraits =
                        if exportsTrait then Set.add localName moduleInfo.ExportedTraits else moduleInfo.ExportedTraits
                    ExportedConstructors =
                        moduleInfo.ExportedConstructors
                        |> fun constructors ->
                            if exportsConstructor || exportsSameSpellingConstructor then
                                Set.add localName constructors
                            else
                                constructors }

            let moduleInfo =
                if exportsType then
                    { moduleInfo with
                        TypeAliases =
                            importedModule.TypeAliases
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.TypeAliases)
                            |> Option.defaultValue moduleInfo.TypeAliases
                        TypeFacets =
                            importedModule.TypeFacets
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.TypeFacets)
                            |> Option.defaultValue moduleInfo.TypeFacets
                        RecordTypes =
                            importedModule.RecordTypes
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.RecordTypes)
                            |> Option.defaultValue moduleInfo.RecordTypes }
                else
                    moduleInfo

            if exportsBundledConstructors then
                let bundledConstructors =
                    importedModule.ExportedConstructorsByType
                    |> Map.tryFind exportedName
                    |> Option.defaultValue Set.empty

                { moduleInfo with
                    ExportedConstructors = Set.union moduleInfo.ExportedConstructors bundledConstructors
                    ExportedConstructorsByType = Map.add localName bundledConstructors moduleInfo.ExportedConstructorsByType }
            else
                moduleInfo

        let addWildcardReexports (importedModule: ModuleSurfaceInfo) (moduleInfo: ModuleSurfaceInfo) excludedItems =
            let notExcluded namespaceName name = not (excludedItems |> List.exists (exceptMatches namespaceName name))
            let sameSpellingConstructors =
                Set.intersect importedModule.ExportedConstructors importedModule.ExportedTypes
                |> Set.filter (notExcluded ImportNamespace.Constructor)

            let reexportedTypeAliases =
                importedModule.TypeAliases
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.TypeAliases

            let reexportedTypeFacets =
                importedModule.TypeFacets
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.TypeFacets

            let reexportedRecordTypes =
                importedModule.RecordTypes
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.RecordTypes

            let reexportedConstructorsByType =
                importedModule.ExportedConstructorsByType
                |> Map.fold (fun state typeName constructors ->
                    if notExcluded ImportNamespace.Type typeName then
                        Map.add typeName constructors state
                    else
                        state) moduleInfo.ExportedConstructorsByType

            { moduleInfo with
                TypeAliases = reexportedTypeAliases
                TypeFacets = reexportedTypeFacets
                RecordTypes = reexportedRecordTypes
                ExportedTerms = Set.union moduleInfo.ExportedTerms (Set.filter (notExcluded ImportNamespace.Term) importedModule.ExportedTerms)
                ExportedTypes = Set.union moduleInfo.ExportedTypes (Set.filter (notExcluded ImportNamespace.Type) importedModule.ExportedTypes)
                ExportedTraits = Set.union moduleInfo.ExportedTraits (Set.filter (notExcluded ImportNamespace.Trait) importedModule.ExportedTraits)
                ExportedConstructors = Set.union moduleInfo.ExportedConstructors sameSpellingConstructors
                ExportedConstructorsByType = reexportedConstructorsByType }

        let applyReexportSpec (surfaceIndex: Map<string, ModuleSurfaceInfo>) (moduleInfo: ModuleSurfaceInfo) (spec: ImportSpec) =
            match spec.Source with
            | Url _ ->
                moduleInfo
            | Dotted moduleSegments ->
                let importedModuleName = SyntaxFacts.moduleNameToText moduleSegments

                match Map.tryFind importedModuleName surfaceIndex with
                | None ->
                    moduleInfo
                | Some importedModule ->
                    match spec.Selection with
                    | QualifiedOnly ->
                        moduleInfo
                    | Items items ->
                        items
                        |> List.filter (fun item -> List.isEmpty item.Modifiers)
                        |> List.fold (addReexportedItem importedModule) moduleInfo
                    | All ->
                        addWildcardReexports importedModule moduleInfo []
                    | AllExcept excludedItems ->
                        addWildcardReexports importedModule moduleInfo excludedItems

        let rec saturate surfaceIndex =
            let updatedUserSurfaceIndex =
                moduleGroups
                |> Map.map (fun moduleName moduleDumps ->
                    let directModuleInfo = Map.find moduleName directUserSurfaceIndex

                    moduleDumps
                    |> List.collect (fun moduleDump ->
                        moduleDump.Declarations
                        |> List.choose (function
                            | ImportDeclaration (true, specs) -> Some specs
                            | _ -> None)
                        |> List.concat)
                    |> List.fold (applyReexportSpec surfaceIndex) directModuleInfo)

            let nextSurfaceIndex =
                updatedUserSurfaceIndex
                |> fun state -> standardSurfaceIndex |> Map.fold (fun current moduleName moduleInfo -> Map.add moduleName moduleInfo current) state
                |> fun state -> hostSurfaceIndex |> Map.fold (fun current moduleName moduleInfo -> Map.add moduleName moduleInfo current) state

            if nextSurfaceIndex = surfaceIndex then
                surfaceIndex
            else
                saturate nextSurfaceIndex

        saturate directIndex

    let private importedModuleInfos (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        surfaceIndex
        |> Map.tryFind moduleName
        |> Option.map (fun moduleInfo ->
            moduleInfo.Imports
            |> List.choose (fun spec ->
                match spec.Source with
                | Url _ ->
                    None
                | Dotted moduleSegments ->
                    let importedModuleName = SyntaxFacts.moduleNameToText moduleSegments
                    surfaceIndex
                    |> Map.tryFind importedModuleName
                    |> Option.map (fun importedModule -> spec, importedModule)))
        |> Option.defaultValue []

    let private importedEffectDeclarations
        (surfaceIndex: Map<string, ModuleSurfaceInfo>)
        (effectDeclarationsByModule: Map<string, EffectDeclaration list>)
        (moduleName: string)
        =
        let importedEffectsForSpec (spec: ImportSpec, importedModule: ModuleSurfaceInfo) =
            let importedModuleName =
                match spec.Source with
                | Dotted moduleSegments -> Some(SyntaxFacts.moduleNameToText moduleSegments)
                | Url _ -> None

            importedModuleName
            |> Option.bind effectDeclarationsByModule.TryFind
            |> Option.defaultValue []
            |> List.choose (fun declaration ->
                let canImportType =
                    Set.contains declaration.Name importedModule.ExportedTypes

                let importedName =
                    match spec.Selection with
                    | QualifiedOnly ->
                        if canImportType then
                            let qualifiedPrefix = spec.Alias |> Option.defaultValue importedModuleName.Value
                            Some(qualifiedPrefix + "." + declaration.Name)
                        else
                            None
                    | _ ->
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item -> canImportType || itemRequestsUnhide item)
                            spec.Selection
                            declaration.Name

                importedName
                |> Option.map (fun localName ->
                    declaration |> EffectSemantics.importAs localName))

        importedModuleInfos surfaceIndex moduleName
        |> List.collect importedEffectsForSpec

    let private appendVisibleCandidate localName candidate state =
        let updatedCandidates =
            state
            |> Map.tryFind localName
            |> Option.defaultValue []
            |> fun existing -> candidate :: existing

        Map.add localName updatedCandidates state

    let private collectImportedOrdinaryTermCandidates (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        importedModuleInfos surfaceIndex moduleName
        |> List.fold (fun state (spec, importedModule) ->
            let importedModuleName =
                match spec.Source with
                | Dotted moduleSegments -> SyntaxFacts.moduleNameToText moduleSegments
                | Url _ -> importedModule.BindingSchemes |> Map.toSeq |> Seq.tryHead |> Option.map (fun (_, info) -> info.ModuleName) |> Option.defaultValue "<unknown>"

            let visibleBindingCandidateNames =
                Set.union
                    importedModule.ExportedTerms
                    (importedModule.BindingSchemes |> Map.keys |> Set.ofSeq)

            let withBindings =
                visibleBindingCandidateNames
                |> Set.fold (fun current name ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName ->
                        let candidate =
                            match importedModule.BindingSchemes |> Map.tryFind name with
                            | Some info -> OrdinaryVisibleBindingCandidate info
                            | None -> OrdinaryVisibleExportedBindingCandidate(importedModuleName, name)

                        appendVisibleCandidate localName candidate current
                    | None ->
                        current) state

            let withConstructors =
                importedModule.Constructors
                |> Map.fold (fun current name info ->
                    let parentTypeInfo =
                        info.ConstructorTypeName
                        |> Option.bind (fun typeName -> importedModule.TypeFacets |> Map.tryFind typeName)

                    let constructorAccessAllowed item =
                        match info.ConstructorTypeName, parentTypeInfo with
                        | Some typeName, Some typeInfo ->
                            let parentExported = Set.contains typeName importedModule.ExportedTypes
                            let canSeeParent = parentExported || itemRequestsUnhide item
                            let canClarifyParent = not typeInfo.IsOpaque || itemRequestsClarify item
                            canSeeParent && canClarifyParent
                        | _ ->
                            false

                    let importedName =
                        match spec.Selection with
                        | QualifiedOnly ->
                            None
                        | All
                        | AllExcept _ ->
                            None
                        | Items items ->
                            items
                            |> List.tryPick (fun item ->
                                if not (constructorAccessAllowed item) then
                                    None
                                elif String.Equals(item.Name, name, StringComparison.Ordinal)
                                     && itemImportsConstructorName item then
                                    Some(importedItemLocalName item)
                                else
                                    match info.ConstructorTypeName with
                                    | Some typeName when itemImportsConstructorsOfType typeName item ->
                                        Some name
                                    | _ ->
                                        None)

                    match importedName with
                    | Some localName ->
                        appendVisibleCandidate localName (OrdinaryVisibleConstructorCandidate info) current
                    | None ->
                        current) withBindings

            match spec.Source, spec.Alias, spec.Selection with
            | Dotted moduleSegments, Some alias, QualifiedOnly ->
                let importedModuleName = SyntaxFacts.moduleNameToText moduleSegments
                appendVisibleCandidate alias (OrdinaryVisibleModuleCandidate importedModuleName) withConstructors
            | Dotted moduleSegments, None, QualifiedOnly ->
                let importedModuleName = SyntaxFacts.moduleNameToText moduleSegments

                if surfaceIndex.ContainsKey importedModuleName then
                    appendVisibleCandidate importedModuleName (OrdinaryVisibleModuleCandidate importedModuleName) withConstructors
                else
                    withConstructors
            | _ ->
                withConstructors) Map.empty

    let private collectImportedOrdinarySurfaceNames (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        importedModuleInfos surfaceIndex moduleName
        |> List.fold (fun state (spec, importedModule) ->
            let visibleBindingCandidateNames =
                Set.union
                    importedModule.ExportedTerms
                    (importedModule.BindingSchemes |> Map.keys |> Set.ofSeq)

            let withTerms =
                visibleBindingCandidateNames
                |> Set.fold (fun current name ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName ->
                        Set.add localName current
                    | None ->
                        current) state

            match spec.Selection with
            | Items items ->
                items
                |> List.fold (fun current item ->
                    let withConstructorName =
                        if itemImportsConstructorName item
                           && Set.contains item.Name importedModule.ExportedConstructors then
                            Set.add (importedItemLocalName item) current
                        else
                            current

                    match importedModule.ExportedConstructorsByType |> Map.tryFind item.Name with
                    | Some constructors when itemImportsConstructorsOfType item.Name item ->
                        Set.union withConstructorName constructors
                    | _ ->
                        withConstructorName) withTerms
            | _ ->
                withTerms) Set.empty

    let private partitionImportedOrdinaryTermCandidates candidateMap =
        candidateMap
        |> Map.fold (fun (bindings, constructors, modules, ambiguities) localName reversedCandidates ->
            let candidates = List.rev reversedCandidates

            match candidates with
            | [ OrdinaryVisibleBindingCandidate info ] ->
                Map.add localName info bindings, constructors, modules, ambiguities
            | [ OrdinaryVisibleExportedBindingCandidate _ ] ->
                bindings, constructors, modules, ambiguities
            | [ OrdinaryVisibleConstructorCandidate info ] ->
                bindings, Map.add localName info constructors, modules, ambiguities
            | [ OrdinaryVisibleModuleCandidate _ ] ->
                bindings, constructors, Set.add localName modules, ambiguities
            | _ ->
                bindings, constructors, modules, Map.add localName candidates ambiguities)
            (Map.empty, Map.empty, Set.empty, Map.empty)

    let private shadowAmbiguousVisibleTermCandidates
        (visibleBindings: Map<string, BindingSchemeInfo>)
        (visibleConstructors: Map<string, BindingSchemeInfo>)
        (visibleModules: Set<string>)
        (ambiguities: Map<string, OrdinaryVisibleTermCandidate list>)
        =
        let shadowingNames =
            [ visibleBindings |> Map.keys |> Set.ofSeq
              visibleConstructors |> Map.keys |> Set.ofSeq
              visibleModules ]
            |> Set.unionMany

        ambiguities
        |> Map.filter (fun localName _ -> not (Set.contains localName shadowingNames))

    let private mergeVisibleBindings (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleName
        let importedBindings, _, _, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeBindings =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let moduleBindings =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        preludeBindings
        |> Map.fold (fun state name info -> Map.add name info state) importedBindings
        |> fun state -> moduleBindings |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleConstructors (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleName
        let _, importedConstructors, _, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeConstructors =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo ->
                moduleInfo.Constructors
                |> Map.filter (fun name _ -> List.contains name Stdlib.FixedPreludeConstructors))
            |> Option.defaultValue Map.empty

        let moduleConstructors =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.Constructors)
            |> Option.defaultValue Map.empty

        preludeConstructors
        |> Map.fold (fun state name info -> Map.add name info state) importedConstructors
        |> fun state -> moduleConstructors |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleProjections (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedProjections =
            importedModuleInfos surfaceIndex moduleName
            |> List.fold (fun state (spec, importedModule) ->
                importedModule.Projections
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let moduleProjections =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.Projections)
            |> Option.defaultValue Map.empty

        moduleProjections
        |> Map.fold (fun state name info -> Map.add name info state) importedProjections

    let private mergeVisibleTypeAliases (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedAliases =
            importedModuleInfos surfaceIndex moduleName
            |> List.fold (fun state (spec, importedModule) ->
                importedModule.TypeAliases
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item ->
                                (Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                                && (not info.IsOpaque || itemRequestsClarify item))
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeAliases =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo -> moduleInfo.TypeAliases)
            |> Option.defaultValue Map.empty

        let moduleAliases =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.TypeAliases)
            |> Option.defaultValue Map.empty

        preludeAliases
        |> Map.fold (fun state name info -> Map.add name info state) importedAliases
        |> fun state -> moduleAliases |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleTypeFacets (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedFacets =
            importedModuleInfos surfaceIndex moduleName
            |> List.fold (fun state (spec, importedModule) ->
                importedModule.TypeFacets
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item -> Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeFacets =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo -> moduleInfo.TypeFacets)
            |> Option.defaultValue Map.empty

        let moduleFacets =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.TypeFacets)
            |> Option.defaultValue Map.empty

        preludeFacets
        |> Map.fold (fun state name info -> Map.add name info state) importedFacets
        |> fun state -> moduleFacets |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleModules (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleName
        let _, _, importedModules, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        Set.add moduleName importedModules

    let private mergeAmbiguousVisibleOrdinaryTerms (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleName
        let importedBindings, importedConstructors, importedModules, importedAmbiguities =
            partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeBindings =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let moduleBindings =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let visibleBindings =
            preludeBindings
            |> Map.fold (fun state name info -> Map.add name info state) importedBindings
            |> fun state -> moduleBindings |> Map.fold (fun current name info -> Map.add name info current) state

        let preludeConstructors =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo ->
                moduleInfo.Constructors
                |> Map.filter (fun name _ -> List.contains name Stdlib.FixedPreludeConstructors))
            |> Option.defaultValue Map.empty

        let moduleConstructors =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.Constructors)
            |> Option.defaultValue Map.empty

        let visibleConstructors =
            preludeConstructors
            |> Map.fold (fun state name info -> Map.add name info state) importedConstructors
            |> fun state -> moduleConstructors |> Map.fold (fun current name info -> Map.add name info current) state

        let visibleModules = Set.add moduleName importedModules

        shadowAmbiguousVisibleTermCandidates visibleBindings visibleConstructors visibleModules importedAmbiguities

    let private mergeVisibleRecordTypes (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedRecordTypes =
            importedModuleInfos surfaceIndex moduleName
            |> List.fold (fun state (spec, importedModule) ->
                importedModule.RecordTypes
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item ->
                                match importedModule.TypeFacets |> Map.tryFind name with
                                | Some facetInfo when facetInfo.FacetKind = TypeAliasFacet ->
                                    (Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                                    && (not facetInfo.IsOpaque || itemRequestsClarify item)
                                | None ->
                                    false
                                | Some _ ->
                                    false)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let moduleRecordTypes =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.RecordTypes)
            |> Option.defaultValue Map.empty

        moduleRecordTypes
        |> Map.fold (fun state name info -> Map.add name info state) importedRecordTypes

    let private mergeVisibleTraits (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let importedTraits =
            importedModuleInfos surfaceIndex moduleName
            |> List.fold (fun state (spec, importedModule) ->
                importedModule.Traits
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Trait
                            importedModule.ExportedTraits
                            itemImportsTraitName
                            (fun item -> Set.contains name importedModule.ExportedTraits || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeTraits =
            surfaceIndex
            |> Map.tryFind Stdlib.PreludeModuleText
            |> Option.map (fun moduleInfo -> moduleInfo.Traits)
            |> Option.defaultValue Map.empty

        let moduleTraits =
            surfaceIndex
            |> Map.tryFind moduleName
            |> Option.map (fun moduleInfo -> moduleInfo.Traits)
            |> Option.defaultValue Map.empty

        preludeTraits
        |> Map.fold (fun state name info -> Map.add name info state) importedTraits
        |> fun state -> moduleTraits |> Map.fold (fun current name info -> Map.add name info current) state

    let private moduleDependencyClosure (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        let rec visit visited currentModuleName =
            if Set.contains currentModuleName visited then
                visited
            else
                let visited = Set.add currentModuleName visited

                let dependencies =
                    surfaceIndex
                    |> Map.tryFind currentModuleName
                    |> Option.map (fun moduleInfo ->
                        moduleInfo.Imports
                        |> List.choose (fun spec ->
                            match spec.Source with
                            | Url _ ->
                                None
                            | Dotted moduleSegments ->
                                let importedModuleName = SyntaxFacts.moduleNameToText moduleSegments

                                if surfaceIndex.ContainsKey importedModuleName then
                                    Some importedModuleName
                                else
                                    None))
                    |> Option.defaultValue []

                dependencies |> List.fold visit visited

        visit Set.empty moduleName |> Set.toList |> List.sort

    let private visibleInstances (surfaceIndex: Map<string, ModuleSurfaceInfo>) moduleName =
        moduleDependencyClosure surfaceIndex moduleName
        |> List.collect (fun visibleModuleName ->
            surfaceIndex
            |> Map.tryFind visibleModuleName
            |> Option.map (fun moduleInfo -> moduleInfo.Instances)
            |> Option.defaultValue [])
        |> List.sortBy (fun instanceInfo ->
            instanceInfo.ModuleName,
            instanceInfo.TraitName,
            instanceInfo.InstanceKey)

    let private buildStaticObjectAliasesForModule
        (environment: BindingLoweringEnvironment)
        (declarations: TopLevelDeclaration list)
        =
        let aliasKey segments = SyntaxFacts.moduleNameToText segments

        let transparentSealFields ascriptionTokens =
            match tryParseRecordSurfaceInfo ascriptionTokens with
            | Some recordInfo ->
                recordInfo.Fields
                |> List.filter (fun field -> not field.IsOpaque)
                |> List.map (fun field -> field.Name)
                |> Set.ofList
                |> Some
            | None ->
                match significantTokens ascriptionTokens with
                | [ nameToken ] when Token.isName nameToken ->
                    environment.VisibleRecordTypes
                    |> Map.tryFind (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                    |> Option.map (fun recordInfo ->
                        recordInfo.Fields
                        |> List.filter (fun field -> not field.IsOpaque)
                        |> List.map (fun field -> field.Name)
                        |> Set.ofList)
                | _ ->
                    None

        let copyNestedAliasesFiltered
            (sourcePrefix: string list)
            (targetPrefix: string list)
            (fieldFilter: string -> bool)
            (aliases: Map<string, StaticObjectInfo>)
            =
            let sourceKey = aliasKey sourcePrefix
            let sourceNestedPrefix = sourceKey + "."

            aliases
            |> Map.toList
            |> List.filter (fun ((key: string), _) ->
                if key.StartsWith(sourceNestedPrefix, StringComparison.Ordinal) then
                    let suffix = key.Substring(sourceNestedPrefix.Length)
                    let firstSegment = suffix.Split('.')[0]

                    fieldFilter firstSegment
                else
                    false)
            |> List.fold (fun (current: Map<string, StaticObjectInfo>) ((key: string), staticObject) ->
                let suffix = key.Substring(sourceNestedPrefix.Length)
                Map.add (aliasKey targetPrefix + "." + suffix) staticObject current) aliases

        let copyNestedAliases sourcePrefix targetPrefix aliases =
            copyNestedAliasesFiltered sourcePrefix targetPrefix (fun _ -> true) aliases

        let rec collectAliases
            (environment: BindingLoweringEnvironment)
            (prefix: string list)
            (expression: SurfaceExpression)
            (aliases: Map<string, StaticObjectInfo>)
            =
            let aliasEnvironment =
                { environment with
                    VisibleStaticObjects = aliases }

            match tryResolveStaticObject aliasEnvironment expression with
            | Some staticObject ->
                let aliases = Map.add (aliasKey prefix) staticObject aliases

                match expression with
                | Name sourcePrefix -> copyNestedAliases sourcePrefix prefix aliases
                | _ -> aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectAliases environment (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(value, ascriptionTokens) ->
                    match value, transparentSealFields ascriptionTokens with
                    | Name sourcePrefix, Some transparentFields ->
                        copyNestedAliasesFiltered sourcePrefix prefix (fun fieldName -> Set.contains fieldName transparentFields) aliases
                    | RecordLiteral fields, Some transparentFields ->
                        fields
                        |> List.filter (fun field -> Set.contains field.Name transparentFields)
                        |> List.fold (fun current field -> collectAliases environment (prefix @ [ field.Name ]) field.Value current) aliases
                    | _, Some _ ->
                        aliases
                    | _ ->
                        collectAliases environment prefix value aliases
                | _ ->
                    aliases

        declarations
        |> List.fold (fun aliases declaration ->
            match declaration with
            | LetDeclaration definition when definition.Name.IsSome && definition.Body.IsSome ->
                collectAliases environment [ definition.Name.Value ] definition.Body.Value aliases
            | _ ->
                aliases) Map.empty

    let private normalizeTypeAliases (aliases: Map<string, TypeAliasInfo>) =
        let rec loop visited typeExpr =
            match typeExpr with
            | TypeLevelLiteral _ ->
                typeExpr
            | TypeUniverse None ->
                typeExpr
            | TypeUniverse(Some universeExpr) ->
                TypeUniverse(Some(loop visited universeExpr))
            | TypeIntrinsic _ ->
                typeExpr
            | TypeApply(callee, arguments) ->
                TypeApply(loop visited callee, arguments |> List.map (loop visited))
            | TypeLambda(parameterName, parameterSort, body) ->
                TypeLambda(parameterName, loop visited parameterSort, loop visited body)
            | TypeDelay inner ->
                TypeDelay(loop visited inner)
            | TypeMemo inner ->
                TypeMemo(loop visited inner)
            | TypeForce inner ->
                TypeForce(loop visited inner)
            | TypeProject(target, fieldName) ->
                TypeProject(loop visited target, fieldName)
            | TypeVariable _ ->
                typeExpr
            | TypeArrow(quantity, parameterType, resultType) ->
                TypeArrow(quantity, loop visited parameterType, loop visited resultType)
            | TypeEquality(left, right) ->
                TypeEquality(loop visited left, loop visited right)
            | TypeCapture(inner, captures) ->
                TypeCapture(loop visited inner, captures)
            | TypeEffectRow(entries, tail) ->
                TypeEffectRow(
                    entries
                    |> List.map (fun entry ->
                        { Label = loop visited entry.Label
                          Effect = loop visited entry.Effect }),
                    tail |> Option.map (loop visited)
                )
            | TypeRecord fields ->
                TypeRecord(
                    fields
                    |> List.map (fun field ->
                        { field with
                            Type = loop visited field.Type })
                )
            | TypeUnion members ->
                TypeUnion(members |> List.map (loop visited))
            | TypeName(([ "IO" ] as nameSegments), [ inner ]) ->
                TypeName(nameSegments, [ voidType; loop visited inner ])
            | TypeName(([ "std"; "prelude"; "IO" ] as nameSegments), [ inner ]) ->
                TypeName(nameSegments, [ voidType; loop visited inner ])
            | TypeName([ name ], arguments) ->
                let normalizedArguments = arguments |> List.map (loop visited)

                match aliases |> Map.tryFind name with
                | Some aliasInfo
                    when not (Set.contains name visited)
                         && aliasInfo.ConversionReducible
                         && List.length aliasInfo.Parameters = List.length normalizedArguments ->
                    let substitution = List.zip aliasInfo.Parameters normalizedArguments |> Map.ofList
                    aliasInfo.Body
                    |> TypeSignatures.applySubstitution substitution
                    |> loop (Set.add name visited)
                | _ ->
                    TypeName([ name ], normalizedArguments)
            | TypeName(name, arguments) ->
                TypeName(name, arguments |> List.map (loop visited))

        loop Set.empty

    let rec private tryUnwrapBindablePayloadType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeCapture(inner, _) ->
            tryUnwrapBindablePayloadType aliases inner
        | TypeName([ "Eff" ], [ _; inner ]) -> Some inner
        | TypeName([ "IO" ], [ inner ]) -> Some inner
        | TypeName([ "IO" ], [ _; inner ]) -> Some inner
        | TypeName([ "UIO" ], [ inner ]) -> Some inner
        | TypeName(_, [ inner ]) -> Some inner
        | _ -> None

    let rec private isCallableValidationType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeCapture(inner, _) ->
            isCallableValidationType aliases inner
        | TypeVariable _
        | TypeArrow _
        | TypeLambda _
        | TypeName(([ "Projector" ] | [ "std"; "prelude"; "Projector" ]), _) ->
            true
        | _ ->
            false

    type private EffectRowSplitResult =
        | SplitResolved of TypeExpr
        | SplitMismatch
        | SplitNeedsTailRefinement

    let private trySplitHandledEffectRow
        (aliases: Map<string, TypeAliasInfo>)
        (declaration: EffectSemanticDeclaration)
        effectRow
        =
        let normalize = normalizeTypeAliases aliases
        let expectedLabel = scopedEffectLabelType declaration |> normalize
        let expectedInterface = scopedEffectInterfaceType declaration |> normalize

        let matchesLabel typeExpr =
            TypeSignatures.definitionallyEqual (normalize typeExpr) expectedLabel

        let matchesInterface typeExpr =
            TypeSignatures.tryUnify (normalize typeExpr) expectedInterface
            |> Option.isSome

        let rec split current =
            match normalize current with
            | TypeEffectRow(entries, tail) ->
                let handledEntryIndex =
                    entries
                    |> List.tryFindIndex (fun entry ->
                        matchesLabel entry.Label
                        && matchesInterface entry.Effect)

                match handledEntryIndex with
                | Some entryIndex ->
                    let remainingEntries =
                        entries
                        |> List.mapi (fun index entry -> index, entry)
                        |> List.choose (fun (index, entry) ->
                            if index = entryIndex then
                                None
                            else
                                Some entry)

                    match remainingEntries, tail |> Option.map normalize with
                    | [], Some tailExpr ->
                        SplitResolved tailExpr
                    | _ ->
                        SplitResolved(TypeEffectRow(remainingEntries, tail |> Option.map normalize))
                | None ->
                    let mismatchedHandledLabel =
                        entries
                        |> List.exists (fun entry ->
                            matchesLabel entry.Label
                            && not (matchesInterface entry.Effect))

                    if mismatchedHandledLabel then
                        SplitMismatch
                    else
                        match tail with
                        | Some tailExpr ->
                            match split tailExpr with
                            | SplitResolved remainderTail ->
                                if List.isEmpty entries then
                                    SplitResolved remainderTail
                                else
                                    match normalize remainderTail with
                                    | TypeEffectRow(remainderEntries, remainderTailTail) ->
                                        SplitResolved(TypeEffectRow(entries @ remainderEntries, remainderTailTail))
                                    | _ ->
                                        SplitResolved(TypeEffectRow(entries, Some remainderTail))
                            | SplitMismatch ->
                                SplitMismatch
                            | SplitNeedsTailRefinement ->
                                SplitNeedsTailRefinement
                        | None ->
                            SplitMismatch
            | TypeVariable _ ->
                SplitNeedsTailRefinement
            | _ ->
                SplitMismatch

        split effectRow

    let private renderSurfaceSchemeTokens (scheme: TypeScheme) =
        let binderText (binder: TypeSignatures.ForallBinder) =
            let quantityPrefix =
                match binder.Quantity with
                | QuantityZero -> ""
                | quantity -> Quantity.toSurfaceText quantity + " "

            $"({quantityPrefix}{binder.Name} : {TypeSignatures.toText binder.Sort})"

        let constraintText (constraintInfo: TypeSignatures.TraitConstraint) =
            match constraintInfo.Arguments with
            | [] -> constraintInfo.TraitName
            | arguments ->
                String.concat " " (constraintInfo.TraitName :: (arguments |> List.map TypeSignatures.toText))

        let forallPrefix =
            match scheme.Forall with
            | [] -> ""
            | binders ->
                "forall " + (binders |> List.map binderText |> String.concat " ") + ". "

        let constraintsPrefix =
            match scheme.Constraints with
            | [] -> ""
            | constraints ->
                (constraints |> List.map constraintText |> String.concat ", ") + " => "

        typeTextTokens (forallPrefix + constraintsPrefix + TypeSignatures.toText scheme.Body)

    let private rewriteLocalTypeAliasesInSurfaceExpression
        currentModuleName
        (visibleAliases: Map<string, TypeAliasInfo>)
        expression
        =
        let mergeAliases localAliases =
            visibleAliases
            |> Map.fold (fun state name info -> Map.add name info state) localAliases

        let expandTypeTokens localAliases tokens =
            let aliases = mergeAliases localAliases

            match TypeSignatures.parseScheme tokens with
            | Some scheme ->
                { scheme with
                    Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = normalizeTypeAliases aliases binder.Sort })
                    Constraints =
                        scheme.Constraints
                        |> List.map (fun constraintInfo ->
                            { constraintInfo with
                                Arguments = constraintInfo.Arguments |> List.map (normalizeTypeAliases aliases) })
                    Body = normalizeTypeAliases aliases scheme.Body }
                |> renderSurfaceSchemeTokens
            | None ->
                tokens
                |> TypeSignatures.parseType
                |> Option.map (normalizeTypeAliases aliases)
                |> Option.map TypeSignatures.toText
                |> Option.map typeTextTokens
                |> Option.defaultValue tokens

        let expandTypeTokenOption localAliases tokens =
            tokens |> Option.map (expandTypeTokens localAliases)

        let expandParameter localAliases (parameter: Parameter) =
            { parameter with
                TypeTokens = expandTypeTokenOption localAliases parameter.TypeTokens }

        let expandBinding localAliases (binding: SurfaceBindPattern) =
            { binding with
                TypeTokens = expandTypeTokenOption localAliases binding.TypeTokens }

        let expandEffectDeclaration localAliases (declaration: EffectDeclaration) =
            { declaration with
                HeaderTokens = expandTypeTokens localAliases declaration.HeaderTokens
                Operations =
                    declaration.Operations
                    |> List.map (fun operation ->
                        { operation with
                            SignatureTokens = expandTypeTokens localAliases operation.SignatureTokens }) }

        let expandTypeAlias localAliases (declaration: TypeAlias) =
            { declaration with
                HeaderTokens = expandTypeTokens localAliases declaration.HeaderTokens
                BodyTokens = expandTypeTokenOption localAliases declaration.BodyTokens }

        let rec rewritePattern localAliases pattern =
            match pattern with
            | TypedPattern(inner, typeTokens) ->
                TypedPattern(rewritePattern localAliases inner, expandTypeTokens localAliases typeTokens)
            | AsPattern(name, inner) ->
                AsPattern(name, rewritePattern localAliases inner)
            | ConstructorPattern(name, items) ->
                ConstructorPattern(name, items |> List.map (rewritePattern localAliases))
            | NamedConstructorPattern(name, fields) ->
                NamedConstructorPattern(
                    name,
                    fields
                    |> List.map (fun field ->
                        { field with
                            Pattern = rewritePattern localAliases field.Pattern })
                )
            | OrPattern items ->
                OrPattern(items |> List.map (rewritePattern localAliases))
            | TuplePattern items ->
                TuplePattern(items |> List.map (rewritePattern localAliases))
            | AnonymousRecordPattern(fields, rest) ->
                AnonymousRecordPattern(
                    fields |> List.map (fun field -> { field with Pattern = rewritePattern localAliases field.Pattern }),
                    rest
                )
            | VariantPattern variantPattern ->
                let rewrittenVariant =
                    match variantPattern with
                    | BoundVariantPattern(name, typeTokens) ->
                        BoundVariantPattern(name, expandTypeTokenOption localAliases typeTokens)
                    | WildcardVariantPattern typeTokens ->
                        WildcardVariantPattern(expandTypeTokenOption localAliases typeTokens)
                    | RestVariantPattern _ ->
                        variantPattern

                VariantPattern rewrittenVariant
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                pattern

        let rec rewriteDoStatement localAliases statement =
            match statement with
            | DoLet(binding, inner) ->
                DoLet(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoLetQuestion(binding, inner, failure) ->
                let rewrittenFailure =
                    failure
                    |> Option.map (fun failure ->
                        { failure with
                            ResiduePattern = expandBinding localAliases failure.ResiduePattern
                            Body = failure.Body |> List.map (rewriteDoStatement localAliases) })

                DoLetQuestion(expandBinding localAliases binding, rewriteExpression localAliases inner, rewrittenFailure)
            | DoBind(binding, inner) ->
                DoBind(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoUsing(binding, inner) ->
                DoUsing(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoVar(name, inner) ->
                DoVar(name, rewriteExpression localAliases inner)
            | DoAssign(name, inner) ->
                DoAssign(name, rewriteExpression localAliases inner)
            | DoDefer inner ->
                DoDefer(rewriteExpression localAliases inner)
            | DoIf(condition, whenTrue, whenFalse) ->
                DoIf(
                    rewriteExpression localAliases condition,
                    whenTrue |> List.map (rewriteDoStatement localAliases),
                    whenFalse |> List.map (rewriteDoStatement localAliases)
                )
            | DoWhile(condition, body) ->
                DoWhile(rewriteExpression localAliases condition, body |> List.map (rewriteDoStatement localAliases))
            | DoReturn inner ->
                DoReturn(rewriteExpression localAliases inner)
            | DoExpression inner ->
                DoExpression(rewriteExpression localAliases inner)

        and rewriteExpression localAliases current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewriteExpression localAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewriteExpression localAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewriteExpression localAliases inner)
            | CodeQuote inner ->
                CodeQuote(rewriteExpression localAliases inner)
            | CodeSplice inner ->
                CodeSplice(rewriteExpression localAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        ArgumentTokens = clause.ArgumentTokens |> List.map (expandTypeTokens localAliases)
                        Body = rewriteExpression localAliases clause.Body }

                Handle(
                    isDeep,
                    rewriteExpression localAliases label,
                    rewriteExpression localAliases body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | LocalSignature(declaration, body) ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokens localAliases declaration.TypeTokens }

                LocalSignature(expandedDeclaration, rewriteExpression localAliases body)
            | LocalTypeAlias(declaration, body) ->
                let expandedDeclaration = expandTypeAlias localAliases declaration

                match tryParseTypeAliasInfo currentModuleName expandedDeclaration with
                | Some(_, aliasInfo) ->
                    rewriteExpression (Map.add declaration.Name aliasInfo localAliases) body
                | None ->
                    LocalTypeAlias(expandedDeclaration, rewriteExpression localAliases body)
            | LocalLet(binding, value, body) ->
                LocalLet(expandBinding localAliases binding, rewriteExpression localAliases value, rewriteExpression localAliases body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(expandEffectDeclaration localAliases declaration, rewriteExpression localAliases body)
            | Lambda(parameters, body) ->
                Lambda(parameters |> List.map (expandParameter localAliases), rewriteExpression localAliases body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(
                    rewriteExpression localAliases condition,
                    rewriteExpression localAliases whenTrue,
                    rewriteExpression localAliases whenFalse
                )
            | Match(scrutinee, cases) ->
                Match(
                    rewriteExpression localAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Pattern = rewritePattern localAliases caseClause.Pattern
                            Guard = caseClause.Guard |> Option.map (rewriteExpression localAliases)
                            Body = rewriteExpression localAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewriteExpression localAliases value, expandTypeTokens localAliases ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewriteExpression localAliases receiver, fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewriteExpression localAliases receiver, segments, arguments |> List.map (rewriteExpression localAliases))
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewriteExpression localAliases receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map (rewriteExpression localAliases) }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewriteExpression localAliases receiver, constructorName)
            | Do statements ->
                Do(statements |> List.map (rewriteDoStatement localAliases))
            | MonadicSplice inner ->
                MonadicSplice(rewriteExpression localAliases inner)
            | Apply(callee, arguments) ->
                Apply(rewriteExpression localAliases callee, arguments |> List.map (rewriteExpression localAliases))
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewriteExpression localAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewriteExpression localAliases inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewriteExpression localAliases inner)
            | Binary(left, operatorName, right) ->
                Binary(rewriteExpression localAliases left, operatorName, rewriteExpression localAliases right)
            | Elvis(left, right) ->
                Elvis(rewriteExpression localAliases left, rewriteExpression localAliases right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewriteExpression localAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewriteExpression localAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                current

        rewriteExpression Map.empty expression

    let private tryUnwrapElabType aliases typeExpr =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(([ "Elab" ] | [ "std"; "prelude"; "Elab" ]), [ inner ]) -> Some inner
        | _ -> None

    let private tryUnwrapSyntaxType aliases typeExpr =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(([ "Syntax" ] | [ "std"; "prelude"; "Syntax" ]), [ inner ]) -> Some inner
        | _ -> None

    let private tryUnwrapTopLevelSyntaxSpliceType aliases typeExpr =
        tryUnwrapSyntaxType aliases typeExpr
        |> Option.orElseWith (fun () ->
            typeExpr
            |> tryUnwrapElabType aliases
            |> Option.bind (tryUnwrapSyntaxType aliases))

    let private tryCanonicalRecordType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeRecord fields ->
            Some(TypeRecord fields)
        | _ ->
            None

    let rec private eraseSyntheticRecordTypeExpr typeExpr =
        match typeExpr with
        | TypeLevelLiteral _ ->
            typeExpr
        | TypeUniverse None ->
            typeExpr
        | TypeUniverse(Some universeExpr) ->
            TypeUniverse(Some(eraseSyntheticRecordTypeExpr universeExpr))
        | TypeIntrinsic _ ->
            typeExpr
        | TypeApply(callee, arguments) ->
            TypeApply(eraseSyntheticRecordTypeExpr callee, arguments |> List.map eraseSyntheticRecordTypeExpr)
        | TypeLambda(parameterName, parameterSort, body) ->
            TypeLambda(parameterName, eraseSyntheticRecordTypeExpr parameterSort, eraseSyntheticRecordTypeExpr body)
        | TypeDelay inner ->
            TypeDelay(eraseSyntheticRecordTypeExpr inner)
        | TypeMemo inner ->
            TypeMemo(eraseSyntheticRecordTypeExpr inner)
        | TypeForce inner ->
            TypeForce(eraseSyntheticRecordTypeExpr inner)
        | TypeProject(target, fieldName) ->
            TypeProject(eraseSyntheticRecordTypeExpr target, fieldName)
        | TypeVariable name ->
            TypeVariable name
        | TypeName(name, arguments) ->
            TypeName(name, arguments |> List.map eraseSyntheticRecordTypeExpr)
        | TypeArrow(_, parameterType, resultType) ->
            TypeArrow(QuantityOmega, eraseSyntheticRecordTypeExpr parameterType, eraseSyntheticRecordTypeExpr resultType)
        | TypeEquality(left, _) ->
            eraseSyntheticRecordTypeExpr left
        | TypeCapture(inner, _) ->
            eraseSyntheticRecordTypeExpr inner
        | TypeEffectRow(entries, tail) ->
            TypeEffectRow(
                entries
                |> List.map (fun entry ->
                    { Label = eraseSyntheticRecordTypeExpr entry.Label
                      Effect = eraseSyntheticRecordTypeExpr entry.Effect }),
                tail |> Option.map eraseSyntheticRecordTypeExpr
            )
        | TypeRecord fields ->
            fields
            |> List.choose (fun field ->
                if field.Quantity = QuantityZero then
                    None
                else
                    Some
                        { field with
                            Quantity = QuantityOmega
                            Type = eraseSyntheticRecordTypeExpr field.Type })
            |> TypeRecord
        | TypeUnion members ->
            TypeUnion(members |> List.map eraseSyntheticRecordTypeExpr)

    let private ensureSyntheticRecordLayout
        (moduleName: string)
        (filePath: string)
        (layouts: Map<string, SyntheticRecordLayout> ref)
        recordType
        =
        let erasedRecordType = eraseSyntheticRecordTypeExpr recordType
        let recordKey = TypeSignatures.toText erasedRecordType
        let canonicalRecordType = tryParseTypeText recordKey |> Option.defaultValue erasedRecordType

        match Map.tryFind recordKey layouts.Value with
        | Some layout ->
            layout
        | None ->
            let fields =
                match canonicalRecordType with
                | TypeRecord fields -> fields
                | _ -> []

            let typeName = syntheticRecordTypeName recordKey
            let constructorName = syntheticRecordConstructorName recordKey
            let provenance = syntheticOrigin filePath moduleName typeName "synthetic-record"
            let typeParameters = TypeSignatures.collectFreeTypeVariables canonicalRecordType

            let layout =
                { TypeKey = recordKey
                  TypeExpr = canonicalRecordType
                  TypeName = typeName
                  ConstructorName = constructorName
                  TypeParameters = typeParameters
                  Fields = fields
                  Provenance = provenance }

            layouts.Value <- Map.add recordKey layout layouts.Value
            layout

    let private composeTypeSubstitution
        (existing: Map<string, TypeExpr>)
        (next: Map<string, TypeExpr>)
        =
        let rewrittenExisting =
            existing
            |> Map.map (fun _ value -> TypeSignatures.applySubstitution next value)

        next
        |> Map.fold (fun state name value -> Map.add name value state) rewrittenExisting

    let private isCompileTimeArgumentType
        (aliases: Map<string, TypeAliasInfo>)
        parameterType
        =
        match normalizeTypeAliases aliases parameterType with
        | TypeUniverse _
        | TypeIntrinsic UniverseClassifier
        | TypeIntrinsic ConstraintClassifier
        | TypeIntrinsic QuantityClassifier
        | TypeIntrinsic RegionClassifier
        | TypeIntrinsic RecRowClassifier
        | TypeIntrinsic VarRowClassifier
        | TypeIntrinsic EffRowClassifier
        | TypeIntrinsic LabelClassifier
        | TypeIntrinsic EffLabelClassifier
        | TypeName([ "Type" ], [])
        | TypeName([ "Constraint" ], [])
        | TypeName([ "Quantity" ], [])
        | TypeName([ "Region" ], [])
        | TypeName([ "RecRow" ], [])
        | TypeName([ "VarRow" ], [])
        | TypeName([ "EffRow" ], [])
        | TypeName([ "Label" ], [])
        | TypeName([ "EffLabel" ], []) ->
            true
        | _ ->
            false

    let private isReifiedStaticObjectType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        let rec loop current =
            match normalizeTypeAliases aliases current with
            | TypeUniverse _
            | TypeIntrinsic UniverseClassifier
            | TypeIntrinsic ConstraintClassifier
            | TypeIntrinsic QuantityClassifier
            | TypeIntrinsic RegionClassifier
            | TypeIntrinsic RecRowClassifier
            | TypeIntrinsic VarRowClassifier
            | TypeIntrinsic EffRowClassifier
            | TypeIntrinsic LabelClassifier
            | TypeIntrinsic EffLabelClassifier
            | TypeName([ "Type" ], [])
            | TypeName([ "Constraint" ], [])
            | TypeName([ "Quantity" ], [])
            | TypeName([ "Region" ], [])
            | TypeName([ "RecRow" ], [])
            | TypeName([ "VarRow" ], [])
            | TypeName([ "EffRow" ], [])
            | TypeName([ "Label" ], [])
            | TypeName([ "EffLabel" ], []) ->
                true
            | TypeArrow(_, _, resultType) ->
                loop resultType
            | _ ->
                false

        loop typeExpr

    let private tryUnifyVisibleTypes
        (aliases: Map<string, TypeAliasInfo>)
        (pairs: (TypeExpr * TypeExpr) list)
        =
        let normalize = normalizeTypeAliases aliases
        pairs
        |> List.map (fun (left, right) -> normalize left, normalize right)
        |> TypeSignatures.tryUnifyMany

    let private qualifyVisibleTypeNames
        (environment: BindingLoweringEnvironment)
        typeExpr
        =
        let rec loop current =
            match normalizeTypeAliases environment.VisibleTypeAliases current with
            | TypeLevelLiteral _ ->
                current
            | TypeUniverse None ->
                current
            | TypeUniverse(Some universeExpr) ->
                TypeUniverse(Some(loop universeExpr))
            | TypeIntrinsic _ ->
                current
            | TypeApply(callee, arguments) ->
                TypeApply(loop callee, arguments |> List.map loop)
            | TypeLambda(parameterName, parameterSort, body) ->
                TypeLambda(parameterName, loop parameterSort, loop body)
            | TypeDelay inner ->
                TypeDelay(loop inner)
            | TypeMemo inner ->
                TypeMemo(loop inner)
            | TypeForce inner ->
                TypeForce(loop inner)
            | TypeProject(target, fieldName) ->
                TypeProject(loop target, fieldName)
            | TypeName(nameSegments, arguments) ->
                match tryResolveHandledEffectDeclaration environment (Name nameSegments), nameSegments with
                | Some declaration, _ ->
                    TypeName(scopedEffectInterfaceNameSegments declaration, arguments |> List.map loop)
                | None, [ name ] ->
                    match environment.VisibleStaticObjects |> Map.tryFind name with
                    | Some staticObject when staticObject.ObjectKind = StaticTypeObject ->
                        TypeName(staticObject.NameSegments, arguments |> List.map loop)
                    | _ when environment.VisibleTypeFacets.ContainsKey(name) ->
                        let typeFacet = environment.VisibleTypeFacets[name]
                        let qualifiedName =
                            (typeFacet.ModuleName.Split('.', StringSplitOptions.RemoveEmptyEntries) |> Array.toList) @ [ typeFacet.Name ]

                        TypeName(qualifiedName, arguments |> List.map loop)
                    | _ ->
                        TypeName(nameSegments, arguments |> List.map loop)
                | _ ->
                    TypeName(nameSegments, arguments |> List.map loop)
            | TypeArrow(quantity, parameterType, resultType) ->
                TypeArrow(quantity, loop parameterType, loop resultType)
            | TypeEquality(left, right) ->
                TypeEquality(loop left, loop right)
            | TypeCapture(inner, captures) ->
                TypeCapture(loop inner, captures)
            | TypeEffectRow(entries, tail) ->
                TypeEffectRow(
                    entries
                    |> List.map (fun entry ->
                        { Label = qualifyScopedEffectLabel entry.Label
                          Effect = loop entry.Effect }),
                    tail |> Option.map loop
                )
            | TypeRecord fields ->
                TypeRecord(
                    fields
                    |> List.map (fun field ->
                        { field with
                            Type = loop field.Type })
                )
            | TypeUnion members ->
                TypeUnion(members |> List.map loop)
            | TypeVariable _ ->
                current

        and qualifyScopedEffectLabel current =
            match normalizeTypeAliases environment.VisibleTypeAliases current with
            | TypeName(nameSegments, []) when not (List.isEmpty nameSegments) ->
                match tryResolveHandledEffectDeclaration environment (Name nameSegments) with
                | Some declaration -> scopedEffectLabelType declaration
                | None -> loop current
            | _ ->
                loop current

        loop typeExpr

    let private extendPatternLocalTypes
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        expectedType
        pattern
        =
        let rec loop locals expected currentPattern =
            match currentPattern with
            | WildcardPattern
            | LiteralPattern _ ->
                locals
            | NamePattern name ->
                match expected with
                | Some expectedType -> Map.add name expectedType locals
                | None -> locals
            | AsPattern(name, inner) ->
                let locals =
                    match expected with
                    | Some expectedType -> Map.add name expectedType locals
                    | None -> locals

                loop locals expected inner
            | TypedPattern(inner, typeTokens) ->
                let ascribedType =
                    TypeSignatures.parseType typeTokens
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.orElse expected

                loop locals ascribedType inner
            | TuplePattern elements ->
                let tupleFields =
                    elements
                    |> List.mapi (fun index element ->
                        { Name = $"_{index + 1}"
                          IsImplicit = false
                          Pattern = element })

                loop locals expected (AnonymousRecordPattern(tupleFields, None))
            | AnonymousRecordPattern(fields, rest) ->
                match expected |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some(TypeRecord recordFields) ->
                    let afterFields =
                        fields
                        |> List.fold (fun state field ->
                            let fieldType =
                                recordFields
                                |> List.tryFind (fun recordField -> String.Equals(recordField.Name, field.Name, StringComparison.Ordinal))
                                |> Option.map (fun recordField -> recordField.Type)

                            loop state fieldType field.Pattern) locals

                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        let mentioned =
                            fields |> List.map (fun field -> field.Name) |> Set.ofList

                        let residualFields =
                            recordFields
                            |> List.filter (fun field -> not (Set.contains field.Name mentioned))

                        Map.add name (TypeRecord residualFields) afterFields
                    | _ ->
                        afterFields
                | _ ->
                    let afterFields = fields |> List.fold (fun state field -> loop state None field.Pattern) locals

                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        Map.add name (TypeRecord []) afterFields
                    | _ ->
                        afterFields
            | ConstructorPattern(nameSegments, arguments) ->
                let argumentTypes =
                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                        if List.length parameterTypes = List.length arguments then
                            match
                                TypeSignatures.tryUnifyMany
                                    [
                                        qualifyVisibleTypeNames environment constructorResultType,
                                        qualifyVisibleTypeNames environment expectedResultType
                                    ]
                            with
                            | Some substitution ->
                                parameterTypes
                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                            | None ->
                                List.replicate arguments.Length None
                        else
                            List.replicate arguments.Length None
                    | _ ->
                        List.replicate arguments.Length None

                List.zip arguments argumentTypes
                |> List.fold (fun state (argumentPattern, argumentType) -> loop state argumentType argumentPattern) locals
            | NamedConstructorPattern(nameSegments, fields) ->
                let argumentTypes =
                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                        let fieldTypeMap =
                            constructorInfo.ParameterLayouts
                            |> Option.map (fun layouts ->
                                layouts
                                |> List.filter (fun parameter -> not parameter.IsImplicit)
                                |> List.map (fun parameter -> parameter.Name)
                                |> List.zip parameterTypes
                                |> List.map (fun (fieldType, fieldName) -> fieldName, fieldType)
                                |> Map.ofList)
                            |> Option.defaultValue Map.empty

                        match
                            TypeSignatures.tryUnifyMany
                                [
                                    qualifyVisibleTypeNames environment constructorResultType,
                                    qualifyVisibleTypeNames environment expectedResultType
                                ]
                        with
                        | Some substitution ->
                            fieldTypeMap
                            |> Map.map (fun _ fieldType -> TypeSignatures.applySubstitution substitution fieldType)
                        | None ->
                            Map.empty
                    | _ ->
                        Map.empty

                fields
                |> List.fold (fun state field ->
                    let fieldType = argumentTypes |> Map.tryFind field.Name
                    loop state fieldType field.Pattern) locals
            | VariantPattern(BoundVariantPattern(name, Some typeTokens)) ->
                match TypeSignatures.parseType typeTokens with
                | Some parsedType ->
                    Map.add name (qualifyVisibleTypeNames environment parsedType) locals
                | None ->
                    locals
            | VariantPattern(BoundVariantPattern(name, None))
            | VariantPattern(RestVariantPattern name) ->
                match expected with
                | Some expectedType -> Map.add name expectedType locals
                | None -> locals
            | VariantPattern(WildcardVariantPattern _) ->
                locals
            | OrPattern alternatives ->
                match alternatives with
                | first :: _ ->
                    loop locals expected first
                | [] ->
                    locals

        loop localTypes expectedType pattern

    let private extendBindingLocalTypes
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (binding: SurfaceBindPattern)
        expectedType
        =
        extendPatternLocalTypes environment freshCounter localTypes expectedType binding.Pattern

    let private unwrapInstantiatedCallType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (scheme: TypeScheme)
        (argumentTypes: TypeExpr list)
        =
        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value scheme
        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

        let parameterTypes, resultType = TypeSignatures.schemeParts instantiated

        if List.length parameterTypes <> List.length argumentTypes then
            None
        else
            tryUnifyVisibleTypes environment.VisibleTypeAliases (List.zip parameterTypes argumentTypes)
            |> Option.map (fun substitution ->
                instantiated
                |> TypeSignatures.applySchemeSubstitution substitution,
                TypeSignatures.applySubstitution substitution resultType)

    let private inferLiteralType literal =
        match literal with
        | LiteralValue.Integer _ -> intType
        | LiteralValue.Float _ -> floatType
        | LiteralValue.String _ -> stringType
        | LiteralValue.Character _ -> unicodeScalarType
        | LiteralValue.Grapheme _ -> graphemeType
        | LiteralValue.Byte _ -> byteType
        | LiteralValue.Unit -> unitType

    let private inferSurfaceNumericLiteralType literal =
        match literal with
        | SurfaceIntegerLiteral _ -> intType
        | SurfaceRealLiteral _ -> floatType

    let private lowerBindingReturnTypeExpr
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (fallbackTokens: Token list option)
        =
        match tryParseReturnTypeType fallbackTokens with
        | Some explicitReturnType ->
            Some explicitReturnType
        | None ->
            match scheme with
            | Some scheme ->
                let resultType =
                    if List.isEmpty parameters then
                        scheme.Body
                    else
                        let _, resultType = TypeSignatures.schemeParts scheme
                        resultType

                Some resultType
            | None ->
                None

    let private lowerBindingReturnType
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (fallbackTokens: Token list option)
        =
        lowerBindingReturnTypeExpr scheme parameters fallbackTokens
        |> Option.map typeTextOf

    let private buildBindingParameters
        (_aliases: Map<string, TypeAliasInfo>)
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        let coreParameters scheme =
            parameters
            |> List.filter (fun parameter ->
                not (
                    parameter.IsImplicit
                    && parameter.TypeTokens.IsNone
                    && (scheme.Forall |> List.exists (fun binder -> binder.Name = parameter.Name))
                ))

        match scheme with
        | Some scheme ->
            let parameters = coreParameters scheme
            let parameterTypes, _ = TypeSignatures.schemeParts scheme
            if List.length parameterTypes = List.length parameters then
                List.zip parameters parameterTypes
                |> List.map (fun (parameter, parameterType) ->
                    lowerKCoreParameter parameter (Some parameterType))
            else
                parameters |> List.map (fun parameter -> lowerKCoreParameter parameter (parameter.TypeTokens |> Option.bind TypeSignatures.parseType))
        | None ->
            parameters |> List.map (fun parameter -> lowerKCoreParameter parameter (parameter.TypeTokens |> Option.bind TypeSignatures.parseType))

    let private buildLocalTypes
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        let fromScheme =
            match scheme with
            | Some scheme ->
                let parameters =
                    let rec stripLeadingForallParameters
                        (remainingBinders: TypeSignatures.ForallBinder list)
                        (remainingParameters: Parameter list)
                        =
                        match remainingBinders, remainingParameters with
                        | binder :: restBinders, parameter :: restParameters
                            when String.Equals(binder.Name, parameter.Name, StringComparison.Ordinal) ->
                            stripLeadingForallParameters restBinders restParameters
                        | _ ->
                            remainingParameters

                    stripLeadingForallParameters scheme.Forall parameters

                let parameterTypes, _ = TypeSignatures.schemeParts scheme
                if List.length parameterTypes = List.length parameters then
                    List.zip parameters parameterTypes
                    |> List.map (fun (parameter, parameterType) -> parameter.Name, parameterType)
                else
                    []
            | None ->
                []

        let fromAnnotations =
            parameters
            |> List.choose (fun parameter ->
                tryParseParameterType parameter
                |> Option.map (fun parameterType -> parameter.Name, parameterType))

        let fromConstraints =
            match scheme with
            | Some scheme ->
                scheme.Constraints
                |> List.mapi (fun index constraintInfo ->
                    let dictionaryParameterName = $"__kappa_dict_{constraintInfo.TraitName}_{index}"
                    dictionaryParameterName, TypeName([ constraintInfo.TraitName ], constraintInfo.Arguments))
            | None ->
                []

        fromScheme @ fromAnnotations @ fromConstraints
        |> List.fold (fun state (name, parameterType) -> Map.add name parameterType state) Map.empty

    let private tryOptionPayloadType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeName([ "Option" ], [ payloadType ])
        | TypeName([ "std"; "prelude"; "Option" ], [ payloadType ]) ->
            Some payloadType
        | _ ->
            None

    let private tryProjectVisibleRecordType
        (aliases: Map<string, TypeAliasInfo>)
        currentType
        path
        =
        let normalize = normalizeTypeAliases aliases

        let rec loop typeExpr remainingPath =
            match remainingPath, normalize typeExpr with
            | [], normalizedType ->
                Some normalizedType
            | fieldName :: rest, TypeRecord fields ->
                fields
                |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                |> Option.bind (fun field -> loop field.Type rest)
            | _ ->
                None

        loop currentType path

    let private instantiateVisibleBindingResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleBindings
        |> Map.tryFind name
        |> Option.map (fun bindingInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            snd (TypeSignatures.schemeParts instance))

    let private instantiateVisibleBindingBodyType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleBindings
        |> Map.tryFind name
        |> Option.map (fun bindingInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            instance.Body)

    let private instantiateVisibleConstructorBodyType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleConstructors
        |> Map.tryFind name
        |> Option.map (fun constructorInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            instance.Body)

    let private tryInterpolatedMacroResultType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(([ "Dict" ] | [ "std"; "prelude"; "Dict" ]), [ dictionaryConstraint ]) ->
            match normalize dictionaryConstraint with
            | TypeName(([ "InterpolatedMacro" ] | [ "std"; "prelude"; "InterpolatedMacro" ]), [ resultType ]) ->
                Some resultType
            | _ ->
                None
        | TypeName([ dictionaryTypeName ], [ resultType ])
            when String.Equals(dictionaryTypeName, TraitRuntime.dictionaryTypeName "InterpolatedMacro", StringComparison.Ordinal) ->
            Some resultType
        | _ ->
            None

    let private tryElabInterpolatedMacroResultType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        typeExpr
        |> tryUnwrapElabType aliases
        |> Option.bind (tryInterpolatedMacroResultType aliases)

    let private tryInferPrefixedStringMacroResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        prefix
        =
        let tryResolve allowPlainDictionary resolvedType =
            tryElabInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
            |> Option.orElseWith (fun () ->
                if allowPlainDictionary then
                    tryInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                else
                    None)

        match localTypes |> Map.tryFind prefix with
        | Some localType ->
            tryResolve false localType
        | None ->
            instantiateVisibleBindingResultType environment freshCounter prefix
            |> Option.bind (tryResolve (Set.contains prefix environment.ElaborationAvailableBindings))

    let private tryInferVisibleAppliedType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        headType
        arguments
        =
        let normalize = normalizeTypeAliases aliases

        let rec loop currentType remainingArguments =
            match remainingArguments with
            | [] ->
                Some currentType
            | argument :: rest ->
                match normalize currentType with
                | TypeArrow(_, parameterType, resultType) ->
                    inferArgumentType argument
                    |> Option.map qualifyTypeNames
                    |> Option.bind (fun argumentType ->
                        tryUnifyVisibleTypes aliases [ parameterType, argumentType ]
                        |> Option.map (fun substitution ->
                            TypeSignatures.applySubstitution substitution resultType)
                        |> Option.orElseWith (fun () ->
                            if TypeSignatures.definitionallyEqual (normalize parameterType) (normalize argumentType) then
                                Some resultType
                            else
                                None))
                    |> Option.bind (fun nextType -> loop nextType rest)
                | _ ->
                    None

        loop (qualifyTypeNames headType) arguments

    let private tryInferLocalAppliedType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (localTypes: Map<string, TypeExpr>)
        expression
        =
        match expression with
        | Apply(Name [ calleeName ], arguments) ->
            localTypes
            |> Map.tryFind calleeName
            |> Option.bind (fun localType ->
                tryInferVisibleAppliedType aliases qualifyTypeNames inferArgumentType localType arguments)
        | _ ->
            None

    let private tryInferSafeNavigationMemberType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        payloadType
        (navigation: SurfaceSafeNavigationMember)
        =
        tryProjectVisibleRecordType aliases payloadType navigation.Segments
        |> Option.bind (fun headType -> tryInferVisibleAppliedType aliases qualifyTypeNames inferArgumentType headType navigation.Arguments)

    let rec private tryParseTypeLikeSurfaceExpression expression =
        match expression with
        | Name segments when not (List.isEmpty segments) ->
            Some(TypeName(segments, []))
        | NumericLiteral(SurfaceIntegerLiteral(value, _, None)) when value = 0I || value = 1I ->
            Some(TypeName([ value.ToString() ], []))
        | Apply(head, arguments) ->
            match tryParseTypeLikeSurfaceExpression head, arguments |> List.map tryParseTypeLikeSurfaceExpression with
            | Some(TypeName(name, existingArguments)), parsedArguments when parsedArguments |> List.forall Option.isSome ->
                Some(TypeName(name, existingArguments @ (parsedArguments |> List.choose id)))
            | _ ->
                None
        | ExplicitImplicitArgument inner ->
            tryParseTypeLikeSurfaceExpression inner
        | _ ->
            None

    type private QueryCarrierShape =
        { ExpectedMode: QuerySemantics.QueryModeInfo
          ExpectedItemQuantity: ResourceModel.ResourceQuantity
          Comprehension: SurfaceComprehension }

    type private QueryPlanShape =
        { InferredMode: QuerySemantics.QueryModeInfo
          InferredItemQuantity: ResourceModel.ResourceQuantity
          InferredItemType: TypeExpr }

    let private tryMatchQueryCarrierShape expression =
        let tryExplicit modeExpression itemQuantityExpression comprehension =
            match
                tryParseTypeLikeSurfaceExpression modeExpression |> Option.bind QuerySemantics.tryParseModeExpr,
                tryParseTypeLikeSurfaceExpression itemQuantityExpression |> Option.bind QuerySemantics.tryParseQuantityExpr
            with
            | Some modeInfo, Some itemQuantity ->
                Some
                    { ExpectedMode = modeInfo
                      ExpectedItemQuantity = itemQuantity
                      Comprehension = comprehension }
            | _ ->
                None

        match expression with
        | Apply(Name nameSegments, [ Comprehension comprehension ]) ->
            match nameSegments |> List.tryLast with
            | Some "Query" ->
                Some
                    { ExpectedMode = QuerySemantics.reusableZeroOrMoreMode
                      ExpectedItemQuantity = ResourceQuantity.omega
                      Comprehension = comprehension }
            | Some "OnceQuery" ->
                Some
                    { ExpectedMode = QuerySemantics.oneShotZeroOrMoreMode
                      ExpectedItemQuantity = ResourceQuantity.omega
                      Comprehension = comprehension }
            | _ ->
                None
        | Apply(Name nameSegments, [ modeExpression; itemQuantityExpression; Comprehension comprehension ])
            when nameSegments |> List.tryLast = Some "QueryCore" ->
            tryExplicit modeExpression itemQuantityExpression comprehension
        | _ ->
            None

    let private tryInferComprehensionPlanShape
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (inferExpressionType: Map<string, TypeExpr> -> SurfaceExpression -> TypeExpr option)
        (comprehension: SurfaceComprehension)
        =
        let normalize = normalizeTypeAliases environment.VisibleTypeAliases

        let trySourceInfo currentLocals sourceExpression =
            inferExpressionType currentLocals sourceExpression
            |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalize)

        let addPatternQuantities
            (quantity: ResourceQuantity)
            (binding: SurfaceBindPattern)
            (quantities: Map<string, ResourceQuantity>)
            =
            ResourceCheckingSurface.collectPatternNames binding.Pattern
            |> List.fold (fun current name -> Map.add name quantity current) quantities

        let rec loop
            (currentMode: QuerySemantics.QueryModeInfo)
            currentLocals
            (currentQuantities: Map<string, ResourceQuantity>)
            clauses
            =
            match clauses with
            | [] ->
                let inferYield expression =
                    inferExpressionType currentLocals expression
                    |> Option.map (fun itemType ->
                        let itemQuantity =
                            match expression with
                            | Name [ name ] ->
                                currentQuantities |> Map.tryFind name |> Option.defaultValue ResourceQuantity.omega
                            | _ ->
                                ResourceQuantity.omega

                        { InferredMode = currentMode
                          InferredItemQuantity = itemQuantity
                          InferredItemType = itemType })

                match comprehension.Yield with
                | YieldValue value ->
                    inferYield value
                | YieldKeyValue(_, value) ->
                    inferYield value
            | clause :: rest ->
                match clause with
                | ForClause(_, _, binding, source) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let nextLocals =
                            extendPatternLocalTypes environment freshCounter currentLocals (Some sourceInfo.Query.ItemType) binding.Pattern

                        let nextQuantities =
                            addPatternQuantities sourceInfo.Query.ItemQuantity binding currentQuantities

                        let nextMode : QuerySemantics.QueryModeInfo =
                            { Use = QuerySemantics.composeUse currentMode.Use sourceInfo.Query.Mode.Use
                              Card = QuerySemantics.multiplyCard currentMode.Card sourceInfo.Query.Mode.Card }

                        loop nextMode nextLocals nextQuantities rest)
                | LetClause(_, binding, value) ->
                    let nextLocals =
                        match inferExpressionType currentLocals value with
                        | Some valueType ->
                            extendPatternLocalTypes environment freshCounter currentLocals (Some valueType) binding.Pattern
                        | None ->
                            currentLocals

                    let nextQuantities =
                        let quantity =
                            binding.Quantity
                            |> Option.map ResourceQuantity.ofSurface
                            |> Option.defaultValue ResourceQuantity.omega

                        addPatternQuantities quantity binding currentQuantities

                    loop currentMode nextLocals nextQuantities rest
                | JoinClause(binding, source, _) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let nextLocals =
                            extendPatternLocalTypes environment freshCounter currentLocals (Some sourceInfo.Query.ItemType) binding.Pattern

                        let nextQuantities =
                            addPatternQuantities sourceInfo.Query.ItemQuantity binding currentQuantities

                        let nextMode : QuerySemantics.QueryModeInfo =
                            { Use = QuerySemantics.composeUse currentMode.Use sourceInfo.Query.Mode.Use
                              Card = QuerySemantics.multiplyCard currentMode.Card sourceInfo.Query.Mode.Card }

                        loop { nextMode with Card = QuerySemantics.filterCard nextMode.Card } nextLocals nextQuantities rest)
                | IfClause _ ->
                    loop { currentMode with Card = QuerySemantics.filterCard currentMode.Card } currentLocals currentQuantities rest
                | GroupByClause(_, _, intoName) ->
                    let nextLocals =
                        Map.add intoName (TypeVariable $"__kappa_group_{intoName}") Map.empty

                    loop currentMode nextLocals Map.empty rest
                | OrderByClause _ ->
                    loop currentMode currentLocals currentQuantities rest
                | DistinctClause
                | DistinctByClause _ ->
                    loop currentMode currentLocals currentQuantities rest
                | SkipClause _
                | TakeClause _ ->
                    loop { currentMode with Card = QuerySemantics.filterCard currentMode.Card } currentLocals currentQuantities rest
                | LeftJoinClause(_, source, _, intoName) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let intoQueryType =
                            TypeName(
                                [ "QueryCore" ],
                                [
                                    TypeName(
                                        [ "QueryMode"; "QueryMode" ],
                                        [
                                            TypeName(
                                                [ "QueryUse"
                                                  match sourceInfo.Query.Mode.Use with
                                                  | QuerySemantics.Reusable -> "Reusable"
                                                  | QuerySemantics.OneShot -> "OneShot" ],
                                                []
                                            )
                                            TypeName(
                                                [ "QueryCard"
                                                  match sourceInfo.Query.Mode.Card with
                                                  | QuerySemantics.QZero -> "QZero"
                                                  | QuerySemantics.QOne -> "QOne"
                                                  | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                                                  | QuerySemantics.QOneOrMore -> "QOneOrMore"
                                                  | QuerySemantics.QZeroOrMore -> "QZeroOrMore" ],
                                                []
                                            )
                                        ]
                                    )
                                    TypeName([ ResourceQuantity.toSurfaceText sourceInfo.Query.ItemQuantity ], [])
                                    sourceInfo.Query.ItemType
                                ]
                            )

                        let nextLocals = Map.add intoName intoQueryType currentLocals
                        loop currentMode nextLocals currentQuantities rest)

        loop
            { Use = QuerySemantics.Reusable
              Card = QuerySemantics.QOne }
            localTypes
            Map.empty
            comprehension.Clauses

    let private tryInferQueryCarrierType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (inferExpressionType: Map<string, TypeExpr> -> SurfaceExpression -> TypeExpr option)
        expression
        =
        tryMatchQueryCarrierShape expression
        |> Option.bind (fun carrier ->
            tryInferComprehensionPlanShape environment freshCounter localTypes inferExpressionType carrier.Comprehension
            |> Option.map (fun plan ->
                TypeName(
                    [ "QueryCore" ],
                    [
                        TypeName(
                            [ "QueryMode"; "QueryMode" ],
                            [
                                TypeName(
                                    [ "QueryUse"
                                      match carrier.ExpectedMode.Use with
                                      | QuerySemantics.Reusable -> "Reusable"
                                      | QuerySemantics.OneShot -> "OneShot" ],
                                    []
                                )
                                TypeName(
                                    [ "QueryCard"
                                      match carrier.ExpectedMode.Card with
                                      | QuerySemantics.QZero -> "QZero"
                                      | QuerySemantics.QOne -> "QOne"
                                      | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                                      | QuerySemantics.QOneOrMore -> "QOneOrMore"
                                      | QuerySemantics.QZeroOrMore -> "QZeroOrMore" ],
                                    []
                                )
                            ]
                        )
                        TypeName([ ResourceQuantity.toSurfaceText carrier.ExpectedItemQuantity ], [])
                        plan.InferredItemType
                    ]
                )))

    let private tryInstantiateTraitSupertraits
        (traitInfo: TraitInfo)
        (arguments: TypeExpr list)
        =
        if List.length traitInfo.TypeParameters = List.length arguments then
            let substitution = List.zip traitInfo.TypeParameters arguments |> Map.ofList
            traitInfo.Supertraits
            |> List.map (TypeSignatures.applyConstraintSubstitution substitution)
            |> Some
        else
            None

    let private reachableTraitConstraints
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let rec visit visited acc (current: TraitConstraint) =
            let key =
                current.TraitName,
                (current.Arguments
                 |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText))

            if Set.contains key visited then
                visited, acc
            else
                let visited = Set.add key visited
                let acc = current :: acc

                let nextConstraints =
                    environment.VisibleTraits
                    |> Map.tryFind current.TraitName
                    |> Option.bind (fun traitInfo -> tryInstantiateTraitSupertraits traitInfo current.Arguments)
                    |> Option.defaultValue []

                nextConstraints |> List.fold (fun (visitedState, accState) next -> visit visitedState accState next) (visited, acc)

        visit Set.empty [] constraintInfo |> snd |> List.rev

    let private tryResolveTraitMemberProjection
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        nameSegments
        =
        let tryFindOwnerTrait traitName arguments memberName =
            let rootConstraint: TraitConstraint =
                { TraitName = traitName
                  Arguments = arguments }

            reachableTraitConstraints environment rootConstraint
            |> List.tryPick (fun candidateConstraint ->
                environment.VisibleTraits
                |> Map.tryFind candidateConstraint.TraitName
                |> Option.bind (fun candidateTraitInfo ->
                    if candidateTraitInfo.Members.ContainsKey(memberName) then
                        Some(candidateTraitInfo, memberName, candidateConstraint.Arguments)
                    else
                        None))

        match nameSegments with
        | receiverName :: [ memberName ] ->
            localTypes
            |> Map.tryFind receiverName
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind receiverName
                |> Option.map (fun bindingInfo -> snd (TypeSignatures.schemeParts bindingInfo.Scheme)))
            |> Option.bind (fun receiverType ->
                match normalizeTypeAliases environment.VisibleTypeAliases receiverType with
                | TypeName([ traitName ], arguments) when environment.VisibleTraits.ContainsKey(traitName) ->
                    tryFindOwnerTrait traitName arguments memberName
                    |> Option.map (fun (traitInfo, resolvedMemberName, resolvedArguments) ->
                        traitInfo, resolvedMemberName, resolvedArguments, receiverName)
                | TypeName(qualifiedName, arguments) ->
                    let traitName = SyntaxFacts.moduleNameToText qualifiedName

                    if environment.VisibleTraits.ContainsKey(traitName) then
                        tryFindOwnerTrait traitName arguments memberName
                        |> Option.map (fun (traitInfo, resolvedMemberName, resolvedArguments) ->
                            traitInfo, resolvedMemberName, resolvedArguments, receiverName)
                    else
                        None
                | _ ->
                    None)
        | _ ->
            None

    let private tryReceiverProjection
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        receiverName
        memberName
        =
        let receiverType =
            localTypes
            |> Map.tryFind receiverName
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind receiverName
                |> Option.map (fun bindingInfo -> snd (TypeSignatures.schemeParts bindingInfo.Scheme)))
            |> Option.map (normalizeTypeAliases environment.VisibleTypeAliases)

        let binderMatchesReceiverType (binder: ProjectionPlaceBinder) =
            match receiverType, TypeSignatures.parseType binder.TypeTokens with
            | Some actualType, Some expectedType ->
                TypeSignatures.definitionallyEqual
                    actualType
                    (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
            | _ ->
                true

        environment.VisibleProjections
        |> Map.tryFind memberName
        |> Option.bind (fun projectionInfo ->
            let placeBinders =
                projectionInfo.Binders
                |> List.choose (function
                    | ProjectionPlaceBinder binder -> Some binder
                    | ProjectionValueBinder _ -> None)

            match placeBinders with
            | [ binder ] when binder.IsReceiver && binderMatchesReceiverType binder ->
                Some projectionInfo
            | _ ->
                None)

    let private tryBuildReceiverMethodArguments
        (bindingInfo: BindingSchemeInfo)
        receiverExpression
        arguments
        =
        let tryReceiverMethodCallInfo () =
            bindingInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                let receiverParameters =
                    layouts
                    |> List.mapi (fun index layout -> index, layout)
                    |> List.filter (fun (_, layout) -> layout.IsReceiver)

                match receiverParameters with
                | [ receiverIndex, _ ] ->
                    let precedingExplicitCount =
                        layouts
                        |> List.take receiverIndex
                        |> List.filter (fun layout -> not layout.IsImplicit)
                        |> List.length

                    let requiredExplicitArgumentCount =
                        layouts
                        |> List.filter (fun layout -> not layout.IsImplicit)
                        |> List.length
                        |> fun count -> max 0 (count - 1)

                    Some(precedingExplicitCount, requiredExplicitArgumentCount)
                | _ ->
                    None)

        tryReceiverMethodCallInfo ()
        |> Option.bind (fun (precedingExplicitCount, _) ->
            if List.length arguments >= precedingExplicitCount then
                let precedingArguments = arguments |> List.take precedingExplicitCount
                let followingArguments = arguments |> List.skip precedingExplicitCount
                Some(precedingArguments @ [ receiverExpression ] @ followingArguments)
            else
                None)

    let private receiverMethodCallHasRequiredExplicitArguments
        (bindingInfo: BindingSchemeInfo)
        (arguments: SurfaceExpression list)
        =
        bindingInfo.ParameterLayouts
        |> Option.bind (fun layouts ->
            let receiverParameters =
                layouts
                |> List.filter (fun layout -> layout.IsReceiver)

            let requiredExplicitArgumentCount =
                layouts
                |> List.filter (fun layout -> not layout.IsImplicit)
                |> List.length
                |> fun count -> max 0 (count - 1)

            if List.length receiverParameters = 1 then
                Some(List.length arguments >= requiredExplicitArgumentCount)
            else
                None)
        |> Option.defaultValue true

    let rec private isIntrinsicPreludeEqType
        (visibleTypeAliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        let isPreludeTypeName expectedName nameSegments =
            let typeNameText = SyntaxFacts.moduleNameToText nameSegments

            String.Equals(typeNameText, expectedName, StringComparison.Ordinal)
            || String.Equals(typeNameText, $"{Stdlib.PreludeModuleText}.{expectedName}", StringComparison.Ordinal)

        let isStdHashTypeName expectedName nameSegments =
            let typeNameText = SyntaxFacts.moduleNameToText nameSegments

            String.Equals(typeNameText, expectedName, StringComparison.Ordinal)
            || String.Equals(typeNameText, $"std.hash.{expectedName}", StringComparison.Ordinal)

        match normalizeTypeAliases visibleTypeAliases typeExpr with
        | TypeName(name, [])
            when isPreludeTypeName "Unit" name
                 || isPreludeTypeName "Bool" name
                 || isPreludeTypeName "Byte" name
                 || isPreludeTypeName "Bytes" name
                 || isPreludeTypeName "UnicodeScalar" name
                 || isPreludeTypeName "Grapheme" name
                 || isPreludeTypeName "String" name
                 || isPreludeTypeName "Int" name
                 || isPreludeTypeName "Nat" name
                 || isPreludeTypeName "Integer" name
                 || isPreludeTypeName "Float" name
                 || isPreludeTypeName "Double" name
                 || isPreludeTypeName "Real" name
                 || isPreludeTypeName "Ordering" name
                 || isStdHashTypeName "HashCode" name ->
            true
        | _ ->
            false

