    let private tryResolveIntrinsicTraitInstance
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases)

        let supportsConstraint, moduleName, instancePrefix =
            match constraintInfo.TraitName, normalizedArguments with
            | "Eq", [ argumentType ] ->
                isIntrinsicPreludeEqType environment.VisibleTypeAliases argumentType,
                Stdlib.PreludeModuleText,
                "builtin-prelude"
            | "Ord", [ argumentType ] ->
                isIntrinsicPreludeOrdType environment.VisibleTypeAliases argumentType,
                Stdlib.PreludeModuleText,
                "builtin-prelude"
            | "Show", [ argumentType ] ->
                isIntrinsicPreludeShowType environment.VisibleTypeAliases argumentType,
                Stdlib.PreludeModuleText,
                "builtin-prelude"
            | "Rangeable", [ argumentType ] ->
                isIntrinsicPreludeRangeableType environment.VisibleTypeAliases argumentType,
                Stdlib.PreludeModuleText,
                "builtin-prelude"
            | _ ->
                false, "", ""

        if not supportsConstraint then
            None
        else
            let normalizedArgumentText =
                normalizedArguments
                |> List.map TypeSignatures.toText
                |> String.concat ","

            let instanceKey =
                $"{instancePrefix}:{constraintInfo.TraitName}:{normalizedArgumentText}"

            Some
                { ModuleName = moduleName
                  TraitName = constraintInfo.TraitName
                  InstanceKey = instanceKey
                  Constraints = []
                  HeadTypes = normalizedArguments
                  Members = Map.empty }

    let private resolveConstraintInstanceDetailedWithSubstitution
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let normalizeConstraint (constraintInfo: TraitConstraint) =
            let normalizedArguments =
                constraintInfo.Arguments
                |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
                |> String.concat ","

            $"{constraintInfo.TraitName}({normalizedArguments})"

        let rec solve visited (goal: TraitConstraint) =
            let goalKey = normalizeConstraint goal

            if Set.contains goalKey visited then
                ConstraintUnresolved
            else
                let visited = Set.add goalKey visited

                let mutable nestedAmbiguity = None

                let survivingCandidates =
                    environment.VisibleInstances
                    |> List.choose (fun instanceInfo ->
                        if not (String.Equals(instanceInfo.TraitName, goal.TraitName, StringComparison.Ordinal)) then
                            None
                        elif List.length instanceInfo.HeadTypes <> List.length goal.Arguments then
                            None
                        else
                            tryUnifyVisibleTypes environment.VisibleTypeAliases (List.zip instanceInfo.HeadTypes goal.Arguments)
                            |> Option.bind (fun substitution ->
                                let instantiatedPremises =
                                    instanceInfo.Constraints
                                    |> List.map (TypeSignatures.applyConstraintSubstitution substitution)

                                let rec premisesSatisfied premises =
                                    match premises with
                                    | [] ->
                                        true
                                    | premise :: rest ->
                                        match solve visited premise with
                                        | ConstraintResolved _ ->
                                            premisesSatisfied rest
                                        | ConstraintUnresolved ->
                                            false
                                        | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                            nestedAmbiguity <- Some(ambiguousGoal, candidates)
                                            false

                                if premisesSatisfied instantiatedPremises then
                                    Some(instanceInfo, substitution)
                                else
                                    None))
                    |> List.sortBy (fun (instanceInfo, _) ->
                        instanceInfo.ModuleName,
                        instanceInfo.TraitName,
                        instanceInfo.InstanceKey)

                match nestedAmbiguity with
                | Some(ambiguousGoal, candidates) ->
                    ConstraintAmbiguous(ambiguousGoal, candidates)
                | None ->
                    match survivingCandidates with
                    | [] ->
                        match tryResolveIntrinsicTraitInstance environment goal with
                        | Some instanceInfo ->
                            ConstraintResolved(instanceInfo, Map.empty)
                        | None ->
                            ConstraintUnresolved
                    | [ instanceInfo, substitution ] ->
                        ConstraintResolved(instanceInfo, substitution)
                    | candidates ->
                        ConstraintAmbiguous(goal, candidates |> List.map fst)

        solve Set.empty constraintInfo

    let private resolveConstraintInstanceWithSubstitution
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
        | ConstraintResolved(instanceInfo, substitution) ->
            Some(instanceInfo, substitution)
        | ConstraintUnresolved
        | ConstraintAmbiguous _ ->
            None

    let private resolveConstraintInstance
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        resolveConstraintInstanceWithSubstitution environment constraintInfo
        |> Option.map fst

    let private normalizedConstraintKey
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
            |> String.concat ","

        $"{constraintInfo.TraitName}({normalizedArguments})"

    let private addReachableConstraintDictionary
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        (dictionaryExpression: KCoreExpression)
        (state: Map<string, KCoreExpression>)
        =
        reachableTraitConstraints environment constraintInfo
        |> List.fold (fun current reachableConstraint ->
            let key = normalizedConstraintKey environment reachableConstraint

            if Map.containsKey key current then
                current
            else
                Map.add key dictionaryExpression current) state

    let private buildConstraintDictionaries
        (environment: BindingLoweringEnvironment)
        (entries: (TraitConstraint * KCoreExpression) list)
        =
        entries
        |> List.fold (fun state (constraintInfo, dictionaryExpression) ->
            addReachableConstraintDictionary environment constraintInfo dictionaryExpression state) Map.empty

    let private constraintHasLocalDictionary
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        environment.ConstraintDictionaries
        |> Map.containsKey (normalizedConstraintKey environment constraintInfo)

    let private tryLowerResolvedDictionaryValue
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let localKey = normalizedConstraintKey environment constraintInfo

        let rec lower visited currentConstraint =
            let currentKey = normalizedConstraintKey environment currentConstraint

            if Set.contains currentKey visited then
                None
            else
                match environment.ConstraintDictionaries |> Map.tryFind currentKey with
                | Some dictionaryExpression ->
                    Some dictionaryExpression
                | None ->
                    resolveConstraintInstanceWithSubstitution environment currentConstraint
                    |> Option.bind (fun (instanceInfo, substitution) ->
                        let nextVisited = Set.add currentKey visited

                        let rec lowerPremises pending =
                            match pending with
                            | [] ->
                                Some []
                            | premise :: rest ->
                                let instantiatedPremise = TypeSignatures.applyConstraintSubstitution substitution premise

                                lower nextVisited instantiatedPremise
                                |> Option.bind (fun loweredPremise ->
                                    lowerPremises rest
                                    |> Option.map (fun loweredRest -> loweredPremise :: loweredRest))

                        lowerPremises instanceInfo.Constraints
                        |> Option.map (fun loweredPremises ->
                            KCoreDictionaryValue(
                                instanceInfo.ModuleName,
                                instanceInfo.TraitName,
                                instanceInfo.InstanceKey,
                                loweredPremises
                            )))

        environment.ConstraintDictionaries
        |> Map.tryFind localKey
        |> Option.orElseWith (fun () -> lower Set.empty constraintInfo)

    let private lowerResolvedOwningDictionaryValue
        (environment: BindingLoweringEnvironment)
        (traitName: string)
        (preparedCall: PreparedBindingCall)
        (fallbackInstanceInfo: InstanceInfo)
        =
        match preparedCall.InstantiatedScheme.Constraints with
        | owningConstraint :: _
            when String.Equals(owningConstraint.TraitName, traitName, StringComparison.Ordinal) ->
            tryLowerResolvedDictionaryValue environment owningConstraint
            |> Option.defaultValue (
                KCoreDictionaryValue(
                    fallbackInstanceInfo.ModuleName,
                    fallbackInstanceInfo.TraitName,
                    fallbackInstanceInfo.InstanceKey,
                    []
                )
            )
        | _ ->
            KCoreDictionaryValue(
                fallbackInstanceInfo.ModuleName,
                fallbackInstanceInfo.TraitName,
                fallbackInstanceInfo.InstanceKey,
                []
            )

    let private tryTraitConstraintFromType
        (environment: BindingLoweringEnvironment)
        parameterType
        =
        match normalizeTypeAliases environment.VisibleTypeAliases parameterType with
        | TypeName([ traitName ], arguments) when environment.VisibleTraits.ContainsKey(traitName) ->
            Some { TraitName = traitName; Arguments = arguments }
        | TypeName(qualifiedName, arguments) ->
            let traitName = SyntaxFacts.moduleNameToText qualifiedName

            if environment.VisibleTraits.ContainsKey(traitName) then
                Some { TraitName = traitName; Arguments = arguments }
            else
                None
        | _ ->
            None

    let private localTraitConstraints
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        =
        localTypes
        |> Map.toList
        |> List.choose (fun (name, localType) ->
            tryTraitConstraintFromType environment localType
            |> Option.map (fun constraintInfo -> name, constraintInfo))

    let private buildConstrainedMembers
        (environment: BindingLoweringEnvironment)
        (constraints: TraitConstraint list)
        =
        let addConstraintMembers state dictionaryParameterName constraintInfo =
            reachableTraitConstraints environment constraintInfo
            |> List.fold (fun current reachableConstraint ->
                environment.VisibleTraits
                |> Map.tryFind reachableConstraint.TraitName
                |> Option.map (fun traitInfo ->
                    traitInfo.Members
                    |> Map.toList
                    |> List.fold (fun innerState (memberName, _) ->
                        if Map.containsKey memberName innerState then
                            innerState
                        else
                            Map.add memberName (reachableConstraint.TraitName, dictionaryParameterName) innerState) current)
                |> Option.defaultValue current) state

        constraints
        |> List.mapi (fun index constraintInfo ->
            let dictionaryParameterName = $"__kappa_dict_{constraintInfo.TraitName}_{index}"
            constraintInfo, dictionaryParameterName)
        |> List.fold (fun state (constraintInfo, dictionaryParameterName) ->
            addConstraintMembers state dictionaryParameterName constraintInfo) Map.empty

    let private buildParameterConstrainedMembers
        (environment: BindingLoweringEnvironment)
        (scheme: TypeScheme)
        (parameters: Parameter list)
        =
        let parameterTypes, _ = TypeSignatures.schemeParts scheme

        let alignParameterTypesWithParameters () =
            let remaining = ref parameterTypes
            let aligned = ResizeArray<TypeExpr>()
            let mutable success = true

            for parameter in parameters do
                match tryParseParameterType parameter with
                | Some parameterLayoutType when isCompileTimeArgumentType environment.VisibleTypeAliases parameterLayoutType ->
                    aligned.Add(parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | Some parameterLayoutType
                    when parameter.IsImplicit
                         && (tryTraitConstraintFromType environment parameterLayoutType |> Option.isSome) ->
                    aligned.Add(parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | _ ->
                    match !remaining with
                    | parameterType :: rest ->
                        aligned.Add(parameterType)
                        remaining := rest
                    | [] ->
                        success <- false

            if success then
                Some(List.ofSeq aligned)
            else
                None

        match alignParameterTypesWithParameters () with
        | Some alignedParameterTypes when List.length alignedParameterTypes = List.length parameters ->
            List.zip parameters alignedParameterTypes
            |> List.fold (fun state (parameter, parameterType) ->
                if parameter.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                    match tryTraitConstraintFromType environment parameterType with
                    | Some constraintInfo ->
                        reachableTraitConstraints environment constraintInfo
                        |> List.fold (fun current reachableConstraint ->
                            environment.VisibleTraits
                            |> Map.tryFind reachableConstraint.TraitName
                            |> Option.map (fun traitInfo ->
                                traitInfo.Members
                                |> Map.toList
                                |> List.fold (fun innerState (memberName, _) ->
                                    if Map.containsKey memberName innerState then
                                        innerState
                                    else
                                        Map.add memberName (reachableConstraint.TraitName, parameter.Name) innerState) current)
                            |> Option.defaultValue current) state
                    | None ->
                        state
                else
                    state) Map.empty
        | _ ->
            Map.empty

    let private buildParameterConstraintDictionaries
        (environment: BindingLoweringEnvironment)
        (scheme: TypeScheme)
        (parameters: Parameter list)
        =
        let parameterTypes, _ = TypeSignatures.schemeParts scheme

        let alignParameterTypesWithParameters () =
            let remaining = ref parameterTypes
            let aligned = ResizeArray<TypeExpr>()
            let mutable success = true

            for parameter in parameters do
                match tryParseParameterType parameter with
                | Some parameterLayoutType when isCompileTimeArgumentType environment.VisibleTypeAliases parameterLayoutType ->
                    aligned.Add(parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | Some parameterLayoutType
                    when parameter.IsImplicit
                         && (tryTraitConstraintFromType environment parameterLayoutType |> Option.isSome) ->
                    aligned.Add(parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | _ ->
                    match !remaining with
                    | parameterType :: rest ->
                        aligned.Add(parameterType)
                        remaining := rest
                    | [] ->
                        success <- false

            if success then
                Some(List.ofSeq aligned)
            else
                None

        match alignParameterTypesWithParameters () with
        | Some alignedParameterTypes when List.length alignedParameterTypes = List.length parameters ->
            List.zip parameters alignedParameterTypes
            |> List.fold (fun state (parameter, parameterType) ->
                if parameter.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                    match tryTraitConstraintFromType environment parameterType with
                    | Some constraintInfo ->
                        addReachableConstraintDictionary environment constraintInfo (KCoreName [ parameter.Name ]) state
                    | None ->
                        state
                else
                    state) Map.empty
        | _ ->
            Map.empty

    let private renderTraitConstraint (environment: BindingLoweringEnvironment) (constraintInfo: TraitConstraint) =
        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
            |> String.concat ", "

        if String.IsNullOrWhiteSpace normalizedArguments then
            constraintInfo.TraitName
        else
            $"{constraintInfo.TraitName} {normalizedArguments}"

    let private renderInstanceCandidate (instanceInfo: InstanceInfo) =
        let headArguments =
            instanceInfo.HeadTypes
            |> List.map TypeSignatures.toText
            |> String.concat ", "

        let headText =
            if String.IsNullOrWhiteSpace headArguments then
                instanceInfo.TraitName
            else
                $"{instanceInfo.TraitName} {headArguments}"

        $"{instanceInfo.ModuleName}:{headText}"

    let private matchesBuiltinNumericTarget
        (aliases: Map<string, TypeAliasInfo>)
        literal
        expectedType
        =
        let isIntegerLiteral =
            match literal with
            | SurfaceIntegerLiteral _ -> true
            | _ -> false

        let isRealLiteral =
            match literal with
            | SurfaceRealLiteral _ -> true
            | _ -> false

        match normalizeTypeAliases aliases expectedType with
        | TypeName([ "Int" ], [])
        | TypeName([ "Integer" ], [])
        | TypeName([ "Nat" ], [])
            when isIntegerLiteral ->
            true
        | TypeName([ "Float" ], [])
        | TypeName([ "Double" ], [])
        | TypeName([ "Real" ], [])
            when isRealLiteral ->
            true
        | _ ->
            false

    let private numericLiteralConstraintName literal =
        match literal with
        | SurfaceIntegerLiteral _ -> "FromInteger"
        | SurfaceRealLiteral _ -> "FromFloat"

    let private tryResolveNumericStaticObjectTarget
        (environment: BindingLoweringEnvironment)
        expectedType
        =
        let rec loop visited current =
            let normalizedCurrent =
                normalizeTypeAliases environment.VisibleTypeAliases current

            let candidateKey = TypeSignatures.toText normalizedCurrent

            if Set.contains candidateKey visited then
                None
            else
                let visited = Set.add candidateKey visited

                match normalizedCurrent with
                | TypeName(nameSegments, []) ->
                    let aliasName = SyntaxFacts.moduleNameToText nameSegments

                    environment.VisibleStaticObjects
                    |> Map.tryFind aliasName
                    |> Option.bind (fun staticObject ->
                        match staticObject.ObjectKind with
                        | StaticTypeObject ->
                            loop visited (TypeName(staticObject.NameSegments, []))
                        | _ ->
                            None)
                    |> Option.orElseWith (fun () ->
                        if Set.isEmpty visited then
                            None
                        else
                            Some normalizedCurrent)
                | _ ->
                    if Set.isEmpty visited then
                        None
                    else
                        Some normalizedCurrent

        loop Set.empty expectedType

    let private tryResolveNumericLiteralContext
        (environment: BindingLoweringEnvironment)
        expectedType
        literal
        =
        let candidateTypes =
            expectedType
            :: (tryResolveNumericStaticObjectTarget environment expectedType |> Option.toList)

        let tryResolveAgainstTarget targetType =
            let normalizedTargetType =
                normalizeTypeAliases environment.VisibleTypeAliases targetType

            if isCompileTimeArgumentType environment.VisibleTypeAliases normalizedTargetType then
                None
            elif matchesBuiltinNumericTarget environment.VisibleTypeAliases literal normalizedTargetType then
                Some(expectedType, None)
            else
                let constraintInfo =
                    { TraitName = numericLiteralConstraintName literal
                      Arguments = [ normalizedTargetType ] }

                resolveConstraintInstance environment constraintInfo
                |> Option.map (fun instanceInfo -> expectedType, Some instanceInfo)

        candidateTypes
        |> List.tryPick tryResolveAgainstTarget

    let private tryInferNumericLiteralTypeFromContext
        (environment: BindingLoweringEnvironment)
        expectedType
        literal
        =
        tryResolveNumericLiteralContext environment expectedType literal
        |> Option.map fst

    let private tryInferNumericExpressionTypeFromContext
        (environment: BindingLoweringEnvironment)
        expectedType
        expression
        =
        match expression with
        | NumericLiteral literal ->
            tryInferNumericLiteralTypeFromContext environment expectedType literal
        | Unary("-", NumericLiteral literal) ->
            tryInferNumericLiteralTypeFromContext environment expectedType literal
        | _ ->
            None

    let private tryLowerNumericLiteralForRuntime literal =
        match literal with
        | SurfaceIntegerLiteral(value, _, _) when value >= BigInteger(Int64.MinValue) && value <= BigInteger(Int64.MaxValue) ->
            Some(KCoreLiteral(LiteralValue.Integer(int64 value)))
        | SurfaceRealLiteral(_, text, _) ->
            match Double.TryParse(text, Globalization.NumberStyles.Float, Globalization.CultureInfo.InvariantCulture) with
            | true, value ->
                Some(KCoreLiteral(LiteralValue.Float value))
            | _ ->
                None
        | _ ->
            None

    let private tryLowerNumericExpressionForRuntime expression =
        match expression with
        | NumericLiteral literal ->
            tryLowerNumericLiteralForRuntime literal
        | Unary("-", NumericLiteral(SurfaceIntegerLiteral(value, text, suffix))) ->
            tryLowerNumericLiteralForRuntime (SurfaceIntegerLiteral(-value, "-" + text, suffix))
        | Unary("-", NumericLiteral(SurfaceRealLiteral(decimalValue, text, suffix))) ->
            tryLowerNumericLiteralForRuntime (SurfaceRealLiteral(decimalValue |> Option.map (~-), "-" + text, suffix))
        | _ ->
            None

    let private trySynthesizeImplicitArgument
        (environment: BindingLoweringEnvironment)
        (tryResolveLocalImplicit: TypeExpr -> KCoreExpression option)
        parameterType
        =
        match tryResolveLocalImplicit parameterType with
        | Some implicitArgument ->
            Some implicitArgument
        | None ->
            tryTraitConstraintFromType environment parameterType
            |> Option.bind (tryLowerResolvedDictionaryValue environment)

    let private noLocalImplicit (_: TypeExpr) : KCoreExpression option =
        None

    type private LocalImplicitResolution =
        | NoLocalImplicitCandidate
        | UniqueLocalImplicitCandidate of KCoreExpression
        | AmbiguousLocalImplicitCandidates

    let private classifyLocalImplicitByType
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        parameterType
        =
        let normalizeVisible currentType =
            currentType
            |> qualifyVisibleTypeNames environment
            |> normalizeTypeAliases environment.VisibleTypeAliases

        let normalizedGoal =
            normalizeVisible parameterType

        let matches =
            localTypes
            |> Map.toList
            |> List.filter (fun (_, localType) ->
                TypeSignatures.definitionallyEqual
                    (normalizeVisible localType)
                    normalizedGoal)

        match matches with
        | [ name, _ ] ->
            UniqueLocalImplicitCandidate(KCoreName [ name ])
        | _ :: _ ->
            AmbiguousLocalImplicitCandidates
        | [] ->
            match tryTraitConstraintFromType environment parameterType with
            | Some goalConstraint ->
                let projectedMatches =
                    localTraitConstraints environment localTypes
                    |> List.filter (fun (_, localConstraint: TraitConstraint) ->
                        reachableTraitConstraints environment localConstraint
                        |> List.exists (fun (reachableConstraint: TraitConstraint) ->
                            String.Equals(reachableConstraint.TraitName, goalConstraint.TraitName, StringComparison.Ordinal)
                            && List.length reachableConstraint.Arguments = List.length goalConstraint.Arguments
                            && List.forall2
                                (fun left right ->
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases environment.VisibleTypeAliases left)
                                        (normalizeTypeAliases environment.VisibleTypeAliases right))
                                reachableConstraint.Arguments
                                goalConstraint.Arguments))

                match projectedMatches with
                | [ name, _ ] ->
                    UniqueLocalImplicitCandidate(KCoreName [ name ])
                | _ :: _ ->
                    AmbiguousLocalImplicitCandidates
                | [] ->
                    NoLocalImplicitCandidate
            | None ->
                NoLocalImplicitCandidate

    let private tryResolveUniqueLocalImplicitByType
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        parameterType
        =
        match classifyLocalImplicitByType environment localTypes parameterType with
        | UniqueLocalImplicitCandidate candidate ->
            Some candidate
        | NoLocalImplicitCandidate
        | AmbiguousLocalImplicitCandidates ->
            None

    let private tryResolveUniqueLocalImplicitByTypeWithSubstitution
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        substitution
        parameterType
        =
        let substitutedLocalTypes =
            localTypes
            |> Map.map (fun _ localType -> TypeSignatures.applySubstitution substitution localType)

        let substitutedParameterType =
            TypeSignatures.applySubstitution substitution parameterType

        tryResolveUniqueLocalImplicitByType environment substitutedLocalTypes substitutedParameterType

    let private tryAlignParameterTypesWithLayouts
        (environment: BindingLoweringEnvironment)
        (layouts: Parameter list)
        (parameterTypes: TypeExpr list)
        =
        let remaining = ref parameterTypes
        let aligned = ResizeArray<TypeExpr>()
        let mutable success = true

        for layout in layouts do
            match tryParseParameterType layout with
            | Some layoutType when isCompileTimeArgumentType environment.VisibleTypeAliases layoutType ->
                aligned.Add(layoutType)

                match !remaining with
                | parameterType :: rest
                    when TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                    remaining := rest
                | _ ->
                    ()
            | Some layoutType
                when layout.IsImplicit
                     && (tryTraitConstraintFromType environment layoutType |> Option.isSome) ->
                aligned.Add(layoutType)
                match !remaining with
                | parameterType :: rest
                    when TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                    remaining := rest
                | _ ->
                    ()
            | _ ->
                match !remaining with
                | parameterType :: rest ->
                    aligned.Add(parameterType)
                    remaining := rest
                | [] ->
                    success <- false

        if success then
            Some(List.ofSeq aligned, List.ofSeq !remaining)
        else
            None

    let private tryPrepareVisibleBindingCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (bindingInfo: BindingSchemeInfo)
        (localImplicitTypes: Map<string, TypeExpr> option)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (tryResolveLocalImplicit: TypeExpr -> KCoreExpression option)
        (arguments: SurfaceExpression list)
        =
        let inferArgumentTypeForParameter parameterType argument =
            tryInferNumericExpressionTypeFromContext environment parameterType argument
            |> Option.orElseWith (fun () -> inferArgumentType argument)

        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

        let rec consumeCompileTimeApplications
            (remainingForall: TypeSignatures.ForallBinder list)
            (remainingArguments: SurfaceExpression list)
            substitution
            =
            match remainingForall, remainingArguments with
            | binder :: restForall, ExplicitImplicitArgument explicitArgument :: restArguments ->
                match tryParseTypeLikeSurfaceExpression explicitArgument with
                | Some explicitTypeArgument ->
                    consumeCompileTimeApplications
                        restForall
                        restArguments
                        (composeTypeSubstitution substitution (Map.ofList [ binder.Name, explicitTypeArgument ]))
                | None ->
                    None
            | _, _ ->
                Some(substitution, remainingArguments)

        let explicitTypeApplicationsValid, instantiated, arguments =
            match consumeCompileTimeApplications instantiated.Forall arguments Map.empty with
            | Some(substitution, remainingArguments) ->
                true,
                TypeSignatures.applySchemeSubstitution substitution instantiated,
                remainingArguments
            | None ->
                false,
                instantiated,
                arguments

        let hasApplicationOnlyArgument arguments =
            arguments
            |> List.exists (function
                | ExplicitImplicitArgument _
                | NamedApplicationBlock _ -> true
                | _ -> false)

        let hasDefaultArgument (parameterLayout: Parameter) =
            bindingInfo.DefaultArguments.ContainsKey(parameterLayout.Name)

        let tryResolveCurrentLocalImplicit substitution parameterType =
            match localImplicitTypes with
            | Some localTypes ->
                tryResolveUniqueLocalImplicitByTypeWithSubstitution
                    environment
                    localTypes
                    substitution
                    parameterType
            | None ->
                tryResolveLocalImplicit parameterType

        let tryPrepareSchemeOnlyCall instantiated arguments =
            let trySynthesizeSchemeOnlyImplicit substitution parameterType =
                tryResolveCurrentLocalImplicit substitution parameterType
                |> Option.orElseWith (fun () ->
                    tryTraitConstraintFromType environment parameterType
                    |> Option.bind (tryLowerResolvedDictionaryValue environment))
            let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated
            let maxLeadingImplicitCount = List.length schemeParameterTypes - List.length arguments

            if maxLeadingImplicitCount < 0 then
                None
            else
                let tryCandidate leadingImplicitCount =
                    let leadingImplicitTypes =
                        schemeParameterTypes |> List.take leadingImplicitCount

                    let remainingParameterTypes =
                        schemeParameterTypes |> List.skip leadingImplicitCount

                    let explicitParameterTypes =
                        remainingParameterTypes |> List.truncate arguments.Length

                    let trailingParameterTypes =
                        remainingParameterTypes |> List.skip arguments.Length

                    if List.length explicitParameterTypes <> List.length arguments then
                        None
                    else
                        let explicitArgumentTypes =
                            List.zip explicitParameterTypes arguments
                            |> List.map (fun (parameterType, argument) ->
                                inferArgumentTypeForParameter parameterType argument)

                        if explicitArgumentTypes |> List.exists Option.isNone then
                            None
                        else
                            let explicitArgumentTypes = explicitArgumentTypes |> List.choose id

                            tryUnifyVisibleTypes
                                environment.VisibleTypeAliases
                                (List.zip explicitParameterTypes explicitArgumentTypes)
                            |> Option.bind (fun explicitSubstitution ->
                                let instantiatedScheme =
                                    TypeSignatures.applySchemeSubstitution explicitSubstitution instantiated

                                let substitutedLeadingImplicitTypes =
                                    leadingImplicitTypes
                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)

                                let substitutedTrailingParameterTypes =
                                    trailingParameterTypes
                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)

                                let rec synthesizeLeadingImplicits
                                    pendingImplicitTypes
                                    synthesizedArguments
                                    synthesizedTypes
                                    =
                                    match pendingImplicitTypes with
                                    | [] ->
                                        Some(List.rev synthesizedArguments, List.rev synthesizedTypes)
                                    | parameterType :: rest ->
                                        match trySynthesizeSchemeOnlyImplicit explicitSubstitution parameterType with
                                        | Some implicitArgument ->
                                            synthesizeLeadingImplicits
                                                rest
                                                (ImplicitArgument implicitArgument :: synthesizedArguments)
                                                (parameterType :: synthesizedTypes)
                                        | None ->
                                            None

                                synthesizeLeadingImplicits
                                    substitutedLeadingImplicitTypes
                                    []
                                    []
                                |> Option.map (fun (implicitArguments, implicitArgumentTypes) ->
                                    let _, substitutedResultType = TypeSignatures.schemeParts instantiatedScheme

                                    let appliedResultType =
                                        substitutedTrailingParameterTypes
                                        |> List.rev
                                        |> List.fold
                                            (fun current parameterType ->
                                                TypeArrow(QuantityOmega, parameterType, current))
                                            substitutedResultType

                                    { InstantiatedScheme = instantiatedScheme
                                      ResultType = appliedResultType
                                      Parameters = []
                                      Arguments = implicitArguments @ (arguments |> List.map ExplicitArgument) }))

                [ maxLeadingImplicitCount .. -1 .. 0 ]
                |> List.tryPick tryCandidate

        match bindingInfo.ParameterLayouts with
        | None ->
            if (not explicitTypeApplicationsValid) || hasApplicationOnlyArgument arguments then
                None
            else
                tryPrepareSchemeOnlyCall instantiated arguments
        | Some parameterLayouts when List.isEmpty parameterLayouts ->
            if (not explicitTypeApplicationsValid) || hasApplicationOnlyArgument arguments then
                None
            else
                tryPrepareSchemeOnlyCall instantiated arguments
        | Some parameterLayouts ->
            if not explicitTypeApplicationsValid then
                None
            else
                let schemeParameterTypes, resultType = TypeSignatures.schemeParts instantiated

                match tryAlignParameterTypesWithLayouts environment parameterLayouts schemeParameterTypes with
                | None ->
                    None
                | Some(parameterTypes, trailingParameterTypes) ->
                    let splitNamedBlock (arguments: SurfaceExpression list) =
                        let indexedNamedBlocks =
                            arguments
                            |> List.mapi (fun index argument ->
                                match argument with
                                | NamedApplicationBlock fields -> Some(index, fields)
                                | _ -> None)
                            |> List.choose id

                        match indexedNamedBlocks with
                        | [] ->
                            Some(arguments, None)
                        | [ index, fields ] when index = List.length arguments - 1 ->
                            Some(arguments |> List.take index, Some fields)
                        | _ ->
                            None

                    match splitNamedBlock arguments with
                    | None ->
                        None
                    | Some(positionalArguments, namedFields) ->
                        let tryPrepareLeadingRuntimeImplicits
                            (layouts: Parameter list)
                            (types: TypeExpr list)
                            (positionalArguments: SurfaceExpression list)
                            =
                            if
                                List.isEmpty positionalArguments
                                || (positionalArguments
                                    |> List.exists (function
                                        | ExplicitImplicitArgument _ -> true
                                        | _ -> false))
                            then
                                None
                            else
                                let rec splitLeading
                                    (pendingLayouts: Parameter list)
                                    (pendingTypes: TypeExpr list)
                                    (consumedLeading: (Parameter * TypeExpr) list)
                                    =
                                    match pendingLayouts, pendingTypes with
                                    | layout :: restLayouts, parameterType :: restTypes
                                        when layout.IsImplicit
                                             && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) ->
                                        splitLeading restLayouts restTypes ((layout, parameterType) :: consumedLeading)
                                    | _ ->
                                        List.rev consumedLeading, pendingLayouts, pendingTypes

                                let (leadingImplicits: (Parameter * TypeExpr) list), (remainingLayouts: Parameter list), (remainingTypes: TypeExpr list) =
                                    splitLeading layouts types []

                                let rec collectExplicitParameterTypes
                                    (pendingLayouts: Parameter list)
                                    (pendingTypes: TypeExpr list)
                                    (pendingArguments: SurfaceExpression list)
                                    (explicitParameterTypes: TypeExpr list)
                                    =
                                    match pendingArguments with
                                    | [] ->
                                        Some(List.rev explicitParameterTypes)
                                    | _ ->
                                        match pendingLayouts, pendingTypes with
                                        | layout :: restLayouts, parameterType :: restTypes
                                            when isCompileTimeArgumentType environment.VisibleTypeAliases parameterType ->
                                            None
                                        | layout :: restLayouts, parameterType :: restTypes
                                            when layout.IsImplicit ->
                                            collectExplicitParameterTypes restLayouts restTypes pendingArguments explicitParameterTypes
                                        | _ :: restLayouts, parameterType :: restTypes ->
                                            match pendingArguments with
                                            | _ :: restArguments ->
                                                collectExplicitParameterTypes
                                                    restLayouts
                                                    restTypes
                                                    restArguments
                                                    (parameterType :: explicitParameterTypes)
                                            | [] ->
                                                Some(List.rev explicitParameterTypes)
                                        | _ ->
                                            None

                                collectExplicitParameterTypes remainingLayouts remainingTypes positionalArguments []
                                |> Option.bind (fun explicitParameterTypes ->
                                    if List.isEmpty leadingImplicits then
                                        None
                                    elif List.length explicitParameterTypes <> List.length positionalArguments then
                                        None
                                    else
                                        let explicitArgumentTypes =
                                            List.zip explicitParameterTypes positionalArguments
                                            |> List.map (fun (parameterType, argument) ->
                                                inferArgumentTypeForParameter parameterType argument)

                                        if explicitArgumentTypes |> List.exists Option.isNone then
                                            None
                                        else
                                            let explicitArgumentTypes = explicitArgumentTypes |> List.choose id

                                            tryUnifyVisibleTypes
                                                environment.VisibleTypeAliases
                                                (List.zip explicitParameterTypes explicitArgumentTypes)
                                            |> Option.bind (fun initialSubstitution ->
                                                let rec synthesize
                                                    (pendingImplicits: (Parameter * TypeExpr) list)
                                                    (preparedArguments: PreparedCallArgument list)
                                                    (preparedParameters: PreparedCallParameter list)
                                                    =
                                                    match pendingImplicits with
                                                    | [] ->
                                                        Some(List.rev preparedArguments, List.rev preparedParameters)
                                                    | (layout, rawParameterType) :: rest ->
                                                        let parameterType =
                                                            TypeSignatures.applySubstitution initialSubstitution rawParameterType

                                                        match
                                                            trySynthesizeImplicitArgument
                                                                environment
                                                                (tryResolveCurrentLocalImplicit initialSubstitution)
                                                                parameterType
                                                        with
                                                        | Some implicitArgument ->
                                                            synthesize
                                                                rest
                                                                (ImplicitArgument implicitArgument :: preparedArguments)
                                                                ({ Layout = Some layout
                                                                   ParameterType = parameterType
                                                                   AssignedArgument = Some(ImplicitArgument implicitArgument) }
                                                                 :: preparedParameters)
                                                        | None ->
                                                            None

                                                synthesize leadingImplicits [] []
                                                |> Option.map (fun (preparedImplicitArguments, preparedImplicitParameters) ->
                                                    preparedImplicitArguments,
                                                    preparedImplicitParameters,
                                                    initialSubstitution,
                                                    remainingLayouts,
                                                    remainingTypes)))

                        let (initialPreparedArguments: PreparedCallArgument list), (initialPreparedParameters: PreparedCallParameter list), initialSubstitution, (parameterLayoutsToProcess: Parameter list), (parameterTypesToProcess: TypeExpr list) =
                            match tryPrepareLeadingRuntimeImplicits parameterLayouts parameterTypes positionalArguments with
                            | Some(preparedImplicitArguments, preparedImplicitParameters, initialSubstitution, remainingLayouts, remainingTypes) ->
                                preparedImplicitArguments,
                                preparedImplicitParameters,
                                initialSubstitution,
                                remainingLayouts,
                                remainingTypes
                            | None ->
                                [],
                                [],
                                Map.empty,
                                parameterLayouts,
                                parameterTypes

                        let mutable remainingArguments = positionalArguments
                        let mutable substitution = initialSubstitution
                        let preparedArguments = ResizeArray<PreparedCallArgument>(initialPreparedArguments)
                        let preparedParameters = ResizeArray<PreparedCallParameter>(initialPreparedParameters)
                        let remainingParameters = ResizeArray<Parameter * TypeExpr>()
                        let mutable usedNamedFields = Set.empty<string>
                        let mutable success = true
                        let mutable stoppedAtPartialApplication = false

                        let namedFieldCounts =
                            namedFields
                            |> Option.map (fun fields -> fields |> List.countBy (fun field -> field.Name) |> Map.ofList)
                            |> Option.defaultValue Map.empty

                        let tryTakeNamedArgument (parameterLayout: Parameter) =
                            namedFields
                            |> Option.bind (fun fields ->
                                fields
                                |> List.tryFind (fun field -> String.Equals(field.Name, parameterLayout.Name, StringComparison.Ordinal)))
                            |> Option.bind (fun field ->
                                if field.IsImplicit then
                                    None
                                else
                                    usedNamedFields <- Set.add field.Name usedNamedFields
                                    Some field.Value)

                        for parameterLayout, rawParameterType in List.zip parameterLayoutsToProcess parameterTypesToProcess do
                            let parameterType = TypeSignatures.applySubstitution substitution rawParameterType

                            if stoppedAtPartialApplication then
                                remainingParameters.Add(parameterLayout, parameterType)
                            elif parameterLayout.IsImplicit then
                                match remainingArguments with
                                | ExplicitImplicitArgument explicitArgument :: rest ->
                                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        match tryParseTypeLikeSurfaceExpression explicitArgument with
                                        | Some explicitTypeArgument ->
                                            remainingArguments <- rest
                                            substitution <-
                                                composeTypeSubstitution
                                                    substitution
                                                    (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = None }
                                            )
                                        | None ->
                                            success <- false
                                    else
                                        match inferArgumentType explicitArgument with
                                        | Some argumentType ->
                                            match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                            | Some inferredSubstitution ->
                                                preparedArguments.Add(ExplicitArgument explicitArgument)
                                                preparedParameters.Add(
                                                    { Layout = Some parameterLayout
                                                      ParameterType = parameterType
                                                      AssignedArgument = Some(ExplicitArgument explicitArgument) }
                                                )
                                                remainingArguments <- rest
                                                let termSubstitution =
                                                    tryParseTypeLikeSurfaceExpression explicitArgument
                                                    |> Option.map (fun argumentType -> Map.ofList [ parameterLayout.Name, argumentType ])
                                                    |> Option.defaultValue Map.empty

                                                substitution <-
                                                    composeTypeSubstitution
                                                        (composeTypeSubstitution substitution inferredSubstitution)
                                                        termSubstitution
                                            | None ->
                                                success <- false
                                        | None ->
                                            success <- false
                                | _ ->
                                    match
                                        trySynthesizeImplicitArgument
                                            environment
                                            (tryResolveCurrentLocalImplicit substitution)
                                            parameterType
                                    with
                                    | Some implicitArgument ->
                                        preparedArguments.Add(ImplicitArgument implicitArgument)
                                        preparedParameters.Add(
                                            { Layout = Some parameterLayout
                                              ParameterType = parameterType
                                              AssignedArgument = Some(ImplicitArgument implicitArgument) }
                                        )
                                    | None ->
                                        success <- false
                            elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                match remainingArguments with
                                | ExplicitImplicitArgument _ :: _ ->
                                    success <- false
                                | nextArgument :: rest ->
                                    match tryParseTypeLikeSurfaceExpression nextArgument with
                                    | Some explicitTypeArgument ->
                                        remainingArguments <- rest
                                        substitution <-
                                            composeTypeSubstitution
                                                substitution
                                                (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                        preparedParameters.Add(
                                            { Layout = Some parameterLayout
                                              ParameterType = parameterType
                                              AssignedArgument = None }
                                        )
                                    | None ->
                                        success <- false
                                | [] ->
                                    match tryTakeNamedArgument parameterLayout with
                                    | Some namedArgument ->
                                        match tryParseTypeLikeSurfaceExpression namedArgument with
                                        | Some explicitTypeArgument ->
                                            substitution <-
                                                composeTypeSubstitution
                                                    substitution
                                                    (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = None }
                                            )
                                        | None ->
                                            success <- false
                                    | None ->
                                        if namedFields.IsSome && not (hasDefaultArgument parameterLayout) then
                                            success <- false
                                        else
                                            if namedFields.IsSome then
                                                preparedParameters.Add(
                                                    { Layout = Some parameterLayout
                                                      ParameterType = parameterType
                                                      AssignedArgument = None }
                                                )
                                            else
                                                stoppedAtPartialApplication <- true
                                                remainingParameters.Add(parameterLayout, parameterType)
                            else
                                let explicitArgument =
                                    match remainingArguments with
                                    | ExplicitImplicitArgument _ :: _ ->
                                        success <- false
                                        None
                                    | nextArgument :: rest ->
                                        remainingArguments <- rest
                                        Some nextArgument
                                    | [] ->
                                        match tryTakeNamedArgument parameterLayout with
                                        | Some namedArgument ->
                                            Some namedArgument
                                        | None ->
                                            if namedFields.IsSome && not (hasDefaultArgument parameterLayout) then
                                                success <- false
                                                None
                                            else
                                                if namedFields.IsSome then
                                                    preparedParameters.Add(
                                                        { Layout = Some parameterLayout
                                                          ParameterType = parameterType
                                                          AssignedArgument = None }
                                                    )
                                                else
                                                    stoppedAtPartialApplication <- true
                                                    remainingParameters.Add(parameterLayout, parameterType)
                                                None

                                explicitArgument
                                |> Option.iter (fun nextArgument ->
                                    match inferArgumentTypeForParameter parameterType nextArgument with
                                    | Some argumentType ->
                                        match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                        | Some inferredSubstitution ->
                                            preparedArguments.Add(ExplicitArgument nextArgument)
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = Some(ExplicitArgument nextArgument) }
                                            )
                                            let termSubstitution =
                                                tryParseTypeLikeSurfaceExpression nextArgument
                                                |> Option.map (fun argumentType -> Map.ofList [ parameterLayout.Name, argumentType ])
                                                |> Option.defaultValue Map.empty

                                            substitution <-
                                                composeTypeSubstitution
                                                    (composeTypeSubstitution substitution inferredSubstitution)
                                                    termSubstitution
                                        | None ->
                                            success <- false
                                    | None ->
                                        success <- false)

                        let namedFieldsValid =
                            namedFieldCounts
                            |> Map.forall (fun _ count -> count = 1)
                            && (namedFields
                                |> Option.map (fun fields ->
                                    fields
                                    |> List.forall (fun field -> Set.contains field.Name usedNamedFields))
                                |> Option.defaultValue true)

                        if success && namedFieldsValid && List.isEmpty remainingArguments then
                            let instantiatedScheme = TypeSignatures.applySchemeSubstitution substitution instantiated
                            let appliedResultType =
                                let loweredRemainingParameters =
                                    remainingParameters
                                    |> Seq.toList
                                    |> List.map (fun (parameterLayout, parameterType) ->
                                        parameterLayout.Quantity |> Option.defaultValue QuantityOmega,
                                        TypeSignatures.applySubstitution substitution parameterType)

                                let trailingParameters =
                                    trailingParameterTypes
                                    |> List.map (fun parameterType ->
                                        QuantityOmega,
                                        TypeSignatures.applySubstitution substitution parameterType)

                                loweredRemainingParameters @ trailingParameters
                                |> List.rev
                                |> List.fold
                                    (fun current (parameterQuantity, parameterType) ->
                                        TypeArrow(parameterQuantity, parameterType, current))
                                    (TypeSignatures.applySubstitution substitution resultType)

                            Some
                                { InstantiatedScheme = instantiatedScheme
                                  ResultType = appliedResultType
                                  Parameters = List.ofSeq preparedParameters
                                  Arguments = List.ofSeq preparedArguments }
                        else
                            None

    let private bindingHasRuntimeImplicitParameter
        (environment: BindingLoweringEnvironment)
        (bindingInfo: BindingSchemeInfo)
        =
        match bindingInfo.ParameterLayouts with
        | Some layouts ->
            let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

            if List.length layouts = List.length parameterTypes then
                List.zip layouts parameterTypes
                |> List.exists (fun (layout, parameterType) ->
                    layout.IsImplicit
                    && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType))
            else
                layouts |> List.exists (fun layout -> layout.IsImplicit)
        | None ->
            false

    let private bindingHasResolvableLocalRuntimeImplicitParameter
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        (bindingInfo: BindingSchemeInfo)
        =
        match bindingInfo.ParameterLayouts with
        | Some layouts ->
            let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

            if List.length layouts = List.length parameterTypes then
                List.zip layouts parameterTypes
                |> List.exists (fun (layout, parameterType) ->
                    layout.IsImplicit
                    && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                    && (match classifyLocalImplicitByType environment localTypes parameterType with
                        | UniqueLocalImplicitCandidate _ -> true
                        | NoLocalImplicitCandidate
                        | AmbiguousLocalImplicitCandidates -> false))
            else
                false
        | None ->
            false

    let private tryPrepareVisibleTraitMemberCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        memberName
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (arguments: SurfaceExpression list)
        =
        let candidates =
            environment.VisibleTraits
            |> Map.toList
            |> List.choose (fun (_, traitInfo) ->
                traitInfo.Members
                |> Map.tryFind memberName
                |> Option.bind (fun memberInfo ->
                    let candidateCounter = ref freshCounter.Value

                    let overloadedScheme =
                        { memberInfo.Scheme with
                            Constraints =
                                { TraitName = traitInfo.Name
                                  Arguments = traitInfo.TypeParameters |> List.map TypeVariable }
                                :: memberInfo.Scheme.Constraints }

                    let bindingInfo =
                        { ModuleName = traitInfo.ModuleName
                          Name = memberName
                          IsPattern = false
                          Scheme = overloadedScheme
                          TypeTokens = []
                          ParameterLayouts = None
                          ConstructorTypeName = None
                          DefaultArguments = Map.empty }

                    tryPrepareVisibleBindingCall environment candidateCounter bindingInfo None inferArgumentType noLocalImplicit arguments
                    |> Option.bind (fun preparedCall ->
                        match preparedCall.InstantiatedScheme.Constraints with
                        | owningConstraint :: [] when String.Equals(owningConstraint.TraitName, traitInfo.Name, StringComparison.Ordinal) ->
                            resolveConstraintInstance environment owningConstraint
                            |> Option.map (fun instanceInfo ->
                                traitInfo, memberInfo, preparedCall, instanceInfo, candidateCounter.Value)
                        | _ ->
                            None)))

        match candidates with
        | [ traitInfo, memberInfo, preparedCall, instanceInfo, nextFreshValue ] ->
            freshCounter.Value <- nextFreshValue
            Some(traitInfo, memberInfo, preparedCall, instanceInfo)
        | _ ->
            None

    let private tryPrepareResolvedTraitProjectionCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        nameSegments
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (arguments: SurfaceExpression list)
        =
        tryResolveTraitMemberProjection environment localTypes nameSegments
        |> Option.bind (fun (traitInfo, resolvedMemberName, resolvedArguments, _) ->
            traitInfo.Members
            |> Map.tryFind resolvedMemberName
            |> Option.bind (fun memberInfo ->
                let specializedScheme =
                    if List.length traitInfo.TypeParameters = List.length resolvedArguments then
                        List.zip traitInfo.TypeParameters resolvedArguments
                        |> Map.ofList
                        |> fun substitution -> TypeSignatures.applySchemeSubstitution substitution memberInfo.Scheme
                    else
                        memberInfo.Scheme

                let bindingInfo =
                    { ModuleName = traitInfo.ModuleName
                      Name = resolvedMemberName
                      IsPattern = false
                      Scheme = specializedScheme
                      TypeTokens = []
                      ParameterLayouts = None
                      ConstructorTypeName = None
                      DefaultArguments = Map.empty }

                tryPrepareVisibleBindingCall
                    environment
                    freshCounter
                    bindingInfo
                    None
                    inferArgumentType
                    noLocalImplicit
                    arguments))

    let private constructorResultBelongsToType
        (environment: BindingLoweringEnvironment)
        (typeObject: StaticObjectInfo)
        (constructorInfo: BindingSchemeInfo)
        =
        match typeObject.ObjectKind, typeObject.NameSegments with
        | StaticTypeObject, _ ->
            let _, resultType = TypeSignatures.schemeParts constructorInfo.Scheme

            match normalizeTypeAliases environment.VisibleTypeAliases resultType with
            | TypeName(resultName, _) ->
                match List.tryLast resultName, List.tryLast typeObject.NameSegments with
                | Some resultTypeName, Some objectTypeName ->
                    String.Equals(resultTypeName, objectTypeName, StringComparison.Ordinal)
                | _ ->
                    false
            | _ ->
                false
        | _ ->
            false

    let private tryResolveStaticConstructor
        (environment: BindingLoweringEnvironment)
        receiverExpression
        memberName
        =
        tryResolveStaticReceiverObject environment receiverExpression
        |> Option.bind (fun typeObject ->
            let visibleResolution () =
                environment.VisibleConstructors
                |> Map.tryFind memberName
                |> Option.filter (constructorResultBelongsToType environment typeObject)

            match typeObject.ObjectKind, typeObject.TypeFacet with
            | StaticTypeObject, Some typeFacetInfo ->
                environment.SurfaceIndex
                |> Map.tryFind typeFacetInfo.ModuleName
                |> Option.bind (fun moduleSurface ->
                    moduleSurface.Constructors
                    |> Map.tryFind memberName
                    |> Option.filter (constructorResultBelongsToType environment typeObject))
                |> Option.orElseWith visibleResolution
            | _ ->
                visibleResolution ())

    let private tryInferStaticConstructorCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        receiverExpression
        memberName
        arguments
        =
        tryResolveStaticConstructor environment receiverExpression memberName
        |> Option.bind (fun constructorInfo ->
            tryPrepareVisibleBindingCall
                environment
                freshCounter
                constructorInfo
                None
                inferArgumentType
                noLocalImplicit
                arguments
            |> Option.map (fun preparedCall -> preparedCall.ResultType))


    let rec private inferValidationExpressionType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        expression
        =
        let inferExpressionType = inferValidationExpressionType environment freshCounter localTypes
        let normalizeVisibleType typeExpr =
            typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases
        let visibleTypeEquals left right =
            TypeSignatures.definitionallyEqual (normalizeVisibleType left) (normalizeVisibleType right)

        let tryInferMemberAccessType receiver segments arguments =
            match segments with
            | [] ->
                inferExpressionType receiver
                |> Option.bind (fun receiverType ->
                    tryInferVisibleAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        inferExpressionType
                        receiverType
                        arguments)
            | [ memberName ] ->
                (tryResolveHandledEffectDeclaration environment receiver
                 |> Option.bind (fun declaration ->
                     EffectSemantics.tryFindOperation memberName declaration
                     |> Option.bind (fun operation ->
                         operation.SignatureTokens
                         |> TypeSignatures.parseType
                         |> Option.map (qualifyVisibleTypeNames environment)
                         |> Option.bind (fun operationType ->
                             let parameterTypes, resultType = TypeSignatures.functionParts operationType

                             if List.length arguments = List.length parameterTypes then
                                 Some(effType (scopedEffectRowType declaration) resultType)
                             else
                                 tryInferVisibleAppliedType
                                     environment.VisibleTypeAliases
                                     (qualifyVisibleTypeNames environment)
                                     inferExpressionType
                                     operationType
                                     arguments))))
                |> Option.orElseWith (fun () ->
                    tryInferStaticConstructorCall environment freshCounter inferExpressionType receiver memberName arguments)
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind memberName
                    |> Option.bind (fun bindingInfo ->
                        if receiverMethodCallHasRequiredExplicitArguments bindingInfo arguments then
                            tryBuildReceiverMethodArguments bindingInfo receiver arguments
                            |> Option.bind (fun receiverArguments ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    inferExpressionType
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    receiverArguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType))
                        else
                            None))
                |> Option.orElseWith (fun () ->
                    inferExpressionType receiver
                    |> Option.bind (fun receiverType ->
                        tryProjectVisibleRecordType environment.VisibleTypeAliases receiverType [ memberName ]
                        |> Option.bind (fun memberType ->
                            tryInferVisibleAppliedType
                                environment.VisibleTypeAliases
                                (qualifyVisibleTypeNames environment)
                                inferExpressionType
                                memberType
                                arguments)))
            | memberName :: rest ->
                inferExpressionType (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))

        match expression with
        | Literal literal ->
            Some(inferLiteralType literal)
        | NumericLiteral literal ->
            match SurfaceNumericLiteral.suffix literal with
            | Some suffixName ->
                inferValidationExpressionType environment freshCounter localTypes (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
            | None ->
                Some(inferSurfaceNumericLiteralType literal)
        | TypeSyntaxTokens tokens ->
            TypeSignatures.parseType tokens |> Option.map (fun _ -> TypeName([ "Type" ], []))
        | SyntaxQuote inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.map syntaxType
        | SyntaxSplice inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases)
        | TopLevelSyntaxSplice inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases)
        | CodeQuote inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.map codeType
        | CodeSplice inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.bind (function
                | TypeName([ "Code" ], [ innerType ]) -> Some innerType
                | _ -> None)
        | Name [ "True" ]
        | Name [ "False" ] ->
            Some boolType
        | KindQualifiedName _ ->
            tryResolveScopedStaticObject environment expression
            |> Option.bind (fun staticObject -> staticObject.Scheme)
            |> Option.map (fun scheme -> scheme.Body)
        | Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
            Some(TypeIntrinsic EffLabelClassifier)
        | Name(root :: path) ->
            let scopedEffectOperationType =
                match path with
                | [ operationName ] ->
                    tryFindScopedEffectOperation root operationName
                    |> Option.bind (fun (_, operation) ->
                        operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment))
                | _ ->
                    None

            let resolvedEffectOperationType =
                tryResolveEffectOperationNamePath environment (root :: path)
                |> Option.bind (fun (_, _, operation) ->
                    operation.SignatureTokens
                    |> TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment))

            let ordinaryResolution =
                localTypes
                |> Map.tryFind root
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind root
                    |> Option.bind (fun bindingInfo ->
                        if bindingHasResolvableLocalRuntimeImplicitParameter environment localTypes bindingInfo then
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localTypes)
                                (inferValidationExpressionType environment freshCounter localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                []
                            |> Option.map (fun preparedCall -> preparedCall.ResultType)
                            |> Option.orElseWith (fun () -> instantiateVisibleBindingBodyType environment freshCounter root)
                        else
                            instantiateVisibleBindingBodyType environment freshCounter root))
                |> Option.orElseWith (fun () ->
                    environment.VisibleConstructors
                    |> Map.tryFind root
                    |> Option.bind (fun _ -> instantiateVisibleConstructorBodyType environment freshCounter root))
                |> Option.orElseWith (fun () ->
                    tryResolveScopedStaticObject environment (Name [ root ])
                    |> Option.bind (fun staticObject ->
                        if List.isEmpty path then
                            staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                        else
                            None))
                |> Option.bind (fun rootType -> tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)

            let receiverBindingResolution memberName =
                environment.VisibleBindings
                |> Map.tryFind memberName
                |> Option.bind (fun bindingInfo ->
                    tryBuildReceiverMethodArguments bindingInfo (Name [ root ]) []
                    |> Option.bind (fun receiverArguments ->
                        tryPrepareVisibleBindingCall
                            environment
                            freshCounter
                            bindingInfo
                            (Some localTypes)
                            (inferValidationExpressionType environment freshCounter localTypes)
                            (tryResolveUniqueLocalImplicitByType environment localTypes)
                            receiverArguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                |> Option.orElseWith (fun () ->
                    tryPrepareResolvedTraitProjectionCall
                        environment
                        freshCounter
                        localTypes
                        [ root; memberName ]
                        (inferValidationExpressionType environment freshCounter localTypes)
                        []
                    |> Option.map (fun preparedCall -> preparedCall.ResultType))
                |> Option.orElseWith (fun () ->
                    tryPrepareVisibleTraitMemberCall
                        environment
                        freshCounter
                        memberName
                        (inferValidationExpressionType environment freshCounter localTypes)
                        [ Name [ root ] ]
                    |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))

            match path with
            | [ memberName ] ->
                scopedEffectOperationType
                |> Option.orElse resolvedEffectOperationType
                |> Option.orElseWith (fun () -> receiverBindingResolution memberName)
                |> Option.orElseWith (fun () ->
                    tryInferStaticConstructorCall
                        environment
                        freshCounter
                        (inferValidationExpressionType environment freshCounter localTypes)
                        (Name [ root ])
                        memberName
                        [])
                |> Option.orElse ordinaryResolution
            | _ ->
                resolvedEffectOperationType
                |> Option.orElse ordinaryResolution
        | Name [] ->
            None
        | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
            match
                tryResolveHandledEffectDeclaration environment receiver
                |> Option.bind (fun declaration ->
                    EffectSemantics.tryFindOperation memberName declaration
                    |> Option.bind (fun operation ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.map TypeSignatures.functionParts
                        |> Option.map (fun (parameterTypes, resultType) -> declaration, parameterTypes, resultType)))
            with
            | Some(declaration, parameterTypes, resultType) when List.length parameterTypes = List.length arguments ->
                Some(effType (scopedEffectRowType declaration) resultType)
            | _ ->
                match tryInferQueryCarrierType environment freshCounter localTypes (inferValidationExpressionType environment freshCounter) expression with
                | Some queryCarrierType ->
                    Some queryCarrierType
                | None ->
                    inferValidationApplicationType environment freshCounter localTypes expression
        | Apply(Name nameSegments, arguments) ->
            match
                tryResolveEffectOperationNamePath environment nameSegments
                |> Option.bind (fun (_, declaration, operation) ->
                    operation.SignatureTokens
                    |> TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.map (fun signature -> declaration, TypeSignatures.functionParts signature))
            with
            | Some(declaration, (parameterTypes, resultType)) when List.length parameterTypes = List.length arguments ->
                Some(effType (scopedEffectRowType declaration) resultType)
            | _ ->
                match tryInferQueryCarrierType environment freshCounter localTypes (inferValidationExpressionType environment freshCounter) expression with
                | Some queryCarrierType ->
                    Some queryCarrierType
                | None ->
                    inferValidationApplicationType environment freshCounter localTypes expression
        | LocalSignature(_, body) ->
            inferValidationExpressionType environment freshCounter localTypes body
        | LocalTypeAlias _ ->
            inferValidationExpressionType
                environment
                freshCounter
                localTypes
                (rewriteLocalTypeAliasesInSurfaceExpression environment.CurrentModuleName environment.VisibleTypeAliases expression)
        | LocalLet(binding, value, body) ->
            let bindingNames = collectPatternNames binding.Pattern

            let nextLocals =
                match inferValidationExpressionType environment freshCounter localTypes value with
                | Some valueType ->
                    extendBindingLocalTypes environment freshCounter localTypes binding (Some valueType)
                | None ->
                    extendBindingLocalTypes
                        environment
                        freshCounter
                        localTypes
                        binding
                        (Some(inferFallbackLocalType freshCounter value))

            let bodyForInference =
                match bindingNames, tryResolveScopedStaticObject environment value with
                | [ aliasName ], Some staticObject ->
                    rewriteStaticObjectAliasUse aliasName staticObject body
                | _ ->
                    body

            inferValidationExpressionType environment freshCounter nextLocals bodyForInference
        | LocalScopedEffect(declaration, body) ->
            withScopedEffectDeclaration declaration (fun () ->
                inferValidationExpressionType environment freshCounter localTypes body)
        | Handle(_, label, body, returnClause, _) ->
            let handledResultType =
                match
                    tryResolveHandledEffectDeclaration environment label,
                    inferValidationExpressionType environment freshCounter localTypes body |> Option.bind tryUnwrapEffType
                with
                | Some declaration, Some(effectRow, payloadType) ->
                    match trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow with
                    | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                    | _ -> None
                | _ ->
                    None

            handledResultType
            |> Option.orElseWith (fun () ->
                inferValidationExpressionType environment freshCounter localTypes returnClause.Body)
        | Lambda(parameters, body) ->
            let parameterTypes =
                parameters
                |> List.map (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

            let parameterQuantities =
                parameters
                |> List.map (fun parameter -> parameter.Quantity |> Option.defaultValue QuantityOmega)

            let lambdaLocals =
                List.zip parameters parameterTypes
                |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) localTypes

            inferValidationExpressionType environment freshCounter lambdaLocals body
            |> Option.map (fun resultType ->
                List.zip parameterTypes parameterQuantities
                |> List.rev
                |> List.fold (fun state (parameterType, quantity) -> TypeArrow(quantity, parameterType, state)) resultType)
        | IfThenElse(_, whenTrue, whenFalse) ->
            match
                inferValidationExpressionType environment freshCounter localTypes whenTrue,
                inferValidationExpressionType environment freshCounter localTypes whenFalse
            with
            | Some trueType, Some falseType when trueType = falseType ->
                Some trueType
            | _ ->
                None
        | Match(scrutinee, cases) ->
            let scrutineeType =
                inferValidationExpressionType environment freshCounter localTypes scrutinee

            cases
            |> List.choose (fun caseClause ->
                let caseLocals =
                    extendPatternLocalTypes environment freshCounter localTypes scrutineeType caseClause.Pattern

                inferValidationExpressionType environment freshCounter caseLocals caseClause.Body)
            |> function
                | first :: rest when rest |> List.forall ((=) first) -> Some first
                | _ -> None
        | RecordLiteral fields ->
            let inferredFields =
                fields
                |> List.map (fun field ->
                    inferValidationExpressionType environment freshCounter localTypes field.Value
                    |> Option.map (fun fieldType ->
                        ({ Name = field.Name
                           Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                           Type = fieldType }: TypeSignatures.RecordField)))

            if inferredFields |> List.forall Option.isSome then
                inferredFields
                |> List.choose id
                |> TypeRecord
                |> Some
            else
                None
        | Seal(value, _) ->
            inferValidationExpressionType environment freshCounter localTypes value
        | RecordUpdate(receiver, _) ->
            inferValidationExpressionType environment freshCounter localTypes receiver
        | MemberAccess(receiver, segments, arguments) ->
            tryInferMemberAccessType receiver segments arguments
        | SafeNavigation(receiver, navigation) ->
            inferValidationExpressionType environment freshCounter localTypes receiver
            |> Option.bind (fun receiverType ->
                tryOptionPayloadType environment.VisibleTypeAliases receiverType
                |> Option.bind (fun payloadType ->
                    tryInferSafeNavigationMemberType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferValidationExpressionType environment freshCounter localTypes)
                        payloadType
                        navigation
                    |> Option.map (fun memberType ->
                        match tryOptionPayloadType environment.VisibleTypeAliases memberType with
                        | Some _ -> memberType
                        | None -> TypeName([ "Option" ], [ memberType ]))))
        | TagTest _ ->
            Some boolType
        | Do statements ->
            inferValidationDoResultType environment freshCounter localTypes statements
        | MonadicSplice inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
            |> Option.map unwrapIoType
        | ExplicitImplicitArgument inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
        | NamedApplicationBlock _ ->
            None
        | InoutArgument inner ->
            inferValidationExpressionType environment freshCounter localTypes inner
        | Apply _ as application ->
            inferValidationApplicationType environment freshCounter localTypes application
        | Unary("not", _) ->
            Some boolType
        | Unary("negate", operand) ->
            inferValidationExpressionType environment freshCounter localTypes operand
        | Unary _ ->
            None
        | Binary(left, ("+" | "-" | "*" | "/"), right) ->
            match
                inferValidationExpressionType environment freshCounter localTypes left,
                inferValidationExpressionType environment freshCounter localTypes right
            with
            | Some leftType, Some rightType when visibleTypeEquals leftType intType && visibleTypeEquals rightType intType ->
                Some intType
            | Some leftType, Some rightType when visibleTypeEquals leftType floatType && visibleTypeEquals rightType floatType ->
                Some floatType
            | _ ->
                None
        | Binary(_, ("==" | "!=" | "<" | ">" | "<=" | ">=" | "&&" | "||"), _) ->
            Some boolType
        | Binary(left, operatorName, right) ->
            inferValidationExpressionType environment freshCounter localTypes (Apply(Name [ operatorName ], [ left; right ]))
        | Elvis(left, right) ->
            match
                inferValidationExpressionType environment freshCounter localTypes left,
                inferValidationExpressionType environment freshCounter localTypes right
            with
            | Some leftType, Some defaultType ->
                tryOptionPayloadType environment.VisibleTypeAliases leftType
                |> Option.bind (fun payloadType ->
                    tryUnifyVisibleTypes environment.VisibleTypeAliases [ payloadType, defaultType ]
                    |> Option.map (fun substitution -> TypeSignatures.applySubstitution substitution payloadType)
                    |> Option.orElseWith (fun () ->
                        if
                            TypeSignatures.definitionallyEqual
                                (normalizeTypeAliases environment.VisibleTypeAliases payloadType)
                                (normalizeTypeAliases environment.VisibleTypeAliases defaultType)
                        then
                            Some payloadType
                        else
                            None))
            | _ ->
                None
        | Comprehension comprehension ->
            inferValidationExpressionType environment freshCounter localTypes comprehension.Lowered
        | PrefixedString(prefix, _) ->
            tryInferPrefixedStringMacroResultType environment freshCounter localTypes prefix

    and private inferValidationApplicationType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        application
        =
        tryInferQueryCarrierType
            environment
            freshCounter
            localTypes
            (fun currentLocals currentExpression ->
                inferValidationExpressionType environment freshCounter currentLocals currentExpression)
            application
        |> Option.orElseWith (fun () ->
            match application with
            | Apply(Name [ receiverName; memberName ], arguments) ->
                tryInferStaticConstructorCall
                    environment
                    freshCounter
                    (inferValidationExpressionType environment freshCounter localTypes)
                    (Name [ receiverName ])
                    memberName
                    arguments
                |> Option.orElseWith (fun () ->
                    tryPrepareResolvedTraitProjectionCall
                        environment
                        freshCounter
                        localTypes
                        [ receiverName; memberName ]
                        (inferValidationExpressionType environment freshCounter localTypes)
                        arguments
                    |> Option.map (fun preparedCall -> preparedCall.ResultType))
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind memberName
                    |> Option.bind (fun bindingInfo ->
                        tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments
                        |> Option.bind (fun receiverArguments ->
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localTypes)
                                (inferValidationExpressionType environment freshCounter localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                receiverArguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType))))
            | Apply(Name [ calleeName ], arguments) ->
                localTypes
                |> Map.tryFind calleeName
                |> Option.bind (fun localType ->
                    tryInferVisibleAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferValidationExpressionType environment freshCounter localTypes)
                        localType
                        arguments)
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind calleeName
                    |> Option.bind (fun bindingInfo ->
                        let preparedResultType =
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localTypes)
                                (inferValidationExpressionType environment freshCounter localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                arguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType)

                        preparedResultType
                        |> Option.orElseWith (fun () ->
                            instantiateVisibleBindingBodyType environment freshCounter calleeName
                            |> Option.bind (fun bodyType ->
                                tryInferVisibleAppliedType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferValidationExpressionType environment freshCounter localTypes)
                                    bodyType
                                    arguments))))
                |> Option.orElseWith (fun () ->
                    environment.VisibleConstructors
                    |> Map.tryFind calleeName
                    |> Option.bind (fun constructorInfo ->
                        tryPrepareVisibleBindingCall
                            environment
                            freshCounter
                            constructorInfo
                            (Some localTypes)
                            (inferValidationExpressionType environment freshCounter localTypes)
                            (tryResolveUniqueLocalImplicitByType environment localTypes)
                            arguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                |> Option.orElseWith (fun () ->
                    tryPrepareVisibleTraitMemberCall
                        environment
                        freshCounter
                        calleeName
                        (inferValidationExpressionType environment freshCounter localTypes)
                        arguments
                    |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))
            | _ ->
                None)

    and private inferValidationDoResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        statements
        =
        let tryMergeBranchResultTypes leftType rightType =
            tryUnifyVisibleTypes environment.VisibleTypeAliases [ leftType, rightType ]
            |> Option.map (fun substitution -> TypeSignatures.applySubstitution substitution leftType)
            |> Option.orElseWith (fun () ->
                if
                    TypeSignatures.definitionallyEqual
                        (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                        (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                then
                    Some leftType
                else
                    None)

        match statements with
        | [] ->
            Some unitType
        | DoExpression expression :: [] ->
            inferValidationExpressionType environment freshCounter localTypes expression
        | DoExpression _ :: rest ->
            inferValidationDoResultType environment freshCounter localTypes rest
        | DoLet(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionType environment freshCounter localTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultType environment freshCounter nextLocals rest
        | DoLetQuestion(binding, expression, failure) :: rest ->
            let nextLocals =
                inferValidationExpressionType environment freshCounter localTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                |> Option.defaultValue localTypes

            failure
            |> Option.iter (fun failure ->
                inferValidationDoResultType environment freshCounter localTypes failure.Body |> ignore)

            inferValidationDoResultType environment freshCounter nextLocals rest
        | DoBind(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionType environment freshCounter localTypes expression
                |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases)
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes
                        environment
                        freshCounter
                        localTypes
                        (Some valueType)
                        binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultType environment freshCounter nextLocals rest
        | DoUsing(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionType environment freshCounter localTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes
                        environment
                        freshCounter
                        localTypes
                        (Some(unwrapIoType valueType))
                        binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultType environment freshCounter nextLocals rest
        | DoVar(bindingName, expression) :: rest ->
            let nextLocals =
                match inferValidationExpressionType environment freshCounter localTypes expression with
                | Some valueType -> Map.add bindingName (refType valueType) localTypes
                | None -> localTypes

            inferValidationDoResultType environment freshCounter nextLocals rest
        | DoAssign _ :: rest ->
            inferValidationDoResultType environment freshCounter localTypes rest
        | DoDefer _ :: rest ->
            inferValidationDoResultType environment freshCounter localTypes rest
        | DoIf(_, whenTrue, whenFalse) :: [] ->
            match
                inferValidationDoResultType environment freshCounter localTypes whenTrue,
                inferValidationDoResultType environment freshCounter localTypes whenFalse
            with
            | Some whenTrueType, Some whenFalseType ->
                tryMergeBranchResultTypes whenTrueType whenFalseType
            | _ ->
                None
        | DoIf(_, _, _) :: rest ->
            inferValidationDoResultType environment freshCounter localTypes rest
        | DoWhile _ :: rest ->
            inferValidationDoResultType environment freshCounter localTypes rest
        | DoReturn expression :: _ ->
            inferValidationExpressionType environment freshCounter localTypes expression

    let private tryResolveTopLevelManifestStaticFieldFromFunctionResult
        (environment: BindingLoweringEnvironment)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        calleeName
        (arguments: SurfaceExpression list)
        fieldName
        =
        let rec tryResolveStaticValue parameterStaticObjects expression =
            match expression with
            | Name [ name ] ->
                parameterStaticObjects
                |> Map.tryFind name
                |> Option.orElseWith (fun () -> tryResolveScopedStaticObject environment expression)
            | Seal(inner, _) ->
                tryResolveStaticValue parameterStaticObjects inner
            | _ ->
                tryResolveScopedStaticObject environment expression

        let rec tryResolveField parameterStaticObjects expression =
            match expression with
            | RecordLiteral fields ->
                fields
                |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                |> Option.bind (fun field -> tryResolveStaticValue parameterStaticObjects field.Value)
            | Seal(inner, _) ->
                tryResolveField parameterStaticObjects inner
            | _ ->
                None

        topLevelDefinitionsByName
        |> Map.tryFind calleeName
        |> Option.bind (fun calleeDefinition ->
            if List.length calleeDefinition.Parameters <> List.length arguments then
                None
            else
                let parameterStaticObjects =
                    List.zip calleeDefinition.Parameters arguments
                    |> List.choose (fun (parameter, argument) ->
                        tryResolveScopedStaticObject environment argument
                        |> Option.map (fun staticObject -> parameter.Name, staticObject))
                    |> Map.ofList

                calleeDefinition.Body
                |> Option.bind (tryResolveField parameterStaticObjects))

    let private rewriteTopLevelManifestStaticFieldUses
        (environment: BindingLoweringEnvironment)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        expression
        =
        let rec rewrite current =
            match current with
            | MemberAccess(Apply(Name [ calleeName ], callArguments), [ fieldName ], [])
                when topLevelDefinitionsByName.ContainsKey(calleeName) ->
                match
                    tryResolveTopLevelManifestStaticFieldFromFunctionResult
                        environment
                        topLevelDefinitionsByName
                        calleeName
                        callArguments
                        fieldName
                with
                | Some staticObject ->
                    Name staticObject.NameSegments
                | None ->
                    MemberAccess(
                        Apply(Name [ calleeName ], callArguments |> List.map rewrite),
                        [ fieldName ],
                        []
                    )
            | LocalLet(binding, value, body) ->
                LocalLet(binding, rewrite value, rewrite body)
            | LocalSignature(signature, body) ->
                LocalSignature(signature, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    { returnClause with Body = rewrite returnClause.Body },
                    operationClauses
                    |> List.map (fun clause ->
                        { clause with
                            Body = rewrite clause.Body })
                )
            | Lambda(parameters, body) ->
                Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewrite receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map rewrite }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteDoStatement statement =
                    match statement with
                    | DoLet(binding, inner) -> DoLet(binding, rewrite inner)
                    | DoLetQuestion(binding, inner, failure) ->
                        let rewrittenFailure =
                            failure
                            |> Option.map (fun block ->
                                { block with
                                    Body = block.Body |> List.map rewriteDoStatement })

                        DoLetQuestion(binding, rewrite inner, rewrittenFailure)
                    | DoBind(binding, inner) -> DoBind(binding, rewrite inner)
                    | DoVar(name, inner) -> DoVar(name, rewrite inner)
                    | DoAssign(name, inner) -> DoAssign(name, rewrite inner)
                    | DoUsing(binding, inner) -> DoUsing(binding, rewrite inner)
                    | DoDefer inner -> DoDefer(rewrite inner)
                    | DoIf(condition, whenTrue, whenFalse) ->
                        DoIf(rewrite condition, whenTrue |> List.map rewriteDoStatement, whenFalse |> List.map rewriteDoStatement)
                    | DoWhile(condition, body) ->
                        DoWhile(rewrite condition, body |> List.map rewriteDoStatement)
                    | DoReturn inner -> DoReturn(rewrite inner)
                    | DoExpression inner -> DoExpression(rewrite inner)

                Do(statements |> List.map rewriteDoStatement)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | TypeSyntaxTokens _
            | Name _ ->
                current

        rewrite expression

    let private tryRewriteLegacyRecordDestructuringParametersForBinding
        (visibleTypeAliases: Map<string, TypeAliasInfo>)
        (bindingScheme: TypeScheme)
        (parameters: Parameter list)
        (body: SurfaceExpression option)
        =
        let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

        match parameterTypes, parameters, body with
        | [ recordType ], firstParameter :: remainingParameters, Some body ->
            match normalizeTypeAliases visibleTypeAliases recordType with
            | TypeRecord fields when not (List.isEmpty fields) ->
                let parameterCountMatches = List.length fields = List.length parameters
                let collapsedLegacyRecordParameter = List.length parameters = 1 && List.length fields > 1

                let trailingParametersMatchFieldTypes =
                    if parameterCountMatches then
                        remainingParameters
                        |> List.zip (fields |> List.skip 1)
                        |> List.forall (fun (field, parameter) ->
                            String.Equals(parameter.Name, field.Name, StringComparison.Ordinal)
                            && (parameter.TypeTokens
                                |> Option.bind TypeSignatures.parseType
                                |> Option.map (fun parameterType ->
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases visibleTypeAliases parameterType)
                                        (normalizeTypeAliases visibleTypeAliases field.Type))
                                |> Option.defaultValue false))
                    else
                        false

                let firstParameterMatchesFirstField =
                    String.Equals(firstParameter.Name, fields.Head.Name, StringComparison.Ordinal)

                if not firstParameterMatchesFirstField
                   || not (collapsedLegacyRecordParameter || (parameterCountMatches && trailingParametersMatchFieldTypes)) then
                    None
                else
                    let syntheticParameterName = "__kappa_record_param_0"
                    let recordTypeText = TypeSignatures.toText recordType

                    let syntheticParameter =
                        { Name = syntheticParameterName
                          TypeTokens = Some(typeTextTokens recordTypeText)
                          Quantity = None
                          IsImplicit = false
                          IsInout = false
                          IsReceiver = false }

                    let destructuringBinding =
                        { Pattern =
                            AnonymousRecordPattern(
                                fields
                                |> List.map (fun field ->
                                    { Name = field.Name
                                      IsImplicit = false
                                      Pattern = NamePattern field.Name }),
                                None
                            )
                          Quantity = None
                          IsImplicit = false
                          TypeTokens = Some(typeTextTokens recordTypeText)
                          BinderSpans = Map.empty }

                    Some([ syntheticParameter ], Some(LocalLet(destructuringBinding, Name [ syntheticParameterName ], body)))
            | _ ->
                None
        | _ ->
            None

    let private validateBuiltInExpressionsForBinding
        (environment: BindingLoweringEnvironment)
        (knownSurfaceTermNames: Set<string>)
        (allowUnresolvedCallDiagnostics: bool)
        (explicitSignatureNames: Set<string>)
        (sourceSignatureScheme: TypeScheme option)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        (definition: LetDefinition)
        (scheme: TypeScheme option)
        =
        let freshCounter = ref 0
        let effectiveScheme = sourceSignatureScheme |> Option.orElse scheme
        let rewrittenDefinitionBody =
            definition.Body
            |> Option.map (rewriteTopLevelManifestStaticFieldUses environment topLevelDefinitionsByName)

        let effectiveParameters, effectiveBody =
            match definition.Parameters, rewrittenDefinitionBody, effectiveScheme with
            | parameters, body, Some bindingScheme ->
                match
                    tryRewriteLegacyRecordDestructuringParametersForBinding
                        environment.VisibleTypeAliases
                        bindingScheme
                        parameters
                        body
                with
                | Some rewritten ->
                    rewritten
                | None ->
                    parameters, body
            | parameters, body, None ->
                parameters, body

        let tupleParameterLocalTypes =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.map significantTokens
                |> Option.map splitTopLevelCommaGroups
                |> Option.map (fun groups ->
                    groups
                    |> List.skip 1
                    |> List.choose (fun group ->
                        match significantTokens group with
                        | nameToken :: colonToken :: typeTokens
                            when Token.isName nameToken && colonToken.Kind = Colon ->
                            typeTokens
                            |> TypeSignatures.parseType
                            |> Option.map (fun fieldType -> SyntaxFacts.trimIdentifierQuotes nameToken.Text, fieldType)
                        | _ ->
                            None))
                |> Option.defaultValue [])

        let recordParameterLocalTypes =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryParseRecordSurfaceInfo
                |> Option.map (fun recordInfo ->
                    recordInfo.Fields
                    |> List.choose (fun field ->
                        field.TypeTokens
                        |> TypeSignatures.parseType
                        |> Option.map (fun fieldType -> field.Name, fieldType)))
                |> Option.defaultValue [])

        let declaredParameterLocalTypes = buildLocalTypes effectiveScheme effectiveParameters

        let bodyInferredNumericParameterTypes =
            let parameterNames =
                effectiveParameters
                |> List.map (fun parameter -> parameter.Name)
                |> Set.ofList

            let annotatedParameterLocals =
                effectiveParameters
                |> List.choose (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (fun parameterType -> parameter.Name, parameterType))
                |> Map.ofList

            let normalize typeExpr =
                normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            let isSupportedArithmeticType normalizedTypeExpr =
                match normalizedTypeExpr with
                | TypeName(([ "Int" ] | [ "std"; "prelude"; "Int" ]), [])
                | TypeName(([ "Float" ] | [ "std"; "prelude"; "Float" ]), [])
                | TypeName(([ "Double" ] | [ "std"; "prelude"; "Double" ]), []) ->
                    true
                | _ ->
                    false

            let tryInferNumericOperandType expression =
                match expression with
                | NumericLiteral literal ->
                    Some(inferSurfaceNumericLiteralType literal)
                | Unary("-", NumericLiteral literal) ->
                    Some(inferSurfaceNumericLiteralType literal)
                | _ ->
                    inferValidationExpressionType environment freshCounter annotatedParameterLocals expression
                    |> Option.map normalize
                    |> Option.filter isSupportedArithmeticType

            let addExpectation parameterName inferredType expectations =
                match Map.tryFind parameterName expectations with
                | Some existingType
                    when TypeSignatures.definitionallyEqual
                             (normalize existingType)
                             (normalize inferredType) ->
                    expectations
                | Some _ ->
                    expectations
                | None ->
                    Map.add parameterName inferredType expectations

            let rec walk expectations expression =
                let addFromOperand parameterExpression counterpart currentExpectations =
                    match parameterExpression with
                    | Name [ parameterName ]
                        when Set.contains parameterName parameterNames ->
                        match tryInferNumericOperandType counterpart with
                        | Some inferredType ->
                            addExpectation parameterName inferredType currentExpectations
                        | None ->
                            currentExpectations
                    | _ ->
                        currentExpectations

                let descend currentExpression currentExpectations =
                    walk currentExpectations currentExpression

                match expression with
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    expectations
                    |> addFromOperand left right
                    |> addFromOperand right left
                    |> descend left
                    |> descend right
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    expectations |> descend left |> descend right
                | Apply(callee, arguments) ->
                    (descend callee expectations, arguments)
                    ||> List.fold (fun state argument -> descend argument state)
                | LocalLet(_, value, nestedBody) ->
                    expectations |> descend value |> descend nestedBody
                | LocalSignature(_, nestedBody)
                | LocalTypeAlias(_, nestedBody)
                | LocalScopedEffect(_, nestedBody)
                | Lambda(_, nestedBody)
                | SyntaxQuote nestedBody
                | SyntaxSplice nestedBody
                | TopLevelSyntaxSplice nestedBody
                | CodeQuote nestedBody
                | CodeSplice nestedBody
                | MonadicSplice nestedBody
                | ExplicitImplicitArgument nestedBody
                | InoutArgument nestedBody
                | Unary(_, nestedBody)
                | Seal(nestedBody, _)
                | TagTest(nestedBody, _) ->
                    descend nestedBody expectations
                | TypeSyntaxTokens _ ->
                    expectations
                | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                    expectations
                    |> descend label
                    |> descend nestedBody
                    |> descend returnClause.Body
                    |> fun state ->
                        operationClauses
                        |> List.fold (fun clauseState clause -> descend clause.Body clauseState) state
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    expectations
                    |> descend condition
                    |> descend whenTrue
                    |> descend whenFalse
                | Match(scrutinee, cases) ->
                    expectations
                    |> descend scrutinee
                    |> fun state ->
                        cases
                        |> List.fold
                            (fun caseState caseClause ->
                                caseState
                                |> fun innerState ->
                                    match caseClause.Guard with
                                    | Some guard -> descend guard innerState
                                    | None -> innerState
                                |> descend caseClause.Body)
                            state
                | RecordLiteral fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | RecordUpdate(receiver, fields) ->
                    expectations
                    |> descend receiver
                    |> fun state -> fields |> List.fold (fun innerState field -> descend field.Value innerState) state
                | MemberAccess(receiver, _, arguments) ->
                    expectations
                    |> descend receiver
                    |> fun state -> arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | SafeNavigation(receiver, navigation) ->
                    expectations
                    |> descend receiver
                    |> fun state -> navigation.Arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | Do statements ->
                    statements
                    |> List.fold
                        (fun state statement ->
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                descend value state
                            | DoLetQuestion(_, value, failure) ->
                                let nextState = descend value state

                                match failure with
                                | Some block ->
                                    block.Body
                                    |> List.fold
                                        (fun innerState nestedStatement ->
                                            match nestedStatement with
                                            | DoLet(_, nestedValue)
                                            | DoBind(_, nestedValue)
                                            | DoUsing(_, nestedValue)
                                            | DoVar(_, nestedValue)
                                            | DoAssign(_, nestedValue)
                                            | DoDefer nestedValue
                                            | DoExpression nestedValue
                                            | DoReturn nestedValue ->
                                                descend nestedValue innerState
                                            | DoIf(condition, whenTrue, whenFalse) ->
                                                let afterCondition = descend condition innerState

                                                let descendDoBody bodyStatements bodyState =
                                                    bodyStatements
                                                    |> List.fold
                                                        (fun bodyInnerState bodyStatement ->
                                                            match bodyStatement with
                                                            | DoLet(_, bodyValue)
                                                            | DoBind(_, bodyValue)
                                                            | DoUsing(_, bodyValue)
                                                            | DoVar(_, bodyValue)
                                                            | DoAssign(_, bodyValue)
                                                            | DoDefer bodyValue
                                                            | DoExpression bodyValue
                                                            | DoReturn bodyValue ->
                                                                descend bodyValue bodyInnerState
                                                            | _ ->
                                                                bodyInnerState)
                                                        bodyState

                                                afterCondition |> descendDoBody whenTrue |> descendDoBody whenFalse
                                            | _ ->
                                                innerState)
                                        nextState
                                | None ->
                                    nextState
                            | DoIf(condition, whenTrue, whenFalse) ->
                                let nextState = descend condition state

                                let descendDoBody bodyStatements bodyState =
                                    bodyStatements
                                    |> List.fold
                                        (fun innerState nestedStatement ->
                                            match nestedStatement with
                                            | DoLet(_, nestedValue)
                                            | DoBind(_, nestedValue)
                                            | DoUsing(_, nestedValue)
                                            | DoVar(_, nestedValue)
                                            | DoAssign(_, nestedValue)
                                            | DoDefer nestedValue
                                            | DoExpression nestedValue
                                            | DoReturn nestedValue ->
                                                descend nestedValue innerState
                                            | _ ->
                                                innerState)
                                        bodyState

                                nextState |> descendDoBody whenTrue |> descendDoBody whenFalse
                            | DoWhile(condition, doBody) ->
                                let nextState = descend condition state

                                doBody
                                |> List.fold
                                    (fun innerState nestedStatement ->
                                        match nestedStatement with
                                        | DoLet(_, nestedValue)
                                        | DoBind(_, nestedValue)
                                        | DoUsing(_, nestedValue)
                                        | DoVar(_, nestedValue)
                                        | DoAssign(_, nestedValue)
                                        | DoDefer nestedValue
                                        | DoExpression nestedValue
                                        | DoReturn nestedValue ->
                                            descend nestedValue innerState
                                        | _ ->
                                            innerState)
                                    nextState)
                        expectations
                | Comprehension comprehension ->
                    descend comprehension.Lowered expectations
                | PrefixedString(_, parts) ->
                    parts
                    |> List.fold
                        (fun state part ->
                            match part with
                            | StringText _ -> state
                            | StringInterpolation(inner, _) -> descend inner state)
                        expectations
                | NamedApplicationBlock fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    expectations

            effectiveBody
            |> Option.map (walk Map.empty)
            |> Option.defaultValue Map.empty

        let inferredParameterLocalTypes =
            bodyInferredNumericParameterTypes
            |> Map.toList
            |> List.filter (fun (name, _) -> not (Map.containsKey name declaredParameterLocalTypes))

        let localTypes =
            (inferredParameterLocalTypes @ tupleParameterLocalTypes @ recordParameterLocalTypes)
            |> List.fold (fun state (name, fieldType) -> Map.add name fieldType state) declaredParameterLocalTypes

        let parameterNames =
            [ effectiveParameters |> List.map (fun parameter -> parameter.Name)
              inferredParameterLocalTypes |> List.map fst
              tupleParameterLocalTypes |> List.map fst
              recordParameterLocalTypes |> List.map fst ]
            |> List.concat
            |> Set.ofList

        let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()
        let standardRuntimeNames =
            Set.ofList
                [ "bindModule"; "bindModuleOwned"; "bridgePackageValue"; "bridgePackageOrigin"; "bridgeFailureToCastBlame"
                  "checkedCast"; "checkedCastWith"; "sameDynRep"; "toDyn"; "toDynWith"
                  "Conservative"; "Exact"; "IntoKappa"; "LaterUse"; "Lossy"; "OutOfKappa" ]

        let compilerKnownSurfaceTerms =
            Set.ofList
                [ "thunk"
                  "lazy"
                  "force"
                  "captureBorrow"
                  "withBorrowView"
                  "break"
                  "continue"
                  "fork"
                  "defEqSyntax"
                  "headSymbolSyntax"
                  "sameSymbol" ]

        let visibleTraitMemberNames =
            environment.VisibleTraits
            |> Map.values
            |> Seq.collect (fun traitInfo -> traitInfo.Members.Keys)
            |> Set.ofSeq

        let knownValueNames =
            [ preludeContract.TermNames
              Set.ofList Stdlib.FixedPreludeConstructors
              IntrinsicCatalog.namedIntrinsicTermNames ()
              standardRuntimeNames
              compilerKnownSurfaceTerms
              environment.VisibleBindings |> Map.keys |> Set.ofSeq
              environment.VisibleConstructors |> Map.keys |> Set.ofSeq
              visibleTraitMemberNames
              environment.ConstrainedMembers |> Map.keys |> Set.ofSeq ]
            |> Set.unionMany
            |> Set.remove "<anonymous>"

        let knownTermLikeNames =
            [ knownSurfaceTermNames
              knownValueNames
              topLevelDefinitionsByName |> Map.keys |> Set.ofSeq
              explicitSignatureNames
              environment.VisibleProjections |> Map.keys |> Set.ofSeq ]
            |> Set.unionMany
            |> fun names -> Set.difference names environment.VisibleModules
            |> Set.remove "<anonymous>"

        let makeDiagnostic code message =
            { Severity = DiagnosticSeverity.Error
              Code = code
              Stage = Some "KFrontIR"
              Phase = Some(KFrontIRPhase.phaseName CORE_LOWERING)
              Message = message
              Location = None
              RelatedLocations = [] }

        let tryVisibleOrdinaryTermAmbiguityCandidates localName =
            environment.AmbiguousVisibleOrdinaryTerms |> Map.tryFind localName

        let tryVisiblePatternHeadAmbiguityCandidates localName =
            tryVisibleOrdinaryTermAmbiguityCandidates localName
            |> Option.bind (fun candidates ->
                let admissible =
                    candidates
                    |> List.filter (function
                        | OrdinaryVisibleConstructorCandidate _ -> true
                        | OrdinaryVisibleBindingCandidate info when info.IsPattern -> true
                        | _ -> false)

                if List.length admissible > 1 then Some admissible else None)

        let ordinaryNameAmbiguityDiagnostic name candidates =
            makeDiagnostic
                DiagnosticCode.NameAmbiguous
                (ordinaryNameAmbiguityMessage name candidates)

        let declaredParameterContextConflictDiagnostics =
            bodyInferredNumericParameterTypes
            |> Map.toList
            |> List.choose (fun (parameterName, inferredType) ->
                declaredParameterLocalTypes
                |> Map.tryFind parameterName
                |> Option.bind (fun declaredType ->
                    let normalizedDeclaredType = normalizeTypeAliases environment.VisibleTypeAliases declaredType
                    let normalizedInferredType = normalizeTypeAliases environment.VisibleTypeAliases inferredType

                    match normalizedDeclaredType with
                    | TypeVariable _
                        when not (TypeSignatures.definitionallyEqual normalizedDeclaredType normalizedInferredType) ->
                        Some(
                            makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Parameter '{parameterName}' is used in a numeric context that requires '{TypeSignatures.toText inferredType}', but its declared type is '{TypeSignatures.toText declaredType}'."
                        )
                    | _ ->
                        None))

        let tryInstantiateVisibleBindingType name =
            let instantiate (bindingInfo: BindingSchemeInfo) =
                let probe = ref freshCounter.Value
                let instance = TypeSignatures.instantiate "t" probe.Value bindingInfo.Scheme
                snd (TypeSignatures.schemeParts instance)

            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.map instantiate
            |> Option.orElseWith (fun () ->
                environment.VisibleConstructors
                |> Map.tryFind name
                |> Option.map instantiate)

        let rec tryInferExpressionTypeWithSiblingFallback
            (visitedTopLevelNames: Set<string>)
            (localTypes: Map<string, TypeExpr>)
            (expression: SurfaceExpression)
            =
            inferValidationExpressionType environment (ref freshCounter.Value) localTypes expression
            |> Option.orElseWith (fun () ->
                match expression with
                | Name [ name ] ->
                    Map.tryFind name localTypes
                    |> Option.orElseWith (fun () -> tryInferSiblingBindingType visitedTopLevelNames name)
                | Apply(Name [ calleeName ], arguments) ->
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes (Name [ calleeName ])
                    |> Option.bind (fun calleeType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (fun argument ->
                                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes argument)
                            calleeType
                            arguments)
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    match
                        tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes left,
                        tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes right
                    with
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                                 intType
                             && TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                                 intType ->
                        Some intType
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                                 floatType
                             && TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                                 floatType ->
                        Some floatType
                    | _ ->
                        None
                | Do statements ->
                    tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes statements
                | _ ->
                    None)

        and tryInferDoResultTypeWithSiblingFallback
            (visitedTopLevelNames: Set<string>)
            (localTypes: Map<string, TypeExpr>)
            (statements: SurfaceDoStatement list)
            =
            match statements with
            | [] ->
                Some unitType
            | DoExpression expression :: [] ->
                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                |> Option.map unwrapIoType
            | DoExpression _ :: rest ->
                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes rest
            | DoLet(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some valueType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some valueType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                failure
                |> Option.iter (fun failureBlock ->
                    tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes failureBlock.Body
                    |> ignore)

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoBind(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases)
                    |> Option.map (fun payloadType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some payloadType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoUsing(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some(unwrapIoType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoVar(bindingName, expression) :: rest ->
                let nextLocals =
                    match tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoAssign _ :: rest
            | DoDefer _ :: rest
            | DoIf _ :: rest
            | DoWhile _ :: rest ->
                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes rest
            | DoReturn expression :: _ ->
                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression

        and tryInferSiblingParameterTypesFromNumericUse
            (visitedTopLevelNames: Set<string>)
            (parameters: Parameter list)
            (body: SurfaceExpression)
            =
            let parameterNames =
                parameters
                |> List.map (fun parameter -> parameter.Name)
                |> Set.ofList

            let annotatedLocals =
                parameters
                |> List.choose (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (fun parameterType -> parameter.Name, parameterType))
                |> Map.ofList

            let normalize typeExpr =
                normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            let isSupportedArithmeticType normalizedTypeExpr =
                match normalizedTypeExpr with
                | TypeName(([ "Int" ] | [ "std"; "prelude"; "Int" ]), [])
                | TypeName(([ "Float" ] | [ "std"; "prelude"; "Float" ]), [])
                | TypeName(([ "Double" ] | [ "std"; "prelude"; "Double" ]), []) ->
                    true
                | _ ->
                    false

            let tryInferNumericOperandType expression =
                match expression with
                | NumericLiteral literal ->
                    Some(inferSurfaceNumericLiteralType literal)
                | Unary("-", NumericLiteral literal) ->
                    Some(inferSurfaceNumericLiteralType literal)
                | _ ->
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames annotatedLocals expression
                    |> Option.map normalize
                    |> Option.filter isSupportedArithmeticType

            let addExpectation parameterName inferredType expectations =
                match Map.tryFind parameterName expectations with
                | Some existingType
                    when TypeSignatures.definitionallyEqual
                             (normalize existingType)
                             (normalize inferredType) ->
                    expectations
                | Some _ ->
                    expectations
                | None ->
                    Map.add parameterName inferredType expectations

            let rec walk expectations expression =
                let addFromOperand parameterExpression counterpart currentExpectations =
                    match parameterExpression with
                    | Name [ parameterName ] when Set.contains parameterName parameterNames ->
                        match tryInferNumericOperandType counterpart with
                        | Some inferredType ->
                            addExpectation parameterName inferredType currentExpectations
                        | None ->
                            currentExpectations
                    | _ ->
                        currentExpectations

                let descend currentExpression currentExpectations =
                    walk currentExpectations currentExpression

                match expression with
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    expectations
                    |> addFromOperand left right
                    |> addFromOperand right left
                    |> descend left
                    |> descend right
                | Binary(left, _, right) ->
                    expectations |> descend left |> descend right
                | Apply(callee, arguments) ->
                    (descend callee expectations, arguments)
                    ||> List.fold (fun state argument -> descend argument state)
                | LocalLet(_, value, nestedBody) ->
                    expectations |> descend value |> descend nestedBody
                | LocalSignature(_, nestedBody)
                | LocalTypeAlias(_, nestedBody)
                | LocalScopedEffect(_, nestedBody)
                | Lambda(_, nestedBody)
                | SyntaxQuote nestedBody
                | SyntaxSplice nestedBody
                | TopLevelSyntaxSplice nestedBody
                | CodeQuote nestedBody
                | CodeSplice nestedBody
                | MonadicSplice nestedBody
                | ExplicitImplicitArgument nestedBody
                | InoutArgument nestedBody
                | Unary(_, nestedBody)
                | Seal(nestedBody, _)
                | TagTest(nestedBody, _) ->
                    descend nestedBody expectations
                | TypeSyntaxTokens _ ->
                    expectations
                | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                    expectations
                    |> descend label
                    |> descend nestedBody
                    |> descend returnClause.Body
                    |> fun state ->
                        operationClauses
                        |> List.fold (fun clauseState clause -> descend clause.Body clauseState) state
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    expectations
                    |> descend condition
                    |> descend whenTrue
                    |> descend whenFalse
                | Match(scrutinee, cases) ->
                    expectations
                    |> descend scrutinee
                    |> fun state ->
                        cases
                        |> List.fold
                            (fun caseState caseClause ->
                                caseState
                                |> fun innerState ->
                                    match caseClause.Guard with
                                    | Some guard -> descend guard innerState
                                    | None -> innerState
                                |> descend caseClause.Body)
                            state
                | RecordLiteral fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | RecordUpdate(receiver, fields) ->
                    expectations
                    |> descend receiver
                    |> fun state -> fields |> List.fold (fun innerState field -> descend field.Value innerState) state
                | MemberAccess(receiver, _, arguments) ->
                    expectations
                    |> descend receiver
                    |> fun state -> arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | SafeNavigation(receiver, navigation) ->
                    expectations
                    |> descend receiver
                    |> fun state -> navigation.Arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | Do statements ->
                    statements
                    |> List.fold
                        (fun state statement ->
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                descend value state
                            | DoLetQuestion(_, value, failure) ->
                                let nextState = descend value state

                                match failure with
                                | Some block ->
                                    block.Body |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) nextState
                                | None ->
                                    nextState
                            | DoIf(condition, whenTrue, whenFalse) ->
                                let nextState = descend condition state
                                let descendDoBody bodyStatements bodyState =
                                    bodyStatements |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) bodyState

                                nextState
                                |> descendDoBody whenTrue
                                |> descendDoBody whenFalse
                            | DoWhile(condition, doBody) ->
                                let nextState = descend condition state
                                doBody |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) nextState)
                        expectations
                | Elvis(left, right) ->
                    expectations |> descend left |> descend right
                | Comprehension comprehension ->
                    descend comprehension.Lowered expectations
                | PrefixedString(_, parts) ->
                    parts
                    |> List.fold
                        (fun state part ->
                            match part with
                            | StringText _ -> state
                            | StringInterpolation(inner, _) -> descend inner state)
                        expectations
                | NamedApplicationBlock fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    expectations

            walk Map.empty body

        and tryInferSiblingBindingType (visitedTopLevelNames: Set<string>) name =
            if Set.contains name visitedTopLevelNames then
                None
            else
                let inferFromSiblingDefinition () =
                    topLevelDefinitionsByName
                    |> Map.tryFind name
                    |> Option.bind (fun siblingDefinition ->
                        siblingDefinition.Body
                        |> Option.bind (fun siblingBody ->
                            let nextVisited = Set.add name visitedTopLevelNames

                            match siblingDefinition.Parameters with
                            | [] ->
                                tryInferExpressionTypeWithSiblingFallback nextVisited Map.empty siblingBody
                            | parameters ->
                                let bodyInferredParameterTypes =
                                    tryInferSiblingParameterTypesFromNumericUse nextVisited parameters siblingBody

                                let parameterTypes =
                                    parameters
                                    |> List.map (fun parameter ->
                                        tryParseParameterType parameter
                                        |> Option.orElseWith (fun () -> Map.tryFind parameter.Name bodyInferredParameterTypes))

                                if parameterTypes |> List.exists Option.isNone then
                                    None
                                else
                                    let parameterTypes = parameterTypes |> List.choose id
                                    let siblingLocals =
                                        List.zip parameters parameterTypes
                                        |> List.fold (fun state (parameter, parameterType) ->
                                            Map.add parameter.Name parameterType state) Map.empty

                                    tryInferExpressionTypeWithSiblingFallback nextVisited siblingLocals siblingBody
                                    |> Option.map (fun resultType ->
                                        List.zip parameters parameterTypes
                                        |> List.rev
                                        |> List.fold
                                            (fun current (parameter, parameterType) ->
                                                TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current))
                                            resultType)))

                if Set.contains name explicitSignatureNames then
                    tryInstantiateVisibleBindingType name
                    |> Option.orElseWith inferFromSiblingDefinition
                else
                    inferFromSiblingDefinition ()
                    |> Option.orElseWith (fun () -> tryInstantiateVisibleBindingType name)

        let typeIsMetaPhaseTransferType typeExpr =
            let normalized = normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            match normalized with
            | TypeName(([ "Syntax" ] | [ "std"; "prelude"; "Syntax" ]), [ _ ])
            | TypeName(([ "SyntaxOrigin" ] | [ "std"; "prelude"; "SyntaxOrigin" ]), [])
            | TypeName(([ "SyntaxFragment" ] | [ "std"; "prelude"; "SyntaxFragment" ]), [])
            | TypeName(([ "Elab" ] | [ "std"; "prelude"; "Elab" ]), [ _ ])
            | TypeName(([ "ElabGoal" ] | [ "std"; "prelude"; "ElabGoal" ]), [])
            | TypeName(([ "Code" ] | [ "std"; "prelude"; "Code" ]), [ _ ])
            | TypeName(([ "ClosedCode" ] | [ "std"; "prelude"; "ClosedCode" ]), [ _ ])
            | TypeName(([ "RawComprehension" ] | [ "std"; "prelude"; "RawComprehension" ]), [ _ ])
            | TypeName(([ "ComprehensionPlan" ] | [ "std"; "prelude"; "ComprehensionPlan" ]), [ _ ]) ->
                true
            | _ ->
                isCompileTimeArgumentType environment.VisibleTypeAliases normalized

        let rec typeMentionsMacroReflectionType typeExpr =
            let normalized = normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            match normalized with
            | TypeName(([ "Syntax" ] | [ "std"; "prelude"; "Syntax" ]), [ _ ])
            | TypeName(([ "SyntaxOrigin" ] | [ "std"; "prelude"; "SyntaxOrigin" ]), [])
            | TypeName(([ "SyntaxFragment" ] | [ "std"; "prelude"; "SyntaxFragment" ]), [])
            | TypeName(([ "Elab" ] | [ "std"; "prelude"; "Elab" ]), [ _ ])
            | TypeName(([ "ElabGoal" ] | [ "std"; "prelude"; "ElabGoal" ]), [])
            | TypeName(([ "Code" ] | [ "std"; "prelude"; "Code" ]), [ _ ])
            | TypeName(([ "ClosedCode" ] | [ "std"; "prelude"; "ClosedCode" ]), [ _ ]) ->
                true
            | TypeArrow(_, parameterType, resultType) ->
                typeMentionsMacroReflectionType parameterType
                || typeMentionsMacroReflectionType resultType
            | TypeApply(callee, arguments) ->
                typeMentionsMacroReflectionType callee
                || (arguments |> List.exists typeMentionsMacroReflectionType)
            | TypeLambda(_, parameterSort, body) ->
                typeMentionsMacroReflectionType parameterSort
                || typeMentionsMacroReflectionType body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeMentionsMacroReflectionType inner
            | TypeProject(receiver, _) ->
                typeMentionsMacroReflectionType receiver
            | TypeCapture(baseType, _) ->
                typeMentionsMacroReflectionType baseType
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeMentionsMacroReflectionType field.Type)
            | TypeEffectRow(entries, tail) ->
                (entries
                 |> List.exists (fun entry ->
                     typeMentionsMacroReflectionType entry.Label
                     || typeMentionsMacroReflectionType entry.Effect))
                || (tail |> Option.exists typeMentionsMacroReflectionType)
            | TypeUnion options ->
                options |> List.exists typeMentionsMacroReflectionType
            | TypeEquality(left, right) ->
                typeMentionsMacroReflectionType left
                || typeMentionsMacroReflectionType right
            | TypeName(_, arguments) ->
                arguments |> List.exists typeMentionsMacroReflectionType
            | TypeVariable _
            | TypeLevelLiteral _
            | TypeUniverse _
            | TypeIntrinsic _ ->
                false

        let tryInferPureElabResultType locals expression =
            let isPureElabPayloadType typeExpr =
                match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                | TypeName(([ "Syntax" ] | [ "std"; "prelude"; "Syntax" ]), [ _ ])
                | TypeName(([ "SyntaxOrigin" ] | [ "std"; "prelude"; "SyntaxOrigin" ]), [])
                | TypeName(([ "SyntaxFragment" ] | [ "std"; "prelude"; "SyntaxFragment" ]), [])
                | TypeName(([ "Code" ] | [ "std"; "prelude"; "Code" ]), [ _ ])
                | TypeName(([ "ClosedCode" ] | [ "std"; "prelude"; "ClosedCode" ]), [ _ ]) ->
                    true
                | _ when tryInterpolatedMacroResultType environment.VisibleTypeAliases typeExpr |> Option.isSome ->
                    true
                | _ ->
                    false

            match expression with
            | Apply(Name [ "pure" ], [ argument ]) ->
                inferValidationExpressionType environment freshCounter locals argument
                |> Option.filter isPureElabPayloadType
                |> Option.map elabType
            | _ ->
                None

        let tryInferMacroAwareValidationType locals expression =
            tryInferPureElabResultType locals expression
            |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals expression)

        let tryInferTopLevelSpliceResultType locals expression =
            inferValidationExpressionType environment freshCounter locals expression
            |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases)
            |> Option.orElseWith (fun () ->
                tryInferPureElabResultType locals expression
                |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases))

        let tryResolveVisibleCallable name =
            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind name)

        let tryInstantiateVisibleCallableScheme name =
            tryResolveVisibleCallable name
            |> Option.map (fun bindingInfo ->
                let probe = ref freshCounter.Value
                TypeSignatures.instantiate "v" probe.Value bindingInfo.Scheme)

        let tryInferCallableElabResult name =
            tryInstantiateVisibleCallableScheme name
            |> Option.bind (fun instantiated ->
                instantiated
                |> TypeSignatures.schemeParts
                |> snd
                |> tryUnwrapElabType environment.VisibleTypeAliases)

        let rec patternIsDefinitelyIrrefutable pattern =
            match pattern with
            | WildcardPattern
            | NamePattern _ ->
                true
            | AsPattern(_, inner)
            | TypedPattern(inner, _) ->
                patternIsDefinitelyIrrefutable inner
            | TuplePattern elements ->
                elements |> List.forall patternIsDefinitelyIrrefutable
            | AnonymousRecordPattern(fields, rest) ->
                let fieldsIrrefutable =
                    fields |> List.forall (fun field -> patternIsDefinitelyIrrefutable field.Pattern)

                let restIrrefutable =
                    match rest with
                    | Some DiscardRecordPatternRest
                    | Some(BindRecordPatternRest _) -> true
                    | None -> true

                fieldsIrrefutable && restIrrefutable
            | LiteralPattern _
            | ConstructorPattern _
            | NamedConstructorPattern _
            | VariantPattern _
            | OrPattern _ ->
                false

        let tryResolveTraitConstraint typeExpr traitName =
            resolveConstraintInstanceWithSubstitution environment { TraitName = traitName; Arguments = [ typeExpr ] }
            |> Option.map (fun (instanceInfo, substitution) ->
                instanceInfo,
                substitution)

        let tryParseInstanceAssociatedType substitution (instanceInfo: InstanceInfo) memberName =
            instanceInfo.Members
            |> Map.tryFind memberName
            |> Option.bind (fun memberDefinition ->
                memberDefinition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.orElseWith (fun () -> TypeSignatures.parseType memberDefinition.BodyTokens))
            |> Option.map (TypeSignatures.applySubstitution substitution)

        let tryParseInterpolatedMacroGoal body =
            let rec loop current =
                match current with
                | Apply(Name [ "pure" ], [ inner ]) ->
                    loop inner
                | Apply(Name [ "summonDict" ], [ argument ]) ->
                    tryParseTypeLikeSurfaceExpression argument
                    |> Option.bind (function
                        | TypeName(nameSegments, [ resultType ]) when nameSegments |> List.tryLast = Some "InterpolatedMacro" ->
                            Some resultType
                        | _ ->
                            None)
                | _ ->
                    None

            loop body

        let tryExtractFailElabDiagnosticMessage body =
            let rec fromExpression current =
                match current with
                | Apply(Name [ "failElabWith" ], [ Literal(LiteralValue.String code); Literal(LiteralValue.String message); _ ]) ->
                    Some($"{code}: {message}")
                | Apply(Name [ calleeName ], arguments) ->
                    topLevelDefinitionsByName
                    |> Map.tryFind calleeName
                    |> Option.bind (fun definition -> definition.Body |> Option.bind fromExpression)
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | Apply(callee, arguments) ->
                    fromExpression callee
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | Do statements ->
                    statements |> List.tryPick fromDoStatement
                | LocalLet(_, value, inner) ->
                    fromExpression value |> Option.orElseWith (fun () -> fromExpression inner)
                | LocalSignature(_, inner)
                | LocalTypeAlias(_, inner)
                | LocalScopedEffect(_, inner)
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    fromExpression inner
                | TypeSyntaxTokens _ ->
                    None
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> fromExpression whenTrue)
                    |> Option.orElseWith (fun () -> fromExpression whenFalse)
                | Handle(_, label, handledBody, returnClause, operationClauses) ->
                    fromExpression label
                    |> Option.orElseWith (fun () -> fromExpression handledBody)
                    |> Option.orElseWith (fun () -> fromExpression returnClause.Body)
                    |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> fromExpression clause.Body))
                | Match(scrutinee, cases) ->
                    fromExpression scrutinee
                    |> Option.orElseWith (fun () ->
                        cases
                        |> List.tryPick (fun caseClause ->
                            caseClause.Guard
                            |> Option.bind fromExpression
                            |> Option.orElseWith (fun () -> fromExpression caseClause.Body)))
                | RecordLiteral fields ->
                    fields |> List.tryPick (fun field -> fromExpression field.Value)
                | RecordUpdate(receiver, fields) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> fromExpression field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | SafeNavigation(receiver, navigation) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick fromExpression)
                | NamedApplicationBlock fields ->
                    fields |> List.tryPick (fun field -> fromExpression field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    fromExpression left |> Option.orElseWith (fun () -> fromExpression right)
                | Comprehension comprehension ->
                    fromExpression comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.tryPick (function
                        | StringText _ -> None
                        | StringInterpolation(inner, _) -> fromExpression inner)
                | Lambda(_, inner)
                | Seal(inner, _)
                | TagTest(inner, _) ->
                    fromExpression inner
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    None

            and fromDoStatement statement =
                match statement with
                | DoLet(_, value)
                | DoBind(_, value)
                | DoUsing(_, value)
                | DoVar(_, value)
                | DoAssign(_, value)
                | DoDefer value
                | DoReturn value
                | DoExpression value ->
                    fromExpression value
                | DoLetQuestion(_, value, failure) ->
                    fromExpression value
                    |> Option.orElseWith (fun () ->
                        failure
                        |> Option.bind (fun failureBlock -> failureBlock.Body |> List.tryPick fromDoStatement))
                | DoIf(condition, whenTrue, whenFalse) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> whenTrue |> List.tryPick fromDoStatement)
                    |> Option.orElseWith (fun () -> whenFalse |> List.tryPick fromDoStatement)
                | DoWhile(condition, body) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> body |> List.tryPick fromDoStatement)

            fromExpression body

        let tryResolvePrefixedStringFailureDiagnostic prefix =
            topLevelDefinitionsByName
            |> Map.tryFind prefix
            |> Option.bind (fun prefixDefinition ->
                prefixDefinition.Body
                |> Option.bind tryParseInterpolatedMacroGoal
                |> Option.bind (fun resultType ->
                    tryResolveTraitConstraint resultType "InterpolatedMacro"
                    |> Option.bind (fun (instanceInfo, _) ->
                        instanceInfo.Members
                        |> Map.tryFind "buildInterpolated"
                        |> Option.bind (fun memberDefinition ->
                            memberDefinition.Body |> Option.bind tryExtractFailElabDiagnosticMessage))))

        let comprehensionSinkItemTypesEqual expectedItemType actualItemType =
            let normalize = normalizeTypeAliases environment.VisibleTypeAliases

            let rec canonicalize typeExpr =
                let normalized = normalize typeExpr

                match QuerySemantics.tryParseQueryType normalize normalized with
                | Some queryType ->
                    let useName =
                        match queryType.Mode.Use with
                        | QuerySemantics.Reusable -> "Reusable"
                        | QuerySemantics.OneShot -> "OneShot"

                    let cardName =
                        match queryType.Mode.Card with
                        | QuerySemantics.QZero -> "QZero"
                        | QuerySemantics.QOne -> "QOne"
                        | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                        | QuerySemantics.QOneOrMore -> "QOneOrMore"
                        | QuerySemantics.QZeroOrMore -> "QZeroOrMore"

                    TypeName(
                        [ "QueryCore" ],
                        [
                            TypeName([ "QueryMode" ], [ TypeName([ useName ], []); TypeName([ cardName ], []) ])
                            TypeName([ ResourceQuantity.toSurfaceText queryType.ItemQuantity ], [])
                            canonicalize queryType.ItemType
                        ]
                    )
                | None ->
                    match normalized with
                    | TypeName(nameSegments, arguments) ->
                        TypeName(nameSegments, arguments |> List.map canonicalize)
                    | TypeApply(callee, arguments) ->
                        TypeApply(canonicalize callee, arguments |> List.map canonicalize)
                    | TypeLambda(name, parameterSort, body) ->
                        TypeLambda(name, canonicalize parameterSort, canonicalize body)
                    | TypeDelay inner ->
                        TypeDelay(canonicalize inner)
                    | TypeMemo inner ->
                        TypeMemo(canonicalize inner)
                    | TypeForce inner ->
                        TypeForce(canonicalize inner)
                    | TypeProject(receiver, memberName) ->
                        TypeProject(canonicalize receiver, memberName)
                    | TypeArrow(quantity, parameterType, resultType) ->
                        TypeArrow(quantity, canonicalize parameterType, canonicalize resultType)
                    | TypeEquality(left, right) ->
                        TypeEquality(canonicalize left, canonicalize right)
                    | TypeCapture(inner, captures) ->
                        TypeCapture(canonicalize inner, captures)
                    | TypeEffectRow(entries, tail) ->
                        TypeEffectRow(
                            entries
                            |> List.map (fun entry ->
                                { Label = canonicalize entry.Label
                                  Effect = canonicalize entry.Effect }),
                            tail |> Option.map canonicalize
                        )
                    | TypeRecord fields ->
                        TypeRecord(
                            fields
                            |> List.map (fun field ->
                                { field with
                                    Type = canonicalize field.Type })
                        )
                    | TypeUnion options ->
                        TypeUnion(options |> List.map canonicalize)
                    | TypeVariable _
                    | TypeLevelLiteral _
                    | TypeUniverse _
                    | TypeIntrinsic _ ->
                        normalized

            let sameQueryShape =
                match
                    QuerySemantics.tryParseQueryType normalize expectedItemType,
                    QuerySemantics.tryParseQueryType normalize actualItemType
                with
                | Some expectedQuery, Some actualQuery ->
                    expectedQuery.Mode = actualQuery.Mode
                    && expectedQuery.ItemQuantity = actualQuery.ItemQuantity
                    && expectedQuery.CaptureSet = actualQuery.CaptureSet
                    && TypeSignatures.definitionallyEqual
                        (normalize expectedQuery.ItemType)
                        (normalize actualQuery.ItemType)
                | _ ->
                    false

            sameQueryShape
            || TypeSignatures.definitionallyEqual (canonicalize expectedItemType) (canonicalize actualItemType)

        let syntaxCarrierEscapeDiagnostics visibleNames valueType valueExpression =
            let unwrapSyntaxCarrier typeExpr =
                tryUnwrapSyntaxType environment.VisibleTypeAliases typeExpr
                |> Option.orElseWith (fun () ->
                    typeExpr
                    |> tryUnwrapElabType environment.VisibleTypeAliases
                    |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases))

            let rec quotedVisibleNames visible current =
                seq {
                    match current with
                    | Name(root :: _) when Set.contains root visible ->
                        yield root
                    | Name [] ->
                        ()
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! quotedVisibleNames visible inner
                    | LocalLet(binding, value, body) ->
                        yield! quotedVisibleNames visible value

                        let nextVisible =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union visible

                        yield! quotedVisibleNames nextVisible body
                    | LocalSignature(declaration, body) ->
                        yield! quotedVisibleNames (Set.add declaration.Name visible) body
                    | LocalTypeAlias(_, body) ->
                        yield! quotedVisibleNames visible body
                    | LocalScopedEffect(declaration, body) ->
                        yield! quotedVisibleNames (Set.add declaration.Name visible) body
                    | Lambda(parameters, body) ->
                        let nextVisible =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union visible

                        yield! quotedVisibleNames nextVisible body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! quotedVisibleNames visible label
                        yield! quotedVisibleNames visible body

                        let addClauseNames (clause: SurfaceEffectHandlerClause) visibleNames =
                            let argumentNames =
                                clause.ArgumentTokens
                                |> List.choose (fun tokens ->
                                    match significantTokens tokens with
                                    | [ token ] when Token.isName token ->
                                        Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                                    | _ ->
                                        None)
                                |> Set.ofList

                            let resumptionNames =
                                clause.ResumptionName |> Option.toList |> Set.ofList

                            visibleNames
                            |> Set.union argumentNames
                            |> Set.union resumptionNames

                        yield! quotedVisibleNames (addClauseNames returnClause visible) returnClause.Body

                        for clause in operationClauses do
                            yield! quotedVisibleNames (addClauseNames clause visible) clause.Body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! quotedVisibleNames visible condition
                        yield! quotedVisibleNames visible whenTrue
                        yield! quotedVisibleNames visible whenFalse
                    | Match(scrutinee, cases) ->
                        yield! quotedVisibleNames visible scrutinee

                        for caseClause in cases do
                            let caseVisible =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union visible

                            match caseClause.Guard with
                            | Some guard -> yield! quotedVisibleNames caseVisible guard
                            | None -> ()

                            yield! quotedVisibleNames caseVisible caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | Seal(value, _) ->
                        yield! quotedVisibleNames visible value
                    | RecordUpdate(receiver, fields) ->
                        yield! quotedVisibleNames visible receiver

                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! quotedVisibleNames visible receiver

                        for argument in arguments do
                            yield! quotedVisibleNames visible argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! quotedVisibleNames visible receiver

                        for argument in navigation.Arguments do
                            yield! quotedVisibleNames visible argument
                    | TagTest(receiver, _) ->
                        yield! quotedVisibleNames visible receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                yield! quotedVisibleNames visible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union visible

                                yield! quotedVisibleNames nextVisible (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, expression, failure) ->
                                yield! quotedVisibleNames visible expression

                                match failure with
                                | Some failure ->
                                    let failureVisible =
                                        collectPatternNames failure.ResiduePattern.Pattern
                                        |> Set.ofList
                                        |> Set.union visible

                                    for failureStatement in failure.Body do
                                        match failureStatement with
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) ->
                                            yield! quotedVisibleNames failureVisible inner
                                        | _ ->
                                            ()
                                | None ->
                                    ()

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union visible

                                yield! quotedVisibleNames nextVisible (Literal LiteralValue.Unit)
                            | DoVar(_, inner)
                            | DoAssign(_, inner)
                            | DoDefer inner
                            | DoExpression inner
                            | DoReturn inner ->
                                yield! quotedVisibleNames visible inner
                            | DoIf(condition, whenTrue, whenFalse) ->
                                yield! quotedVisibleNames visible condition

                                for nested in whenTrue @ whenFalse do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! quotedVisibleNames visible inner
                                    | _ ->
                                        ()
                            | DoWhile(condition, body) ->
                                yield! quotedVisibleNames visible condition

                                for nested in body do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! quotedVisibleNames visible inner
                                    | _ ->
                                        ()
                    | Apply(callee, arguments) ->
                        yield! quotedVisibleNames visible callee

                        for argument in arguments do
                            yield! quotedVisibleNames visible argument
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! quotedVisibleNames visible left
                        yield! quotedVisibleNames visible right
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringText _ -> ()
                            | StringInterpolation(inner, _) -> yield! quotedVisibleNames visible inner
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _ ->
                        ()
                    | _ ->
                        ()
                }

            let rec escapedCapturedNames bindingVisible currentVisible current =
                seq {
                    match current with
                    | SyntaxQuote inner ->
                        yield!
                            quotedVisibleNames currentVisible inner
                            |> Seq.filter (fun name -> not (Set.contains name bindingVisible))
                    | TypeSyntaxTokens _ ->
                        ()
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! escapedCapturedNames bindingVisible currentVisible inner
                    | LocalLet(binding, value, body) ->
                        yield! escapedCapturedNames bindingVisible currentVisible value

                        let nextVisible =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union currentVisible

                        yield! escapedCapturedNames bindingVisible nextVisible body
                    | LocalSignature(declaration, body) ->
                        yield! escapedCapturedNames bindingVisible (Set.add declaration.Name currentVisible) body
                    | LocalTypeAlias(_, body) ->
                        yield! escapedCapturedNames bindingVisible currentVisible body
                    | LocalScopedEffect(declaration, body) ->
                        yield! escapedCapturedNames bindingVisible (Set.add declaration.Name currentVisible) body
                    | Lambda(parameters, body) ->
                        let nextVisible =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union currentVisible

                        yield! escapedCapturedNames bindingVisible nextVisible body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! escapedCapturedNames bindingVisible currentVisible label
                        yield! escapedCapturedNames bindingVisible currentVisible body
                        yield! escapedCapturedNames bindingVisible currentVisible returnClause.Body

                        for clause in operationClauses do
                            yield! escapedCapturedNames bindingVisible currentVisible clause.Body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! escapedCapturedNames bindingVisible currentVisible condition
                        yield! escapedCapturedNames bindingVisible currentVisible whenTrue
                        yield! escapedCapturedNames bindingVisible currentVisible whenFalse
                    | Match(scrutinee, cases) ->
                        yield! escapedCapturedNames bindingVisible currentVisible scrutinee

                        for caseClause in cases do
                            let nextVisible =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union currentVisible

                            match caseClause.Guard with
                            | Some guard -> yield! escapedCapturedNames bindingVisible nextVisible guard
                            | None -> ()

                            yield! escapedCapturedNames bindingVisible nextVisible caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | Seal(value, _) ->
                        yield! escapedCapturedNames bindingVisible currentVisible value
                    | RecordUpdate(receiver, fields) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for argument in arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for argument in navigation.Arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | TagTest(receiver, _) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                yield! escapedCapturedNames bindingVisible currentVisible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union currentVisible

                                yield! escapedCapturedNames bindingVisible nextVisible (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, expression, _) ->
                                yield! escapedCapturedNames bindingVisible currentVisible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union currentVisible

                                yield! escapedCapturedNames bindingVisible nextVisible (Literal LiteralValue.Unit)
                            | DoVar(_, inner)
                            | DoAssign(_, inner)
                            | DoDefer inner
                            | DoExpression inner
                            | DoReturn inner ->
                                yield! escapedCapturedNames bindingVisible currentVisible inner
                            | DoIf(condition, whenTrue, whenFalse) ->
                                yield! escapedCapturedNames bindingVisible currentVisible condition

                                for nested in whenTrue @ whenFalse do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! escapedCapturedNames bindingVisible currentVisible inner
                                    | _ ->
                                        ()
                            | DoWhile(condition, body) ->
                                yield! escapedCapturedNames bindingVisible currentVisible condition

                                for nested in body do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! escapedCapturedNames bindingVisible currentVisible inner
                                    | _ ->
                                        ()
                    | Apply(callee, arguments) ->
                        yield! escapedCapturedNames bindingVisible currentVisible callee

                        for argument in arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | Comprehension comprehension ->
                        yield! escapedCapturedNames bindingVisible currentVisible comprehension.Lowered
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! escapedCapturedNames bindingVisible currentVisible left
                        yield! escapedCapturedNames bindingVisible currentVisible right
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringText _ -> ()
                            | StringInterpolation(inner, _) ->
                                yield! escapedCapturedNames bindingVisible currentVisible inner
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        ()
                }

            match unwrapSyntaxCarrier valueType with
            | Some _ ->
                let escapedNames =
                    escapedCapturedNames visibleNames visibleNames valueExpression
                    |> Seq.distinct
                    |> Seq.toList

                if List.isEmpty escapedNames then
                    []
                else
                    let escapedText = String.concat ", " escapedNames

                    [
                        makeDiagnostic
                            DiagnosticCode.TypeEqualityMismatch
                            $"Syntax value captures binder(s) '{escapedText}' that do not remain in scope at the binding site; captured locals and borrows cannot escape through Syntax."
                    ]
            | None ->
                []

        let prefixedStringPrefixDiagnostics locals lexicalNames prefix =
            let mismatchMessage =
                $"Prefixed string prefix '{prefix}' must resolve to a term of type 'Elab (Dict (InterpolatedMacro t))' for some 't', or to an elaboration-time dictionary value."

            let prefixType =
                locals
                |> Map.tryFind prefix
                |> Option.orElseWith (fun () -> tryInstantiateVisibleBindingType prefix)

            match prefixType with
            | Some resolvedType ->
                let allowPlainDictionary =
                    not (Map.containsKey prefix locals) && Set.contains prefix environment.ElaborationAvailableBindings

                let resolvedResultType =
                    tryElabInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                    |> Option.orElseWith (fun () ->
                        if allowPlainDictionary then
                            tryInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                        else
                            None)

                match resolvedResultType with
                | Some _ -> []
                | None -> [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch mismatchMessage ]
            | None when Set.contains prefix lexicalNames ->
                []
            | None when allowUnresolvedCallDiagnostics && not (Set.contains prefix knownValueNames) ->
                [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{prefix}' is not in scope." ]
            | None when Set.contains prefix knownSurfaceTermNames ->
                [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch mismatchMessage ]
            | None ->
                []

        let numericLiteralRangeDiagnostic literal =
            let sourceText = SurfaceNumericLiteral.toSurfaceText literal
            makeDiagnostic DiagnosticCode.NumericLiteralOutOfRange $"Numeric literal '{sourceText}' is outside the currently supported runtime range for its target type."

        let tryNumericLiteralRangeDiagnostic expectedType expression =
            match tryInferNumericExpressionTypeFromContext environment expectedType expression with
            | Some _ when tryLowerNumericExpressionForRuntime expression |> Option.isNone ->
                match expression with
                | NumericLiteral literal ->
                    Some(numericLiteralRangeDiagnostic literal)
                | Unary("-", NumericLiteral(SurfaceIntegerLiteral(value, text, suffix))) ->
                    Some(numericLiteralRangeDiagnostic (SurfaceIntegerLiteral(-value, "-" + text, suffix)))
                | Unary("-", NumericLiteral(SurfaceRealLiteral(decimalValue, text, suffix))) ->
                    Some(numericLiteralRangeDiagnostic (SurfaceRealLiteral(decimalValue |> Option.map (~-), "-" + text, suffix)))
                | _ ->
                    None
            | _ ->
                None

        let isVisibleConstructorName name =
            environment.VisibleConstructors |> Map.containsKey name

        let rec expressionExposesManifestStaticObject expression =
            match tryResolveScopedStaticObject environment expression with
            | Some _ ->
                true
            | None ->
                match expression with
                | RecordLiteral _ ->
                    true
                | Seal(inner, _) ->
                    expressionExposesManifestStaticObject inner
                | _ ->
                    false

        let isTopLevelManifestStaticObjectRoot name =
            topLevelDefinitionsByName
            |> Map.tryFind name
            |> Option.exists (fun definition ->
                List.isEmpty definition.Parameters
                && (definition.Body |> Option.exists expressionExposesManifestStaticObject))

        let isVisibleQualifiedRootName locals lexicalNames name =
            let isVisibleModuleRoot =
                environment.VisibleModules
                |> Seq.exists (fun visibleModule ->
                    String.Equals(visibleModule, name, StringComparison.Ordinal)
                    || visibleModule.StartsWith(name + ".", StringComparison.Ordinal))

            (Map.containsKey name locals)
            || (Set.contains name lexicalNames)
            || (Set.contains name knownValueNames)
            || String.Equals(name, "this", StringComparison.Ordinal)
            || isVisibleModuleRoot
            || environment.VisibleTypeFacets.ContainsKey(name)
            || environment.VisibleStaticObjects.ContainsKey(name)
            || isTopLevelManifestStaticObjectRoot name
            || (tryResolveScopedStaticObject environment (Name [ name ]) |> Option.isSome)

        let qualifiedNamePreservesResolution nameSegments =
            let qualifiedName = SyntaxFacts.moduleNameToText nameSegments

            let isVisibleQualifiedModule =
                environment.VisibleModules
                |> Seq.exists (fun visibleModule ->
                    String.Equals(visibleModule, qualifiedName, StringComparison.Ordinal)
                    || visibleModule.StartsWith(qualifiedName + ".", StringComparison.Ordinal))

            let resolveQualifiedModuleAlias moduleName =
                environment.SurfaceIndex
                |> Map.tryFind environment.CurrentModuleName
                |> Option.bind (fun currentModule ->
                    currentModule.Imports
                    |> List.tryPick (fun spec ->
                        match spec.Source, spec.Selection, spec.Alias with
                        | Dotted moduleSegments, QualifiedOnly, Some alias
                            when String.Equals(alias, moduleName, StringComparison.Ordinal) ->
                            Some(SyntaxFacts.moduleNameToText moduleSegments)
                        | _ ->
                            None))
                |> Option.defaultValue moduleName

            let resolvesAsQualifiedDeclaration =
                match List.rev nameSegments with
                | [] -> false
                | declaredName :: reversedModuleSegments ->
                    let declaringModuleName =
                        List.rev reversedModuleSegments
                        |> SyntaxFacts.moduleNameToText
                        |> resolveQualifiedModuleAlias

                    environment.SurfaceIndex
                    |> Map.tryFind declaringModuleName
                    |> Option.exists (fun moduleInfo ->
                        Set.contains declaredName moduleInfo.ExportedTerms
                        || Set.contains declaredName moduleInfo.ExportedTypes
                        || Set.contains declaredName moduleInfo.ExportedTraits
                        || Set.contains declaredName moduleInfo.ExportedConstructors)

            isVisibleQualifiedModule
            || (tryResolveScopedStaticObject environment (Name nameSegments) |> Option.isSome)
            || (tryResolveVisibleTypeFacetInfo environment nameSegments |> Option.isSome)
            || resolvesAsQualifiedDeclaration

        let expressionSelectsOpaqueField expression =
            let tryRecordInfoFromType typeExpr =
                match typeExpr with
                | TypeName(nameSegments, []) ->
                    nameSegments
                    |> List.tryLast
                    |> Option.bind (fun name -> environment.VisibleRecordTypes |> Map.tryFind name)
                    |> Option.orElseWith (fun () ->
                        match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                        | TypeRecord fields ->
                            Some
                                { Fields =
                                    fields
                                    |> List.map (fun field ->
                                        { Name = field.Name
                                          IsOpaque = false
                                          IsImplicit = field.Quantity = QuantityZero
                                          TypeTokens = [] })
                                  RowTail = None }
                        | _ ->
                            None)
                | _ ->
                    None

            let rootField expression =
                match expression with
                | Name [ root; fieldName ] ->
                    Some(root, fieldName)
                | MemberAccess(Name [ root ], [ fieldName ], []) ->
                    Some(root, fieldName)
                | _ ->
                    None

            rootField expression
            |> Option.bind (fun (root, fieldName) ->
                environment.VisibleBindings
                |> Map.tryFind root
                |> Option.bind (fun bindingInfo -> tryRecordInfoFromType bindingInfo.Scheme.Body)
                |> Option.bind (fun recordInfo ->
                    recordInfo.Fields
                    |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))))
            |> Option.exists (fun field -> field.IsOpaque)

        let hasProvenStaticObjectIdentity locals expression =
            match expression with
            | KindQualifiedName(TypeKind, [ name ]) when Set.contains name (currentScopedEffectNames ()) ->
                true
            | KindQualifiedName(EffectLabelKind, [ name ]) when Set.contains name (currentScopedEffectNames ()) ->
                true
            | Name(root :: _) when locals |> Map.containsKey root ->
                not (Set.contains root parameterNames)
            | _ ->
                tryResolveStaticReceiverObject environment expression
                |> Option.isSome
                |> function
                    | true -> true
                    | false ->
                        match expression with
                        | Name _ ->
                            false
                        | _ ->
                            not (expressionSelectsOpaqueField expression)
                            && (inferValidationExpressionType environment (ref freshCounter.Value) locals expression
                                |> Option.exists (isReifiedStaticObjectType environment.VisibleTypeAliases))

        let staticConstructorIdentityDiagnostic locals receiver memberName =
            if isVisibleConstructorName memberName
               && not (hasProvenStaticObjectIdentity locals receiver) then
                [ makeDiagnostic DiagnosticCode.StaticObjectUnresolved $"Static constructor '{memberName}' requires a receiver with preserved static-object identity." ]
            else
                []

        let rec staticPatternIdentityDiagnostics locals pattern =
            match pattern with
            | AsPattern(_, inner) ->
                staticPatternIdentityDiagnostics locals inner
            | TypedPattern(inner, _) ->
                staticPatternIdentityDiagnostics locals inner
            | ConstructorPattern(segments, arguments) ->
                let nested = arguments |> List.collect (staticPatternIdentityDiagnostics locals)

                match List.rev segments with
                | memberName :: receiverSegments when not (List.isEmpty receiverSegments) ->
                    let receiver = Name(List.rev receiverSegments)
                    staticConstructorIdentityDiagnostic locals receiver memberName @ nested
                | _ ->
                    nested
            | NamedConstructorPattern(segments, fields) ->
                staticPatternIdentityDiagnostics locals (ConstructorPattern(segments, fields |> List.map (fun field -> field.Pattern)))
            | TuplePattern elements ->
                elements |> List.collect (staticPatternIdentityDiagnostics locals)
            | VariantPattern _ ->
                []
            | OrPattern alternatives ->
                alternatives |> List.collect (staticPatternIdentityDiagnostics locals)
            | AnonymousRecordPattern(fields, _) ->
                fields |> List.collect (fun field -> staticPatternIdentityDiagnostics locals field.Pattern)
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                []

        let transparentSealFields ascriptionTokens =
            match tryParseRecordSurfaceInfo ascriptionTokens with
            | Some recordInfo ->
                recordInfo.Fields
                |> List.filter (fun field -> not field.IsOpaque)
                |> List.map (fun field -> field.Name)
                |> Set.ofList
                |> Some
            | None ->
                match significantTokens ascriptionTokens with
                | [ nameToken ] when Token.isName nameToken ->
                    environment.VisibleRecordTypes
                    |> Map.tryFind (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                    |> Option.map (fun recordInfo ->
                        recordInfo.Fields
                        |> List.filter (fun field -> not field.IsOpaque)
                        |> List.map (fun field -> field.Name)
                        |> Set.ofList)
                | _ ->
                    None

        let aliasesAsVisibleStaticObjects (aliases: Map<string list, StaticObjectInfo>) =
            aliases
            |> Map.fold
                (fun current segments staticObject ->
                    Map.add (SyntaxFacts.moduleNameToText segments) staticObject current)
                environment.VisibleStaticObjects

        let tryResolveWithLocalAliases aliases expression =
            let aliasEnvironment =
                { environment with
                    VisibleStaticObjects = aliasesAsVisibleStaticObjects aliases }

            tryResolveScopedStaticObject aliasEnvironment expression

        let copyVisibleNestedAliases
            (sourcePrefix: string list)
            (targetPrefix: string list)
            fieldFilter
            (aliases: Map<string list, StaticObjectInfo>)
            =
            let sourceKey = SyntaxFacts.moduleNameToText sourcePrefix
            let sourceNestedPrefix = sourceKey + "."

            aliasesAsVisibleStaticObjects aliases
            |> Map.toList
            |> List.filter (fun ((key: string), _) ->
                if key.StartsWith(sourceNestedPrefix, StringComparison.Ordinal) then
                    let suffix = key.Substring(sourceNestedPrefix.Length)
                    let firstSegment = suffix.Split('.')[0]

                    fieldFilter firstSegment
                else
                    false)
            |> List.fold (fun current ((key: string), staticObject) ->
                let suffixSegments =
                    key.Substring(sourceNestedPrefix.Length).Split('.', StringSplitOptions.RemoveEmptyEntries)
                    |> Array.toList

                Map.add (targetPrefix @ suffixSegments) staticObject current) aliases

        let rec collectExpressionStaticAliases prefix expression aliases =
            match tryResolveWithLocalAliases aliases expression with
            | Some staticObject ->
                let aliases = Map.add prefix staticObject aliases

                match expression with
                | Name sourcePrefix -> copyVisibleNestedAliases sourcePrefix prefix (fun _ -> true) aliases
                | _ -> aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectExpressionStaticAliases (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(value, ascriptionTokens) ->
                    match value, transparentSealFields ascriptionTokens with
                    | Name sourcePrefix, Some transparentFields ->
                        copyVisibleNestedAliases sourcePrefix prefix (fun fieldName -> Set.contains fieldName transparentFields) aliases
                    | RecordLiteral fields, Some transparentFields ->
                        fields
                        |> List.filter (fun field -> Set.contains field.Name transparentFields)
                        |> List.fold (fun current field -> collectExpressionStaticAliases (prefix @ [ field.Name ]) field.Value current) aliases
                    | _, Some _ ->
                        aliases
                    | _ ->
                        collectExpressionStaticAliases prefix value aliases
                | _ ->
                    aliases

        let rec collectPatternStaticAliases pattern value aliases =
            match pattern with
            | NamePattern name ->
                collectExpressionStaticAliases [ name ] value aliases
            | AsPattern(name, inner) ->
                collectPatternStaticAliases inner value (collectExpressionStaticAliases [ name ] value aliases)
            | TypedPattern(inner, _) ->
                collectPatternStaticAliases inner value aliases
            | AnonymousRecordPattern(fields, rest) ->
                fields
                |> List.fold (fun current field ->
                    let fieldExpression =
                        match value with
                        | Name segments -> Name(segments @ [ field.Name ])
                        | _ -> MemberAccess(value, [ field.Name ], [])

                    collectPatternStaticAliases field.Pattern fieldExpression current) aliases
                |> fun current ->
                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        collectExpressionStaticAliases [ name ] value current
                    | _ ->
                        current
            | ConstructorPattern(_, arguments) ->
                arguments |> List.fold (fun current argument -> collectPatternStaticAliases argument value current) aliases
            | NamedConstructorPattern(_, fields) ->
                fields |> List.fold (fun current field -> collectPatternStaticAliases field.Pattern value current) aliases
            | TuplePattern elements ->
                elements |> List.fold (fun current element -> collectPatternStaticAliases element value current) aliases
            | VariantPattern(BoundVariantPattern(name, _))
            | VariantPattern(RestVariantPattern name) ->
                collectExpressionStaticAliases [ name ] value aliases
            | VariantPattern(WildcardVariantPattern _) ->
                aliases
            | OrPattern alternatives ->
                alternatives
                |> List.tryHead
                |> Option.map (fun first -> collectPatternStaticAliases first value aliases)
                |> Option.defaultValue aliases
            | WildcardPattern
            | LiteralPattern _ ->
                aliases

        let typeHeadName typeExpr =
            match typeExpr with
            | TypeName(nameSegments, _) when not (List.isEmpty nameSegments) -> Some(List.last nameSegments)
            | _ -> None

        let rec finalResultType typeExpr =
            match typeExpr with
            | TypeArrow(_, _, resultType) -> finalResultType resultType
            | other -> other

        let isMonadicType typeExpr =
            match typeHeadName (finalResultType typeExpr) with
            | Some "IO"
            | Some "UIO" -> true
            | _ -> false

        let activePatternResultKind (bindingInfo: BindingSchemeInfo) =
            match typeHeadName (finalResultType bindingInfo.Scheme.Body) with
            | Some "Option" -> Some "Option"
            | Some "Match" -> Some "Match"
            | Some _ -> Some "Total"
            | None -> None

        let activePatternScrutineeQuantity (bindingInfo: BindingSchemeInfo) =
            bindingInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                layouts
                |> List.filter (fun parameter -> not parameter.IsImplicit)
                |> List.tryLast
                |> Option.bind (fun parameter -> parameter.Quantity))

        let tryActivePatternBinding pattern =
            match pattern with
            | ConstructorPattern(nameSegments, _) when not (List.isEmpty nameSegments) ->
                environment.VisibleBindings
                |> Map.tryFind (List.last nameSegments)
                |> Option.filter (fun bindingInfo -> bindingInfo.IsPattern)
            | _ ->
                None

        let rec validatePatternHead pattern =
            match pattern with
            | AsPattern(_, inner) ->
                validatePatternHead inner
            | TypedPattern(inner, _) ->
                validatePatternHead inner
            | ConstructorPattern(nameSegments, arguments) ->
                let nestedDiagnostics = arguments |> List.collect validatePatternHead
                let headDiagnostics =
                    match nameSegments with
                    | [] -> []
                    | _ ->
                        let headName = List.last nameSegments
                        match tryVisiblePatternHeadAmbiguityCandidates headName with
                        | Some candidates ->
                            [ ordinaryNameAmbiguityDiagnostic headName candidates ]
                        | None ->
                            let isConstructor = environment.VisibleConstructors |> Map.containsKey headName

                            match environment.VisibleBindings |> Map.tryFind headName with
                            | Some bindingInfo when not bindingInfo.IsPattern && not isConstructor ->
                                [ makeDiagnostic DiagnosticCode.PatternHeadNotConstructorOrActivePattern $"Pattern head '{headName}' resolves to an ordinary term, not a constructor or active pattern." ]
                            | _ ->
                                []

                headDiagnostics @ nestedDiagnostics
            | NamedConstructorPattern(nameSegments, fields) ->
                validatePatternHead (ConstructorPattern(nameSegments, fields |> List.map (fun field -> field.Pattern)))
            | TuplePattern elements ->
                elements |> List.collect validatePatternHead
            | VariantPattern _ ->
                []
            | OrPattern alternatives ->
                alternatives |> List.collect validatePatternHead
            | AnonymousRecordPattern(fields, _) ->
                fields |> List.collect (fun field -> validatePatternHead field.Pattern)
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                []

        let activePatternLinearityDiagnostics pattern context =
            match tryActivePatternBinding pattern with
            | Some bindingInfo ->
                match activePatternResultKind bindingInfo, activePatternScrutineeQuantity bindingInfo with
                | Some "Option", Some QuantityOne ->
                    [ makeDiagnostic DiagnosticCode.ActivePatternLinearityViolation $"Option-returning active pattern '{bindingInfo.Name}' consumes its scrutinee linearly in a refutable {context}." ]
                | Some "Match", _ when String.Equals(context, "let?", StringComparison.Ordinal) ->
                    [ makeDiagnostic DiagnosticCode.ActivePatternMatchResultNotAllowedInPlainLetQuestion $"Match-returning active pattern '{bindingInfo.Name}' is not permitted in plain let? destructuring." ]
                | _ ->
                    []
            | None ->
                []

        let memberText (navigation: SurfaceSafeNavigationMember) =
            let argumentsText =
                navigation.Arguments
                |> List.map (fun _ -> "<arg>")
                |> String.concat " "

            let segmentsText = String.concat "." navigation.Segments
            match argumentsText with
            | "" -> segmentsText
            | _ -> $"{segmentsText} {argumentsText}"

        let tryRecordInfoFromTypeName name =
            environment.VisibleRecordTypes |> Map.tryFind name

        let tryRecordInfoFromTypeExpr typeExpr =
            match typeExpr with
            | TypeName(nameSegments, []) ->
                nameSegments
                |> List.tryLast
                |> Option.bind tryRecordInfoFromTypeName
                |> Option.orElseWith (fun () ->
                    match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                    | TypeRecord fields ->
                        Some
                            { Fields =
                                fields
                                |> List.map (fun field ->
                                    { Name = field.Name
                                      IsOpaque = false
                                      IsImplicit = field.Quantity = QuantityZero
                                      TypeTokens = [] })
                              RowTail = None }
                    | _ ->
                        None)
            | _ ->
                match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                | TypeRecord fields ->
                    Some
                        { Fields =
                            fields
                            |> List.map (fun field ->
                                { Name = field.Name
                                  IsOpaque = false
                                  IsImplicit = field.Quantity = QuantityZero
                                  TypeTokens = [] })
                          RowTail = None }
                | _ ->
                    None

        let tryRecordInfoFromTypeTokens tokens =
            tryParseRecordSurfaceInfo tokens
            |> Option.orElseWith (fun () ->
                match significantTokens tokens with
                | [ nameToken ] when Token.isName nameToken ->
                    tryRecordInfoFromTypeName (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                | _ ->
                    None)

        let localRecordTypes =
            effectiveParameters
            |> List.choose (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens
                |> Option.map (fun recordInfo -> parameter.Name, recordInfo))
            |> Map.ofList

        let tryRecordInfoForRoot locals root =
            localRecordTypes
            |> Map.tryFind root
            |> Option.orElseWith (fun () ->
                locals
                |> Map.tryFind root
                |> Option.bind tryRecordInfoFromTypeExpr)
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind root
                |> Option.bind (fun bindingInfo ->
                    tryRecordInfoFromTypeExpr bindingInfo.Scheme.Body
                    |> Option.orElseWith (fun () -> tryRecordInfoFromTypeTokens bindingInfo.TypeTokens)))

        let tryRecordInfoForExpression locals expression =
            match expression with
            | Name(root :: _) -> tryRecordInfoForRoot locals root
            | _ -> None

        let trueTermType = TypeName([ "True" ], [])
        let falseTermType = TypeName([ "False" ], [])
        let emptyStableAliases: Map<string, string> = Map.empty
        let emptyStaticAliases: Map<string list, StaticObjectInfo> = Map.empty
        let emptyConstructorFacts: Map<string, string option * Set<string>> = Map.empty

        let canonicalStableRoot aliases name =
            let rec loop seen current =
                if Set.contains current seen then
                    current
                else
                    match Map.tryFind current aliases with
                    | Some next -> loop (Set.add current seen) next
                    | None -> current

            loop Set.empty name

        let removeShadowedAliases aliases names =
            names |> List.fold (fun state name -> Map.remove name state) aliases

        let removeShadowedStaticAliases
            (aliases: Map<string list, StaticObjectInfo>)
            names
            =
            if List.isEmpty names then
                aliases
            else
                let shadowed = names |> Set.ofList

                aliases
                |> Map.filter (fun segments _ ->
                    match segments with
                    | root :: _ -> not (Set.contains root shadowed)
                    | [] -> true)

        let tryLocalRootType aliases locals root =
            Map.tryFind root locals
            |> Option.orElseWith (fun () ->
                let canonicalRoot = canonicalStableRoot aliases root
                Map.tryFind canonicalRoot locals)

        let visibleConstructorsForType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, _) ->
                match List.tryLast nameSegments with
                | Some typeName ->
                    environment.VisibleConstructors
                    |> Map.values
                    |> Seq.filter (fun info ->
                        info.ConstructorTypeName
                        |> Option.exists (fun constructorTypeName ->
                            String.Equals(constructorTypeName, typeName, StringComparison.Ordinal)))
                    |> Seq.toList
                | None ->
                    []
            | _ ->
                []

        let tryVisibleConstructorFieldType (constructorInfo: BindingSchemeInfo) fieldName =
            constructorInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                layouts
                |> List.tryPick (fun parameter ->
                    if parameter.IsImplicit || parameter.IsReceiver then
                        None
                    elif String.Equals(parameter.Name, fieldName, StringComparison.Ordinal) then
                        parameter.TypeTokens |> Option.bind TypeSignatures.parseType
                    else
                        None))

        let possibleConstructorsForRoot aliases constructorFacts locals root =
            tryLocalRootType aliases locals root
            |> Option.bind (fun rootType ->
                let visibleConstructors = visibleConstructorsForType rootType

                if List.isEmpty visibleConstructors then
                    None
                else
                    let canonicalRoot = canonicalStableRoot aliases root

                    let filteredConstructors =
                        match Map.tryFind canonicalRoot constructorFacts with
                        | Some(Some positiveConstructor, _) ->
                            visibleConstructors
                            |> List.filter (fun info ->
                                String.Equals(info.Name, positiveConstructor, StringComparison.Ordinal))
                        | Some(None, excludedConstructors) ->
                            visibleConstructors
                            |> List.filter (fun info ->
                                not (Set.contains info.Name excludedConstructors))
                        | None ->
                            visibleConstructors

                    Some filteredConstructors)

        let addPositiveConstructorFact aliases constructorFacts root constructorName =
            let canonicalRoot = canonicalStableRoot aliases root
            Map.add canonicalRoot (Some constructorName, Set.empty) constructorFacts

        let addNegativeConstructorFact aliases constructorFacts root constructorName =
            let canonicalRoot = canonicalStableRoot aliases root

            let positiveConstructor, excludedConstructors =
                Map.tryFind canonicalRoot constructorFacts
                |> Option.defaultValue (None, Set.empty)

            Map.add canonicalRoot (positiveConstructor, Set.add constructorName excludedConstructors) constructorFacts

        let rec conditionConstructorFacts aliases constructorFacts (condition: SurfaceExpression) =
            match condition with
            | TagTest(Name [ root ], constructorNameSegments) ->
                match List.tryLast constructorNameSegments with
                | Some constructorName ->
                    [ addPositiveConstructorFact aliases constructorFacts root constructorName ],
                    [ addNegativeConstructorFact aliases constructorFacts root constructorName ]
                | None ->
                    [ constructorFacts ], [ constructorFacts ]
            | Unary("not", inner) ->
                let whenTrue, whenFalse = conditionConstructorFacts aliases constructorFacts inner
                whenFalse, whenTrue
            | Binary(left, "&&", right) ->
                let leftTrue, leftFalse = conditionConstructorFacts aliases constructorFacts left

                let rightTrue =
                    leftTrue
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> fst)

                let rightFalse =
                    leftTrue
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> snd)

                rightTrue, leftFalse @ rightFalse
            | Binary(left, "||", right) ->
                let leftTrue, leftFalse = conditionConstructorFacts aliases constructorFacts left

                let rightTrue =
                    leftFalse
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> fst)

                let rightFalse =
                    leftFalse
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> snd)

                leftTrue @ rightTrue, rightFalse
            | _ ->
                [ constructorFacts ], [ constructorFacts ]

        let rec tryTopLevelSurfaceConstructorPatternName (pattern: SurfacePattern) =
            match pattern with
            | ConstructorPattern(nameSegments, _)
            | NamedConstructorPattern(nameSegments, _) ->
                List.tryLast nameSegments
            | AsPattern(_, inner)
            | TypedPattern(inner, _) ->
                tryTopLevelSurfaceConstructorPatternName inner
            | _ ->
                None

        let rec doBlockDefinitelyTerminal (statements: SurfaceDoStatement list) =
            match statements |> List.tryLast with
            | Some(DoReturn _) ->
                true
            | Some(DoExpression(Do nestedStatements)) ->
                doBlockDefinitelyTerminal nestedStatements
            | Some(DoIf(_, whenTrue, whenFalse)) ->
                doBlockDefinitelyTerminal whenTrue && doBlockDefinitelyTerminal whenFalse
            | _ ->
                false

        let extendStableAliases aliases (binding: SurfaceBindPattern) (value: SurfaceExpression) =
            let shadowedNames = collectPatternNames binding.Pattern
            let clearedAliases = removeShadowedAliases aliases shadowedNames

            match binding.Pattern, value with
            | NamePattern aliasName, Name [ targetName ] ->
                Map.add aliasName (canonicalStableRoot clearedAliases targetName) clearedAliases
            | _ ->
                clearedAliases

        let constructorProjectionDiagnostics aliases constructorFacts locals root fieldName =
            match tryRecordInfoForRoot locals root with
            | Some recordInfo ->
                if
                    recordInfo.Fields
                    |> List.exists (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                then
                    []
                else
                    [ makeDiagnostic DiagnosticCode.RecordProjectionMissingField $"Record type has no field named '{fieldName}'." ]
            | None ->
                match possibleConstructorsForRoot aliases constructorFacts locals root with
                | Some [] ->
                    []
                | Some [ constructorInfo ] ->
                    match tryVisibleConstructorFieldType constructorInfo fieldName with
                    | Some _
                    | None ->
                        []
                | Some _ ->
                    [
                        makeDiagnostic
                            DiagnosticCode.TypeEqualityMismatch
                            $"Constructor-field projection '{root}.{fieldName}' requires a unique constructor refinement in this branch."
                    ]
                | None ->
                    []

        let applyRefinements refinements typeExpr =
            TypeSignatures.applySubstitution refinements typeExpr

        let normalizeExpectedType refinements typeExpr =
            typeExpr
            |> applyRefinements refinements
            |> qualifyVisibleTypeNames environment
            |> normalizeTypeAliases environment.VisibleTypeAliases

        let rec typeContainsLocalTermVariable locals typeExpr =
            match typeExpr with
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsLocalTermVariable locals universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsLocalTermVariable locals callee
                || (arguments |> List.exists (typeContainsLocalTermVariable locals))
            | TypeLambda(_, parameterSort, body) ->
                typeContainsLocalTermVariable locals parameterSort
                || typeContainsLocalTermVariable locals body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeContainsLocalTermVariable locals inner
            | TypeProject(target, _) ->
                typeContainsLocalTermVariable locals target
            | TypeVariable name ->
                Map.containsKey name locals
            | TypeName(_, arguments) ->
                arguments |> List.exists (typeContainsLocalTermVariable locals)
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsLocalTermVariable locals parameterType
                || typeContainsLocalTermVariable locals resultType
            | TypeEquality(left, right) ->
                typeContainsLocalTermVariable locals left
                || typeContainsLocalTermVariable locals right
            | TypeCapture(inner, _) ->
                typeContainsLocalTermVariable locals inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsLocalTermVariable locals entry.Label
                    || typeContainsLocalTermVariable locals entry.Effect)
                || tail |> Option.exists (typeContainsLocalTermVariable locals)
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsLocalTermVariable locals field.Type)
            | TypeUnion members ->
                members |> List.exists (typeContainsLocalTermVariable locals)

        let rec typeContainsSuspension typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeDelay _
            | TypeMemo _
            | TypeForce _ ->
                true
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsSuspension universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsSuspension callee || (arguments |> List.exists typeContainsSuspension)
            | TypeLambda(_, parameterSort, body) ->
                typeContainsSuspension parameterSort || typeContainsSuspension body
            | TypeProject(target, _) ->
                typeContainsSuspension target
            | TypeName(([ "Thunk" ] | [ "std"; "prelude"; "Thunk" ] | [ "Need" ] | [ "std"; "prelude"; "Need" ]), _) ->
                true
            | TypeName(_, arguments) ->
                arguments |> List.exists typeContainsSuspension
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsSuspension parameterType || typeContainsSuspension resultType
            | TypeEquality(left, right) ->
                typeContainsSuspension left || typeContainsSuspension right
            | TypeCapture(inner, _) ->
                typeContainsSuspension inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsSuspension entry.Label
                    || typeContainsSuspension entry.Effect)
                || tail |> Option.exists typeContainsSuspension
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsSuspension field.Type)
            | TypeUnion members ->
                members |> List.exists typeContainsSuspension
            | TypeVariable _ ->
                false

        let rec typeContainsUnion typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsUnion universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsUnion callee || (arguments |> List.exists typeContainsUnion)
            | TypeLambda(_, parameterSort, body) ->
                typeContainsUnion parameterSort || typeContainsUnion body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeContainsUnion inner
            | TypeProject(target, _) ->
                typeContainsUnion target
            | TypeUnion _ ->
                true
            | TypeName(_, arguments) ->
                arguments |> List.exists typeContainsUnion
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsUnion parameterType || typeContainsUnion resultType
            | TypeEquality(left, right) ->
                typeContainsUnion left || typeContainsUnion right
            | TypeCapture(inner, _) ->
                typeContainsUnion inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsUnion entry.Label
                    || typeContainsUnion entry.Effect)
                || tail |> Option.exists typeContainsUnion
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsUnion field.Type)
            | TypeVariable _ ->
                false

        let rec typeIsStableForValidationInference locals typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeLevelLiteral _ ->
                true
            | TypeUniverse None ->
                true
            | TypeUniverse(Some universeExpr) ->
                typeIsStableForValidationInference locals universeExpr
            | TypeIntrinsic _ ->
                true
            | TypeApply _
            | TypeLambda _
            | TypeDelay _
            | TypeMemo _
            | TypeForce _
            | TypeProject _
            | TypeEquality _
            | TypeCapture _
            | TypeVariable _ ->
                false
            | TypeName(_, arguments) ->
                arguments |> List.forall (typeIsStableForValidationInference locals)
            | TypeArrow(quantity, parameterType, resultType) ->
                quantity = QuantityOmega
                && typeIsStableForValidationInference locals parameterType
                && typeIsStableForValidationInference locals resultType
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.forall (fun entry ->
                    typeIsStableForValidationInference locals entry.Label
                    && typeIsStableForValidationInference locals entry.Effect)
                && tail |> Option.forall (typeIsStableForValidationInference locals)
            | TypeRecord fields ->
                fields
                |> List.forall (fun field ->
                    (field.Quantity = QuantityOmega || field.Quantity = QuantityZero)
                    && typeIsStableForValidationInference locals field.Type)
            | TypeUnion members ->
                members |> List.forall (typeIsStableForValidationInference locals)

        let canCompareInferredValidationTypes locals expectedType actualType =
            not (typeContainsLocalTermVariable locals expectedType)
            && not (typeContainsLocalTermVariable locals actualType)
            && typeIsStableForValidationInference locals expectedType
            && typeIsStableForValidationInference locals actualType

        let rec tryValidationTypeShape typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, _) ->
                Some("name:" + (String.concat "." nameSegments))
            | TypeApply(callee, _) ->
                tryValidationTypeShape callee
            | TypeCapture(inner, _) ->
                tryValidationTypeShape inner
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                tryValidationTypeShape inner
            | TypeArrow _ ->
                Some("arrow")
            | TypeIntrinsic intrinsic ->
                Some("intrinsic:" + string intrinsic)
            | TypeRecord _ ->
                Some("record")
            | TypeUnion _ ->
                Some("union")
            | TypeEffectRow _ ->
                Some("effect-row")
            | TypeUniverse _ ->
                Some("universe")
            | TypeLevelLiteral _ ->
                Some("type-literal")
            | TypeVariable _
            | TypeLambda _
            | TypeProject _
            | TypeEquality _ ->
                None

        let canCompareDistinctValidationShapes expectedType actualType =
            let normalizedExpected = normalizeTypeAliases environment.VisibleTypeAliases expectedType
            let normalizedActual = normalizeTypeAliases environment.VisibleTypeAliases actualType

            if isCompileTimeArgumentType environment.VisibleTypeAliases normalizedExpected
               || isCompileTimeArgumentType environment.VisibleTypeAliases normalizedActual
               || (tryTraitConstraintFromType environment normalizedExpected |> Option.isSome)
               || (tryTraitConstraintFromType environment normalizedActual |> Option.isSome) then
                false
            else
                match tryValidationTypeShape normalizedExpected, tryValidationTypeShape normalizedActual with
                | Some expectedShape, Some actualShape when not (String.Equals(expectedShape, actualShape, StringComparison.Ordinal)) ->
                    true
                | _ ->
                    false

        let rec typeIsCallableLikeForValidation typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeCapture(innerType, _) ->
                typeIsCallableLikeForValidation innerType
            | normalizedType ->
                isCallableValidationType environment.VisibleTypeAliases normalizedType

        let canCompareDirectLocalNameArgumentTypes locals argument expectedType actualType =
            match argument with
            | Name [ name ]
                when Map.containsKey name locals
                     || environment.VisibleBindings.ContainsKey(name)
                     || environment.VisibleConstructors.ContainsKey(name) ->
                typeIsCallableLikeForValidation expectedType
                && typeIsCallableLikeForValidation actualType
            | _ ->
                false

        let needsDependentTransportComparison locals expectedType actualType =
            typeIsStableForValidationInference locals expectedType
            && typeContainsLocalTermVariable locals actualType

        let trySuspensionInner typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(([ "Thunk" ] | [ "std"; "prelude"; "Thunk" ]), [ inner ]) ->
                Some inner
            | TypeName(([ "Need" ] | [ "std"; "prelude"; "Need" ]), [ inner ]) ->
                Some inner
            | _ ->
                None

        let tryUnionMembers typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeUnion members -> Some members
            | _ -> None

        let rec expectedTypeAccepts locals refinements expectedType actualType =
            let expectedType = normalizeExpectedType refinements expectedType
            let actualType = normalizeExpectedType refinements actualType

            if TypeSignatures.definitionallyEqual expectedType actualType then
                true
            else
                match trySuspensionInner expectedType with
                | Some innerType ->
                    expectedTypeAccepts locals refinements innerType actualType
                | None ->
                    match expectedType, actualType with
                    | TypeArrow(expectedQuantity, expectedParameter, expectedResult),
                      TypeArrow(actualQuantity, actualParameter, actualResult)
                        when TypeSignatures.definitionallyEqual expectedParameter actualParameter
                             && TypeSignatures.definitionallyEqual expectedResult actualResult
                             && ResourceModel.ResourceQuantity.satisfies
                                    (ResourceModel.ResourceQuantity.ofSurface expectedQuantity)
                                    (ResourceModel.ResourceQuantity.ofSurface actualQuantity) ->
                        true
                    | TypeRecord expectedFields, TypeRecord actualFields ->
                        let actualFieldMap =
                            actualFields
                            |> List.map (fun field -> field.Name, field)
                            |> Map.ofList

                        List.length expectedFields = List.length actualFields
                        && expectedFields
                           |> List.forall (fun expectedField ->
                               actualFieldMap
                               |> Map.tryFind expectedField.Name
                               |> Option.exists (fun actualField ->
                                   expectedField.Quantity = actualField.Quantity
                                   && expectedTypeAccepts locals refinements expectedField.Type actualField.Type))
                    | _ ->
                        match tryUnionMembers expectedType, tryUnionMembers actualType with
                        | Some expectedMembers, Some actualMembers ->
                            actualMembers
                            |> List.forall (fun actualMember ->
                                expectedMembers
                                |> List.exists (fun expectedMember ->
                                    expectedTypeAccepts locals refinements expectedMember actualMember))
                        | Some expectedMembers, None ->
                            expectedMembers
                            |> List.exists (fun expectedMember ->
                                expectedTypeAccepts locals refinements expectedMember actualType)
                        | _ when typeContainsLocalTermVariable locals expectedType
                                 || typeContainsLocalTermVariable locals actualType ->
                            false
                        | _ ->
                            tryUnifyVisibleTypes environment.VisibleTypeAliases [ expectedType, actualType ]
                            |> Option.isSome

        let bindablePayloadTypesAgree locals refinements expectedType actualType =
            match
                tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualType
            with
            | Some expectedPayload, Some actualPayload ->
                expectedTypeAccepts locals refinements expectedPayload actualPayload
            | _ ->
                false

        let expectedMismatchDiagnostic locals refinements context expectedType actualType =
            let expectedType = normalizeExpectedType refinements expectedType
            let actualType = normalizeExpectedType refinements actualType

            let message =
                if typeContainsLocalTermVariable locals expectedType
                   || typeContainsLocalTermVariable locals actualType then
                    $"{context} requires equality transport evidence for dependent expected type '{TypeSignatures.toText expectedType}', but the argument has type '{TypeSignatures.toText actualType}'."
                elif
                    match expectedType, actualType with
                    | TypeArrow _, TypeArrow _ -> true
                    | _ -> false
                then
                    $"{context} has incompatible function quantity: expected '{TypeSignatures.toText expectedType}' but found '{TypeSignatures.toText actualType}'."
                elif typeContainsUnion expectedType then
                    $"{context} does not match the expected union type '{TypeSignatures.toText expectedType}'; no valid union injection or widening applies from '{TypeSignatures.toText actualType}'."
                elif typeContainsSuspension expectedType then
                    $"{context} does not match the expected suspension type '{TypeSignatures.toText expectedType}' from expression type '{TypeSignatures.toText actualType}'."
                else
                    $"{context} type mismatch: expected '{TypeSignatures.toText expectedType}' but found '{TypeSignatures.toText actualType}'."

            makeDiagnostic DiagnosticCode.TypeEqualityMismatch message

        let expectedTypeDiagnostics locals refinements context expectedType expression =
            match tryNumericLiteralRangeDiagnostic expectedType expression with
            | Some diagnostic ->
                [ diagnostic ]
            | None ->
                match tryInferNumericExpressionTypeFromContext environment expectedType expression with
                | Some actualType when not (expectedTypeAccepts locals refinements expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals refinements context expectedType actualType ]
                | Some _ ->
                    []
                | None ->
                    match inferValidationExpressionType environment freshCounter locals expression with
                    | Some actualType when not (expectedTypeAccepts locals refinements expectedType actualType) ->
                        [ expectedMismatchDiagnostic locals refinements context expectedType actualType ]
                    | _ ->
                        []

        let bindableCarrierExpectedTypeDiagnostics locals refinements context expectedType expression =
            match expression with
            | Do statements ->
                match
                    tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                    inferValidationDoResultType environment freshCounter locals statements
                with
                | Some expectedPayload, Some actualDoResultType ->
                    let actualPayload =
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                        |> Option.defaultValue actualDoResultType

                    if expectedTypeAccepts locals refinements expectedPayload actualPayload then
                        []
                    else
                        [ expectedMismatchDiagnostic locals refinements context expectedPayload actualPayload ]
                | _ ->
                    expectedTypeDiagnostics locals refinements context expectedType expression
            | _ ->
                match inferValidationExpressionType environment freshCounter locals expression with
                | Some actualType when bindablePayloadTypesAgree locals refinements expectedType actualType ->
                    []
                | _ ->
                    expectedTypeDiagnostics locals refinements context expectedType expression

        let rec isHandlerCarrierResultType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeCapture(innerType, _) ->
                isHandlerCarrierResultType innerType
            | TypeName(_, _ :: _) ->
                true
            | _ ->
                false

        let isSimpleExpectedBodyType locals typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeIntrinsic _ ->
                true
            | TypeName(root :: _, []) ->
                not (
                    Map.containsKey root locals
                    || environment.VisibleBindings.ContainsKey(root)
                    || environment.VisibleConstructors.ContainsKey(root)
                )
            | TypeName([], []) ->
                true
            | _ ->
                false

        let fieldTypeReferences (recordInfo: RecordSurfaceInfo) (tokens: Token list) =
            let fieldNames = recordSurfaceFieldNames recordInfo
            let tokenArray = significantTokens tokens |> List.toArray
            let references = ResizeArray<string>()

            for index = 0 to tokenArray.Length - 1 do
                let token = tokenArray[index]

                if Token.isName token then
                    let name = SyntaxFacts.trimIdentifierQuotes token.Text

                    if String.Equals(name, "this", StringComparison.Ordinal)
                       && index + 2 < tokenArray.Length
                       && tokenArray[index + 1].Kind = Dot
                       && Token.isName tokenArray[index + 2] then
                        references.Add(SyntaxFacts.trimIdentifierQuotes tokenArray[index + 2].Text)
                    elif Set.contains name fieldNames then
                        references.Add(name)

            references |> Seq.toList |> List.distinct

        let expressionThisReferences expression =
            let rec loop current =
                seq {
                    match current with
                    | Name("this" :: fieldName :: _) ->
                        yield fieldName
                    | TypeSyntaxTokens _ ->
                        ()
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner ->
                        yield! loop inner
                    | LocalLet(_, value, body) ->
                        yield! loop value
                        yield! loop body
                    | LocalSignature(_, body) ->
                        yield! loop body
                    | LocalTypeAlias(_, body) ->
                        yield! loop body
                    | LocalScopedEffect(_, body) ->
                        yield! loop body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! loop label
                        yield! loop body
                        yield! loop returnClause.Body

                        for clause in operationClauses do
                            yield! loop clause.Body
                    | Lambda(_, body) ->
                        yield! loop body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! loop condition
                        yield! loop whenTrue
                        yield! loop whenFalse
                    | Match(scrutinee, cases) ->
                        yield! loop scrutinee
                        for caseClause in cases do
                            match caseClause.Guard with
                            | Some guard -> yield! loop guard
                            | None -> ()
                            yield! loop caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! loop field.Value
                    | Seal(value, _) ->
                        yield! loop value
                    | RecordUpdate(receiver, fields) ->
                        yield! loop receiver
                        for field in fields do
                            yield! loop field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! loop receiver
                        for argument in arguments do
                            yield! loop argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! loop receiver
                        for argument in navigation.Arguments do
                            yield! loop argument
                    | TagTest(receiver, _) ->
                        yield! loop receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                yield! loop value
                            | DoLetQuestion(_, value, failure) ->
                                yield! loop value
                                match failure with
                                | Some failure ->
                                    for nested in failure.Body do
                                        match nested with
                                        | DoExpression expression -> yield! loop expression
                                        | _ -> ()
                                | None -> ()
                            | DoIf(condition, _, _) ->
                                yield! loop condition
                            | DoWhile(condition, _) ->
                                yield! loop condition
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! loop inner
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! loop field.Value
                    | Apply(callee, arguments) ->
                        yield! loop callee
                        for argument in arguments do
                            yield! loop argument
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! loop left
                        yield! loop right
                    | Comprehension comprehension ->
                        yield! loop comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringInterpolation(inner, _) -> yield! loop inner
                            | StringText _ -> ()
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        ()
                }

            loop expression |> Seq.toList |> List.distinct

        let hasCycle (edges: Map<string, Set<string>>) =
            let rec visit visiting visited node =
                if Set.contains node visiting then
                    true
                elif Set.contains node visited then
                    false
                else
                    let nextVisiting = Set.add node visiting
                    let dependencies = edges |> Map.tryFind node |> Option.defaultValue Set.empty

                    dependencies
                    |> Set.exists (visit nextVisiting (Set.add node visited))

            edges |> Map.exists (fun node _ -> visit Set.empty Set.empty node)

        let validateRecordSurfaceInfo (recordInfo: RecordSurfaceInfo) =
            let duplicateDiagnostics =
                recordInfo.Fields
                |> List.countBy (fun field -> field.Name)
                |> List.choose (fun (name, count) ->
                    if count > 1 then
                        Some(makeDiagnostic DiagnosticCode.RecordDuplicateField $"Record field '{name}' is declared more than once.")
                    else
                        None)

            let fieldNames = recordSurfaceFieldNames recordInfo

            let dependencyDiagnostics =
                recordInfo.Fields
                |> List.collect (fun field ->
                    fieldTypeReferences recordInfo field.TypeTokens
                    |> List.choose (fun referencedField ->
                        if Set.contains referencedField fieldNames then
                            None
                        else
                            Some(
                                makeDiagnostic
                                    DiagnosticCode.RecordDependencyInvalid
                                    $"Record field '{field.Name}' depends on field '{referencedField}', which is not in the explicit record telescope."
                            )))

            let cycleDiagnostics =
                let dependencyMap =
                    recordInfo.Fields
                    |> List.map (fun field ->
                        field.Name,
                        fieldTypeReferences recordInfo field.TypeTokens
                        |> List.filter (fun referencedField ->
                            Set.contains referencedField fieldNames
                            && not (String.Equals(referencedField, field.Name, StringComparison.Ordinal)))
                        |> Set.ofList)
                    |> Map.ofList

                if hasCycle dependencyMap then
                    [ makeDiagnostic DiagnosticCode.RecordDependencyCycle "Record type field dependencies must be acyclic." ]
                else
                    []

            duplicateDiagnostics @ dependencyDiagnostics @ cycleDiagnostics

        let pathKey (field: SurfaceRecordUpdateField) =
            field.Path
            |> List.map (fun segment -> if segment.IsImplicit then $"@{segment.Name}" else segment.Name)
            |> String.concat "."

        let isStrictPrefix left right =
            List.length left < List.length right
            && List.forall2
                (fun (leftSegment: SurfaceRecordUpdatePathSegment) (rightSegment: SurfaceRecordUpdatePathSegment) ->
                    leftSegment.IsImplicit = rightSegment.IsImplicit
                    && String.Equals(leftSegment.Name, rightSegment.Name, StringComparison.Ordinal))
                left
                (right |> List.take (List.length left))

        let hasLacksConstraint rowName labelName =
            let parameterHasConstraint =
                definition.Parameters
                |> List.exists (fun parameter ->
                    parameter.TypeTokens
                    |> Option.map tokenText
                    |> Option.exists (fun text -> String.Equals(text, $"LacksRec {rowName} {labelName}", StringComparison.Ordinal)))

            let schemeHasConstraint =
                scheme
                |> Option.exists (fun scheme ->
                    scheme.Constraints
                    |> List.exists (fun constraintInfo ->
                        String.Equals(constraintInfo.TraitName, "LacksRec", StringComparison.Ordinal)
                        && match constraintInfo.Arguments with
                           | [ TypeVariable row; TypeVariable label ] ->
                               String.Equals(row, rowName, StringComparison.Ordinal)
                               && String.Equals(label, labelName, StringComparison.Ordinal)
                           | _ ->
                               false))

            parameterHasConstraint || schemeHasConstraint

        let validateRecordPatch locals receiver fields =
            let ordinaryFields = fields |> List.filter (fun field -> not field.IsExtension && field.Name <> "<missing>")
            let extensionFields = fields |> List.filter (fun field -> field.IsExtension && field.Name <> "<missing>")

            let projectionPatchInfo (field: SurfaceRecordUpdateField) =
                match receiver, field.Path with
                | Name [ receiverName ], [ segment ] ->
                    tryReceiverProjection environment locals receiverName segment.Name
                | _ ->
                    None

            let projectionSupportsSet (projectionInfo: ProjectionInfo) =
                match projectionInfo.Body with
                | Some(ProjectionAccessors clauses) ->
                    let clauseKinds =
                        clauses
                        |> List.map (function
                            | ProjectionGet _ -> "get"
                            | ProjectionInout _ -> "open"
                            | ProjectionSet _ -> "set"
                            | ProjectionSink _ -> "sink")
                        |> Set.ofList

                    Set.contains "set" clauseKinds || Set.contains "open" clauseKinds
                | Some _ ->
                    true
                | None ->
                    false

            let duplicatePathDiagnostics =
                ordinaryFields
                |> List.countBy pathKey
                |> List.choose (fun (path, count) ->
                    if count > 1 then
                        Some(makeDiagnostic DiagnosticCode.RecordPatchDuplicatePath $"Record patch updates path '{path}' more than once.")
                    else
                        None)

            let prefixDiagnostics =
                ordinaryFields
                |> List.allPairs ordinaryFields
                |> List.choose (fun (left, right) ->
                    if isStrictPrefix left.Path right.Path then
                        Some(
                            makeDiagnostic
                                DiagnosticCode.RecordPatchPrefixConflict
                                $"Record patch path '{pathKey left}' is a strict prefix of '{pathKey right}'."
                        )
                    else
                        None)
                |> List.distinctBy (fun diagnostic -> diagnostic.Message)

            let duplicateExtensionDiagnostics =
                extensionFields
                |> List.countBy (fun field -> field.Name)
                |> List.choose (fun (name, count) ->
                    if count > 1 then
                        Some(makeDiagnostic DiagnosticCode.RowExtensionDuplicateLabel $"Row extension label '{name}' appears more than once.")
                    else
                        None)

            let receiverRecordInfo = tryRecordInfoForExpression locals receiver

            let extensionDiagnostics =
                match receiverRecordInfo with
                | Some recordInfo ->
                    let explicitFields = recordSurfaceFieldNames recordInfo

                    extensionFields
                    |> List.choose (fun field ->
                        if Set.contains field.Name explicitFields then
                            Some(makeDiagnostic DiagnosticCode.RowExtensionExistingField $"Row extension label '{field.Name}' already exists in the receiver record.")
                        else
                            match recordInfo.RowTail with
                            | Some rowName when not (hasLacksConstraint rowName field.Name) ->
                                Some(
                                    makeDiagnostic
                                        DiagnosticCode.RowExtensionMissingLacksConstraint
                                        $"Row extension label '{field.Name}' for row '{rowName}' requires a matching LacksRec constraint."
                                )
                            | _ ->
                                None)
                | None ->
                    []

            let unknownPathDiagnostics =
                let rec validatePath (currentRecordInfo: RecordSurfaceInfo) (path: SurfaceRecordUpdatePathSegment list) =
                    match path with
                    | [] ->
                        []
                    | segment :: rest ->
                        match currentRecordInfo.Fields |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, segment.Name, StringComparison.Ordinal)) with
                        | None ->
                            [ makeDiagnostic DiagnosticCode.RecordPatchUnknownPath $"Record patch path contains unknown field '{segment.Name}'." ]
                        | Some field when List.isEmpty rest ->
                            []
                        | Some field ->
                            match tryRecordInfoFromTypeTokens field.TypeTokens with
                            | Some nestedRecordInfo -> validatePath nestedRecordInfo rest
                            | None ->
                                [ makeDiagnostic DiagnosticCode.RecordPatchUnknownPath $"Record patch path continues through non-record field '{field.Name}'." ]

                match receiverRecordInfo with
                | Some recordInfo ->
                    ordinaryFields
                    |> List.collect (fun field ->
                        match projectionPatchInfo field with
                        | Some _ -> []
                        | None -> validatePath recordInfo field.Path)
                | None ->
                    []

            let projectionPatchDiagnostics =
                ordinaryFields
                |> List.choose (fun field ->
                    projectionPatchInfo field
                    |> Option.bind (fun projectionInfo ->
                        if projectionSupportsSet projectionInfo then
                            None
                        else
                            Some(makeDiagnostic DiagnosticCode.ProjectionUpdateTargetUnsupported "Projection-section update requires an accessor/setter or selector projection.")))

            duplicatePathDiagnostics
            @ prefixDiagnostics
            @ duplicateExtensionDiagnostics
            @ extensionDiagnostics
            @ unknownPathDiagnostics
            @ projectionPatchDiagnostics

        let validateRecordLiteral (fields: SurfaceRecordLiteralField list) =
            let fieldNames = fields |> List.map (fun (field: SurfaceRecordLiteralField) -> field.Name) |> Set.ofList

            let dependencyMap =
                fields
                |> List.map (fun (field: SurfaceRecordLiteralField) ->
                    field.Name,
                    expressionThisReferences field.Value
                    |> List.filter (fun name -> Set.contains name fieldNames && not (String.Equals(name, field.Name, StringComparison.Ordinal)))
                    |> Set.ofList)
                |> Map.ofList

            if hasCycle dependencyMap then
                [ makeDiagnostic DiagnosticCode.RecordDependencyCycle "Record literal field dependencies must be acyclic." ]
            else
                []

        let validateRecordLiteralFieldValuesWithRecordInfo
            (validateNested: SurfaceExpression -> Diagnostic list)
            (recordInfo: RecordSurfaceInfo)
            (fields: SurfaceRecordLiteralField list)
            =
            fields
            |> List.collect (fun literalField ->
                match recordInfo.Fields |> List.tryFind (fun field -> String.Equals(field.Name, literalField.Name, StringComparison.Ordinal)) with
                | Some recordField ->
                    match recordField.TypeTokens |> TypeSignatures.parseType with
                    | Some fieldType when isCompileTimeArgumentType environment.VisibleTypeAliases fieldType ->
                        match tryParseTypeLikeSurfaceExpression literalField.Value with
                        | Some _ ->
                            []
                        | None ->
                            match tryResolveScopedStaticObject environment literalField.Value with
                            | Some _ ->
                                []
                            | None ->
                                validateNested literalField.Value
                    | _ ->
                        validateNested literalField.Value
                | None ->
                    validateNested literalField.Value)

        let recordInfoHasOpaqueMembers (recordInfo: RecordSurfaceInfo) =
            recordInfo.Fields |> List.exists (fun (field: RecordSurfaceFieldInfo) -> field.IsOpaque)

        let compactTokenText tokens =
            tokens
            |> significantTokens
            |> List.map (fun token -> token.Text)
            |> String.concat ""

        let fieldMentionsOpaqueMember (recordInfo: RecordSurfaceInfo) (field: RecordSurfaceFieldInfo) =
            let opaqueNames =
                recordInfo.Fields
                |> List.filter (fun (item: RecordSurfaceFieldInfo) -> item.IsOpaque)
                |> List.map (fun item -> item.Name)
                |> Set.ofList

            let compactFieldType = compactTokenText field.TypeTokens

            (fieldTypeReferences recordInfo field.TypeTokens
             |> List.exists (fun name -> Set.contains name opaqueNames))
            || (opaqueNames
                |> Set.exists (fun opaqueName -> compactFieldType.Contains($"this.{opaqueName}", StringComparison.Ordinal)))

        let expectedTypeCompactText =
            definition.ReturnTypeTokens
            |> Option.map compactTokenText
            |> Option.orElseWith (fun () ->
                scheme
                |> Option.map (fun scheme -> TypeSignatures.toText scheme.Body)
                |> Option.map (fun text -> text.Replace(" ", "")))

        let isTransparentCompileTimeField (field: RecordSurfaceFieldInfo) =
            not field.IsOpaque
            &&
                match significantTokens field.TypeTokens with
                | [ typeToken ] when Token.isName typeToken ->
                    let typeName = SyntaxFacts.trimIdentifierQuotes typeToken.Text
                    List.contains typeName [ "Type"; "Constraint"; "Quantity"; "Region"; "RecRow"; "Label" ]
                | _ ->
                    false

        let expressionOpaqueUnfoldingDiagnostic locals expression =
            let expectedText = expectedTypeCompactText |> Option.defaultValue ""

            let checkRootMember root memberName =
                tryRecordInfoForRoot locals root
                |> Option.bind (fun recordInfo ->
                    recordInfo.Fields
                    |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, memberName, StringComparison.Ordinal))
                    |> Option.bind (fun field ->
                        if fieldMentionsOpaqueMember recordInfo field then
                            let opaqueNames =
                                recordInfo.Fields
                                |> List.filter (fun (item: RecordSurfaceFieldInfo) -> item.IsOpaque)
                                |> List.map (fun item -> $"{root}.{item.Name}")

                            if opaqueNames |> List.exists (fun opaqueName -> expectedText.Contains(opaqueName, StringComparison.Ordinal)) then
                                None
                            else
                                Some(makeDiagnostic DiagnosticCode.SealOpaqueUnfolding $"Projection '{root}.{memberName}' would expose a member whose type depends on an opaque package member.")
                        else
                            None))

            match expression with
            | Name(root :: memberName :: _) ->
                checkRootMember root memberName
            | Apply(Name(root :: memberName :: _), _) ->
                checkRootMember root memberName
            | MemberAccess(Name [ root ], [ memberName ], []) ->
                checkRootMember root memberName
            | Apply(MemberAccess(Name [ root ], [ memberName ], []), _) ->
                checkRootMember root memberName
            | _ ->
                None

        let projectionMismatchDiagnostics locals root memberName (expectedText: string) =
            match tryRecordInfoForRoot locals root with
            | Some recordInfo ->
                match recordInfo.Fields |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, memberName, StringComparison.Ordinal)) with
                | Some field ->
                    if fieldMentionsOpaqueMember recordInfo field then
                        []
                    else
                        let unstableDependencies =
                            fieldTypeReferences recordInfo field.TypeTokens
                            |> List.choose (fun dependencyName ->
                                recordInfo.Fields
                                |> List.tryFind (fun candidate -> String.Equals(candidate.Name, dependencyName, StringComparison.Ordinal))
                                |> Option.filter (isTransparentCompileTimeField >> not)
                                |> Option.map (fun _ -> dependencyName))

                        if
                            unstableDependencies
                            |> List.exists (fun dependencyName -> expectedText.Contains($"{root}.{dependencyName}", StringComparison.Ordinal) |> not)
                        then
                            [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Projected field type does not match the declared result type." ]
                        else
                            []
                | None ->
                    []
            | None ->
                []

        let validateExpectedBody locals body =
            let dropDefinitionParameters typeExpr =
                let rec loop remaining current =
                    if remaining <= 0 then
                        current
                    else
                        match current with
                        | TypeArrow(_, _, resultType) -> loop (remaining - 1) resultType
                        | _ -> current

                loop effectiveParameters.Length typeExpr

            let signatureExpectedBodyType =
                effectiveScheme
                |> Option.map (fun scheme ->
                    if List.isEmpty effectiveParameters then
                        scheme.Body
                    else
                        let schemeParameterTypes, schemeResultType = TypeSignatures.schemeParts scheme

                        let rec dropLeadingOmittableParameters remaining =
                            match remaining with
                            | parameterType :: rest
                                when isCompileTimeArgumentType environment.VisibleTypeAliases parameterType
                                     || (tryTraitConstraintFromType environment parameterType |> Option.isSome) ->
                                dropLeadingOmittableParameters rest
                            | _ ->
                                remaining

                        let alignableParameterTypes =
                            dropLeadingOmittableParameters schemeParameterTypes

                        match tryAlignParameterTypesWithLayouts environment effectiveParameters alignableParameterTypes with
                        | Some(_, trailingParameterTypes) ->
                            trailingParameterTypes
                            |> List.rev
                            |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) schemeResultType
                        | None ->
                            dropDefinitionParameters scheme.Body)

            let expectedBodyType =
                definition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.orElse signatureExpectedBodyType

            let signatureReturnAnnotationDiagnostics =
                match definition.ReturnTypeTokens |> Option.bind TypeSignatures.parseType, signatureExpectedBodyType with
                | Some annotatedReturnType, Some signatureReturnType
                    when not (expectedTypeAccepts locals Map.empty signatureReturnType annotatedReturnType) ->
                    [ expectedMismatchDiagnostic locals Map.empty "Definition result annotation" signatureReturnType annotatedReturnType ]
                | _ ->
                    []

            let directSignatureLiteralDiagnostic =
                match body, definition.ReturnTypeTokens |> Option.bind tryRecordInfoFromTypeTokens with
                | RecordLiteral _, Some recordInfo when recordInfoHasOpaqueMembers recordInfo ->
                    [ makeDiagnostic DiagnosticCode.SealDirectLiteralForSignature "A record literal cannot be checked directly against a signature type; use 'seal ... as ...'." ]
                | _ ->
                    []

            let sealAscriptionDiagnostics =
                let rec loop expression =
                    match expression with
                    | Seal(value, ascriptionTokens) ->
                        let nested = loop value

                        match tryParseRecordSurfaceInfo ascriptionTokens with
                        | Some recordInfo when recordInfo.RowTail.IsSome ->
                            makeDiagnostic DiagnosticCode.SealOpenRecordAscription "The ascribed type of 'seal' must be a closed record type." :: nested
                        | _ ->
                            nested
                    | LocalLet(_, value, nestedBody) -> loop value @ loop nestedBody
                    | LocalSignature(_, nestedBody) -> loop nestedBody
                    | LocalTypeAlias(_, nestedBody) -> loop nestedBody
                    | LocalScopedEffect(_, nestedBody) -> loop nestedBody
                    | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                        loop label
                        @ loop nestedBody
                        @ loop returnClause.Body
                        @ (operationClauses |> List.collect (fun clause -> loop clause.Body))
                    | Lambda(_, nestedBody) -> loop nestedBody
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner -> loop inner
                    | IfThenElse(condition, whenTrue, whenFalse) -> loop condition @ loop whenTrue @ loop whenFalse
                    | Match(scrutinee, cases) ->
                        loop scrutinee
                        @ (cases
                           |> List.collect (fun caseClause ->
                               (caseClause.Guard |> Option.map loop |> Option.defaultValue [])
                               @ loop caseClause.Body))
                    | RecordLiteral fields -> fields |> List.collect (fun field -> loop field.Value)
                    | RecordUpdate(receiver, fields) -> loop receiver @ (fields |> List.collect (fun field -> loop field.Value))
                    | MemberAccess(receiver, _, arguments) -> loop receiver @ (arguments |> List.collect loop)
                    | SafeNavigation(receiver, navigation) -> loop receiver @ (navigation.Arguments |> List.collect loop)
                    | TagTest(receiver, _) -> loop receiver
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) -> loop inner
                    | TypeSyntaxTokens _ -> []
                    | NamedApplicationBlock fields -> fields |> List.collect (fun field -> loop field.Value)
                    | Apply(callee, arguments) -> loop callee @ (arguments |> List.collect loop)
                    | Binary(left, _, right)
                    | Elvis(left, right) -> loop left @ loop right
                    | Comprehension comprehension -> loop comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.collect (function
                            | StringInterpolation(inner, _) -> loop inner
                            | StringText _ -> [])
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _
                    | Do _ -> []

                loop body

            let opaqueUnfoldingDiagnostics =
                expressionOpaqueUnfoldingDiagnostic locals body |> Option.toList

            let projectionTypeMismatchDiagnostics =
                match body, expectedTypeCompactText with
                | Name(root :: memberName :: _), Some expectedText ->
                    projectionMismatchDiagnostics locals root memberName expectedText
                | MemberAccess(Name [ root ], [ memberName ], []), Some expectedText ->
                    projectionMismatchDiagnostics locals root memberName expectedText
                | _ ->
                    []

            let binaryExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Binary(_, _, _) when isSimpleExpectedBodyType locals (normalizeExpectedType Map.empty expectedType) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let listConsExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Binary(left, "::", right) ->
                    match normalizeExpectedType Map.empty expectedType with
                    | TypeName(([ "List" ] | [ "std"; "prelude"; "List" ]), [ expectedElementType ]) ->
                        match
                            inferValidationExpressionType environment freshCounter locals left,
                            inferValidationExpressionType environment freshCounter locals right
                        with
                        | Some headType, Some tailType ->
                            let headDiagnostics =
                                if expectedTypeAccepts locals Map.empty expectedElementType headType then
                                    []
                                else
                                    [ expectedMismatchDiagnostic locals Map.empty "List cons head" expectedElementType headType ]

                            let tailDiagnostics =
                                if expectedTypeAccepts locals Map.empty expectedType tailType then
                                    []
                                else
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.TypeEqualityMismatch
                                            $"List cons tail must have type '{TypeSignatures.toText expectedType}', but found '{TypeSignatures.toText tailType}'."
                                    ]

                            headDiagnostics @ tailDiagnostics
                        | _ ->
                            []
                    | normalizedExpectedType ->
                        [
                            makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Definition body uses list-cons syntax and therefore must have a List result type, but the declared result type is '{TypeSignatures.toText normalizedExpectedType}'."
                        ]
                | _ ->
                    []

            let staticObjectResultDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when isReifiedStaticObjectType environment.VisibleTypeAliases actualType
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let constructorAsStaticObjectDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Name [ root ]
                    when isVisibleConstructorName root
                         && TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                             typeObjectType ->
                    [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "A data constructor term cannot satisfy a Type-valued definition body; use an explicit kind-qualified type object when the type facet is intended." ]
                | _ ->
                    []

            let expectedUnionDiagnostics =
                match expectedBodyType with
                | Some expectedType when typeContainsUnion expectedType ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let contextualNumericBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, (NumericLiteral _ | Unary("-", NumericLiteral _)) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | Some _, _ ->
                    []
                | None, _ ->
                    []

            let doBlockExpectedBodySatisfied =
                match body, expectedBodyType with
                | Do statements, Some expectedType ->
                    match
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                        inferValidationDoResultType environment freshCounter locals statements
                    with
                    | Some expectedPayload, Some actualDoResultType ->
                        let actualPayload =
                            tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                            |> Option.defaultValue actualDoResultType

                        expectedTypeAccepts locals Map.empty expectedPayload actualPayload
                    | _ ->
                        false
                | _ ->
                    false

            let doBlockExpectedBodyDiagnostics =
                match body, expectedBodyType with
                | Do statements, Some expectedType when not doBlockExpectedBodySatisfied ->
                    match
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                        inferValidationDoResultType environment freshCounter locals statements
                    with
                    | Some expectedPayload, Some actualDoResultType ->
                        let actualPayload =
                            tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                            |> Option.defaultValue actualDoResultType

                        if expectedTypeAccepts locals Map.empty expectedPayload actualPayload then
                            []
                        else
                            [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedPayload actualPayload ]
                    | _ ->
                        []
                | _ ->
                    []

            let rec expectedTypeIsCallableLike typeExpr =
                match normalizeExpectedType Map.empty typeExpr with
                | TypeCapture(innerType, _) ->
                    expectedTypeIsCallableLike innerType
                | normalizedType ->
                    isCallableValidationType environment.VisibleTypeAliases normalizedType

            let lambdaExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Lambda _
                    when not (expectedTypeIsCallableLike expectedType) ->
                    match inferValidationExpressionType environment freshCounter locals body with
                    | Some actualType ->
                        [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                    | None ->
                        []
                | _ ->
                    []

            let callableExpectedBodyDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when typeIsCallableLikeForValidation expectedType
                         && (canCompareInferredValidationTypes locals expectedType actualType
                             || needsDependentTransportComparison locals expectedType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                | _ ->
                    []

            let macroExpectedBodyDiagnostics =
                match expectedBodyType, tryInferMacroAwareValidationType locals body with
                | Some expectedType, Some actualType
                    when (match body with
                          | Name _
                          | Apply _
                          | PrefixedString _ -> true
                          | _ -> false)
                         && (typeMentionsMacroReflectionType expectedType
                             || typeMentionsMacroReflectionType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                | _ ->
                    []

            let textBinaryExpectedBodyDiagnostics =
                let isTextBinarySurfaceType typeExpr =
                    match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                    | TypeName(([ "String" ] | [ "std"; "prelude"; "String" ]), [])
                    | TypeName(([ "Bytes" ] | [ "std"; "prelude"; "Bytes" ]), [])
                    | TypeName(([ "Byte" ] | [ "std"; "prelude"; "Byte" ]), [])
                    | TypeName(([ "UnicodeScalar" ] | [ "std"; "prelude"; "UnicodeScalar" ]), [])
                    | TypeName(([ "Grapheme" ] | [ "std"; "prelude"; "Grapheme" ]), [])
                    | TypeName(([ "Char" ] | [ "std"; "prelude"; "Char" ]), []) ->
                        true
                    | _ ->
                        false

                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when isTextBinarySurfaceType expectedType
                         && isTextBinarySurfaceType actualType
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                | _ ->
                    []

            let recordLiteralExpectedBodyDiagnostics =
                match expectedBodyType, body, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, RecordLiteral _, Some actualType
                    when not doBlockExpectedBodySatisfied
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty binaryExpectedBodyDiagnostics
                         && List.isEmpty listConsExpectedBodyDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty doBlockExpectedBodyDiagnostics
                         && List.isEmpty lambdaExpectedBodyDiagnostics
                         && List.isEmpty callableExpectedBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics ->
                    match normalizeTypeAliases environment.VisibleTypeAliases expectedType with
                    | TypeRecord _ ->
                        []
                    | _ ->
                        [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                | _ ->
                    []

            let generalInferredExpectedBodyDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when definition.ReturnTypeTokens.IsSome
                         && (match body with
                             | Apply _
                             | MemberAccess _
                             | SafeNavigation _ -> true
                             | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty binaryExpectedBodyDiagnostics
                         && List.isEmpty listConsExpectedBodyDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty doBlockExpectedBodyDiagnostics
                         && List.isEmpty lambdaExpectedBodyDiagnostics
                         && List.isEmpty callableExpectedBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty recordLiteralExpectedBodyDiagnostics
                         && (canCompareInferredValidationTypes locals expectedType actualType
                             || needsDependentTransportComparison locals expectedType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals Map.empty "Definition body" expectedType actualType ]
                | _ ->
                    []

            let generalExpectedBodyDiagnostics =
                match expectedBodyType with
                | Some expectedType
                    when (match body with
                          | Literal _
                          | NumericLiteral _ -> true
                          | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && isSimpleExpectedBodyType locals (normalizeExpectedType Map.empty expectedType)
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty generalInferredExpectedBodyDiagnostics ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | Some expectedType
                    when (match body with
                          | Name [ _ ] -> true
                          | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && isSimpleExpectedBodyType locals (normalizeExpectedType Map.empty expectedType)
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty generalInferredExpectedBodyDiagnostics ->
                    match inferValidationExpressionType environment freshCounter locals body with
                    | Some actualType when isSimpleExpectedBodyType locals actualType ->
                        expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                    | _ ->
                        []
                | _ ->
                    []

            directSignatureLiteralDiagnostic
            @ signatureReturnAnnotationDiagnostics
            @ sealAscriptionDiagnostics
            @ opaqueUnfoldingDiagnostics
            @ projectionTypeMismatchDiagnostics
            @ staticObjectResultDiagnostics
            @ constructorAsStaticObjectDiagnostics
            @ expectedUnionDiagnostics
            @ binaryExpectedBodyDiagnostics
            @ listConsExpectedBodyDiagnostics
            @ contextualNumericBodyDiagnostics
            @ doBlockExpectedBodyDiagnostics
            @ lambdaExpectedBodyDiagnostics
            @ callableExpectedBodyDiagnostics
            @ macroExpectedBodyDiagnostics
            @ textBinaryExpectedBodyDiagnostics
            @ recordLiteralExpectedBodyDiagnostics
            @ generalInferredExpectedBodyDiagnostics
            @ generalExpectedBodyDiagnostics

        let tryResolveComparableOperandTypes locals left right =
            let normalizeVisibleType typeExpr =
                typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases

            let trySameType leftType rightType =
                let normalizedLeftType = normalizeVisibleType leftType
                let normalizedRightType = normalizeVisibleType rightType

                if TypeSignatures.definitionallyEqual normalizedLeftType normalizedRightType then
                    Some(normalizedLeftType, normalizedRightType, leftType, rightType)
                else
                    None

            match
                inferValidationExpressionType environment freshCounter locals left,
                inferValidationExpressionType environment freshCounter locals right
            with
            | Some leftType, Some rightType ->
                trySameType leftType rightType
                |> Option.orElseWith (fun () ->
                    tryInferNumericExpressionTypeFromContext environment leftType right
                    |> Option.bind (fun contextualRightType -> trySameType leftType contextualRightType))
                |> Option.orElseWith (fun () ->
                    tryInferNumericExpressionTypeFromContext environment rightType left
                    |> Option.bind (fun contextualLeftType -> trySameType contextualLeftType rightType))
            | _ ->
                None

        let rec dropLeadingCompileTimeArguments
            (remainingForall: TypeSignatures.ForallBinder list)
            (remainingArguments: SurfaceExpression list)
            =
            match remainingForall, remainingArguments with
            | _ :: restForall, ExplicitImplicitArgument _ :: restArguments ->
                dropLeadingCompileTimeArguments restForall restArguments
            | _ ->
                remainingArguments

        let applicationExpectedArgumentDiagnostics locals refinements lexicalNames (bindingInfo: BindingSchemeInfo) arguments =
            let inferArgumentTypeForParameter parameterType argument =
                tryInferNumericExpressionTypeFromContext environment parameterType argument
                |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals argument)

            let preserveOrdinaryConstructorApplication =
                bindingInfo.ConstructorTypeName.IsSome
                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

            if preserveOrdinaryConstructorApplication then
                []
            else
                match bindingInfo.ParameterLayouts with
                | None ->
                        []
                | Some parameterLayouts ->
                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                    let runtimeArguments = dropLeadingCompileTimeArguments instantiated.Forall arguments
                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated

                    let hasApplicationOnlyArgument =
                        runtimeArguments
                        |> List.exists (function
                            | ExplicitImplicitArgument _
                            | NamedApplicationBlock _ -> true
                            | _ -> false)

                    if hasApplicationOnlyArgument then
                        []
                    else
                        match tryAlignParameterTypesWithLayouts environment parameterLayouts schemeParameterTypes with
                        | Some(parameterTypes, []) ->
                            let remainingArguments = ref runtimeArguments
                            let substitution = ref Map.empty<string, TypeExpr>
                            let diagnostics = ResizeArray<Diagnostic>()

                            for parameterLayout, rawParameterType in List.zip parameterLayouts parameterTypes do
                                let parameterType =
                                    rawParameterType
                                    |> TypeSignatures.applySubstitution !substitution

                                if parameterLayout.IsImplicit then
                                    ()
                                elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                    match !remainingArguments with
                                    | nextArgument :: rest ->
                                        remainingArguments := rest

                                        match tryParseTypeLikeSurfaceExpression nextArgument with
                                        | Some typeArgument ->
                                            substitution :=
                                                composeTypeSubstitution
                                                    !substitution
                                                    (Map.ofList [ parameterLayout.Name, typeArgument ])
                                        | None ->
                                            ()
                                    | [] ->
                                        ()
                                else
                                    match !remainingArguments with
                                    | nextArgument :: rest ->
                                        remainingArguments := rest

                                        match inferArgumentTypeForParameter parameterType nextArgument with
                                        | Some argumentType ->
                                            match tryNumericLiteralRangeDiagnostic parameterType nextArgument with
                                            | Some diagnostic ->
                                                diagnostics.Add(diagnostic)
                                            | None
                                                when (canCompareInferredValidationTypes locals parameterType argumentType
                                                      || canCompareDirectLocalNameArgumentTypes
                                                          locals
                                                          nextArgument
                                                          parameterType
                                                          argumentType
                                                      || canCompareDistinctValidationShapes parameterType argumentType
                                                      || needsDependentTransportComparison locals parameterType argumentType)
                                                     && not (expectedTypeAccepts locals refinements parameterType argumentType) ->
                                                diagnostics.Add(
                                                    expectedMismatchDiagnostic
                                                        locals
                                                        refinements
                                                        "Application argument"
                                                        parameterType
                                                        argumentType
                                                )
                                            | None ->
                                                match tryParseTypeLikeSurfaceExpression nextArgument with
                                                | Some termArgument ->
                                                    substitution :=
                                                        composeTypeSubstitution
                                                            !substitution
                                                            (Map.ofList [ parameterLayout.Name, termArgument ])
                                                | None ->
                                                    match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                                    | Some inferredSubstitution ->
                                                        substitution :=
                                                            composeTypeSubstitution
                                                                !substitution
                                                                inferredSubstitution
                                                    | None ->
                                                        ()
                                        | None ->
                                            ()
                                    | [] ->
                                        ()

                            List.ofSeq diagnostics
                        | Some _
                        | None ->
                            []

        let localApplicationExpectedArgumentDiagnostics locals refinements calleeType arguments =
            let inferArgumentTypeForParameter parameterType argument =
                tryInferNumericExpressionTypeFromContext environment parameterType argument
                |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals argument)

            let hasApplicationOnlyArgument =
                arguments
                |> List.exists (function
                    | ExplicitImplicitArgument _
                    | NamedApplicationBlock _ -> true
                    | _ -> false)

            if hasApplicationOnlyArgument then
                []
            else
                let parameterTypes, _ = TypeSignatures.functionParts calleeType

                List.zip (parameterTypes |> List.truncate arguments.Length) (arguments |> List.truncate parameterTypes.Length)
                |> List.choose (fun (parameterType, argument) ->
                    match inferArgumentTypeForParameter parameterType argument with
                    | Some argumentType ->
                        match tryNumericLiteralRangeDiagnostic parameterType argument with
                        | Some diagnostic ->
                            Some diagnostic
                        | None
                            when (canCompareInferredValidationTypes locals parameterType argumentType
                                  || canCompareDirectLocalNameArgumentTypes
                                      locals
                                      argument
                                      parameterType
                                      argumentType
                                  || canCompareDistinctValidationShapes parameterType argumentType
                                  || needsDependentTransportComparison locals parameterType argumentType)
                                 && not (expectedTypeAccepts locals refinements parameterType argumentType) ->
                            Some(
                                expectedMismatchDiagnostic
                                    locals
                                    refinements
                                    "Application argument"
                                    parameterType
                                    argumentType
                            )
                        | None ->
                            None
                    | None ->
                        None)

        let siblingFallbackDiagnostics expression =
            let normalize = normalizeTypeAliases environment.VisibleTypeAliases

            let isSiblingDefinitionFallbackCandidate name =
                topLevelDefinitionsByName
                |> Map.tryFind name
                |> Option.exists (fun definition ->
                    not definition.IsPattern
                    && not (Set.contains name explicitSignatureNames))

            let tryInferSiblingParameterTypeList calleeName =
                topLevelDefinitionsByName
                |> Map.tryFind calleeName
                |> Option.bind (fun siblingDefinition ->
                    siblingDefinition.Body
                    |> Option.bind (fun siblingBody ->
                        let nextVisited = Set.singleton calleeName
                        let bodyInferredParameterTypes =
                            tryInferSiblingParameterTypesFromNumericUse nextVisited siblingDefinition.Parameters siblingBody

                        let parameterTypes =
                            siblingDefinition.Parameters
                            |> List.map (fun parameter ->
                                tryParseParameterType parameter
                                |> Option.orElseWith (fun () -> Map.tryFind parameter.Name bodyInferredParameterTypes))

                        if parameterTypes |> List.exists Option.isNone then
                            None
                        else
                            Some(parameterTypes |> List.choose id)))

            let inferDirect currentLocals currentExpression =
                inferValidationExpressionType environment (ref freshCounter.Value) currentLocals currentExpression

            let inferWithSiblingFallback currentLocals currentExpression =
                tryInferExpressionTypeWithSiblingFallback Set.empty currentLocals currentExpression

            let applyFallbackDiagnostics currentLocals lexicalNames calleeName arguments =
                if Map.containsKey calleeName currentLocals
                   || Set.contains calleeName lexicalNames
                   || not (isSiblingDefinitionFallbackCandidate calleeName) then
                    []
                else
                    let parameterDiagnostics =
                        tryInferSiblingParameterTypeList calleeName
                        |> Option.map (fun parameterTypes ->
                            parameterTypes
                            |> List.rev
                            |> List.fold (fun current parameterType ->
                                TypeArrow(QuantityOmega, parameterType, current)) unitType
                            |> fun calleeType ->
                                localApplicationExpectedArgumentDiagnostics currentLocals Map.empty calleeType arguments)
                        |> Option.defaultValue []

                    if not (List.isEmpty parameterDiagnostics) then
                        parameterDiagnostics
                    else
                        match tryInferSiblingBindingType Set.empty calleeName with
                        | Some calleeType when not (isCallableValidationType environment.VisibleTypeAliases calleeType) ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.ApplicationNonCallable
                                    $"Expression of type '{TypeSignatures.toText (normalize calleeType)}' is not callable."
                            ]
                        | Some calleeType ->
                            localApplicationExpectedArgumentDiagnostics currentLocals Map.empty calleeType arguments
                        | None ->
                            []

            let literalApplicationDiagnostics currentLocals callee =
                match inferWithSiblingFallback currentLocals callee with
                | Some calleeType when not (isCallableValidationType environment.VisibleTypeAliases calleeType) ->
                    [
                        makeDiagnostic
                            DiagnosticCode.ApplicationNonCallable
                            $"Expression of type '{TypeSignatures.toText (normalize calleeType)}' is not callable."
                    ]
                | _ ->
                    []

            let arithmeticFallbackDiagnostics currentLocals left right =
                let directLeft = inferDirect currentLocals left
                let directRight = inferDirect currentLocals right

                let isDirectNumeric typeExpr =
                    TypeSignatures.definitionallyEqual (normalize typeExpr) intType
                    || TypeSignatures.definitionallyEqual (normalize typeExpr) floatType

                let hasSiblingPlusConcreteNumericPair =
                    (match left, directRight with
                     | Name [ name ], Some rightType when isSiblingDefinitionFallbackCandidate name && isDirectNumeric rightType -> true
                     | _ -> false)
                    || (match right, directLeft with
                        | Name [ name ], Some leftType when isSiblingDefinitionFallbackCandidate name && isDirectNumeric leftType -> true
                        | _ -> false)

                if
                    (directLeft.IsSome && directRight.IsSome)
                    || not hasSiblingPlusConcreteNumericPair
                then
                    []
                else
                    match inferWithSiblingFallback currentLocals left, inferWithSiblingFallback currentLocals right with
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual (normalize leftType) intType
                             && TypeSignatures.definitionallyEqual (normalize rightType) intType ->
                        []
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual (normalize leftType) floatType
                             && TypeSignatures.definitionallyEqual (normalize rightType) floatType ->
                        []
                    | Some leftType, Some rightType
                        when typeIsCallableLikeForValidation leftType
                             || typeIsCallableLikeForValidation rightType ->
                        []
                    | Some leftType, Some rightType ->
                        [
                            makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Arithmetic operator operands must both be numeric, but found '{TypeSignatures.toText (normalize leftType)}' and '{TypeSignatures.toText (normalize rightType)}'."
                        ]
                    | _ ->
                        []

            let rec validateExpression currentLocals lexicalNames current =
                let recurse = validateExpression currentLocals lexicalNames

                match current with
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | InoutArgument inner
                | Unary(_, inner)
                | Seal(inner, _) ->
                    recurse inner
                | TypeSyntaxTokens _ ->
                    []
                | ExplicitImplicitArgument inner ->
                    match tryParseTypeLikeSurfaceExpression inner with
                    | Some _ ->
                        []
                    | None ->
                        recurse inner
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurse label
                    @ recurse body
                    @ recurse returnClause.Body
                    @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
                | Apply(Name [ calleeName ], arguments) ->
                    (arguments |> List.collect recurse)
                    @ applyFallbackDiagnostics currentLocals lexicalNames calleeName arguments
                | Apply((Literal _ | NumericLiteral _) as callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | Apply(callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | LocalLet(binding, value, body) ->
                    let valueType = inferWithSiblingFallback currentLocals value
                    let nextLocals =
                        match valueType with
                        | Some inferredType ->
                            extendBindingLocalTypes
                                environment
                                (ref freshCounter.Value)
                                currentLocals
                                binding
                                (Some inferredType)
                        | None ->
                            currentLocals

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    recurse value @ validateExpression nextLocals nextLexicalNames body
                | LocalSignature(declaration, body) ->
                    let nextLocals =
                        declaration.TypeTokens
                        |> TypeSignatures.parseType
                        |> Option.map (fun declarationType -> Map.add declaration.Name declarationType currentLocals)
                        |> Option.defaultValue currentLocals

                    validateExpression nextLocals (Set.add declaration.Name lexicalNames) body
                | LocalTypeAlias(_, body) ->
                    validateExpression currentLocals lexicalNames body
                | LocalScopedEffect(_, body) ->
                    validateExpression currentLocals lexicalNames body
                | Lambda(parameters, body) ->
                    let nextLocals =
                        parameters
                        |> List.fold (fun state parameter ->
                            let parameterType =
                                tryParseParameterType parameter
                                |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}")

                            Map.add parameter.Name parameterType state) currentLocals

                    let nextLexicalNames =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union lexicalNames

                    validateExpression nextLocals nextLexicalNames body
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurse condition
                    @ validateExpression currentLocals lexicalNames whenTrue
                    @ validateExpression currentLocals lexicalNames whenFalse
                | Match(scrutinee, cases) ->
                    let scrutineeType = inferWithSiblingFallback currentLocals scrutinee

                    recurse scrutinee
                    @ (cases
                       |> List.collect (fun caseClause ->
                           let caseLocals =
                               extendPatternLocalTypes
                                   environment
                                   (ref freshCounter.Value)
                                   currentLocals
                                   scrutineeType
                                   caseClause.Pattern

                           let caseLexicalNames =
                               collectPatternNames caseClause.Pattern
                               |> Set.ofList
                               |> Set.union lexicalNames

                           (caseClause.Guard
                            |> Option.map (validateExpression caseLocals caseLexicalNames)
                            |> Option.defaultValue [])
                           @ validateExpression caseLocals caseLexicalNames caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | RecordUpdate(receiver, fields) ->
                    recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurse receiver @ (arguments |> List.collect recurse)
                | SafeNavigation(receiver, navigation) ->
                    recurse receiver @ (navigation.Arguments |> List.collect recurse)
                | TagTest(receiver, _) ->
                    recurse receiver
                | Do statements ->
                    validateDo currentLocals lexicalNames statements
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    recurse left @ recurse right @ arithmeticFallbackDiagnostics currentLocals left right
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurse left @ recurse right
                | Comprehension comprehension ->
                    validateExpression currentLocals lexicalNames comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.collect (function
                        | StringText _ -> []
                        | StringInterpolation(inner, _) -> recurse inner)
                | NamedApplicationBlock fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    []

            and validateDo currentLocals lexicalNames statements =
                match statements with
                | [] ->
                    []
                | statement :: rest ->
                    match statement with
                    | DoLet(binding, value) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some inferredType)
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoBind(binding, value) ->
                        let directSourceType = inferDirect currentLocals value
                        let shouldFallback =
                            match value with
                            | Name [ name ] when isSiblingDefinitionFallbackCandidate name -> true
                            | _ -> false

                        let fallbackSourceType =
                            if directSourceType.IsSome || not shouldFallback then
                                None
                            else
                                inferWithSiblingFallback currentLocals value

                        let bindDiagnostics =
                            match fallbackSourceType with
                            | Some sourceType when tryUnwrapBindablePayloadType environment.VisibleTypeAliases sourceType |> Option.isNone ->
                                [
                                    makeDiagnostic
                                        DiagnosticCode.TypeEqualityMismatch
                                        $"A '<-' do binding requires a bindable carrier value, but found '{TypeSignatures.toText sourceType}'."
                                ]
                            | _ ->
                                []

                        let nextLocals =
                            match fallbackSourceType |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases) with
                            | Some payloadType ->
                                extendPatternLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    (Some payloadType)
                                    binding.Pattern
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ bindDiagnostics
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoLetQuestion(binding, value, failure) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some inferredType)
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        let failureDiagnostics =
                            failure
                            |> Option.map (fun block -> validateDo currentLocals lexicalNames block.Body)
                            |> Option.defaultValue []

                        validateExpression currentLocals lexicalNames value
                        @ failureDiagnostics
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoUsing(binding, value) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some(unwrapIoType inferredType))
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoVar(bindingName, value) ->
                        let nextLocals =
                            match inferWithSiblingFallback currentLocals value with
                            | Some inferredType -> Map.add bindingName (refType inferredType) currentLocals
                            | None -> currentLocals

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals (Set.add bindingName lexicalNames) rest
                    | DoAssign(_, value)
                    | DoDefer value
                    | DoExpression value
                    | DoReturn value ->
                        validateExpression currentLocals lexicalNames value
                        @ validateDo currentLocals lexicalNames rest
                    | DoIf(condition, whenTrue, whenFalse) ->
                        validateExpression currentLocals lexicalNames condition
                        @ validateDo currentLocals lexicalNames whenTrue
                        @ validateDo currentLocals lexicalNames whenFalse
                        @ validateDo currentLocals lexicalNames rest
                    | DoWhile(condition, body) ->
                        validateExpression currentLocals lexicalNames condition
                        @ validateDo currentLocals lexicalNames body
                        @ validateDo currentLocals lexicalNames rest

            validateExpression localTypes parameterNames expression

        let rec validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression =
            let environment =
                { environment with
                    VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

            let recurse = validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts

            let queryUseText useMode =
                match useMode with
                | QuerySemantics.Reusable -> "Reusable"
                | QuerySemantics.OneShot -> "OneShot"

            let queryCardText card =
                match card with
                | QuerySemantics.QZero -> "QZero"
                | QuerySemantics.QOne -> "QOne"
                | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                | QuerySemantics.QOneOrMore -> "QOneOrMore"
                | QuerySemantics.QZeroOrMore -> "QZeroOrMore"

            let rec comprehensionRemainderReferencesName target shadowed (comprehension: SurfaceComprehension) =
                let rec expressionReferences currentShadowed current =
                    match current with
                    | Name(root :: _) ->
                        String.Equals(root, target, StringComparison.Ordinal)
                        && not (Set.contains root currentShadowed)
                    | Name [] ->
                        false
                    | TypeSyntaxTokens _ ->
                        false
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        expressionReferences currentShadowed inner
                    | LocalLet(binding, value, body) ->
                        expressionReferences currentShadowed value
                        || expressionReferences
                            (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                            body
                    | LocalSignature(declaration, body) ->
                        expressionReferences (Set.add declaration.Name currentShadowed) body
                    | LocalTypeAlias(_, body)
                    | LocalScopedEffect(_, body)
                    | Lambda(_, body) ->
                        expressionReferences currentShadowed body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        expressionReferences currentShadowed label
                        || expressionReferences currentShadowed body
                        || expressionReferences currentShadowed returnClause.Body
                        || (operationClauses |> List.exists (fun clause -> expressionReferences currentShadowed clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        expressionReferences currentShadowed condition
                        || expressionReferences currentShadowed whenTrue
                        || expressionReferences currentShadowed whenFalse
                    | Match(scrutinee, cases) ->
                        expressionReferences currentShadowed scrutinee
                        || (cases
                            |> List.exists (fun caseClause ->
                                let caseShadowed =
                                    Set.union currentShadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                                (caseClause.Guard |> Option.exists (expressionReferences caseShadowed))
                                || expressionReferences caseShadowed caseClause.Body))
                    | RecordLiteral fields ->
                        fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value)
                    | Seal(value, _) ->
                        expressionReferences currentShadowed value
                    | RecordUpdate(receiver, fields) ->
                        expressionReferences currentShadowed receiver
                        || (fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        expressionReferences currentShadowed receiver
                        || (arguments |> List.exists (expressionReferences currentShadowed))
                    | SafeNavigation(receiver, navigation) ->
                        expressionReferences currentShadowed receiver
                        || (navigation.Arguments |> List.exists (expressionReferences currentShadowed))
                    | TagTest(receiver, _) ->
                        expressionReferences currentShadowed receiver
                    | Do statements ->
                        statements
                        |> List.exists (function
                            | DoLet(binding, value)
                            | DoBind(binding, value)
                            | DoUsing(binding, value) ->
                                expressionReferences currentShadowed value
                                || expressionReferences
                                    (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                    (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, value, failure) ->
                                expressionReferences currentShadowed value
                                || (failure
                                    |> Option.exists (fun failure ->
                                        failure.Body
                                        |> List.exists (function
                                            | DoExpression inner
                                            | DoReturn inner
                                            | DoDefer inner
                                            | DoVar(_, inner)
                                            | DoAssign(_, inner) -> expressionReferences currentShadowed inner
                                            | _ -> false)))
                                || expressionReferences
                                    (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                    (Literal LiteralValue.Unit)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value -> expressionReferences currentShadowed value
                            | DoIf(condition, whenTrue, whenFalse) ->
                                expressionReferences currentShadowed condition
                                || (whenTrue |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false))
                                || (whenFalse |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false))
                            | DoWhile(condition, body) ->
                                expressionReferences currentShadowed condition
                                || (body |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false)))
                    | Apply(callee, arguments) ->
                        expressionReferences currentShadowed callee
                        || (arguments |> List.exists (expressionReferences currentShadowed))
                    | NamedApplicationBlock fields ->
                        fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value)
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        expressionReferences currentShadowed left
                        || expressionReferences currentShadowed right
                    | Comprehension nested ->
                        comprehensionRemainderReferencesName target currentShadowed nested
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.exists (function
                            | StringText _ -> false
                            | StringInterpolation(inner, _) -> expressionReferences currentShadowed inner)
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        false

                let yieldReferences currentShadowed =
                    match comprehension.Yield with
                    | YieldValue value ->
                        expressionReferences currentShadowed value
                    | YieldKeyValue(key, value) ->
                        expressionReferences currentShadowed key
                        || expressionReferences currentShadowed value

                let rec loop currentShadowed clauses =
                    match clauses with
                    | [] ->
                        yieldReferences currentShadowed
                    | clause :: rest ->
                        match clause with
                        | ForClause(_, _, binding, source) ->
                            expressionReferences currentShadowed source
                            || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                        | JoinClause(binding, source, condition) ->
                            let nextShadowed =
                                Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            expressionReferences currentShadowed source
                            || expressionReferences nextShadowed condition
                            || loop nextShadowed rest
                        | LetClause(_, binding, value) ->
                            expressionReferences currentShadowed value
                            || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                        | IfClause condition ->
                            expressionReferences currentShadowed condition || loop currentShadowed rest
                        | GroupByClause(key, aggregations, intoName) ->
                            expressionReferences currentShadowed key
                            || (aggregations |> List.exists (fun field -> expressionReferences currentShadowed field.Value))
                            || loop (Set.singleton intoName) rest
                        | OrderByClause(_, key) ->
                            expressionReferences currentShadowed key || loop currentShadowed rest
                        | DistinctClause ->
                            loop currentShadowed rest
                        | DistinctByClause key ->
                            expressionReferences currentShadowed key || loop currentShadowed rest
                        | SkipClause count ->
                            expressionReferences currentShadowed count || loop currentShadowed rest
                        | TakeClause count ->
                            expressionReferences currentShadowed count || loop currentShadowed rest
                        | LeftJoinClause(binding, source, condition, intoName) ->
                            let joinShadowed =
                                Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            expressionReferences currentShadowed source
                            || expressionReferences joinShadowed condition
                            || loop (Set.add intoName currentShadowed) rest

                loop shadowed comprehension.Clauses

            let recurseComprehension (comprehension: SurfaceComprehension) =
                let normalizeVisibleType = normalizeTypeAliases environment.VisibleTypeAliases
                let validateYield currentLocals currentLexical =
                    match comprehension.Yield with
                    | YieldValue value ->
                        validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value
                    | YieldKeyValue(key, value) ->
                        validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                        @ validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value

                let rec loop currentLocals currentLexical clauses =
                    match clauses with
                    | [] ->
                        validateYield currentLocals currentLexical
                    | clause :: rest ->
                        match clause with
                        | ForClause(_, isRefutable, binding, source) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let refutableDiagnostics =
                                if not isRefutable && not (patternIsDefinitelyIrrefutable binding.Pattern) then
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.TypeEqualityMismatch
                                            "Refutable generator patterns must use 'for?'; plain 'for' requires an irrefutable pattern."
                                    ]
                                else
                                    []

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            sourceDiagnostics @ refutableDiagnostics @ loop nextLocals nextLexical rest
                        | JoinClause(binding, source, condition) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            let conditionDiagnostics =
                                validateExpressionWithFlow nextLocals refinements nextLexical aliases staticAliases constructorFacts condition

                            sourceDiagnostics @ conditionDiagnostics @ loop nextLocals nextLexical rest
                        | LetClause(_, binding, value) ->
                            let valueDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals value
                                |> Option.map (fun valueType ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some valueType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            valueDiagnostics @ loop nextLocals nextLexical rest
                        | IfClause condition ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts condition
                            @ loop currentLocals currentLexical rest
                        | GroupByClause(key, aggregations, intoName) ->
                            let aggregationDiagnostics =
                                aggregations
                                |> List.collect (fun field ->
                                    validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts field.Value)

                            let nextLocals =
                                Map.add intoName (TypeSignatures.TypeVariable $"__kappa_group_{intoName}") Map.empty

                            let nextLexical = Set.singleton intoName

                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ aggregationDiagnostics
                            @ loop nextLocals nextLexical rest
                        | OrderByClause(_, key) ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ loop currentLocals currentLexical rest
                        | DistinctClause ->
                            loop currentLocals currentLexical rest
                        | DistinctByClause key ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ loop currentLocals currentLexical rest
                        | SkipClause count ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts count
                            @ loop currentLocals currentLexical rest
                        | TakeClause count ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts count
                            @ loop currentLocals currentLexical rest
                        | LeftJoinClause(binding, source, condition, intoName) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let joinLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let joinLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            let conditionDiagnostics =
                                validateExpressionWithFlow joinLocals refinements joinLexical aliases staticAliases constructorFacts condition

                            let nextLocals =
                                Map.add intoName (TypeSignatures.TypeVariable $"__kappa_left_join_{intoName}") currentLocals

                            let nextLexical = Set.add intoName currentLexical
                            let remainderComprehension =
                                { comprehension with
                                    Clauses = rest }

                            let leakedBindingNames =
                                collectPatternNames binding.Pattern
                                |> List.distinct
                                |> List.filter (fun bindingName ->
                                    not (Set.contains bindingName currentLexical)
                                    && comprehensionRemainderReferencesName bindingName currentLexical remainderComprehension)

                            let leakDiagnostics =
                                leakedBindingNames
                                |> List.map (fun bindingName ->
                                    makeDiagnostic
                                        DiagnosticCode.NameUnresolved
                                        $"Left-join binder '{bindingName}' is not in scope after the clause; only '{intoName}' remains available.")

                            let nextLexical =
                                leakedBindingNames
                                |> Set.ofList
                                |> Set.union nextLexical

                            sourceDiagnostics @ conditionDiagnostics @ leakDiagnostics @ loop nextLocals nextLexical rest

                loop locals lexicalNames comprehension.Clauses

            let simpleClauseBinderName (tokens: Token list) =
                match tokens |> List.filter (fun token -> token.Kind <> Newline && token.Kind <> Indent && token.Kind <> Dedent) with
                | [ token ] when Token.isName token ->
                    Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                | _ ->
                    None

            let clauseBoundNames (clause: SurfaceEffectHandlerClause) =
                let argumentNames =
                    clause.ArgumentTokens
                    |> List.choose simpleClauseBinderName

                match clause.ResumptionName with
                | Some name -> name :: argumentNames
                | None -> argumentNames
                |> Set.ofList

            let rec expressionReferencesName target shadowed current =
                let recurseName = expressionReferencesName target shadowed

                let rec comprehensionReferencesName shadowed (comprehension: SurfaceComprehension) =
                    let yieldReferences currentShadowed =
                        match comprehension.Yield with
                        | YieldValue value ->
                            expressionReferencesName target currentShadowed value
                        | YieldKeyValue(key, value) ->
                            expressionReferencesName target currentShadowed key
                            || expressionReferencesName target currentShadowed value

                    let rec loop currentShadowed clauses =
                        match clauses with
                        | [] ->
                            yieldReferences currentShadowed
                        | clause :: rest ->
                            match clause with
                            | ForClause(_, _, binding, source) ->
                                expressionReferencesName target currentShadowed source
                                || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                            | JoinClause(binding, source, condition) ->
                                let nextShadowed =
                                    Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                expressionReferencesName target currentShadowed source
                                || expressionReferencesName target nextShadowed condition
                                || loop nextShadowed rest
                            | LetClause(_, binding, value) ->
                                expressionReferencesName target currentShadowed value
                                || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                            | IfClause condition ->
                                expressionReferencesName target currentShadowed condition || loop currentShadowed rest
                            | GroupByClause(key, aggregations, intoName) ->
                                expressionReferencesName target currentShadowed key
                                || (aggregations
                                    |> List.exists (fun field -> expressionReferencesName target currentShadowed field.Value))
                                || loop (Set.singleton intoName) rest
                            | OrderByClause(_, key) ->
                                expressionReferencesName target currentShadowed key || loop currentShadowed rest
                            | DistinctClause ->
                                loop currentShadowed rest
                            | DistinctByClause key ->
                                expressionReferencesName target currentShadowed key || loop currentShadowed rest
                            | SkipClause count ->
                                expressionReferencesName target currentShadowed count || loop currentShadowed rest
                            | TakeClause count ->
                                expressionReferencesName target currentShadowed count || loop currentShadowed rest
                            | LeftJoinClause(binding, source, condition, intoName) ->
                                let joinShadowed =
                                    Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                expressionReferencesName target currentShadowed source
                                || expressionReferencesName target joinShadowed condition
                                || loop (Set.add intoName currentShadowed) rest

                    loop shadowed comprehension.Clauses

                match current with
                | Name [ name ] ->
                    String.Equals(name, target, StringComparison.Ordinal)
                    && not (Set.contains name shadowed)
                | TypeSyntaxTokens _ ->
                    false
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    recurseName inner
                | LocalLet(binding, value, body) ->
                    recurseName value
                    || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) body
                | LocalSignature(declaration, body) ->
                    if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                        recurseName body
                    else
                        expressionReferencesName target (Set.add declaration.Name shadowed) body
                | LocalTypeAlias(_, body) ->
                    recurseName body
                | LocalScopedEffect(declaration, body) ->
                    if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                        false
                    else
                        recurseName body
                | Lambda(parameters, body) ->
                    let shadowedParameters =
                        parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList |> Set.union shadowed

                    expressionReferencesName target shadowedParameters body
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurseName label
                    || recurseName body
                    || expressionReferencesName target (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                    || (operationClauses
                        |> List.exists (fun clause ->
                            expressionReferencesName target (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurseName condition || recurseName whenTrue || recurseName whenFalse
                | Match(scrutinee, cases) ->
                    recurseName scrutinee
                    || (cases
                        |> List.exists (fun caseClause ->
                            let caseShadowed = Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)
                            let guardUses =
                                caseClause.Guard
                                |> Option.exists (expressionReferencesName target caseShadowed)

                            guardUses || expressionReferencesName target caseShadowed caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.exists (fun field -> recurseName field.Value)
                | Seal(value, _) ->
                    recurseName value
                | RecordUpdate(receiver, fields) ->
                    recurseName receiver || (fields |> List.exists (fun field -> recurseName field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurseName receiver || (arguments |> List.exists recurseName)
                | SafeNavigation(receiver, navigation) ->
                    recurseName receiver || (navigation.Arguments |> List.exists recurseName)
                | TagTest(receiver, _) ->
                    recurseName receiver
                | Do statements ->
                    statements
                    |> List.exists (function
                        | DoLet(binding, value)
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            recurseName value
                            || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) (Literal LiteralValue.Unit)
                        | DoLetQuestion(binding, value, failure) ->
                            recurseName value
                            || (failure
                                |> Option.exists (fun failure ->
                                    let failureShadowed =
                                        Set.union shadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                    failure.Body
                                    |> List.exists (function
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) -> expressionReferencesName target failureShadowed inner
                                        | _ -> false)))
                            || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) (Literal LiteralValue.Unit)
                        | DoVar(_, value)
                        | DoAssign(_, value)
                        | DoDefer value
                        | DoExpression value
                        | DoReturn value -> recurseName value
                        | DoIf(condition, whenTrue, whenFalse) ->
                            recurseName condition
                            || (whenTrue |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false))
                            || (whenFalse |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false))
                        | DoWhile(condition, body) ->
                            recurseName condition
                            || (body |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false)))
                | Apply(callee, arguments) ->
                    recurseName callee || (arguments |> List.exists recurseName)
                | NamedApplicationBlock fields ->
                    fields |> List.exists (fun field -> recurseName field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurseName left || recurseName right
                | Comprehension comprehension ->
                    comprehensionReferencesName shadowed comprehension
                | PrefixedString(_, parts) ->
                    parts
                    |> List.exists (function
                        | StringText _ -> false
                        | StringInterpolation(inner, _) -> recurseName inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    false

            let quoteSpliceDiagnostics inner =
                match inferValidationExpressionType environment freshCounter locals inner with
                | Some actualType ->
                    match tryUnwrapSyntaxType environment.VisibleTypeAliases actualType with
                    | Some _ ->
                        []
                    | None ->
                        match
                            actualType
                            |> tryUnwrapElabType environment.VisibleTypeAliases
                            |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases)
                        with
                        | Some _ ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    "Quote splice `${...}` requires `Syntax t`; `Elab (Syntax t)` is not run implicitly inside a quote."
                            ]
                        | None ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"Quote splice `${{...}}` requires `Syntax t`, but found '{TypeSignatures.toText actualType}'."
                            ]
                | None ->
                    []

            let topLevelSpliceTypeDiagnostics inner =
                match tryInferTopLevelSpliceResultType locals inner with
                | Some _ ->
                    []
                | None ->
                    match tryInferMacroAwareValidationType locals inner with
                    | Some actualType ->
                        [
                            makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Top-level splice `$(...)` requires `Syntax t` or `Elab (Syntax t)`, but found '{TypeSignatures.toText actualType}'."
                        ]
                    | None ->
                        []

            let rec substituteSyntaxArguments substitutions shadowed current =
                let rewrite = substituteSyntaxArguments substitutions shadowed

                match current with
                | Name [ name ] when not (Set.contains name shadowed) ->
                    substitutions |> Map.tryFind name |> Option.defaultValue current
                | TypeSyntaxTokens _ ->
                    current
                | SyntaxQuote inner ->
                    SyntaxQuote(rewrite inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(rewrite inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(rewrite inner)
                | CodeQuote inner ->
                    CodeQuote(rewrite inner)
                | CodeSplice inner ->
                    CodeSplice(rewrite inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let rewriteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = rewrite clause.Body }

                    Handle(
                        isDeep,
                        rewrite label,
                        rewrite body,
                        rewriteClause returnClause,
                        operationClauses |> List.map rewriteClause
                    )
                | Apply(callee, arguments) ->
                    Apply(rewrite callee, arguments |> List.map rewrite)
                | LocalLet(binding, value, body) ->
                    let nextShadowed =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union shadowed

                    LocalLet(binding, rewrite value, substituteSyntaxArguments substitutions nextShadowed body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, substituteSyntaxArguments substitutions (Set.add declaration.Name shadowed) body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, rewrite body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, substituteSyntaxArguments substitutions (Set.add declaration.Name shadowed) body)
                | Lambda(parameters, body) ->
                    let nextShadowed =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union shadowed

                    Lambda(parameters, substituteSyntaxArguments substitutions nextShadowed body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        rewrite scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            let caseShadowed =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union shadowed

                            { caseClause with
                                Guard = caseClause.Guard |> Option.map (substituteSyntaxArguments substitutions caseShadowed)
                                Body = substituteSyntaxArguments substitutions caseShadowed caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(rewrite value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                | TagTest(receiver, constructorName) ->
                    TagTest(rewrite receiver, constructorName)
                | Do statements ->
                    Do statements
                | MonadicSplice inner ->
                    MonadicSplice(rewrite inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(rewrite inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | InoutArgument inner ->
                    InoutArgument(rewrite inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, rewrite inner)
                | Binary(left, operatorName, right) ->
                    Binary(rewrite left, operatorName, rewrite right)
                | Elvis(left, right) ->
                    Elvis(rewrite left, rewrite right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | TypeSyntaxTokens _
                | Name _ ->
                    current

            let rec inlineSyntaxQuoteSplices current =
                let rewrite = inlineSyntaxQuoteSplices

                match current with
                | SyntaxSplice(SyntaxQuote inner) ->
                    rewrite inner
                | SyntaxQuote inner ->
                    SyntaxQuote(rewrite inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(rewrite inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(rewrite inner)
                | CodeQuote inner ->
                    CodeQuote(rewrite inner)
                | CodeSplice inner ->
                    CodeSplice(rewrite inner)
                | Apply(callee, arguments) ->
                    Apply(rewrite callee, arguments |> List.map rewrite)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let rewriteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = rewrite clause.Body }

                    Handle(
                        isDeep,
                        rewrite label,
                        rewrite body,
                        rewriteClause returnClause,
                        operationClauses |> List.map rewriteClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(binding, rewrite value, rewrite body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, rewrite body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, rewrite body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, rewrite body)
                | Lambda(parameters, body) ->
                    Lambda(parameters, rewrite body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        rewrite scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map rewrite
                                Body = rewrite caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(rewrite value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                | TagTest(receiver, constructorName) ->
                    TagTest(rewrite receiver, constructorName)
                | Do statements ->
                    Do statements
                | MonadicSplice inner ->
                    MonadicSplice(rewrite inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(rewrite inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | InoutArgument inner ->
                    InoutArgument(rewrite inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, rewrite inner)
                | Binary(left, operatorName, right) ->
                    Binary(rewrite left, operatorName, rewrite right)
                | Elvis(left, right) ->
                    Elvis(rewrite left, rewrite right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | TypeSyntaxTokens _
                | Name _ ->
                    current

            let rec tryExpandDirectSyntaxProducer visited current =
                match current with
                | SyntaxQuote inner ->
                    Some(inlineSyntaxQuoteSplices inner)
                | Apply(Name [ "pure" ], [ SyntaxQuote inner ]) ->
                    Some(inlineSyntaxQuoteSplices inner)
                | Apply(Name [ macroName ], arguments) when not (Set.contains macroName visited) ->
                    topLevelDefinitionsByName
                    |> Map.tryFind macroName
                    |> Option.bind (fun macroDefinition ->
                        match macroDefinition.Body with
                        | Some macroBody when List.length macroDefinition.Parameters = List.length arguments ->
                            let substitutions =
                                List.zip macroDefinition.Parameters arguments
                                |> List.map (fun (parameter, argument) -> parameter.Name, argument)
                                |> Map.ofList

                            let substitutedBody =
                                substituteSyntaxArguments substitutions Set.empty macroBody

                            tryExpandDirectSyntaxProducer (Set.add macroName visited) substitutedBody
                        | _ ->
                            None)
                | _ ->
                    None

            let rec countNameUses target shadowed current =
                let recurseCount = countNameUses target shadowed

                match current with
                | Name [ name ] when String.Equals(name, target, StringComparison.Ordinal) && not (Set.contains name shadowed) ->
                    1
                | Name _ ->
                    0
                | TypeSyntaxTokens _ ->
                    0
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    recurseCount inner
                | LocalLet(binding, value, body) ->
                    recurseCount value
                    + countNameUses
                        target
                        (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                        body
                | LocalSignature(declaration, body) ->
                    countNameUses target (Set.add declaration.Name shadowed) body
                | LocalTypeAlias(_, body) ->
                    recurseCount body
                | LocalScopedEffect(declaration, body) ->
                    countNameUses target (Set.add declaration.Name shadowed) body
                | Lambda(parameters, body) ->
                    let nextShadowed =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union shadowed

                    countNameUses target nextShadowed body
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurseCount label
                    + recurseCount body
                    + countNameUses target (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                    + (operationClauses
                       |> List.sumBy (fun clause ->
                           countNameUses target (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurseCount condition + recurseCount whenTrue + recurseCount whenFalse
                | Match(scrutinee, cases) ->
                    recurseCount scrutinee
                    + (cases
                       |> List.sumBy (fun caseClause ->
                           let caseShadowed =
                               Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                           let guardCount =
                               caseClause.Guard
                               |> Option.map (countNameUses target caseShadowed)
                               |> Option.defaultValue 0

                           guardCount + countNameUses target caseShadowed caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.sumBy (fun field -> recurseCount field.Value)
                | Seal(value, _) ->
                    recurseCount value
                | RecordUpdate(receiver, fields) ->
                    recurseCount receiver + (fields |> List.sumBy (fun field -> recurseCount field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurseCount receiver + (arguments |> List.sumBy recurseCount)
                | SafeNavigation(receiver, navigation) ->
                    recurseCount receiver + (navigation.Arguments |> List.sumBy recurseCount)
                | TagTest(receiver, _) ->
                    recurseCount receiver
                | Do statements ->
                    statements
                    |> List.sumBy (function
                        | DoLet(binding, value)
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            recurseCount value
                            + countNameUses
                                target
                                (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                (Literal LiteralValue.Unit)
                        | DoLetQuestion(binding, value, failure) ->
                            let failureCount =
                                failure
                                |> Option.map (fun failure ->
                                    let failureShadowed =
                                        Set.union shadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                    failure.Body
                                    |> List.sumBy (function
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) -> countNameUses target failureShadowed inner
                                        | _ -> 0))
                                |> Option.defaultValue 0

                            recurseCount value
                            + failureCount
                            + countNameUses
                                target
                                (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                (Literal LiteralValue.Unit)
                        | DoVar(_, inner)
                        | DoAssign(_, inner)
                        | DoDefer inner
                        | DoExpression inner
                        | DoReturn inner -> recurseCount inner
                        | DoIf(condition, whenTrue, whenFalse) ->
                            recurseCount condition
                            + (whenTrue |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0))
                            + (whenFalse |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0))
                        | DoWhile(condition, body) ->
                            recurseCount condition
                            + (body |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0)))
                | Apply(callee, arguments) ->
                    recurseCount callee + (arguments |> List.sumBy recurseCount)
                | NamedApplicationBlock fields ->
                    fields |> List.sumBy (fun field -> recurseCount field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurseCount left + recurseCount right
                | Comprehension comprehension ->
                    recurseCount comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.sumBy (function
                        | StringText _ -> 0
                        | StringInterpolation(inner, _) -> recurseCount inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _ ->
                    0

            let topLevelSpliceLinearityDiagnostics inner =
                match tryExpandDirectSyntaxProducer Set.empty inner with
                | Some expandedBody ->
                    let linearParameters =
                        definition.Name
                        |> Option.bind (fun name ->
                            environment.VisibleBindings
                            |> Map.tryFind name
                            |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts))
                        |> Option.defaultValue definition.Parameters

                    linearParameters
                    |> List.collect (fun parameter ->
                        match parameter.Quantity with
                        | Some QuantityOne
                        | Some QuantityAtMostOne ->
                            if countNameUses parameter.Name Set.empty expandedBody > 1 then
                                [
                                    makeDiagnostic
                                        DiagnosticCode.QttLinearOveruse
                                        $"Macro-expanded syntax uses linear binder '{parameter.Name}' more than once."
                                ]
                            else
                                []
                        | _ ->
                            [])
                | None ->
                    []

            let topLevelSpliceElabPhaseDiagnostics inner =
                let objectPhaseEscapeDiagnostic name =
                    makeDiagnostic
                        DiagnosticCode.TypeEqualityMismatch
                        $"Object-phase/runtime value '{name}' cannot be passed directly to elaboration. Quote it as Syntax or rebind it inside Elab."

                let localIsCompileTimeOnly name =
                    locals
                    |> Map.tryFind name
                    |> Option.exists typeIsMetaPhaseTransferType

                let rec loop shadowed current =
                    let recurseCurrent = loop shadowed

                    match current with
                    | Name [ name ] when not (Set.contains name shadowed) ->
                        if localIsCompileTimeOnly name then
                            []
                        elif Map.containsKey name locals || Set.contains name lexicalNames then
                            [ objectPhaseEscapeDiagnostic name ]
                        else
                            []
                    | Name _
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | TypeSyntaxTokens _ ->
                        []
                    | SyntaxQuote _ ->
                        []
                    | SyntaxSplice nested
                    | TopLevelSyntaxSplice nested
                    | CodeSplice nested
                    | MonadicSplice nested
                    | InoutArgument nested
                    | Unary(_, nested)
                    | Seal(nested, _) ->
                        recurseCurrent nested
                    | ExplicitImplicitArgument nested ->
                        match tryParseTypeLikeSurfaceExpression nested with
                        | Some _ -> []
                        | None -> recurseCurrent nested
                    | CodeQuote _ ->
                        []
                    | Apply(callee, arguments) ->
                        recurseCurrent callee @ (arguments |> List.collect recurseCurrent)
                    | LocalLet(binding, value, body) ->
                        let nextShadowed =
                            Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)

                        recurseCurrent value @ loop nextShadowed body
                    | LocalSignature(declaration, body) ->
                        loop (Set.add declaration.Name shadowed) body
                    | LocalTypeAlias(_, body) ->
                        recurseCurrent body
                    | LocalScopedEffect(declaration, body) ->
                        loop (Set.add declaration.Name shadowed) body
                    | Lambda(parameters, body) ->
                        let nextShadowed =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union shadowed

                        loop nextShadowed body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        recurseCurrent label
                        @ recurseCurrent body
                        @ loop (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                        @ (operationClauses
                           |> List.collect (fun clause ->
                               loop (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        recurseCurrent condition @ recurseCurrent whenTrue @ recurseCurrent whenFalse
                    | Match(scrutinee, cases) ->
                        recurseCurrent scrutinee
                        @ (cases
                           |> List.collect (fun caseClause ->
                               let caseShadowed =
                                   Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                               (caseClause.Guard |> Option.map (loop caseShadowed) |> Option.defaultValue [])
                               @ loop caseShadowed caseClause.Body))
                    | RecordLiteral fields ->
                        fields |> List.collect (fun field -> recurseCurrent field.Value)
                    | RecordUpdate(receiver, fields) ->
                        recurseCurrent receiver @ (fields |> List.collect (fun field -> recurseCurrent field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        recurseCurrent receiver @ (arguments |> List.collect recurseCurrent)
                    | SafeNavigation(receiver, navigation) ->
                        recurseCurrent receiver @ (navigation.Arguments |> List.collect recurseCurrent)
                    | TagTest(receiver, _) ->
                        recurseCurrent receiver
                    | Do statements ->
                        let rec loopStatements currentShadowed remaining =
                            match remaining with
                            | [] ->
                                []
                            | statement :: rest ->
                                match statement with
                                | DoLet(binding, value)
                                | DoBind(binding, value)
                                | DoUsing(binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    loop currentShadowed value @ loopStatements nextShadowed rest
                                | DoLetQuestion(binding, value, failure) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    let failureDiagnostics =
                                        failure
                                        |> Option.map (fun failure ->
                                            let failureShadowed =
                                                Set.union nextShadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                            loopStatements failureShadowed failure.Body)
                                        |> Option.defaultValue []

                                    loop currentShadowed value @ failureDiagnostics @ loopStatements nextShadowed rest
                                | DoVar(name, value) ->
                                    let nextShadowed = Set.add name currentShadowed
                                    loop currentShadowed value @ loopStatements nextShadowed rest
                                | DoAssign(_, value)
                                | DoDefer value
                                | DoExpression value
                                | DoReturn value ->
                                    loop currentShadowed value @ loopStatements currentShadowed rest
                                | DoIf(condition, whenTrue, whenFalse) ->
                                    loop currentShadowed condition
                                    @ loopStatements currentShadowed whenTrue
                                    @ loopStatements currentShadowed whenFalse
                                    @ loopStatements currentShadowed rest
                                | DoWhile(condition, body) ->
                                    loop currentShadowed condition
                                    @ loopStatements currentShadowed body
                                    @ loopStatements currentShadowed rest

                        loopStatements shadowed statements
                    | NamedApplicationBlock fields ->
                        fields |> List.collect (fun field -> recurseCurrent field.Value)
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        recurseCurrent left @ recurseCurrent right
                    | Comprehension comprehension ->
                        recurseCurrent comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.collect (function
                            | StringText _ -> []
                            | StringInterpolation(nested, _) -> recurseCurrent nested)

                loop Set.empty inner

            match expression with
            | SyntaxQuote inner ->
                recurse inner
            | SyntaxSplice inner ->
                recurse inner @ quoteSpliceDiagnostics inner
            | TopLevelSyntaxSplice inner ->
                recurse inner
                @ topLevelSpliceTypeDiagnostics inner
                @ topLevelSpliceElabPhaseDiagnostics inner
                @ topLevelSpliceLinearityDiagnostics inner
                @ (tryExtractFailElabDiagnosticMessage inner
                   |> Option.map (fun message -> [ makeDiagnostic DiagnosticCode.ElaborationFailed message ])
                   |> Option.defaultValue [])
            | TypeSyntaxTokens _ ->
                []
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let returnClauseLexicalNames =
                    Set.union lexicalNames (clauseBoundNames returnClause)

                let handledBodyType =
                    inferValidationExpressionType environment freshCounter locals body

                let handledPayloadType =
                    handledBodyType
                    |> Option.bind tryUnwrapEffType
                    |> Option.map snd
                    |> Option.defaultValue (TypeVariable $"handlePayload{freshCounter.Value}")

                let handledEffectSplit =
                    match tryResolveHandledEffectDeclaration environment label, handledBodyType with
                    | Some declaration, Some handledType ->
                        match tryUnwrapEffType handledType with
                        | Some(effectRow, payloadType) ->
                            Some(declaration, effectRow, payloadType, trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow)
                        | None ->
                            None
                    | _ ->
                        None

                let extendHandlerLocals argumentTokens argumentTypes resumptionName resumptionType currentLocals =
                    let nextLocals =
                        argumentTokens
                        |> List.mapi (fun index tokens -> tokens, argumentTypes |> List.tryItem index)
                        |> List.fold (fun state (tokens, argumentType) ->
                            match tryParseEffectHandlerArgumentName tokens, argumentType with
                            | Some name, Some currentArgumentType -> Map.add name currentArgumentType state
                            | _ -> state) currentLocals

                    match resumptionName, resumptionType with
                    | Some name, Some currentResumptionType ->
                        Map.add name currentResumptionType nextLocals
                    | _ ->
                        nextLocals

                let returnClauseLocals =
                    extendHandlerLocals returnClause.ArgumentTokens [ handledPayloadType ] None None locals

                let returnClauseType =
                    inferValidationExpressionType environment freshCounter returnClauseLocals returnClause.Body

                let splitDerivedHandlerResultType =
                    handledEffectSplit
                    |> Option.bind (fun (_, _, payloadType, splitResult) ->
                        match splitResult with
                        | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                        | _ -> None)

                let tryOperationClauseLocals (clause: SurfaceEffectHandlerClause) =
                    match tryResolveHandledEffectDeclaration environment label with
                    | Some declaration ->
                        EffectSemantics.tryFindOperation clause.OperationName declaration
                        |> Option.bind (fun operation ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.map TypeSignatures.functionParts
                            |> Option.map (fun (parameterTypes, resultType) ->
                                let resumptionResultType =
                                    if isDeep then
                                        splitDerivedHandlerResultType
                                        |> Option.orElse returnClauseType
                                    else
                                        handledBodyType

                                let resumptionType =
                                    resumptionResultType
                                    |> Option.map (fun currentResultType -> TypeArrow(QuantityOne, resultType, currentResultType))

                                extendHandlerLocals
                                    clause.ArgumentTokens
                                    parameterTypes
                                    clause.ResumptionName
                                    resumptionType
                                    locals))
                    | _ ->
                        None

                let operationClauseInfos =
                    operationClauses
                    |> List.map (fun clause ->
                        let clauseLocals = tryOperationClauseLocals clause |> Option.defaultValue locals
                        clause, clauseLocals, inferValidationExpressionType environment freshCounter clauseLocals clause.Body)

                let finalHandlerResultType =
                    splitDerivedHandlerResultType
                    |> Option.orElseWith (fun () ->
                        if isDeep then
                            returnClauseType
                            |> Option.orElseWith (fun () ->
                                operationClauseInfos
                                |> List.tryPick (fun (_, _, clauseType) -> clauseType))
                        else
                            returnClauseType)

                let operationClauseExpectedType =
                    if isDeep then
                        finalHandlerResultType
                    else
                        handledBodyType

                let handlerClauseTypeDiagnostics =
                    let carrierDiagnostics =
                        finalHandlerResultType
                        |> Option.filter (isHandlerCarrierResultType >> not)
                        |> Option.map (fun actualType ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"Handler clauses must return a carrier-applied result type 'm b', but inferred '{TypeSignatures.toText actualType}'."
                            ])
                        |> Option.defaultValue []

                    let returnDiagnostics =
                        finalHandlerResultType
                        |> Option.map (fun expectedType ->
                            bindableCarrierExpectedTypeDiagnostics
                                returnClauseLocals
                                refinements
                                "Handler return clause"
                                expectedType
                                returnClause.Body)
                        |> Option.defaultValue []

                    let operationDiagnostics =
                        match operationClauseExpectedType with
                        | Some expectedType ->
                            operationClauseInfos
                            |> List.collect (fun (clause, clauseLocals, _) ->
                                bindableCarrierExpectedTypeDiagnostics
                                    clauseLocals
                                    refinements
                                    $"Handler clause for operation '{clause.OperationName}'"
                                    expectedType
                                    clause.Body)
                        | None ->
                            []

                    carrierDiagnostics @ returnDiagnostics @ operationDiagnostics

                let handledEffectRowDiagnostics =
                    match handledEffectSplit, handledBodyType with
                    | Some(declaration, effectRow, _, SplitMismatch), _ ->
                        [
                            makeDiagnostic
                                DiagnosticCode.HandlerEffectRowMismatch
                                $"Handler for '{declaration.VisibleName}' expects the handled computation to carry label '{declaration.VisibleName}' in its effect row, but found '{TypeSignatures.toText effectRow}'."
                        ]
                    | Some(declaration, effectRow, _, SplitNeedsTailRefinement), _ ->
                        [
                            makeDiagnostic
                                DiagnosticCode.HandlerEffectRowMismatch
                                $"Handler for '{declaration.VisibleName}' cannot split label '{declaration.VisibleName}' out of open effect row '{TypeSignatures.toText effectRow}' without explicit row refinement. Mention '{declaration.VisibleName}' explicitly in the handled computation type."
                        ]
                    | Some(_, _, _, SplitResolved _), _ ->
                        []
                    | None, Some handledType when tryUnwrapEffType handledType |> Option.isNone ->
                        [
                            makeDiagnostic
                                DiagnosticCode.HandlerEffectRowMismatch
                                $"Handler expects an Eff computation, but the handled expression has type '{TypeSignatures.toText handledType}'."
                        ]
                    | _ ->
                        []

                let handlerDiagnostics =
                    match tryResolveHandledEffectDeclaration environment label with
                    | Some declaration ->
                        let declaredOperationNames =
                            declaration.Operations
                            |> List.map (fun operation -> operation.Name)
                            |> Set.ofList

                        let declaredOperationMap =
                            declaration.Operations
                            |> List.map (fun operation -> operation.Name, operation)
                            |> Map.ofList

                        let clauseGroups =
                            operationClauses
                            |> List.groupBy (fun clause -> clause.OperationName)

                        let missingDiagnostics =
                            declaration.Operations
                            |> List.choose (fun operation ->
                                if clauseGroups |> List.exists (fun (name, _) -> String.Equals(name, operation.Name, StringComparison.Ordinal)) then
                                    None
                                else
                                    Some(
                                        makeDiagnostic
                                            DiagnosticCode.HandlerClauseMissing
                                            $"Handler for '{declaration.VisibleName}' is missing a clause for operation '{operation.Name}'."
                                    ))

                        let duplicateDiagnostics =
                            clauseGroups
                            |> List.collect (fun (operationName, clauses) ->
                                if List.length clauses > 1 then
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.HandlerClauseDuplicate
                                            $"Handler for '{declaration.VisibleName}' defines more than one clause for operation '{operationName}'."
                                    ]
                                else
                                    [])

                        let unexpectedDiagnostics =
                            clauseGroups
                            |> List.collect (fun (operationName, _) ->
                                if Set.contains operationName declaredOperationNames then
                                    []
                                else
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.HandlerClauseUnexpected
                                            $"Handler for '{declaration.VisibleName}' defines a clause for undeclared operation '{operationName}'."
                                    ])

                        let resumptionDiagnostics =
                            operationClauses
                            |> List.collect (fun clause ->
                                match Map.tryFind clause.OperationName declaredOperationMap with
                                | Some operation ->
                                    let operationArity =
                                        operation.SignatureTokens
                                        |> TypeSignatures.parseType
                                        |> Option.map (qualifyVisibleTypeNames environment)
                                        |> Option.map TypeSignatures.functionParts
                                        |> Option.map (fun (parameterTypes, _) -> List.length parameterTypes)

                                    let arityDiagnostics =
                                        match operationArity with
                                        | Some expectedArity when expectedArity <> List.length clause.ArgumentTokens ->
                                            [
                                                makeDiagnostic
                                                    DiagnosticCode.HandlerClauseArityMismatch
                                                    $"Handler clause for operation '{clause.OperationName}' binds {List.length clause.ArgumentTokens} argument(s), but the effect declaration requires {expectedArity}."
                                            ]
                                        | _ ->
                                            []

                                    let resumptionUseDiagnostics =
                                        match operation.ResumptionQuantity, clause.ResumptionName with
                                        | Some QuantityZero, _
                                        | Some QuantityAtMostOne, _
                                        | None, _ ->
                                            []
                                        | Some _, Some resumptionName
                                            when not (expressionReferencesName resumptionName Set.empty clause.Body) ->
                                            [
                                                makeDiagnostic
                                                    DiagnosticCode.QttLinearDrop
                                                    $"Handler clause for operation '{clause.OperationName}' must use relevant resumption '{resumptionName}'."
                                            ]
                                        | Some _, _ ->
                                            []

                                    arityDiagnostics @ resumptionUseDiagnostics
                                | None ->
                                    [])

                        missingDiagnostics @ duplicateDiagnostics @ unexpectedDiagnostics @ resumptionDiagnostics
                    | _ ->
                        []

                recurse label
                @ recurse body
                @ validateExpressionWithFlow
                    (extendHandlerLocals returnClause.ArgumentTokens [ handledPayloadType ] None None locals)
                    refinements
                    returnClauseLexicalNames
                    aliases
                    staticAliases
                    constructorFacts
                    returnClause.Body
                @ (operationClauses
                   |> List.collect (fun clause ->
                       let clauseLexicalNames = Set.union lexicalNames (clauseBoundNames clause)
                       validateExpressionWithFlow
                           (tryOperationClauseLocals clause |> Option.defaultValue locals)
                           refinements
                           clauseLexicalNames
                           aliases
                           staticAliases
                           constructorFacts
                           clause.Body))
                @ handlerDiagnostics
                @ handlerClauseTypeDiagnostics
                @ handledEffectRowDiagnostics
            | Literal _ ->
                []
            | NumericLiteral _ ->
                []
            | KindQualifiedName(kind, nameSegments) ->
                match tryResolveScopedStaticObject environment expression with
                | Some _ ->
                    []
                | None ->
                    let kindText = kindSelectorText kind
                    let nameText = SyntaxFacts.moduleNameToText nameSegments

                    [
                        makeDiagnostic
                            DiagnosticCode.StaticObjectUnresolved
                            $"No {kindText} static object named '{nameText}' is visible."
                    ]
            | Name(root :: fieldName :: _) ->
                let receiverResolvesAsMemberCall =
                    (environment.VisibleBindings
                     |> Map.tryFind fieldName
                     |> Option.bind (fun bindingInfo -> tryBuildReceiverMethodArguments bindingInfo (Name [ root ]) [])
                     |> Option.isSome)
                    || (tryResolveTraitMemberProjection environment locals [ root; fieldName ] |> Option.isSome)
                    || ((tryPrepareVisibleTraitMemberCall
                            environment
                            (ref freshCounter.Value)
                            fieldName
                            (inferValidationExpressionType environment (ref freshCounter.Value) locals)
                            [ Name [ root ] ])
                        |> Option.isSome)

                let receiverHasStructuredProjectionTarget =
                    if receiverResolvesAsMemberCall then
                        true
                    else
                        match tryReceiverProjection environment locals root fieldName with
                        | Some _ ->
                            true
                        | None ->
                            match tryRecordInfoForRoot locals root with
                            | Some recordInfo ->
                                recordInfo.Fields
                                |> List.exists (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                            | None ->
                                possibleConstructorsForRoot aliases constructorFacts locals root
                                |> Option.isSome

                let missingFieldDiagnostics =
                    if receiverResolvesAsMemberCall then
                        []
                    else
                        match tryReceiverProjection environment locals root fieldName with
                        | Some _ ->
                            []
                        | None ->
                            match tryRecordInfoForRoot locals root with
                            | Some recordInfo
                                when recordInfo.Fields
                                     |> List.exists (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                                     |> not ->
                                [ makeDiagnostic DiagnosticCode.RecordProjectionMissingField $"Record type has no field named '{fieldName}'." ]
                            | _ ->
                                constructorProjectionDiagnostics aliases constructorFacts locals root fieldName
                let staticMemberDiagnostics =
                        match expression with
                        | Name segments ->
                            match List.rev segments with
                            | memberName :: receiverSegments when not (List.isEmpty receiverSegments) ->
                                staticConstructorIdentityDiagnostic locals (Name(List.rev receiverSegments)) memberName
                            | _ ->
                                []
                        | _ ->
                            []
                let unresolvedMemberDiagnostics =
                    let visibleRuntimeRoot =
                        environment.VisibleBindings.ContainsKey(root)
                        || environment.VisibleConstructors.ContainsKey(root)
                        || (topLevelDefinitionsByName |> Map.containsKey root)

                    let rootPreservesStaticObjectIdentity =
                        isTopLevelManifestStaticObjectRoot root
                        || environment.VisibleTypeFacets.ContainsKey(root)
                        || environment.VisibleStaticObjects.ContainsKey(root)
                        || (tryResolveScopedStaticObject environment (Name [ root ]) |> Option.isSome)

                    if allowUnresolvedCallDiagnostics
                       && visibleRuntimeRoot
                       && not rootPreservesStaticObjectIdentity
                       && not receiverHasStructuredProjectionTarget
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics then
                        [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{fieldName}' is not in scope." ]
                    else
                        []
                let unresolvedRootDiagnostics =
                    if allowUnresolvedCallDiagnostics
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics
                       && not (isVisibleQualifiedRootName locals lexicalNames root) then
                        let message =
                            if not (String.IsNullOrEmpty(root)) && Char.IsUpper(root[0]) then
                                $"Module qualifier '{root}' is not in scope."
                            else
                                $"Name '{root}' is not in scope."

                        [ makeDiagnostic DiagnosticCode.NameUnresolved message ]
                    else
                        []

                let unresolvedQualifiedMemberDiagnostics =
                    let rootNamesRuntimeValue =
                        Map.containsKey root locals
                        || Set.contains root lexicalNames
                        || Set.contains root knownValueNames
                        || String.Equals(root, "this", StringComparison.Ordinal)
                        || isTopLevelManifestStaticObjectRoot root
                        || (tryResolveScopedStaticObject environment (Name [ root ]) |> Option.isSome)

                    if allowUnresolvedCallDiagnostics
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics
                       && not rootNamesRuntimeValue
                       && isVisibleQualifiedRootName locals lexicalNames root
                       && not (qualifiedNamePreservesResolution (root :: fieldName :: [])) then
                        [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{fieldName}' is not in scope." ]
                    else
                        []

                missingFieldDiagnostics
                @ staticMemberDiagnostics
                @ unresolvedMemberDiagnostics
                @ unresolvedRootDiagnostics
                @ unresolvedQualifiedMemberDiagnostics
            | Name [ name ]
                when allowUnresolvedCallDiagnostics
                     && not (Map.containsKey name locals)
                     && not (Set.contains name lexicalNames)
                     && not (Set.contains name knownTermLikeNames) ->
                match tryResolveScopedStaticObject environment expression with
                | Some _ ->
                    []
                | None ->
                    [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{name}' is not in scope." ]
            | Name _ ->
                []
            | Comprehension comprehension ->
                recurseComprehension comprehension
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let aliasAwareEnvironment =
                    { environment with
                        VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                let declaredType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames aliasAwareEnvironment)

                let valueLocals =
                    match binding.Pattern, declaredType, value with
                    | NamePattern bindingName, Some currentDeclaredType, Lambda _ ->
                        Map.add bindingName currentDeclaredType locals
                    | _ ->
                        locals

                let inferredValueType =
                    tryInferPureElabResultType valueLocals value
                    |> Option.orElseWith (fun () ->
                        inferValidationExpressionType aliasAwareEnvironment freshCounter valueLocals value)

                let valueType =
                    declaredType
                    |> Option.orElse inferredValueType

                let compareDeclaredAndInferredTypes
                    mismatchPrefix
                    currentDeclaredType
                    currentInferredType
                    =
                    let rec dropLeadingCompileTimeTypeBinders currentType =
                        match normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases currentType with
                        | TypeLambda(_, parameterSort, body)
                            when isCompileTimeArgumentType aliasAwareEnvironment.VisibleTypeAliases parameterSort ->
                            dropLeadingCompileTimeTypeBinders body
                        | _ ->
                            currentType

                    let currentDeclaredType =
                        dropLeadingCompileTimeTypeBinders currentDeclaredType

                    let normalizedDeclaredType =
                        currentDeclaredType
                        |> qualifyVisibleTypeNames aliasAwareEnvironment
                        |> normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases

                    let normalizedInferredType =
                        currentInferredType
                        |> qualifyVisibleTypeNames aliasAwareEnvironment
                        |> normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases

                    match tryUnifyVisibleTypes aliasAwareEnvironment.VisibleTypeAliases [ currentDeclaredType, currentInferredType ] with
                    | Some _ ->
                        []
                    | None when TypeSignatures.definitionallyEqual normalizedDeclaredType normalizedInferredType ->
                        []
                    | None ->
                        [ makeDiagnostic
                              DiagnosticCode.TypeEqualityMismatch
                              $"{mismatchPrefix}: declared '{TypeSignatures.toText normalizedDeclaredType}' but inferred '{TypeSignatures.toText normalizedInferredType}'." ]

                let bindingTypeDiagnostics =
                    match declaredType, value, inferredValueType with
                    | Some currentDeclaredType, RecordLiteral _, Some currentInferredType ->
                        let recordInfo =
                            binding.TypeTokens
                            |> Option.bind tryParseRecordSurfaceInfo

                        let hasDependentFieldReferences =
                            recordInfo
                            |> Option.map (fun parsedRecordInfo ->
                                parsedRecordInfo.Fields
                                |> List.exists (fun field ->
                                    fieldTypeReferences parsedRecordInfo field.TypeTokens |> List.isEmpty |> not))
                            |> Option.defaultValue false

                        if hasDependentFieldReferences then
                            []
                        else
                            compareDeclaredAndInferredTypes
                                "Local binding value type mismatch"
                                currentDeclaredType
                                currentInferredType
                    | Some currentDeclaredType, Do statements, _ ->
                        match
                            tryUnwrapBindablePayloadType aliasAwareEnvironment.VisibleTypeAliases currentDeclaredType,
                            inferValidationDoResultType aliasAwareEnvironment freshCounter locals statements
                        with
                        | Some declaredPayloadType, Some actualDoResultType ->
                            let inferredPayloadType =
                                tryUnwrapBindablePayloadType aliasAwareEnvironment.VisibleTypeAliases actualDoResultType
                                |> Option.defaultValue actualDoResultType

                            compareDeclaredAndInferredTypes
                                "Local binding computation payload type mismatch"
                                declaredPayloadType
                                inferredPayloadType
                        | _ ->
                            []
                    | Some currentDeclaredType, _, Some currentInferredType ->
                        compareDeclaredAndInferredTypes
                            "Local binding value type mismatch"
                            currentDeclaredType
                            currentInferredType
                    | _ ->
                        []

                let nextLocals =
                    match valueType with
                    | Some valueType ->
                        extendBindingLocalTypes environment freshCounter locals binding (Some valueType)
                    | None ->
                        locals

                let rec rewriteNamedAliasUse aliasName targetName expression =
                    let rewrite = rewriteNamedAliasUse aliasName targetName

                    match expression with
                    | SyntaxQuote inner ->
                        SyntaxQuote(rewrite inner)
                    | SyntaxSplice inner ->
                        SyntaxSplice(rewrite inner)
                    | TopLevelSyntaxSplice inner ->
                        TopLevelSyntaxSplice(rewrite inner)
                    | TypeSyntaxTokens _ ->
                        expression
                    | CodeQuote inner ->
                        CodeQuote(rewrite inner)
                    | CodeSplice inner ->
                        CodeSplice(rewrite inner)
                    | Handle(isDeep, label, body, returnClause, operationClauses) ->
                        let rewriteClause (clause: SurfaceEffectHandlerClause) =
                            { clause with
                                Body = rewrite clause.Body }

                        Handle(
                            isDeep,
                            rewrite label,
                            rewrite body,
                            rewriteClause returnClause,
                            operationClauses |> List.map rewriteClause
                        )
                    | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                        Apply(Name [ targetName ], arguments |> List.map rewrite)
                    | Apply(callee, arguments) ->
                        Apply(rewrite callee, arguments |> List.map rewrite)
                    | LocalLet(nestedBinding, nestedValue, nestedBody) ->
                        let shadowsAlias =
                            collectPatternNames nestedBinding.Pattern
                            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                        LocalLet(
                            nestedBinding,
                            rewrite nestedValue,
                            if shadowsAlias then nestedBody else rewrite nestedBody
                        )
                    | LocalSignature(declaration, nestedBody) ->
                        if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                            expression
                        else
                            LocalSignature(declaration, rewrite nestedBody)
                    | LocalTypeAlias(declaration, nestedBody) ->
                        LocalTypeAlias(declaration, rewrite nestedBody)
                    | LocalScopedEffect(declaration, nestedBody) ->
                        if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                            expression
                        else
                            LocalScopedEffect(declaration, rewrite nestedBody)
                    | Lambda(parameters, nestedBody) ->
                        if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                            expression
                        else
                            Lambda(parameters, rewrite nestedBody)
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                    | Match(scrutinee, cases) ->
                        Match(
                            rewrite scrutinee,
                            cases
                            |> List.map (fun caseClause ->
                                { caseClause with
                                    Guard = caseClause.Guard |> Option.map rewrite
                                    Body = rewrite caseClause.Body })
                        )
                    | RecordLiteral fields ->
                        RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | Seal(nestedValue, ascriptionTokens) ->
                        Seal(rewrite nestedValue, ascriptionTokens)
                    | RecordUpdate(receiver, fields) ->
                        RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | MemberAccess(receiver, segments, arguments) ->
                        MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                    | SafeNavigation(receiver, navigation) ->
                        SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                    | TagTest(receiver, constructorName) ->
                        TagTest(rewrite receiver, constructorName)
                    | Do statements ->
                        Do statements
                    | MonadicSplice inner ->
                        MonadicSplice(rewrite inner)
                    | ExplicitImplicitArgument inner ->
                        ExplicitImplicitArgument(rewrite inner)
                    | NamedApplicationBlock fields ->
                        NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | InoutArgument inner ->
                        InoutArgument(rewrite inner)
                    | Unary(operatorName, inner) ->
                        Unary(operatorName, rewrite inner)
                    | Binary(left, operatorName, right) ->
                        Binary(rewrite left, operatorName, rewrite right)
                    | Elvis(left, right) ->
                        Elvis(rewrite left, rewrite right)
                    | Comprehension comprehension ->
                        Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                    | PrefixedString(prefix, parts) ->
                        PrefixedString(
                            prefix,
                            parts
                            |> List.map (function
                                | StringText text -> StringText text
                                | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                        )
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        expression

                let bodyForValidation =
                    match binding.Pattern, value with
                    | NamePattern aliasName, Name [ targetName ]
                        when (environment.VisibleBindings
                              |> Map.tryFind targetName
                              |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind targetName))
                             |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts)
                             |> Option.isSome ->
                        rewriteNamedAliasUse aliasName targetName body
                    | NamePattern aliasName, Lambda(parameters, _) ->
                        rewriteNamedApplicationAliasUse aliasName parameters body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases aliasAwareEnvironment binding.Pattern value
                let bodyForValidation = rewriteStaticObjectPathAliasUses localStaticAliases bodyForValidation
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForValidation = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForValidation

                let nextStaticAliases =
                    let shadowedNames = collectPatternNames binding.Pattern
                    let inheritedAliases = removeShadowedStaticAliases staticAliases shadowedNames

                    localStaticAliases
                    |> Map.fold (fun state segments staticObject -> Map.add segments staticObject state) inheritedAliases

                let nextLexicalNames =
                    collectPatternNames binding.Pattern
                    |> Set.ofList
                    |> Set.union lexicalNames

                let nextAliases =
                    extendStableAliases aliases binding value

                let visibleBindingSiteNames =
                    lexicalNames
                    |> Set.union parameterNames
                    |> Set.union (locals |> Map.keys |> Set.ofSeq)

                validateExpressionWithFlow valueLocals refinements lexicalNames aliases staticAliases constructorFacts value
                @ bindingTypeDiagnostics
                @ (valueType
                   |> Option.map (fun inferredType -> syntaxCarrierEscapeDiagnostics visibleBindingSiteNames inferredType value)
                   |> Option.defaultValue [])
                @ validateExpressionWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts bodyForValidation
            | LocalSignature(declaration, LocalLet(binding, value, body))
                when binding.Pattern = NamePattern declaration.Name && binding.TypeTokens.IsNone ->
                let typedBinding =
                    { binding with
                        TypeTokens = Some declaration.TypeTokens }

                validateExpressionWithFlow
                    locals
                    refinements
                    lexicalNames
                    aliases
                    staticAliases
                    constructorFacts
                    (LocalLet(typedBinding, value, body))
            | LocalSignature(declaration, body) ->
                let nextLocals =
                    declaration.TypeTokens
                    |> TypeSignatures.parseType
                    |> Option.map (fun declarationType -> Map.add declaration.Name declarationType locals)
                    |> Option.defaultValue locals

                validateExpressionWithFlow
                    nextLocals
                    refinements
                    (Set.add declaration.Name lexicalNames)
                    (Map.remove declaration.Name aliases)
                    (removeShadowedStaticAliases staticAliases [ declaration.Name ])
                    constructorFacts
                    body
            | LocalTypeAlias(declaration, body) ->
                validateExpressionWithFlow
                    locals
                    refinements
                    (Set.add declaration.Name lexicalNames)
                    (Map.remove declaration.Name aliases)
                    staticAliases
                    constructorFacts
                    (rewriteLocalTypeAliasesInSurfaceExpression environment.CurrentModuleName environment.VisibleTypeAliases expression)
            | LocalScopedEffect(declaration, body) ->
                borrowedEffectResumptionQuantityDiagnostics makeDiagnostic declaration
                @ withScopedEffectDeclaration declaration (fun () ->
                    validateExpressionWithFlow
                        locals
                        refinements
                        (Set.add declaration.Name lexicalNames)
                        (Map.remove declaration.Name aliases)
                        (removeShadowedStaticAliases staticAliases [ declaration.Name ])
                        constructorFacts
                        body)
            | Lambda(parameters, body) ->
                let nextLocals =
                    parameters
                    |> List.fold (fun state parameter ->
                        let parameterType =
                            tryParseParameterType parameter
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}")

                        Map.add parameter.Name parameterType state) locals

                let nextLexicalNames =
                    parameters
                    |> List.map (fun parameter -> parameter.Name)
                    |> Set.ofList
                    |> Set.union lexicalNames

                validateExpressionWithFlow
                    nextLocals
                    refinements
                    nextLexicalNames
                    (removeShadowedAliases aliases (parameters |> List.map (fun parameter -> parameter.Name)))
                    (removeShadowedStaticAliases staticAliases (parameters |> List.map (fun parameter -> parameter.Name)))
                    constructorFacts
                    body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                let trueRefinements, falseRefinements =
                    match condition with
                    | Name [ conditionName ] when locals |> Map.containsKey conditionName ->
                        Map.add conditionName trueTermType refinements,
                        Map.add conditionName falseTermType refinements
                    | Unary("not", Name [ conditionName ]) when locals |> Map.containsKey conditionName ->
                        Map.add conditionName falseTermType refinements,
                        Map.add conditionName trueTermType refinements
                    | _ ->
                        refinements, refinements

                let trueConstructorFacts, falseConstructorFacts =
                    conditionConstructorFacts aliases constructorFacts condition

                recurse condition
                @ (trueConstructorFacts
                   |> List.collect (fun branchFacts ->
                       validateExpressionWithFlow locals trueRefinements lexicalNames aliases staticAliases branchFacts whenTrue))
                @ (falseConstructorFacts
                   |> List.collect (fun branchFacts ->
                       validateExpressionWithFlow locals falseRefinements lexicalNames aliases staticAliases branchFacts whenFalse))
            | Match(scrutinee, cases) ->
                let scrutineeType =
                    inferValidationExpressionType environment freshCounter locals scrutinee

                let scrutineeRoot =
                    match scrutinee with
                    | Name [ root ] -> Some root
                    | _ -> None

                let rec validateCases residualFacts (remainingCases: SurfaceMatchCase list) =
                    match remainingCases with
                    | [] ->
                        []
                    | caseClause :: restCases ->
                        let caseLocals =
                            extendPatternLocalTypes environment freshCounter locals scrutineeType caseClause.Pattern

                        let caseLexicalNames =
                            collectPatternNames caseClause.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        let caseAliases =
                            removeShadowedAliases aliases (collectPatternNames caseClause.Pattern)

                        let caseStaticAliases =
                            removeShadowedStaticAliases staticAliases (collectPatternNames caseClause.Pattern)

                        let caseFacts =
                            match scrutineeRoot, tryTopLevelSurfaceConstructorPatternName caseClause.Pattern with
                            | Some root, Some constructorName ->
                                addPositiveConstructorFact aliases residualFacts root constructorName
                            | _ ->
                                residualFacts

                        let bodyFactSets =
                            match caseClause.Guard with
                            | Some guard ->
                                conditionConstructorFacts caseAliases caseFacts guard |> fst
                            | None ->
                                [ caseFacts ]

                        let caseDiagnostics =
                            validatePatternHead caseClause.Pattern
                            @ staticPatternIdentityDiagnostics locals caseClause.Pattern
                            @ activePatternLinearityDiagnostics caseClause.Pattern "match case"
                            @ (caseClause.Guard
                               |> Option.map (validateExpressionWithFlow caseLocals refinements caseLexicalNames caseAliases caseStaticAliases caseFacts)
                               |> Option.defaultValue [])
                            @ (bodyFactSets
                               |> List.collect (fun bodyFacts ->
                                   validateExpressionWithFlow caseLocals refinements caseLexicalNames caseAliases caseStaticAliases bodyFacts caseClause.Body))

                        let nextResidualFacts =
                            match scrutineeRoot, tryTopLevelSurfaceConstructorPatternName caseClause.Pattern, caseClause.Guard with
                            | Some root, Some constructorName, None ->
                                addNegativeConstructorFact aliases residualFacts root constructorName
                            | _ ->
                                residualFacts

                        caseDiagnostics @ validateCases nextResidualFacts restCases

                recurse scrutinee @ validateCases constructorFacts cases
            | RecordLiteral fields ->
                validateRecordLiteral fields @ (fields |> List.collect (fun field -> recurse field.Value))
            | Seal(RecordLiteral fields, ascriptionTokens) ->
                let nestedDiagnostics =
                    match tryParseRecordSurfaceInfo ascriptionTokens with
                    | Some recordInfo ->
                        validateRecordLiteralFieldValuesWithRecordInfo recurse recordInfo fields
                    | None ->
                        fields |> List.collect (fun field -> recurse field.Value)

                validateRecordLiteral fields @ nestedDiagnostics
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                let fieldExpectedDiagnostics =
                    match tryRecordInfoForExpression locals receiver with
                    | Some recordInfo ->
                        fields
                        |> List.collect (fun field ->
                            match field.Path with
                            | [ pathSegment ] ->
                                recordInfo.Fields
                                |> List.tryFind (fun recordField ->
                                    String.Equals(recordField.Name, pathSegment.Name, StringComparison.Ordinal))
                                |> Option.bind (fun recordField ->
                                    recordField.TypeTokens |> TypeSignatures.parseType)
                                |> Option.filter (fun expectedType ->
                                    typeContainsSuspension expectedType || typeContainsUnion expectedType)
                                |> Option.map (fun expectedType ->
                                    expectedTypeDiagnostics
                                        locals
                                        refinements
                                        $"Record update field '{field.Name}'"
                                        expectedType
                                        field.Value)
                                |> Option.defaultValue []
                            | _ ->
                                [])
                    | None ->
                        []

                recurse receiver
                @ (fields |> List.collect (fun field -> recurse field.Value))
                @ validateRecordPatch locals receiver fields
                @ fieldExpectedDiagnostics
            | MemberAccess(receiver, segments, arguments) ->
                let memberDiagnostics =
                    match segments with
                    | [ memberName ] ->
                        let receiverStaticDiagnostics =
                            staticConstructorIdentityDiagnostic locals receiver memberName

                        let receiverMethodDiagnostics =
                            match environment.VisibleBindings |> Map.tryFind memberName |> Option.bind (fun info -> info.ParameterLayouts) with
                            | Some layouts ->
                                let receiverParameters =
                                    layouts
                                    |> List.filter (fun layout -> layout.IsReceiver)

                                let precedingExplicitCount =
                                    layouts
                                    |> List.takeWhile (fun layout -> not layout.IsReceiver)
                                    |> List.filter (fun layout -> not layout.IsImplicit)
                                    |> List.length

                                let requiredExplicitArgumentCount =
                                    layouts
                                    |> List.filter (fun layout -> not layout.IsImplicit)
                                    |> List.length
                                    |> fun count -> max 0 (count - 1)

                                if List.length receiverParameters <> 1 then
                                    [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch $"Member-call sugar for '{memberName}' requires exactly one receiver binder." ]
                                elif List.length arguments < precedingExplicitCount then
                                    [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch $"Member-call sugar for '{memberName}' is missing preceding explicit argument(s)." ]
                                elif List.length arguments < requiredExplicitArgumentCount then
                                    [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch $"Member-call sugar for '{memberName}' is missing explicit argument(s)." ]
                                else
                                    []
                            | _ ->
                                []

                        let receiverProjectionDiagnostics =
                            match receiver, arguments with
                            | Name [ root ], [] ->
                                constructorProjectionDiagnostics aliases constructorFacts locals root memberName
                            | _ ->
                                []

                        let unresolvedMemberDiagnostics =
                            match inferValidationExpressionType environment freshCounter locals expression with
                            | Some _ ->
                                []
                            | None when not (List.isEmpty (receiverStaticDiagnostics @ receiverMethodDiagnostics @ receiverProjectionDiagnostics)) ->
                                []
                            | None when tryResolveScopedStaticObject environment receiver |> Option.isSome ->
                                []
                            | None ->
                                match inferValidationExpressionType environment freshCounter locals receiver with
                                | Some receiverType when not (Set.contains memberName knownValueNames) ->
                                    [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{memberName}' is not in scope." ]
                                | Some receiverType ->
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.TypeEqualityMismatch
                                            $"Member access '.{memberName}' is not well-formed for receiver type '{TypeSignatures.toText receiverType}'."
                                    ]
                                | None ->
                                    []

                        receiverStaticDiagnostics @ receiverMethodDiagnostics @ receiverProjectionDiagnostics @ unresolvedMemberDiagnostics
                    | _ ->
                        []

                recurse receiver @ (arguments |> List.collect recurse) @ memberDiagnostics
            | SafeNavigation(receiver, navigation) ->
                let receiverDiagnostics = recurse receiver
                let argumentDiagnostics = navigation.Arguments |> List.collect recurse

                let builtinDiagnostics =
                    match inferValidationExpressionType environment freshCounter locals receiver with
                    | Some receiverType ->
                        match tryOptionPayloadType environment.VisibleTypeAliases receiverType with
                        | Some payloadType ->
                            match
                                tryInferSafeNavigationMemberType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferValidationExpressionType environment freshCounter locals)
                                    payloadType
                                    navigation
                            with
                            | Some _ ->
                                []
                            | None ->
                                [ makeDiagnostic
                                      DiagnosticCode.SafeNavigationAmbiguous
                                      $"Safe-navigation `?.` requires knowing the result type of '{memberText navigation}' to decide whether to wrap or flatten." ]
                        | None ->
                            [ makeDiagnostic
                                  DiagnosticCode.SafeNavigationReceiverNotOption
                                  "Safe-navigation `?.` requires its receiver to have type `Option T` for some `T`." ]
                    | None ->
                        [ makeDiagnostic
                              DiagnosticCode.SafeNavigationAmbiguous
                              $"Safe-navigation `?.` requires knowing the result type of '{memberText navigation}' to decide whether to wrap or flatten." ]

                receiverDiagnostics @ argumentDiagnostics @ builtinDiagnostics
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts statements
            | MonadicSplice inner
            | InoutArgument inner
            | Unary(_, inner) ->
                recurse inner
            | ExplicitImplicitArgument inner ->
                match tryParseTypeLikeSurfaceExpression inner with
                | Some _ ->
                    []
                | None ->
                    recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Apply _ as application ->
                let rec collectApplicationSpine currentExpression collectedArguments =
                    match currentExpression with
                    | Apply(calleeExpression, currentArguments) ->
                        collectApplicationSpine calleeExpression (currentArguments @ collectedArguments)
                    | _ ->
                        currentExpression, collectedArguments

                let isConstructorHeadedApplication currentExpression =
                    match collectApplicationSpine currentExpression [] with
                    | Name [ calleeName ], _ -> environment.VisibleConstructors.ContainsKey(calleeName)
                    | _ -> false

                match tryMatchQueryCarrierShape application with
                | Some carrier ->
                    let metadataDiagnostics =
                        match carrier.Comprehension.CollectionKind with
                        | ListCollection ->
                            []
                        | MapCollection ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    "Query carrier is ill-formed for a map comprehension; Query cannot silently discard map metadata."
                            ]
                        | SetCollection ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    "Query carrier is ill-formed for a set comprehension; Query cannot silently discard set metadata."
                            ]

                    let compatibilityDiagnostics =
                        match
                            tryInferComprehensionPlanShape
                                environment
                                freshCounter
                                locals
                                (fun currentLocals currentExpression ->
                                    inferValidationExpressionType environment freshCounter currentLocals currentExpression)
                                carrier.Comprehension
                        with
                        | Some plan when not (QuerySemantics.canCheckUse plan.InferredMode.Use carrier.ExpectedMode.Use) ->
                            [ makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Query carrier expects a {queryUseText carrier.ExpectedMode.Use} query, but the comprehension infers {queryUseText plan.InferredMode.Use}; use OnceQuery or an explicitly one-shot QueryCore carrier." ]
                        | Some plan when not (QuerySemantics.canCheckCard plan.InferredMode.Card carrier.ExpectedMode.Card) ->
                            [ makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Query cardinality mismatch: inferred {queryCardText plan.InferredMode.Card} cannot be checked as {queryCardText carrier.ExpectedMode.Card}." ]
                        | Some plan when not (QuerySemantics.canCheckItemQuantity plan.InferredItemQuantity carrier.ExpectedItemQuantity) ->
                            [ makeDiagnostic
                                DiagnosticCode.TypeEqualityMismatch
                                $"Query item quantity mismatch: inferred item quantity '{ResourceQuantity.toSurfaceText plan.InferredItemQuantity}' cannot be checked as '{ResourceQuantity.toSurfaceText carrier.ExpectedItemQuantity}'." ]
                        | _ ->
                            []

                    recurseComprehension carrier.Comprehension @ metadataDiagnostics @ compatibilityDiagnostics
                | None ->
                    match application with
                    | Apply(callee, arguments) ->
                        let isConstructorSpine = isConstructorHeadedApplication application
                        let comprehensionSinkDiagnostics =
                            match arguments with
                            | [ Comprehension comprehension ] ->
                                let sinkType =
                                    inferValidationExpressionType environment freshCounter locals application
                                    |> Option.orElseWith (fun () ->
                                        match definition.Body, scheme with
                                        | Some bodyExpression, Some bindingScheme when bodyExpression = application ->
                                            Some(bindingScheme |> TypeSignatures.schemeParts |> snd)
                                        | _ ->
                                            None)

                                sinkType
                                |> Option.bind (fun sinkType ->
                                    tryResolveTraitConstraint sinkType "FromComprehensionRaw"
                                    |> Option.orElseWith (fun () -> tryResolveTraitConstraint sinkType "FromComprehensionPlan"))
                                |> Option.bind (fun (instanceInfo, substitution) ->
                                    tryParseInstanceAssociatedType substitution instanceInfo "Item"
                                    |> Option.bind (fun expectedItemType ->
                                        tryInferComprehensionPlanShape
                                            environment
                                            freshCounter
                                            locals
                                            (fun currentLocals currentExpression ->
                                                inferValidationExpressionType environment freshCounter currentLocals currentExpression)
                                            comprehension
                                        |> Option.map (fun plan -> expectedItemType, plan.InferredItemType)))
                                |> Option.map (fun (expectedItemType, actualItemType) ->
                                    if comprehensionSinkItemTypesEqual expectedItemType actualItemType then
                                        []
                                    else
                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TypeEqualityMismatch
                                                $"Selected comprehension sink expects Item '{TypeSignatures.toText expectedItemType}', but the yielded item type is '{TypeSignatures.toText actualItemType}'."
                                        ])
                                |> Option.defaultValue []
                            | _ ->
                                []

                        let hasNamedBlock =
                            arguments
                            |> List.exists (function
                                | NamedApplicationBlock _ -> true
                                | _ -> false)

                        let hasExplicitImplicitArgument =
                            arguments
                            |> List.exists (function
                                | ExplicitImplicitArgument _ -> true
                                | _ -> false)

                        let validateCompileTimeArgument argument =
                            match tryParseTypeLikeSurfaceExpression argument with
                            | Some _ ->
                                []
                            | None ->
                                recurse argument

                        let validateArgumentsAgainstAlignedLayouts
                            (parameterLayouts: Parameter list)
                            (parameterTypes: TypeExpr list)
                            pendingArguments
                            =
                            let parameterConsumesCompileTimeArgument (layout: Parameter) (parameterType: TypeExpr) =
                                match tryParseParameterType layout with
                                | Some declaredParameterType ->
                                    isCompileTimeArgumentType environment.VisibleTypeAliases declaredParameterType
                                | None ->
                                    isCompileTimeArgumentType environment.VisibleTypeAliases parameterType

                            let rec walk (layouts: Parameter list) (types: TypeExpr list) remainingArguments =
                                match layouts, types, remainingArguments with
                                | [], _, remaining
                                | _, [], remaining ->
                                    remaining |> List.collect recurse
                                | layout :: restLayouts, parameterType :: restTypes, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                    let consumesCompileTimeArgument =
                                        parameterConsumesCompileTimeArgument layout parameterType

                                    if consumesCompileTimeArgument then
                                        validateCompileTimeArgument explicitArgument
                                        @ walk restLayouts restTypes restArguments
                                    else
                                        recurse explicitArgument @ walk restLayouts restTypes restArguments
                                | layout :: restLayouts, parameterType :: restTypes, nextArgument :: restArguments when layout.IsImplicit ->
                                    if parameterConsumesCompileTimeArgument layout parameterType
                                       && (tryParseTypeLikeSurfaceExpression nextArgument |> Option.isSome) then
                                        validateCompileTimeArgument nextArgument
                                        @ walk restLayouts restTypes restArguments
                                    else
                                        walk restLayouts restTypes (nextArgument :: restArguments)
                                | layout :: restLayouts, parameterType :: restTypes, nextArgument :: restArguments ->
                                    let currentDiagnostics =
                                        if parameterConsumesCompileTimeArgument layout parameterType then
                                            validateCompileTimeArgument nextArgument
                                        else
                                            recurse nextArgument

                                    currentDiagnostics @ walk restLayouts restTypes restArguments
                                | _ :: restLayouts, _ :: restTypes, [] ->
                                    walk restLayouts restTypes []

                            walk parameterLayouts parameterTypes pendingArguments

                        let rec consumeLeadingCompileTimeArguments
                            (remainingForall: TypeSignatures.ForallBinder list)
                            (remainingArguments: SurfaceExpression list)
                            =
                            match remainingForall, remainingArguments with
                            | _ :: restForall, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                let currentDiagnostics = validateCompileTimeArgument explicitArgument
                                let remainingDiagnostics, finalArguments =
                                    consumeLeadingCompileTimeArguments restForall restArguments

                                currentDiagnostics @ remainingDiagnostics, finalArguments
                            | _ ->
                                [], remainingArguments

                        let argumentDiagnosticsForBindingInfo (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                let _, constructorArguments = collectApplicationSpine application []
                                constructorArguments |> List.collect recurse
                            else
                                match bindingInfo.ParameterLayouts with
                                | Some parameterLayouts ->
                                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                    let explicitTypeArgumentDiagnostics, alignedArguments =
                                        consumeLeadingCompileTimeArguments instantiated.Forall arguments

                                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated

                                    match tryAlignParameterTypesWithLayouts environment parameterLayouts schemeParameterTypes with
                                    | Some(alignedParameterTypes, []) ->
                                        explicitTypeArgumentDiagnostics
                                        @ validateArgumentsAgainstAlignedLayouts parameterLayouts alignedParameterTypes alignedArguments
                                    | Some _
                                    | None ->
                                        explicitTypeArgumentDiagnostics @ (alignedArguments |> List.collect recurse)
                                | None ->
                                    arguments |> List.collect recurse

                        let argumentDiagnosticsForLocalBindingType calleeType =
                            let parameterTypes, _ = TypeSignatures.functionParts calleeType
                            let pairedArguments =
                                List.zip
                                    (arguments |> List.truncate parameterTypes.Length)
                                    (parameterTypes |> List.truncate arguments.Length)

                            let pairedDiagnostics =
                                pairedArguments
                                |> List.collect (fun (argument, parameterType) ->
                                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        validateCompileTimeArgument argument
                                    else
                                        recurse argument)

                            let remainingDiagnostics =
                                arguments
                                |> List.skip (min arguments.Length parameterTypes.Length)
                                |> List.collect recurse

                            pairedDiagnostics @ remainingDiagnostics

                        let argumentDiagnostics =
                            if isConstructorSpine then
                                let _, constructorArguments = collectApplicationSpine application []
                                constructorArguments |> List.collect recurse
                            else
                                match callee with
                                | Name [ calleeName ] ->
                                    let isLexicallyBoundName =
                                        Map.containsKey calleeName locals || Set.contains calleeName lexicalNames

                                    let localBindingType = Map.tryFind calleeName locals

                                    let bindingInfo =
                                        if isLexicallyBoundName then
                                            None
                                        else
                                            environment.VisibleConstructors
                                            |> Map.tryFind calleeName
                                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind calleeName)

                                    match bindingInfo, localBindingType with
                                    | Some bindingInfo, _ ->
                                        argumentDiagnosticsForBindingInfo bindingInfo
                                    | None, Some localType ->
                                        argumentDiagnosticsForLocalBindingType localType
                                    | None, None
                                        when allowUnresolvedCallDiagnostics
                                             && not (Set.contains calleeName knownSurfaceTermNames)
                                             && not (Set.contains calleeName knownValueNames)
                                             && not (environment.VisibleProjections.ContainsKey(calleeName))
                                             && not (environment.ConstrainedMembers.ContainsKey(calleeName))
                                             && (tryResolveScopedStaticObject environment (Name [ calleeName ]) |> Option.isNone) ->
                                        []
                                    | _ ->
                                        arguments |> List.collect recurse
                                | _ ->
                                    let argumentDiagnostics =
                                        match inferValidationExpressionType environment (ref freshCounter.Value) locals callee with
                                        | Some calleeType ->
                                            argumentDiagnosticsForLocalBindingType calleeType
                                        | None ->
                                            arguments |> List.collect recurse

                                    recurse callee @ argumentDiagnostics

                        let runtimeRelevantParameterLayouts (bindingInfo: BindingSchemeInfo) =
                            bindingInfo.ParameterLayouts
                            |> Option.map (List.filter (fun layout ->
                                match tryParseParameterType layout with
                                | Some parameterType ->
                                    not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                | None ->
                                    true))

                        let localCanSatisfyImplicitParameter (bindingInfo: BindingSchemeInfo) =
                            match runtimeRelevantParameterLayouts bindingInfo with
                            | Some layouts when layouts |> List.exists (fun parameter -> parameter.IsImplicit) ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                if List.length layouts = List.length parameterTypes then
                                    List.zip layouts parameterTypes
                                    |> List.exists (fun (layout, parameterType) ->
                                        layout.IsImplicit
                                        && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                        && (match classifyLocalImplicitByType environment locals parameterType with
                                            | UniqueLocalImplicitCandidate _ -> true
                                            | NoLocalImplicitCandidate
                                            | AmbiguousLocalImplicitCandidates -> false))
                                else
                                    false
                            | _ ->
                                false

                        let hasAmbiguousLocalImplicitParameter (bindingInfo: BindingSchemeInfo) =
                            match runtimeRelevantParameterLayouts bindingInfo with
                            | Some layouts when layouts |> List.exists (fun parameter -> parameter.IsImplicit) ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                if List.length layouts = List.length parameterTypes then
                                    List.zip layouts parameterTypes
                                    |> List.exists (fun (layout, parameterType) ->
                                        layout.IsImplicit
                                        && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                        && (match classifyLocalImplicitByType environment locals parameterType with
                                            | AmbiguousLocalImplicitCandidates -> true
                                            | NoLocalImplicitCandidate
                                            | UniqueLocalImplicitCandidate _ -> false))
                                else
                                    false
                            | _ ->
                                false

                        let hasUnsatisfiedRuntimeImplicit (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                false
                            else
                                match bindingInfo.ParameterLayouts with
                                | Some layouts ->
                                    let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme
                                    let isTraitConstraintType parameterType =
                                        tryTraitConstraintFromType environment parameterType |> Option.isSome

                                    List.length layouts = List.length parameterTypes
                                    && (List.zip layouts parameterTypes
                                        |> List.exists (fun (layout, parameterType) ->
                                            layout.IsImplicit
                                            && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                            && not (isTraitConstraintType parameterType)
                                            && (match classifyLocalImplicitByType environment locals parameterType with
                                                | NoLocalImplicitCandidate -> true
                                                | UniqueLocalImplicitCandidate _
                                                | AmbiguousLocalImplicitCandidates -> false)))
                                | None ->
                                    false

                        let schemeOnlyImplicitTraitConstraintDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let hasApplicationOnlyArgument =
                                arguments
                                |> List.exists (function
                                    | ExplicitImplicitArgument _
                                    | NamedApplicationBlock _ -> true
                                    | _ -> false)

                            if hasApplicationOnlyArgument then
                                []
                            else
                                let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                let argumentTypes =
                                    arguments
                                    |> List.map (fun argument ->
                                        inferValidationExpressionType environment freshCounter locals argument
                                        |> Option.orElseWith (fun () ->
                                            tryInferExpressionTypeWithSiblingFallback Set.empty locals argument))

                                if argumentTypes |> List.exists Option.isNone then
                                    []
                                else
                                    let explicitArgumentTypes = argumentTypes |> List.choose id
                                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated
                                    let maxLeadingImplicitCount = List.length schemeParameterTypes - List.length explicitArgumentTypes

                                    if maxLeadingImplicitCount < 0 then
                                        []
                                    else
                                        let tryCandidate leadingImplicitCount =
                                            let leadingImplicitTypes =
                                                schemeParameterTypes |> List.take leadingImplicitCount

                                            let remainingParameterTypes =
                                                schemeParameterTypes |> List.skip leadingImplicitCount

                                            let explicitParameterTypes =
                                                remainingParameterTypes |> List.truncate explicitArgumentTypes.Length

                                            if List.length explicitParameterTypes <> List.length explicitArgumentTypes then
                                                None
                                            else
                                                tryUnifyVisibleTypes
                                                    environment.VisibleTypeAliases
                                                    (List.zip explicitParameterTypes explicitArgumentTypes)
                                                |> Option.map (fun explicitSubstitution ->
                                                    leadingImplicitTypes
                                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)
                                                    |> List.choose (fun parameterType ->
                                                        if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                                            None
                                                        else
                                                            match classifyLocalImplicitByType environment locals parameterType with
                                                            | UniqueLocalImplicitCandidate _ ->
                                                                None
                                                            | NoLocalImplicitCandidate
                                                            | AmbiguousLocalImplicitCandidates ->
                                                                match tryTraitConstraintFromType environment parameterType with
                                                                | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                                    None
                                                                | Some constraintInfo ->
                                                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                                    | ConstraintResolved _ ->
                                                                        None
                                                                    | ConstraintUnresolved ->
                                                                        Some(
                                                                            makeDiagnostic
                                                                                DiagnosticCode.TypeEqualityMismatch
                                                                                $"Implicit trait constraint '{renderTraitConstraint environment constraintInfo}' could not be resolved."
                                                                        )
                                                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                                        let candidateText =
                                                                            candidates
                                                                            |> List.map renderInstanceCandidate
                                                                            |> String.concat ", "

                                                                        Some(
                                                                            makeDiagnostic
                                                                                DiagnosticCode.TraitInstanceAmbiguous
                                                                                $"Multiple instance candidates survive for constraint '{renderTraitConstraint environment ambiguousGoal}': {candidateText}."
                                                                        )
                                                                | None ->
                                                                    None))

                                        [ maxLeadingImplicitCount .. -1 .. 0 ]
                                        |> List.tryPick (fun leadingImplicitCount ->
                                            tryCandidate leadingImplicitCount
                                            |> Option.filter (List.isEmpty >> not))
                                        |> Option.defaultValue []

                        let implicitTraitConstraintDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                []
                            else
                                match runtimeRelevantParameterLayouts bindingInfo with
                                | None ->
                                    schemeOnlyImplicitTraitConstraintDiagnostics bindingInfo
                                | Some layouts ->
                                    let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                    if List.length layouts = List.length parameterTypes then
                                        List.zip layouts parameterTypes
                                        |> List.choose (fun (layout, parameterType) ->
                                            if layout.IsImplicit
                                               && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                               && (match classifyLocalImplicitByType environment locals parameterType with
                                                   | NoLocalImplicitCandidate -> true
                                                   | UniqueLocalImplicitCandidate _
                                                   | AmbiguousLocalImplicitCandidates -> false) then
                                                match tryTraitConstraintFromType environment parameterType with
                                                | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                    None
                                                | Some constraintInfo ->
                                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                    | ConstraintResolved _ ->
                                                        None
                                                    | ConstraintUnresolved ->
                                                        Some(
                                                            makeDiagnostic
                                                                DiagnosticCode.TypeEqualityMismatch
                                                                $"Implicit trait constraint '{renderTraitConstraint environment constraintInfo}' could not be resolved."
                                                        )
                                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                        let candidateText =
                                                            candidates
                                                            |> List.map renderInstanceCandidate
                                                            |> String.concat ", "

                                                        Some(
                                                            makeDiagnostic
                                                                DiagnosticCode.TraitInstanceAmbiguous
                                                                $"Multiple instance candidates survive for constraint '{renderTraitConstraint environment ambiguousGoal}': {candidateText}."
                                                        )
                                                | None ->
                                                    None
                                            else
                                                None)
                                    else
                                        []
                        let hasTooManyArguments (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                false
                            else
                                match runtimeRelevantParameterLayouts bindingInfo with
                                | Some layouts ->
                                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                    let runtimeArguments =
                                        consumeLeadingCompileTimeArguments instantiated.Forall arguments
                                        |> snd
                                    let visibleParameterCount =
                                        layouts
                                        |> List.filter (fun parameter -> not parameter.IsImplicit)
                                        |> List.length

                                    visibleParameterCount > 0 && runtimeArguments.Length > visibleParameterCount
                                | None ->
                                    false

                        let applicationStructuralDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                []
                            else
                                let instantiatedForStructural =
                                    TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                                let structuralParameterTypes, _ =
                                    TypeSignatures.schemeParts instantiatedForStructural

                                let structuralArguments =
                                    consumeLeadingCompileTimeArguments instantiatedForStructural.Forall arguments
                                    |> snd

                                let rec walk (parameters: (Parameter * TypeExpr) list) pendingArguments =
                                    match parameters, pendingArguments with
                                    | [], [] ->
                                        []
                                    | [], _ :: _ ->
                                        [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Application argument types do not match the callee parameters." ]
                                    | (layout, parameterType) :: restParameters, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                        if not layout.IsImplicit then
                                            [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Implicit application argument could not be resolved or does not match the implicit parameter." ]
                                        else
                                            if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                                walk restParameters restArguments
                                            else
                                                match inferValidationExpressionType environment (ref freshCounter.Value) locals explicitArgument with
                                                | Some argumentType ->
                                                    if
                                                        canCompareInferredValidationTypes locals parameterType argumentType
                                                        && not (expectedTypeAccepts locals refinements parameterType argumentType)
                                                    then
                                                        [ expectedMismatchDiagnostic locals refinements "Application argument" parameterType argumentType ]
                                                    else
                                                        walk restParameters restArguments
                                                | None ->
                                                    walk restParameters restArguments
                                    | (layout, _) :: _, (NamedApplicationBlock _ :: _) ->
                                        []
                                    | (layout, parameterType) :: restParameters, pending when layout.IsImplicit ->
                                        let isRuntimeImplicit =
                                            not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)

                                        let isTraitImplicit =
                                            tryTraitConstraintFromType environment parameterType
                                            |> Option.isSome

                                        if not isRuntimeImplicit then
                                            walk restParameters pending
                                        elif
                                            match classifyLocalImplicitByType environment locals parameterType with
                                            | AmbiguousLocalImplicitCandidates -> true
                                            | NoLocalImplicitCandidate
                                            | UniqueLocalImplicitCandidate _ -> false
                                        then
                                            walk restParameters pending
                                        elif localCanSatisfyImplicitParameter bindingInfo || isTraitImplicit then
                                            walk restParameters pending
                                        elif List.isEmpty pending then
                                            []
                                        else
                                            [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Implicit application argument could not be resolved or does not match the implicit parameter." ]
                                    | _ :: restParameters, _ :: restArguments ->
                                        walk restParameters restArguments
                                    | _ :: _, [] ->
                                        []

                                match bindingInfo.ParameterLayouts with
                                | Some [] ->
                                    []
                                | Some layouts ->
                                    match tryAlignParameterTypesWithLayouts environment layouts structuralParameterTypes with
                                    | Some(alignedParameterTypes, _) ->
                                        walk (List.zip layouts alignedParameterTypes) structuralArguments
                                    | None ->
                                        []
                                | None -> []

                        let constraintResolutionDiagnostics constraints =
                            constraints
                            |> List.collect (fun constraintInfo ->
                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TypeEqualityMismatch
                                                $"Trait constraint '{renderTraitConstraint environment constraintInfo}' could not be resolved."
                                        ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        let candidateText =
                                            candidates
                                            |> List.map renderInstanceCandidate
                                            |> String.concat ", "

                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TraitInstanceAmbiguous
                                                $"Multiple instance candidates survive for constraint '{renderTraitConstraint environment ambiguousGoal}': {candidateText}."
                                        ])

                        let applicationDiagnostics =
                            if isConstructorSpine then
                                []
                            else
                                match callee with
                                | Name [ calleeName ] ->
                                    let isLexicallyBoundName =
                                        Map.containsKey calleeName locals || Set.contains calleeName lexicalNames

                                    let localBindingType = Map.tryFind calleeName locals

                                    let bindingInfo =
                                        if isLexicallyBoundName then
                                            None
                                        else
                                            environment.VisibleConstructors
                                            |> Map.tryFind calleeName
                                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind calleeName)

                                    let resolvesAsTraitMemberCall =
                                        tryPrepareVisibleTraitMemberCall
                                            environment
                                            (ref freshCounter.Value)
                                            calleeName
                                            (inferValidationExpressionType environment (ref freshCounter.Value) locals)
                                            arguments
                                        |> Option.isSome

                                    let traitMemberOwners =
                                        environment.VisibleTraits
                                        |> Map.values
                                        |> Seq.filter (fun traitInfo -> traitInfo.Members.ContainsKey(calleeName))
                                        |> Seq.toList

                                    let rec traitOrSupertraitProvidesMember traitName memberName =
                                        environment.VisibleTraits
                                        |> Map.tryFind traitName
                                        |> Option.exists (fun traitInfo ->
                                            traitInfo.Members.ContainsKey(memberName)
                                            || (traitInfo.Supertraits
                                                |> List.exists (fun supertrait ->
                                                    traitOrSupertraitProvidesMember supertrait.TraitName memberName)))

                                    let localConstraintProjectionAvailable =
                                        locals
                                        |> Map.values
                                        |> Seq.exists (fun localType ->
                                            tryTraitConstraintFromType environment localType
                                            |> Option.exists (fun constraintInfo ->
                                                traitOrSupertraitProvidesMember constraintInfo.TraitName calleeName))

                                    let isKnownVisibleCallee =
                                        isLexicallyBoundName
                                        || (Set.contains calleeName knownSurfaceTermNames)
                                        || (Set.contains calleeName knownValueNames)
                                        || environment.VisibleProjections.ContainsKey(calleeName)
                                        || not (List.isEmpty traitMemberOwners)
                                        || environment.ConstrainedMembers.ContainsKey(calleeName)
                                        || localConstraintProjectionAvailable
                                        || resolvesAsTraitMemberCall

                                    match bindingInfo with
                                    | Some bindingInfo ->
                                        let probeCounter = ref freshCounter.Value
                                        let inferPreparedArgumentType =
                                            tryInferExpressionTypeWithSiblingFallback Set.empty locals

                                        let structuralDiagnostics = applicationStructuralDiagnostics bindingInfo
                                        let siblingFallbackCalleeType =
                                            if List.isEmpty bindingInfo.TypeTokens then
                                                tryInferSiblingBindingType Set.empty calleeName
                                            else
                                                None

                                        let siblingFallbackArgumentDiagnostics =
                                            siblingFallbackCalleeType
                                            |> Option.map (fun calleeType ->
                                                localApplicationExpectedArgumentDiagnostics
                                                    locals
                                                    refinements
                                                    calleeType
                                                    arguments)
                                            |> Option.defaultValue []

                                        let expectedArgumentDiagnostics =
                                            if not (List.isEmpty siblingFallbackArgumentDiagnostics) then
                                                siblingFallbackArgumentDiagnostics
                                            else
                                                applicationExpectedArgumentDiagnostics locals refinements lexicalNames bindingInfo arguments
                                        let traitConstraintDiagnostics = implicitTraitConstraintDiagnostics bindingInfo
                                        let zeroExplicitParameterCallDiagnostics () =
                                            let instantiated =
                                                TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                                            let visibleExplicitParameterCount =
                                                bindingInfo.ParameterLayouts
                                                |> Option.map (fun layouts -> layouts |> List.filter (fun parameter -> not parameter.IsImplicit) |> List.length)
                                                |> Option.defaultValue 0

                                            if arguments.IsEmpty || visibleExplicitParameterCount <> 0 then
                                                []
                                            else
                                                let apparentCalleeType = instantiated.Body

                                                if isCallableValidationType environment.VisibleTypeAliases apparentCalleeType then
                                                    localApplicationExpectedArgumentDiagnostics
                                                        locals
                                                        refinements
                                                        apparentCalleeType
                                                        arguments
                                                else
                                                    [
                                                        makeDiagnostic
                                                            DiagnosticCode.ApplicationNonCallable
                                                            $"Expression of type '{TypeSignatures.toText (normalizeTypeAliases environment.VisibleTypeAliases apparentCalleeType)}' is not callable."
                                                    ]

                                        if not (List.isEmpty structuralDiagnostics) then
                                            structuralDiagnostics
                                        else
                                            match
                                                tryPrepareVisibleBindingCall
                                                    environment
                                                    probeCounter
                                                    bindingInfo
                                                    (Some locals)
                                                    inferPreparedArgumentType
                                                    (tryResolveUniqueLocalImplicitByType environment locals)
                                                    arguments
                                            with
                                            | Some preparedCall ->
                                                expectedArgumentDiagnostics
                                                @ constraintResolutionDiagnostics preparedCall.InstantiatedScheme.Constraints
                                            | None
                                                when hasNamedBlock
                                                     || hasExplicitImplicitArgument
                                                     || hasUnsatisfiedRuntimeImplicit bindingInfo
                                                     || hasAmbiguousLocalImplicitParameter bindingInfo
                                                     || not (List.isEmpty traitConstraintDiagnostics)
                                                     || hasTooManyArguments bindingInfo ->
                                                let message =
                                                    if hasNamedBlock then
                                                        "Named application arguments do not match the callee parameter metadata."
                                                    elif not (List.isEmpty traitConstraintDiagnostics) then
                                                        ""
                                                    elif hasAmbiguousLocalImplicitParameter bindingInfo then
                                                        ""
                                                    elif hasExplicitImplicitArgument
                                                         || (runtimeRelevantParameterLayouts bindingInfo
                                                             |> Option.exists (List.exists (fun parameter -> parameter.IsImplicit))) then
                                                        "Implicit application argument could not be resolved or does not match the implicit parameter."
                                                    else
                                                        "Application argument types do not match the callee parameters."

                                                expectedArgumentDiagnostics
                                                @ traitConstraintDiagnostics
                                                @ (if String.IsNullOrEmpty message then
                                                       []
                                                   else
                                                       [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch message ])
                                            | None when localCanSatisfyImplicitParameter bindingInfo && not hasExplicitImplicitArgument ->
                                                expectedArgumentDiagnostics
                                            | None
                                                when List.isEmpty expectedArgumentDiagnostics
                                                     && List.isEmpty traitConstraintDiagnostics ->
                                                zeroExplicitParameterCallDiagnostics ()
                                            | None ->
                                                expectedArgumentDiagnostics
                                    | None
                                        when not resolvesAsTraitMemberCall
                                             && not (List.isEmpty traitMemberOwners)
                                             && not (environment.ConstrainedMembers.ContainsKey(calleeName))
                                             && not localConstraintProjectionAvailable ->
                                        let inferredArgumentTypes =
                                            arguments
                                            |> List.map (fun argument ->
                                                inferValidationExpressionType environment (ref freshCounter.Value) locals argument
                                                |> Option.map TypeSignatures.toText
                                                |> Option.defaultValue "_")
                                            |> String.concat ", "

                                        let traitOwnerText =
                                            traitMemberOwners
                                            |> List.map (fun traitInfo -> traitInfo.Name)
                                            |> String.concat ", "

                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TypeEqualityMismatch
                                                $"Overloaded trait member '{calleeName}' from [{traitOwnerText}] could not be resolved for argument types '{inferredArgumentTypes}'."
                                        ]
                                    | None
                                        when allowUnresolvedCallDiagnostics
                                             && not isKnownVisibleCallee ->
                                        [ makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{calleeName}' is not in scope." ]
                                    | None when localBindingType |> Option.exists (fun _ -> not hasNamedBlock) ->
                                        localApplicationExpectedArgumentDiagnostics
                                            locals
                                            refinements
                                            (localBindingType.Value)
                                            arguments
                                    | None when hasNamedBlock ->
                                        [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Named application requires a callee with preserved parameter metadata." ]
                                    | _ ->
                                        []
                                | _ when hasNamedBlock ->
                                    [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Named application requires a callee with preserved parameter metadata." ]
                                | _ ->
                                    []

                        let nonCallableDiagnostics =
                            if isConstructorSpine || not (List.isEmpty applicationDiagnostics) then
                                []
                            elif
                                match callee with
                                | Name [ calleeName ] ->
                                    Set.contains calleeName lexicalNames && not (Map.containsKey calleeName locals)
                                | _ ->
                                    false
                            then
                                []
                            elif
                                match callee with
                                | Name [ projectionName ] -> environment.VisibleProjections.ContainsKey(projectionName)
                                | _ -> false
                            then
                                []
                            else
                                match inferValidationExpressionType environment (ref freshCounter.Value) locals callee with
                                | Some calleeType ->
                                    let normalizedCalleeType =
                                        normalizeTypeAliases environment.VisibleTypeAliases calleeType

                                    match normalizedCalleeType with
                                    | _ when isCallableValidationType environment.VisibleTypeAliases normalizedCalleeType ->
                                        []
                                    | _ ->
                                        [
                                            makeDiagnostic
                                                DiagnosticCode.ApplicationNonCallable
                                                $"Expression of type '{TypeSignatures.toText normalizedCalleeType}' is not callable."
                                        ]
                                | None ->
                                    []

                        comprehensionSinkDiagnostics @ argumentDiagnostics @ applicationDiagnostics @ nonCallableDiagnostics
                    | _ ->
                        []
            | Elvis(left, right) ->
                let diagnostics = recurse left @ recurse right

                match inferValidationExpressionType environment freshCounter locals left with
                | Some leftType when tryOptionPayloadType environment.VisibleTypeAliases leftType |> Option.isNone ->
                    diagnostics
                    @ [ makeDiagnostic
                            DiagnosticCode.ElvisReceiverNotOption
                            "Elvis `?:` requires its left-hand side to have type `Option T` for some `T`." ]
                | _ ->
                    diagnostics
            | Binary(left, operatorName, right) ->
                let diagnostics =
                    match operatorName with
                    | "&&" ->
                        let rightFacts =
                            conditionConstructorFacts aliases constructorFacts left |> fst

                        recurse left
                        @ (rightFacts
                           |> List.collect (fun branchFacts ->
                               validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases branchFacts right))
                    | "||" ->
                        let rightFacts =
                            conditionConstructorFacts aliases constructorFacts left |> snd

                        recurse left
                        @ (rightFacts
                           |> List.collect (fun branchFacts ->
                               validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases branchFacts right))
                    | _ ->
                        recurse left @ recurse right

                match operatorName with
                | "&&"
                | "||" ->
                    let operandDiagnostics operandLabel operand =
                        match inferValidationExpressionType environment freshCounter locals operand with
                        | Some operandType when not (expectedTypeAccepts locals refinements boolType operandType) ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"Short-circuit operator {operandLabel} must match the expected suspended Bool operand type, but found '{TypeSignatures.toText operandType}'."
                            ]
                        | _ ->
                            []

                    diagnostics
                    @ operandDiagnostics "left-hand side" left
                    @ operandDiagnostics "right-hand side" right
                | "=="
                | "!="
                | "<"
                | ">"
                | "<="
                | ">=" ->
                    let requiredTraitName =
                        match operatorName with
                        | "=="
                        | "!=" -> "Eq"
                        | _ -> "Ord"

                    let comparisonConstraintDiagnostics =
                        match tryResolveComparableOperandTypes locals left right with
                        | Some(normalizedLeftType, _, leftType, rightType) ->
                                let constraintInfo =
                                    { TraitName = requiredTraitName
                                      Arguments = [ normalizedLeftType ] }

                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TypeEqualityMismatch
                                                $"Trait constraint '{renderTraitConstraint environment constraintInfo}' could not be resolved."
                                        ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        let candidateText =
                                            candidates
                                            |> List.map renderInstanceCandidate
                                            |> String.concat ", "

                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TraitInstanceAmbiguous
                                                $"Multiple instance candidates survive for constraint '{renderTraitConstraint environment ambiguousGoal}': {candidateText}."
                                        ]
                        | None ->
                            match
                                inferValidationExpressionType environment freshCounter locals left,
                                inferValidationExpressionType environment freshCounter locals right
                            with
                            | Some leftType, Some rightType ->
                                [ expectedMismatchDiagnostic locals refinements "Comparison operator operands" leftType rightType ]
                            | _ ->
                                []

                    diagnostics @ comparisonConstraintDiagnostics
                | ".."
                | "..<" ->
                    let rangeConstraintDiagnostics =
                        match tryResolveComparableOperandTypes locals left right with
                        | Some(normalizedLeftType, _, leftType, rightType) ->
                                let constraintInfo =
                                    { TraitName = "Rangeable"
                                      Arguments = [ normalizedLeftType ] }

                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TypeEqualityMismatch
                                                $"Trait constraint '{renderTraitConstraint environment constraintInfo}' could not be resolved."
                                        ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        let candidateText =
                                            candidates
                                            |> List.map renderInstanceCandidate
                                            |> String.concat ", "

                                        [
                                            makeDiagnostic
                                                DiagnosticCode.TraitInstanceAmbiguous
                                                $"Multiple instance candidates survive for constraint '{renderTraitConstraint environment ambiguousGoal}': {candidateText}."
                                        ]
                        | None ->
                            match
                                inferValidationExpressionType environment freshCounter locals left,
                                inferValidationExpressionType environment freshCounter locals right
                            with
                            | Some leftType, Some rightType ->
                                [ expectedMismatchDiagnostic locals refinements "Range operator operands" leftType rightType ]
                            | _ ->
                                []

                    diagnostics @ rangeConstraintDiagnostics
                | "+" | "-" | "*" | "/" ->
                    let operandDiagnostics operandLabel operand =
                        match operand with
                        | Name [ name ]
                            when not (Map.containsKey name locals)
                                 && not (
                                     definition.Name
                                     |> Option.exists (fun definitionName -> String.Equals(name, definitionName, StringComparison.Ordinal))
                                 ) ->
                            let inferredOperandType =
                                inferValidationExpressionType environment freshCounter locals operand
                                |> Option.orElseWith (fun () -> tryInferExpressionTypeWithSiblingFallback Set.empty locals operand)

                            match inferredOperandType with
                            | Some operandType when typeIsCallableLikeForValidation operandType ->
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.TypeEqualityMismatch
                                            $"Arithmetic operator {operandLabel} must be a numeric value, but '{name}' resolves to a callable binding."
                                    ]
                            | _ ->
                                match topLevelDefinitionsByName |> Map.tryFind name with
                                | Some bindingInfo when not (List.isEmpty bindingInfo.Parameters) ->
                                    [
                                        makeDiagnostic
                                            DiagnosticCode.TypeEqualityMismatch
                                            $"Arithmetic operator {operandLabel} must be a numeric value, but '{name}' resolves to a callable binding."
                                    ]
                                | None ->
                                    []
                                | Some _ ->
                                    []
                        | _ ->
                            []

                    let leftOperandDiagnostics = operandDiagnostics "left-hand side" left
                    let rightOperandDiagnostics = operandDiagnostics "right-hand side" right

                    let numericTypeDiagnostics =
                        let isSupportedArithmeticType normalizedTypeExpr =
                            match normalizedTypeExpr with
                            | TypeName(([ "Int" ] | [ "std"; "prelude"; "Int" ]), [])
                            | TypeName(([ "Float" ] | [ "std"; "prelude"; "Float" ]), [])
                            | TypeName(([ "Double" ] | [ "std"; "prelude"; "Double" ]), []) ->
                                true
                            | _ ->
                                false

                        match
                            inferValidationExpressionType environment freshCounter locals left,
                            inferValidationExpressionType environment freshCounter locals right
                        with
                        | Some leftType, Some rightType ->
                            let normalizedLeftType = normalizeTypeAliases environment.VisibleTypeAliases leftType
                            let normalizedRightType = normalizeTypeAliases environment.VisibleTypeAliases rightType

                            match normalizedLeftType, normalizedRightType with
                            | _ when
                                isCompileTimeArgumentType environment.VisibleTypeAliases normalizedLeftType
                                || isCompileTimeArgumentType environment.VisibleTypeAliases normalizedRightType ->
                                [
                                    makeDiagnostic
                                        DiagnosticCode.TypeEqualityMismatch
                                        $"Arithmetic operator operands must both be numeric, but found '{TypeSignatures.toText leftType}' and '{TypeSignatures.toText rightType}'."
                                ]
                            | _ when isSupportedArithmeticType normalizedLeftType && isSupportedArithmeticType normalizedRightType ->
                                []
                            | _ when not (canCompareInferredValidationTypes locals leftType rightType) ->
                                []
                            | _ ->
                                [
                                    makeDiagnostic
                                        DiagnosticCode.TypeEqualityMismatch
                                        $"Arithmetic operator operands must both be numeric, but found '{TypeSignatures.toText leftType}' and '{TypeSignatures.toText rightType}'."
                                ]
                        | _ ->
                            []

                    diagnostics
                    @ leftOperandDiagnostics
                    @ rightOperandDiagnostics
                    @ (if List.isEmpty leftOperandDiagnostics && List.isEmpty rightOperandDiagnostics then
                           numericTypeDiagnostics
                       else
                           [])
                | _ ->
                    let operatorBindingDiagnostics =
                        environment.VisibleConstructors
                        |> Map.tryFind operatorName
                        |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind operatorName)
                        |> Option.map (fun bindingInfo ->
                            let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                            localApplicationExpectedArgumentDiagnostics
                                locals
                                refinements
                                instantiated.Body
                                [ left; right ])
                        |> Option.defaultValue []

                    diagnostics
                    @ (if List.isEmpty operatorBindingDiagnostics then
                           validateExpressionWithFlow
                               locals
                               refinements
                               lexicalNames
                               aliases
                               staticAliases
                               constructorFacts
                               (Apply(Name [ operatorName ], [ left; right ]))
                       else
                           operatorBindingDiagnostics)
            | PrefixedString(prefix, parts) ->
                prefixedStringPrefixDiagnostics locals lexicalNames prefix
                @ (tryResolvePrefixedStringFailureDiagnostic prefix
                   |> Option.map (fun message -> [ makeDiagnostic DiagnosticCode.ElaborationFailed message ])
                   |> Option.defaultValue [])
                @ (parts
                   |> List.collect (function
                       | StringText _ -> []
                       | StringInterpolation(inner, _) -> recurse inner))

        and validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts statements =
            match statements with
            | [] ->
                []
            | statement :: rest ->
                match statement with
                | DoLet(binding, expression) ->
                    let aliasAwareEnvironment =
                        { environment with
                            VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            collectPatternNames binding.Pattern
                            |> List.fold (fun state name -> Map.add name valueType state) locals
                        | None ->
                            locals

                    let localStaticAliases = collectScopedPatternStaticAliases aliasAwareEnvironment binding.Pattern expression
                    let restForValidation =
                        match rewriteStaticObjectPathAliasUses localStaticAliases (Do rest) with
                        | Do rewritten -> rewritten
                        | _ -> rest

                    let nextAliases =
                        extendStableAliases aliases binding expression

                    let nextStaticAliases =
                        let shadowedNames = collectPatternNames binding.Pattern
                        let inheritedAliases = removeShadowedStaticAliases staticAliases shadowedNames

                        localStaticAliases
                        |> Map.fold (fun state segments staticObject -> Map.add segments staticObject state) inheritedAliases

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts restForValidation
                | DoBind(binding, expression) ->
                    let aliasAwareEnvironment =
                        { environment with
                            VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let bindSourceDiagnostics =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some sourceType when tryUnwrapBindablePayloadType environment.VisibleTypeAliases sourceType |> Option.isNone ->
                            [
                                makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"A '<-' do binding requires a bindable carrier value, but found '{TypeSignatures.toText sourceType}'."
                            ]
                        | _ ->
                            []

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            match tryUnwrapBindablePayloadType environment.VisibleTypeAliases valueType with
                            | Some payloadType ->
                                collectPatternNames binding.Pattern
                                |> List.fold (fun state name -> Map.add name payloadType state) locals
                            | None ->
                                locals
                        | None ->
                            locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ bindSourceDiagnostics
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoLetQuestion(binding, expression, failure) ->
                    let aliasAwareEnvironment =
                        { environment with
                            VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            collectPatternNames binding.Pattern
                            |> List.fold (fun state name -> Map.add name valueType state) locals
                        | None ->
                            locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    let failureDiagnostics =
                        match failure with
                        | Some failure ->
                            let failureLexicalNames =
                                collectPatternNames failure.ResiduePattern.Pattern
                                |> Set.ofList
                                |> Set.union lexicalNames

                            validateDoStatementsWithFlow locals refinements failureLexicalNames aliases staticAliases constructorFacts failure.Body
                        | None -> []

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validatePatternHead binding.Pattern
                    @ activePatternLinearityDiagnostics binding.Pattern "let?"
                    @ failureDiagnostics
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoUsing(binding, expression) ->
                    let aliasAwareEnvironment =
                        { environment with
                            VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match binding.Pattern, inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | NamePattern bindingName, Some valueType -> Map.add bindingName (unwrapIoType valueType) locals
                        | _ -> locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoVar(bindingName, expression) ->
                    let aliasAwareEnvironment =
                        { environment with
                            VisibleStaticObjects = aliasesAsVisibleStaticObjects staticAliases }

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType -> Map.add bindingName (refType valueType) locals
                        | None -> locals

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow
                        nextLocals
                        refinements
                        (Set.add bindingName lexicalNames)
                        (Map.remove bindingName aliases)
                        (removeShadowedStaticAliases staticAliases [ bindingName ])
                        constructorFacts
                        rest
                | DoAssign(_, expression)
                | DoDefer expression
                | DoExpression expression ->
                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest
                | DoIf(condition, whenTrue, whenFalse) ->
                    let trueConstructorFacts, falseConstructorFacts =
                        conditionConstructorFacts aliases constructorFacts condition

                    let restDiagnostics =
                        match doBlockDefinitelyTerminal whenTrue, doBlockDefinitelyTerminal whenFalse with
                        | false, true ->
                            trueConstructorFacts
                            |> List.collect (fun branchFacts ->
                                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts rest)
                        | true, false ->
                            falseConstructorFacts
                            |> List.collect (fun branchFacts ->
                                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts rest)
                        | _ ->
                            validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts condition
                    @ (trueConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts whenTrue))
                    @ (falseConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts whenFalse))
                    @ restDiagnostics
                | DoWhile(condition, body) ->
                    let trueConstructorFacts, _ =
                        conditionConstructorFacts aliases constructorFacts condition

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts condition
                    @ (trueConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts body))
                    @ validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest
                | DoReturn expression ->
                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression

        let validateExpression locals refinements lexicalNames expression =
            validateExpressionWithFlow locals refinements lexicalNames emptyStableAliases emptyStaticAliases emptyConstructorFacts expression

        let rec validateInoutPlacement insideDo expression =
            let recurse = validateInoutPlacement insideDo

            match expression with
            | InoutArgument inner ->
                let markerDiagnostics =
                    if insideDo then
                        []
                    else
                        [ makeDiagnostic DiagnosticCode.QttInoutMarkerUnexpected "The '~' inout marker is only valid inside do blocks." ]

                markerDiagnostics @ recurse inner
            | TypeSyntaxTokens _ ->
                []
            | SyntaxQuote inner
            | SyntaxSplice inner
            | TopLevelSyntaxSplice inner
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | Handle(_, label, body, returnClause, operationClauses) ->
                recurse label
                @ recurse body
                @ recurse returnClause.Body
                @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
            | LocalLet(_, value, body) ->
                recurse value @ recurse body
            | LocalSignature(_, body) ->
                recurse body
            | LocalTypeAlias(_, body) ->
                recurse body
            | LocalScopedEffect(_, body) ->
                recurse body
            | Lambda(_, body) ->
                validateInoutPlacement false body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                recurse condition @ recurse whenTrue @ recurse whenFalse
            | Match(scrutinee, cases) ->
                recurse scrutinee
                @ (cases
                   |> List.collect (fun caseClause ->
                       (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                       @ recurse caseClause.Body))
            | RecordLiteral fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
            | MemberAccess(receiver, _, arguments) ->
                recurse receiver @ (arguments |> List.collect recurse)
            | SafeNavigation(receiver, navigation) ->
                recurse receiver @ (navigation.Arguments |> List.collect recurse)
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                statements |> List.collect validateInoutDoStatement
            | MonadicSplice inner
            | ExplicitImplicitArgument inner
            | Unary(_, inner) ->
                recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Apply(callee, arguments) ->
                recurse callee @ (arguments |> List.collect recurse)
            | Binary(left, _, right)
            | Elvis(left, right) ->
                recurse left @ recurse right
            | Comprehension comprehension ->
                recurse comprehension.Lowered
            | PrefixedString(_, parts) ->
                parts
                |> List.collect (function
                    | StringText _ -> []
                    | StringInterpolation(inner, _) -> recurse inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                []

        and validateInoutDoStatement statement =
            match statement with
            | DoLet(_, expression)
            | DoLetQuestion(_, expression, _)
            | DoBind(_, expression)
            | DoVar(_, expression)
            | DoAssign(_, expression)
            | DoDefer expression
            | DoUsing(_, expression)
            | DoReturn expression
            | DoExpression expression ->
                validateInoutPlacement true expression
            | DoIf(condition, whenTrue, whenFalse) ->
                validateInoutPlacement true condition
                @ (whenTrue |> List.collect validateInoutDoStatement)
                @ (whenFalse |> List.collect validateInoutDoStatement)
            | DoWhile(condition, body) ->
                validateInoutPlacement true condition @ (body |> List.collect validateInoutDoStatement)

        let tryProjectionDescriptorAlias (expression: SurfaceExpression) =
            let tryBuild projectionName suppliedArguments =
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.bind (fun projectionInfo ->
                    if List.length suppliedArguments >= List.length projectionInfo.Binders then
                        None
                    else
                        let suppliedBinders = projectionInfo.Binders |> List.take (List.length suppliedArguments)
                        let remainingBinders = projectionInfo.Binders |> List.skip (List.length suppliedArguments)

                        let suppliedAreValues =
                            suppliedBinders
                            |> List.forall (function
                                | ProjectionValueBinder _ -> true
                                | ProjectionPlaceBinder _ -> false)

                        let remainingPlaceBinders =
                            remainingBinders
                            |> List.choose (function
                                | ProjectionPlaceBinder binder -> Some binder
                                | ProjectionValueBinder _ -> None)

                        if suppliedAreValues && List.length remainingPlaceBinders = List.length remainingBinders then
                            Some
                                { Projection = projectionInfo
                                  RemainingPlaceBinders = remainingPlaceBinders }
                        else
                            None)

            match expression with
            | Name [ projectionName ] -> tryBuild projectionName []
            | Apply(Name [ projectionName ], suppliedArguments) -> tryBuild projectionName suppliedArguments
            | _ -> None

        let rec isStableDescriptorPlace (expression: SurfaceExpression) =
            match expression with
            | Name(_ :: _) ->
                true
            | Apply(Name [ projectionName ], arguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.exists (fun projectionInfo ->
                    match projectionInfo.Body with
                    | Some(ProjectionAccessors _) ->
                        false
                    | _ ->
                        List.length projectionInfo.Binders = List.length arguments
                        && (List.zip projectionInfo.Binders arguments
                            |> List.forall (fun (binder, argument) ->
                                match binder with
                                | ProjectionPlaceBinder _ -> isStableDescriptorPlace argument
                                | ProjectionValueBinder _ -> true)))
            | _ ->
                false

        let descriptorApplicationDiagnostics (remainingPlaceBinders: ProjectionPlaceBinder list) rootsArgument =
            let rootPackFieldMap (fields: SurfaceRecordLiteralField list) =
                fields
                |> List.map (fun field -> field.Name, field.Value)
                |> Map.ofList

            let unstableRootDiagnostics expressions =
                expressions
                |> List.choose (fun expression ->
                    if isStableDescriptorPlace expression then
                        None
                    else
                        Some(makeDiagnostic DiagnosticCode.ProjectionRootInvalid "Projector descriptor roots must be stable places or selector-computed places."))

            match remainingPlaceBinders with
            | [] ->
                [ makeDiagnostic DiagnosticCode.ProjectionDescriptorRootMissing "A projector descriptor application must still have at least one root." ]
            | [ binder ] ->
                match rootsArgument with
                | RecordLiteral fields when fields |> List.exists (fun field -> String.Equals(field.Name, binder.Name, StringComparison.Ordinal)) ->
                    let fieldMap = rootPackFieldMap fields
                    let fieldNames = fieldMap |> Map.keys |> Set.ofSeq
                    let expectedNames = Set.singleton binder.Name

                    if fieldNames <> expectedNames then
                        [ makeDiagnostic DiagnosticCode.ProjectionRootsPackMismatch "Projector descriptor roots pack fields must match the projector root binders exactly." ]
                    else
                        fieldMap |> Map.find binder.Name |> List.singleton |> unstableRootDiagnostics
                | RecordLiteral _ ->
                    [ makeDiagnostic DiagnosticCode.ProjectionRootsPackMismatch "Projector descriptor roots pack fields must match the projector root binders exactly." ]
                | _ ->
                    unstableRootDiagnostics [ rootsArgument ]
            | binders ->
                match rootsArgument with
                | RecordLiteral fields ->
                    let fieldMap = rootPackFieldMap fields
                    let fieldNames = fieldMap |> Map.keys |> Set.ofSeq
                    let expectedNames = binders |> List.map (fun binder -> binder.Name) |> Set.ofList

                    if fieldNames <> expectedNames then
                        [ makeDiagnostic DiagnosticCode.ProjectionRootsPackMismatch "Projector descriptor roots pack fields must match the projector root binders exactly." ]
                    else
                        binders
                        |> List.map (fun binder -> fieldMap |> Map.find binder.Name)
                        |> unstableRootDiagnostics
                | _ ->
                    [ makeDiagnostic DiagnosticCode.ProjectionDescriptorRootsLiteralRequired "Multi-root projector descriptors must be applied to a record literal roots pack." ]

        let fullyAppliedProjectionReturningDescriptorDiagnostic body =
            let returnTypeIsProjector =
                definition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.exists (function
                    | TypeName(([ "Projector" ] | [ "std"; "prelude"; "Projector" ]), _) -> true
                    | _ -> false)

            match returnTypeIsProjector, body with
            | true, Apply(Name [ projectionName ], arguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.filter (fun projectionInfo -> List.length projectionInfo.Binders = List.length arguments)
                |> Option.map (fun _ ->
                    [ makeDiagnostic DiagnosticCode.ProjectionDescriptorValueExpected "A fully applied projection produces the projected focus, not a projector descriptor value." ])
                |> Option.defaultValue []
            | _ ->
                []

        let rec validateProjectionDescriptorApplications (aliases: Map<string, ProjectionDescriptorAliasInfo>) (expression: SurfaceExpression) =
            let recurse = validateProjectionDescriptorApplications aliases

            match expression with
            | SyntaxQuote inner
            | SyntaxSplice inner
            | TopLevelSyntaxSplice inner
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | TypeSyntaxTokens _ ->
                []
            | Handle(_, label, body, returnClause, operationClauses) ->
                recurse label
                @ recurse body
                @ recurse returnClause.Body
                @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
            | Apply(Name [ aliasName ], [ rootsArgument ]) ->
                let nested = validateProjectionDescriptorApplications aliases rootsArgument

                match aliases |> Map.tryFind aliasName with
                | Some aliasInfo ->
                    nested @ descriptorApplicationDiagnostics aliasInfo.RemainingPlaceBinders rootsArgument
                | None ->
                    nested
            | Apply(callee, arguments) ->
                recurse callee @ (arguments |> List.collect recurse)
            | LocalLet(binding, value, body) ->
                let valueDiagnostics = recurse value
                let shadowedAliases =
                    collectPatternNames binding.Pattern
                    |> List.fold (fun current name -> Map.remove name current) aliases

                let bodyAliases =
                    match binding.Pattern, tryProjectionDescriptorAlias value with
                    | NamePattern aliasName, Some aliasInfo -> Map.add aliasName aliasInfo shadowedAliases
                    | _ -> shadowedAliases

                valueDiagnostics @ validateProjectionDescriptorApplications bodyAliases body
            | LocalSignature(declaration, body) ->
                validateProjectionDescriptorApplications (Map.remove declaration.Name aliases) body
            | LocalTypeAlias(_, body) ->
                recurse body
            | LocalScopedEffect(_, body) ->
                recurse body
            | Lambda(parameters, body) ->
                let bodyAliases =
                    parameters
                    |> List.fold (fun current parameter -> Map.remove parameter.Name current) aliases

                validateProjectionDescriptorApplications bodyAliases body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                recurse condition @ recurse whenTrue @ recurse whenFalse
            | Match(scrutinee, cases) ->
                recurse scrutinee
                @ (cases
                   |> List.collect (fun caseClause ->
                       (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                       @ recurse caseClause.Body))
            | RecordLiteral fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
            | MemberAccess(receiver, _, arguments) ->
                recurse receiver @ (arguments |> List.collect recurse)
            | SafeNavigation(receiver, navigation) ->
                recurse receiver @ (navigation.Arguments |> List.collect recurse)
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                validateProjectionDescriptorDoStatements aliases statements
            | MonadicSplice inner
            | ExplicitImplicitArgument inner
            | InoutArgument inner
            | Unary(_, inner) ->
                recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Binary(left, _, right)
            | Elvis(left, right) ->
                recurse left @ recurse right
            | Comprehension comprehension ->
                recurse comprehension.Lowered
            | PrefixedString(_, parts) ->
                parts
                |> List.collect (function
                    | StringText _ -> []
                    | StringInterpolation(inner, _) -> recurse inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                []

        and validateProjectionDescriptorDoStatements (aliases: Map<string, ProjectionDescriptorAliasInfo>) (statements: SurfaceDoStatement list) =
            match statements with
            | [] ->
                []
            | statement :: rest ->
                match statement with
                | DoLet(binding, expression)
                | DoBind(binding, expression)
                | DoUsing(binding, expression) ->
                    let nextAliases =
                        collectPatternNames binding.Pattern
                        |> List.fold (fun current name -> Map.remove name current) aliases

                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements nextAliases rest
                | DoLetQuestion(binding, expression, failure) ->
                    let nextAliases =
                        collectPatternNames binding.Pattern
                        |> List.fold (fun current name -> Map.remove name current) aliases

                    let failureDiagnostics =
                        failure
                        |> Option.map (fun block -> validateProjectionDescriptorDoStatements aliases block.Body)
                        |> Option.defaultValue []

                    validateProjectionDescriptorApplications aliases expression
                    @ failureDiagnostics
                    @ validateProjectionDescriptorDoStatements nextAliases rest
                | DoVar(name, expression) ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements (Map.remove name aliases) rest
                | DoAssign(target, expression) ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoDefer expression
                | DoExpression expression
                | DoReturn expression ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoIf(condition, whenTrue, whenFalse) ->
                    validateProjectionDescriptorApplications aliases condition
                    @ validateProjectionDescriptorDoStatements aliases whenTrue
                    @ validateProjectionDescriptorDoStatements aliases whenFalse
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoWhile(condition, body) ->
                    validateProjectionDescriptorApplications aliases condition
                    @ validateProjectionDescriptorDoStatements aliases body
                    @ validateProjectionDescriptorDoStatements aliases rest

        let validateLocalImplicitResolution body =
            let normalizeVisible typeExpr =
                typeExpr
                |> qualifyVisibleTypeNames environment
                |> normalizeTypeAliases environment.VisibleTypeAliases

            let normalizedKey typeExpr =
                normalizeVisible typeExpr |> TypeSignatures.toText

            let implicitQuantity quantity =
                quantity |> Option.defaultValue QuantityOmega

            let addCandidate name quantity typeExpr scope =
                let key = normalizedKey typeExpr
                let existing = scope |> Map.tryFind key |> Option.defaultValue []
                Map.add key ((name, implicitQuantity quantity) :: existing) scope

            let addImplicitBinding (binding: SurfaceBindPattern) valueType scope =
                if binding.IsImplicit then
                    collectPatternNames binding.Pattern
                    |> List.fold (fun current name -> addCandidate name binding.Quantity valueType current) scope
                else
                    scope

            let addImplicitParameter scope (parameter: Parameter) =
                if parameter.IsImplicit then
                    parameter.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (fun parameterType ->
                        addCandidate parameter.Name parameter.Quantity (qualifyVisibleTypeNames environment parameterType) scope)
                    |> Option.defaultValue scope
                else
                    scope

            let initialScope =
                effectiveParameters
                |> List.fold addImplicitParameter Map.empty

            let resolveCandidates scopes parameterType =
                let key = normalizedKey parameterType

                scopes
                |> List.tryPick (fun scope ->
                    scope
                    |> Map.tryFind key
                    |> Option.filter (fun candidates -> not (List.isEmpty candidates)))

            let implicitDemandDiagnostics inEscapingLambda scopes (bindingInfo: BindingSchemeInfo) arguments =
                match bindingInfo.ParameterLayouts with
                | Some layouts ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                    if List.length layouts <> List.length parameterTypes then
                        []
                    else
                        let hasExplicitImplicitArgument =
                            arguments
                            |> List.exists (function
                                | ExplicitImplicitArgument _ -> true
                                | _ -> false)

                        if hasExplicitImplicitArgument then
                            []
                        else
                            List.zip layouts parameterTypes
                            |> List.collect (fun (layout, parameterType) ->
                                if not layout.IsImplicit
                                   || isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                    []
                                else
                                    match resolveCandidates scopes parameterType with
                                    | None ->
                                        []
                                    | Some candidates when List.length candidates > 1 ->
                                        [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "Implicit application argument is ambiguous in the nearest lexical implicit scope." ]
                                    | Some [ _, QuantityZero ] ->
                                        [ makeDiagnostic DiagnosticCode.TypeEqualityMismatch "A quantity-0 local implicit value cannot satisfy a runtime implicit parameter." ]
                                    | Some [ _, QuantityBorrow _ ] when inEscapingLambda ->
                                        [ makeDiagnostic DiagnosticCode.QttBorrowEscape "A lambda cannot capture a borrowed implicit value that may escape its borrow scope." ]
                                    | Some _ ->
                                        [])
                | None ->
                    []

            let rec validateExpr inEscapingLambda scopes expression =
                let recurse = validateExpr inEscapingLambda scopes

                match expression with
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner ->
                    recurse inner
                | TypeSyntaxTokens _ ->
                    []
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurse label
                    @ recurse body
                    @ recurse returnClause.Body
                    @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
                | Apply(Name [ calleeName ], arguments) ->
                    let bindingDiagnostics =
                        environment.VisibleBindings
                        |> Map.tryFind calleeName
                        |> Option.map (fun bindingInfo -> implicitDemandDiagnostics inEscapingLambda scopes bindingInfo arguments)
                        |> Option.defaultValue []

                    bindingDiagnostics @ (arguments |> List.collect recurse)
                | Name [ calleeName ] ->
                    environment.VisibleBindings
                    |> Map.tryFind calleeName
                    |> Option.map (fun bindingInfo -> implicitDemandDiagnostics inEscapingLambda scopes bindingInfo [])
                    |> Option.defaultValue []
                | Apply(callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | LocalSignature(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | LocalTypeAlias(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | LocalLet(binding, value, nestedBody) ->
                    let valueDiagnostics = recurse value
                    let valueType =
                        binding.TypeTokens
                        |> Option.bind TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter Map.empty value)
                    let nestedScopes =
                        valueType
                        |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                        |> Option.defaultValue scopes

                    valueDiagnostics @ validateExpr inEscapingLambda nestedScopes nestedBody
                | LocalScopedEffect(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | Lambda(parameters, nestedBody) ->
                    let lambdaScope =
                        parameters
                        |> List.fold addImplicitParameter Map.empty

                    validateExpr true (lambdaScope :: scopes) nestedBody
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurse condition @ recurse whenTrue @ recurse whenFalse
                | Match(scrutinee, cases) ->
                    recurse scrutinee
                    @ (cases
                       |> List.collect (fun caseClause ->
                           (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                           @ recurse caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | RecordUpdate(receiver, fields) ->
                    recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurse receiver @ (arguments |> List.collect recurse)
                | SafeNavigation(receiver, navigation) ->
                    recurse receiver @ (navigation.Arguments |> List.collect recurse)
                | TagTest(receiver, _) ->
                    recurse receiver
                | Do statements ->
                    validateDo inEscapingLambda scopes statements
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner)
                | Seal(inner, _) ->
                    recurse inner
                | NamedApplicationBlock fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurse left @ recurse right
                | Comprehension comprehension ->
                    recurse comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.collect (function
                        | StringText _ -> []
                        | StringInterpolation(inner, _) -> recurse inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    []

            and validateDo inEscapingLambda scopes statements =
                match statements with
                | [] ->
                    []
                | statement :: rest ->
                    match statement with
                    | DoLet(binding, expression)
                    | DoBind(binding, expression) ->
                        let expressionDiagnostics = validateExpr inEscapingLambda scopes expression
                        let valueType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.orElseWith (fun () ->
                                inferValidationExpressionType environment freshCounter Map.empty expression
                                |> Option.map (fun typeExpr ->
                                    match statement with
                                    | DoBind _ -> unwrapBindPayloadType typeExpr
                                    | _ -> typeExpr))

                        let restScopes =
                            valueType
                            |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                            |> Option.defaultValue scopes

                        expressionDiagnostics @ validateDo inEscapingLambda restScopes rest
                    | DoLetQuestion(binding, expression, failure) ->
                        let expressionDiagnostics = validateExpr inEscapingLambda scopes expression
                        let valueType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter Map.empty expression)

                        let restScopes =
                            valueType
                            |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                            |> Option.defaultValue scopes

                        let failureDiagnostics =
                            failure
                            |> Option.map (fun block -> validateDo inEscapingLambda scopes block.Body)
                            |> Option.defaultValue []

                        expressionDiagnostics @ failureDiagnostics @ validateDo inEscapingLambda restScopes rest
                    | DoUsing(binding, expression) ->
                        validateExpr inEscapingLambda scopes expression @ validateDo inEscapingLambda scopes rest
                    | DoVar(_, expression)
                    | DoAssign(_, expression)
                    | DoDefer expression
                    | DoExpression expression
                    | DoReturn expression ->
                        validateExpr inEscapingLambda scopes expression @ validateDo inEscapingLambda scopes rest
                    | DoIf(condition, whenTrue, whenFalse) ->
                        validateExpr inEscapingLambda scopes condition
                        @ validateDo inEscapingLambda scopes whenTrue
                        @ validateDo inEscapingLambda scopes whenFalse
                        @ validateDo inEscapingLambda scopes rest
                    | DoWhile(condition, body) ->
                        validateExpr inEscapingLambda scopes condition
                        @ validateDo inEscapingLambda scopes body
                        @ validateDo inEscapingLambda scopes rest

            validateExpr false [ initialScope ] body

        let parameterRecordDiagnostics =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens
                |> Option.map validateRecordSurfaceInfo
                |> Option.defaultValue [])

        let activePatternDeclarationDiagnostics =
            if not definition.IsPattern then
                []
            else
                let explicitParameterCount =
                    effectiveParameters
                    |> List.filter (fun parameter -> not parameter.IsImplicit)
                    |> List.length

                let binderDiagnostics =
                    if explicitParameterCount = 0 then
                        [ makeDiagnostic DiagnosticCode.ActivePatternMissingScrutineeBinder "An active pattern declaration must have at least one explicit binder for the scrutinee." ]
                    else
                        []

                let resultDiagnostics =
                    scheme
                    |> Option.map (fun parsedScheme ->
                        if isMonadicType parsedScheme.Body then
                            [ makeDiagnostic DiagnosticCode.ActivePatternMonadicResult "An active pattern declaration result type must not be monadic." ]
                        else
                            [])
                    |> Option.defaultValue []

                binderDiagnostics @ resultDiagnostics

        let directRecordLiteralBodyDiagnostics body =
            let expectedRecordInfo =
                definition.ReturnTypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens

            match body, expectedRecordInfo with
            | RecordLiteral fields, Some recordInfo when recordInfoHasOpaqueMembers recordInfo ->
                validateRecordLiteral fields
                @ validateRecordLiteralFieldValuesWithRecordInfo
                    (validateExpression localTypes Map.empty parameterNames)
                    recordInfo
                    fields
            | _ ->
                validateExpression localTypes Map.empty parameterNames body

        parameterRecordDiagnostics
        @ activePatternDeclarationDiagnostics
        @ declaredParameterContextConflictDiagnostics
        @
            match effectiveBody with
            | Some body ->
                directRecordLiteralBodyDiagnostics body
                @ siblingFallbackDiagnostics body
                @ validateLocalImplicitResolution body
                @ validateExpectedBody localTypes body
                @ validateInoutPlacement false body
                @ validateProjectionDescriptorApplications Map.empty body
                @ fullyAppliedProjectionReturningDescriptorDiagnostic body
            | None -> []

    let validateSurfaceModules
        backendProfile
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<string, HostBindings.HostModuleDescription>)
        =
        let surfaceIndex = buildSurfaceIndex frontendModules hostModules
        let effectDeclarationsByModule = buildEffectDeclarationIndex frontendModules

        let duplicateDeclarationDiagnostics =
            let moduleKey (frontendModule: KFrontIRModule) =
                frontendModule.ModuleIdentity
                |> Option.map SyntaxFacts.moduleNameToText
                |> Option.defaultValue $"<file:{frontendModule.FilePath}>"

            let makeDuplicateDiagnostic moduleName message =
                { Severity = DiagnosticSeverity.Error
                  Code = DiagnosticCode.DuplicateDeclaration
                  Stage = Some "KFrontIR"
                  Phase = Some(KFrontIRPhase.phaseName CORE_LOWERING)
                  Message = $"{message} in module '{moduleName}'."
                  Location = None
                  RelatedLocations = [] }

            frontendModules
            |> List.groupBy moduleKey
            |> List.collect (fun (_, moduleGroup) ->
                let moduleName =
                    moduleGroup
                    |> List.tryHead
                    |> Option.map (fun frontendModule -> moduleNameText frontendModule.ModuleIdentity)
                    |> Option.defaultValue "<unknown>"

                let groupedDeclarations =
                    moduleGroup
                    |> List.collect (fun frontendModule ->
                        frontendModule.Declarations
                        |> List.map (fun declaration -> frontendModule.FilePath, declaration))

                let termNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (filePath, declaration) ->
                        match declaration with
                        | SignatureDeclaration declaration ->
                            [ declaration.Name, TermSignatureContributor, Some filePath ]
                        | LetDeclaration declaration ->
                            declaration.Name
                            |> Option.map (fun name -> [ name, TermLetContributor, Some filePath ])
                            |> Option.defaultValue []
                        | ProjectionDeclarationNode declaration ->
                            [ declaration.Name, TermProjectionContributor, Some filePath ]
                        | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                            [ declaration.Name, TermExpectationContributor, Some filePath ]
                        | _ ->
                            [])
                    |> List.groupBy (fun (name, _, _) -> name)
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor, _) -> currentContributor = contributor)
                            |> List.length

                        let trySingleFile contributor =
                            entries
                            |> List.tryPick (fun (_, currentContributor, filePath) ->
                                if currentContributor = contributor then
                                    filePath
                                else
                                    None)

                        let signatureCount = count TermSignatureContributor
                        let letCount = count TermLetContributor
                        let projectionCount = count TermProjectionContributor
                        let expectationCount = count TermExpectationContributor
                        let totalCount = entries.Length

                        let signatureLetsShareAFile =
                            match trySingleFile TermSignatureContributor, trySingleFile TermLetContributor with
                            | Some signatureFilePath, Some letFilePath ->
                                String.Equals(signatureFilePath, letFilePath, StringComparison.Ordinal)
                            | _ ->
                                false

                        let isAllowedTermNamespaceShape =
                            match totalCount with
                            | 0
                            | 1 -> true
                            | _ when letCount = 1 && projectionCount = 0 && expectationCount <= 1 ->
                                signatureCount = 0 || (signatureCount = 1 && signatureLetsShareAFile)
                            | _ when letCount = 0 && projectionCount = 1 && signatureCount = 0 ->
                                expectationCount <= 1
                            | _ -> false

                        if totalCount <= 1 || isAllowedTermNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Term namespace name '{name}' is declared more than once"))

                let typeNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | DataDeclarationNode declaration ->
                            [ declaration.Name, OrdinaryTypeContributor ]
                        | TypeAliasNode declaration ->
                            [ declaration.Name, OrdinaryTypeContributor ]
                        | EffectDeclarationNode declaration ->
                            [ declaration.Name, EffectTypeContributor ]
                        | ExpectDeclarationNode (ExpectTypeDeclaration declaration) ->
                            [ declaration.Name, ExpectTypeContributor ]
                        | _ ->
                            [])
                    |> List.groupBy fst
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor) -> currentContributor = contributor)
                            |> List.length

                        let ordinaryTypeCount = count OrdinaryTypeContributor
                        let effectTypeCount = count EffectTypeContributor
                        let expectTypeCount = count ExpectTypeContributor
                        let totalCount = entries.Length

                        let isAllowedTypeNamespaceShape =
                            ordinaryTypeCount = 1 && effectTypeCount = 0 && expectTypeCount = 1 && totalCount = 2

                        if totalCount <= 1 || isAllowedTypeNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Type declaration '{name}' is declared more than once"))

                let traitNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | TraitDeclarationNode declaration ->
                            [ declaration.Name, OrdinaryTraitContributor ]
                        | ExpectDeclarationNode (ExpectTraitDeclaration declaration) ->
                            [ declaration.Name, ExpectTraitContributor ]
                        | _ ->
                            [])
                    |> List.groupBy fst
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor) -> currentContributor = contributor)
                            |> List.length

                        let ordinaryTraitCount = count OrdinaryTraitContributor
                        let expectTraitCount = count ExpectTraitContributor
                        let totalCount = entries.Length

                        let isAllowedTraitNamespaceShape =
                            ordinaryTraitCount = 1 && expectTraitCount = 1 && totalCount = 2

                        if totalCount <= 1 || isAllowedTraitNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Trait declaration '{name}' is declared more than once"))

                let constructorNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | DataDeclarationNode declaration ->
                            declaration.Constructors
                            |> List.map (fun constructor -> constructor.Name)
                            |> List.filter (fun name -> not (String.Equals(name, "<anonymous>", StringComparison.Ordinal)))
                        | _ ->
                            [])
                    |> List.countBy id
                    |> List.choose (fun (name, count) ->
                        if count > 1 then
                            Some(makeDuplicateDiagnostic moduleName $"Constructor declaration '{name}' is declared more than once")
                        else
                            None)

                let instanceDiagnostics =
                    groupedDeclarations
                    |> List.choose (fun (_, declaration) ->
                        match declaration with
                        | InstanceDeclarationNode declaration ->
                            Some(tokensText declaration.FullHeaderTokens)
                        | _ ->
                            None)
                    |> List.countBy id
                    |> List.choose (fun (headerText, count) ->
                        if count > 1 then
                            Some(makeDuplicateDiagnostic moduleName $"Instance declaration '{headerText}' is declared more than once")
                        else
                            None)

                termNamespaceDiagnostics
                @ typeNamespaceDiagnostics
                @ traitNamespaceDiagnostics
                @ constructorNamespaceDiagnostics
                @ instanceDiagnostics)

        let validateFrontendModule (frontendModule: KFrontIRModule) =
            let moduleName = moduleNameText frontendModule.ModuleIdentity

            let topLevelNames =
                frontendModule.Declarations
                |> List.collect (function
                    | SignatureDeclaration declaration -> [ declaration.Name ]
                    | LetDeclaration declaration -> declaration.Name |> Option.toList
                    | ProjectionDeclarationNode declaration -> [ declaration.Name ]
                    | DataDeclarationNode declaration ->
                        declaration.Name :: (declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                    | EffectDeclarationNode declaration -> [ declaration.Name ]
                    | TypeAliasNode declaration -> [ declaration.Name ]
                    | TraitDeclarationNode declaration -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> [ declaration.Name ]
                    | _ -> [])
                |> Set.ofList

            let topLevelEffects =
                let localEffects =
                    frontendModule.Declarations
                    |> List.choose (function
                        | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleName declaration)
                        | _ -> None)

                localEffects @ importedEffectDeclarations surfaceIndex effectDeclarationsByModule moduleName

            withScopedEffectDeclarations topLevelEffects (fun () ->
                let makeDiagnostic code message =
                    { Severity = DiagnosticSeverity.Error
                      Code = code
                      Stage = Some "KFrontIR"
                      Phase = Some(KFrontIRPhase.phaseName CORE_LOWERING)
                      Message = message
                      Location = None
                      RelatedLocations = [] }

                let baseEnvironment =
                    { CurrentModuleName = moduleName
                      SurfaceIndex = surfaceIndex
                      VisibleTypeAliases = mergeVisibleTypeAliases surfaceIndex moduleName
                      VisibleTypeFacets = mergeVisibleTypeFacets surfaceIndex moduleName
                      VisibleStaticObjects = Map.empty
                      VisibleModules = mergeVisibleModules surfaceIndex moduleName
                      VisibleRecordTypes = mergeVisibleRecordTypes surfaceIndex moduleName
                      VisibleBindings = mergeVisibleBindings surfaceIndex moduleName
                      VisibleConstructors = mergeVisibleConstructors surfaceIndex moduleName
                      AmbiguousVisibleOrdinaryTerms = mergeAmbiguousVisibleOrdinaryTerms surfaceIndex moduleName
                      VisibleProjections = mergeVisibleProjections surfaceIndex moduleName
                      VisibleTraits = mergeVisibleTraits surfaceIndex moduleName
                      VisibleInstances = visibleInstances surfaceIndex moduleName
                      ElaborationAvailableBindings =
                        mergeVisibleBindings surfaceIndex moduleName
                        |> Map.keys
                        |> Set.ofSeq
                        |> Set.intersect (IntrinsicCatalog.elaborationAvailableIntrinsicTermNames ())
                      ConstraintDictionaries = Map.empty
                      ConstrainedMembers = Map.empty }

                let environment =
                    let staticObjectAliases =
                        let localAliases =
                            buildStaticObjectAliasesForModule baseEnvironment frontendModule.Declarations

                        topLevelEffects
                        |> List.filter (fun declaration -> declaration.Name.Contains("."))
                        |> List.fold (fun current declaration ->
                            let semanticDeclaration =
                                declaration
                                |> EffectSemantics.ensureTopLevel moduleName
                                |> EffectSemantics.toSemantic

                            Map.add declaration.Name (scopedEffectLabelStaticObject semanticDeclaration) current) localAliases

                    { baseEnvironment with
                        VisibleStaticObjects = staticObjectAliases }

                let hasUnknownNonQualifiedImportSurface =
                    frontendModule.Declarations
                    |> List.exists (function
                        | ImportDeclaration (_, specs) ->
                            specs
                            |> List.exists (fun spec ->
                                match spec.Selection, spec.Source with
                                | QualifiedOnly, _ ->
                                    false
                                | _, Url _ ->
                                    true
                                | _, Dotted moduleSegments ->
                                    surfaceIndex.ContainsKey(SyntaxFacts.moduleNameToText moduleSegments) |> not)
                        | _ ->
                            false)

                let allowUnresolvedCallDiagnostics =
                    not (frontendModule.Diagnostics |> List.exists (fun diagnostic -> diagnostic.Severity = Error))
                    && not hasUnknownNonQualifiedImportSurface

                let knownSurfaceTermNames =
                    let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()
                    let standardRuntimeNames =
                        Set.ofList
                            [ "bindModule"; "bindModuleOwned"; "bridgePackageValue"; "bridgePackageOrigin"; "bridgeFailureToCastBlame"
                              "checkedCast"; "checkedCastWith"; "sameDynRep"; "toDyn"; "toDynWith"
                              "Conservative"; "Exact"; "IntoKappa"; "LaterUse"; "Lossy"; "OutOfKappa" ]

                    let compilerKnownSurfaceTerms =
                        Set.ofList
                            [ "thunk"
                              "lazy"
                              "force"
                              "captureBorrow"
                              "withBorrowView"
                              "fork"
                              "defEqSyntax"
                              "headSymbolSyntax"
                              "sameSymbol" ]

                    let visibleTraitMemberNames =
                        environment.VisibleTraits
                        |> Map.values
                        |> Seq.collect (fun traitInfo -> traitInfo.Members.Keys)
                        |> Set.ofSeq

                    let importedOrdinarySurfaceNames =
                        collectImportedOrdinarySurfaceNames surfaceIndex moduleName

                    [ topLevelNames
                      preludeContract.TermNames
                      preludeContract.TypeNames
                      preludeContract.TraitNames
                      Set.ofList Stdlib.FixedPreludeConstructors
                      IntrinsicCatalog.namedIntrinsicTermNames ()
                      standardRuntimeNames
                      compilerKnownSurfaceTerms
                      environment.VisibleBindings |> Map.keys |> Set.ofSeq
                      environment.VisibleConstructors |> Map.keys |> Set.ofSeq
                      importedOrdinarySurfaceNames
                      environment.VisibleModules
                      environment.VisibleStaticObjects |> Map.keys |> Set.ofSeq
                      environment.VisibleTypeFacets |> Map.keys |> Set.ofSeq
                      environment.VisibleTraits |> Map.keys |> Set.ofSeq
                      visibleTraitMemberNames
                      environment.ConstrainedMembers |> Map.keys |> Set.ofSeq ]
                    |> Set.unionMany
                    |> Set.remove "<anonymous>"

                let validateProjectionDeclaration (declaration: ProjectionDeclaration) =
                    let placeBinders =
                        declaration.Binders
                        |> List.choose (function
                            | ProjectionPlaceBinder binder -> Some binder
                            | ProjectionValueBinder _ -> None)

                    let placeBinderNames = placeBinders |> List.map (fun binder -> binder.Name) |> Set.ofList

                    let missingPlaceDiagnostics =
                        if List.isEmpty placeBinders then
                            [ makeDiagnostic DiagnosticCode.ProjectionMissingPlaceBinder "A projection definition must declare at least one place binder." ]
                        else
                            []

                    let rec selectorYieldDiagnostics body =
                        match body with
                        | ProjectionYield(Name(root :: _)) when Set.contains root placeBinderNames ->
                            []
                        | ProjectionYield(Apply(Name [ projectionName ], _)) ->
                            match environment.VisibleProjections |> Map.tryFind projectionName with
                            | Some nestedProjection ->
                                match nestedProjection.Body with
                                | Some(ProjectionAccessors _) ->
                                    [ makeDiagnostic DiagnosticCode.ProjectionYieldInvalid "A selector projection yield must denote a stable place, not an accessor bundle." ]
                                | _ ->
                                    []
                            | None ->
                                [ makeDiagnostic DiagnosticCode.ProjectionYieldInvalid "A selector projection yield must denote a stable place." ]
                        | ProjectionYield _ ->
                            [ makeDiagnostic DiagnosticCode.ProjectionYieldInvalid "A selector projection yield must denote a stable place rooted in a place binder." ]
                        | ProjectionIfThenElse(_, whenTrue, whenFalse) ->
                            selectorYieldDiagnostics whenTrue @ selectorYieldDiagnostics whenFalse
                        | ProjectionMatch(_, cases) ->
                            cases |> List.collect (fun caseClause -> selectorYieldDiagnostics caseClause.Body)
                        | ProjectionAccessors _ ->
                            []

                    let expandedDiagnostics =
                        if List.isEmpty placeBinders then
                            []
                        else
                            match declaration.Body with
                            | Some(ProjectionAccessors clauses) ->
                                let placeCountDiagnostics =
                                    if List.length placeBinders = 1 then
                                        []
                                    else
                                        [ makeDiagnostic DiagnosticCode.ProjectionExpandedAccessorPlaceBinderMismatch "An expanded accessor projection must declare exactly one place binder." ]

                                let duplicateDiagnostics =
                                    clauses
                                    |> List.map (function
                                        | ProjectionGet _ -> "get"
                                        | ProjectionInout _ -> "inout"
                                        | ProjectionSet _ -> "set"
                                        | ProjectionSink _ -> "sink")
                                    |> List.countBy id
                                    |> List.choose (fun (kind, count) ->
                                        if count > 1 then
                                            Some(makeDiagnostic DiagnosticCode.ProjectionAccessorClauseDuplicate $"Projection accessor clause '{kind}' is declared more than once.")
                                        else
                                            None)

                                placeCountDiagnostics @ duplicateDiagnostics
                            | Some body ->
                                selectorYieldDiagnostics body
                            | None ->
                                []

                    missingPlaceDiagnostics @ expandedDiagnostics

                let moduleAttributeDiagnostics =
                    let supportedAttributes =
                        ModuleAttribute.knownAttributes
                        |> Set.toList
                        |> List.sort
                        |> List.map (fun attributeName -> "@" + attributeName)
                        |> String.concat ", "

                    frontendModule.ModuleAttributes
                    |> List.choose (fun attributeName ->
                        if ModuleAttribute.isKnown attributeName then
                            None
                        else
                            Some(
                                makeDiagnostic
                                    DiagnosticCode.ModuleAttributeUnknown
                                    $"Unknown module attribute '@{attributeName}'. Supported module attributes in this implementation are: {supportedAttributes}."
                            ))

                let totalityAssertionDiagnostics =
                    let allowAssertTerminates = moduleHasAttribute frontendModule ModuleAttribute.AllowAssertTerminates
                    let allowAssertReducible = moduleHasAttribute frontendModule ModuleAttribute.AllowAssertReducible

                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition ->
                            match definition.TotalityAssertion with
                            | Some AssertTerminatesAssertion when not allowAssertTerminates ->
                                let bindingName = definition.Name |> Option.defaultValue "<anonymous>"
                                Some(makeDiagnostic DiagnosticCode.AssertTerminatesRequiresModuleAttribute $"Declaration '{bindingName}' uses assertTerminates/assertTotal without enabling module attribute 'allow_assert_terminates'.")
                            | Some AssertReducibleAssertion when not allowAssertReducible ->
                                let bindingName = definition.Name |> Option.defaultValue "<anonymous>"
                                Some(makeDiagnostic DiagnosticCode.AssertReducibleRequiresModuleAttribute $"Declaration '{bindingName}' uses assertReducible without enabling module attribute 'allow_assert_reducible'.")
                            | _ ->
                                None
                        | _ ->
                            None)

                let typeAliasCycleDiagnostics =
                    let rec referencedTypeNames typeExpr =
                        seq {
                            match typeExpr with
                            | TypeLevelLiteral _ ->
                                ()
                            | TypeUniverse None ->
                                ()
                            | TypeUniverse(Some universeExpr) ->
                                yield! referencedTypeNames universeExpr
                            | TypeIntrinsic _ ->
                                ()
                            | TypeApply(callee, arguments) ->
                                yield! referencedTypeNames callee

                                for argument in arguments do
                                    yield! referencedTypeNames argument
                            | TypeLambda(_, parameterSort, body) ->
                                yield! referencedTypeNames parameterSort
                                yield! referencedTypeNames body
                            | TypeDelay inner
                            | TypeMemo inner
                            | TypeForce inner ->
                                yield! referencedTypeNames inner
                            | TypeProject(target, _) ->
                                yield! referencedTypeNames target
                            | TypeName(name, arguments) ->
                                match name with
                                | [ localName ] -> yield localName
                                | _ -> ()

                                for argument in arguments do
                                    yield! referencedTypeNames argument
                            | TypeVariable _ ->
                                ()
                            | TypeArrow(_, parameterType, resultType) ->
                                yield! referencedTypeNames parameterType
                                yield! referencedTypeNames resultType
                            | TypeEquality(left, right) ->
                                yield! referencedTypeNames left
                                yield! referencedTypeNames right
                            | TypeCapture(inner, _) ->
                                yield! referencedTypeNames inner
                            | TypeEffectRow(entries, tail) ->
                                for entry in entries do
                                    yield! referencedTypeNames entry.Label
                                    yield! referencedTypeNames entry.Effect

                                match tail with
                                | Some tailType -> yield! referencedTypeNames tailType
                                | None -> ()
                            | TypeRecord fields ->
                                for field in fields do
                                    yield! referencedTypeNames field.Type
                            | TypeUnion members ->
                                for memberType in members do
                                    yield! referencedTypeNames memberType
                        }

                    let localAliases =
                        frontendModule.Declarations
                        |> List.choose (function
                            | TypeAliasNode declaration -> tryParseTypeAliasInfo moduleName declaration
                            | _ -> None)
                        |> Map.ofList

                    let aliasDependencies =
                        localAliases
                        |> Map.map (fun _ aliasInfo ->
                            referencedTypeNames aliasInfo.Body
                            |> Seq.filter (fun referencedName ->
                                Map.containsKey referencedName localAliases
                                && not (List.contains referencedName aliasInfo.Parameters))
                            |> Set.ofSeq)

                    let rec reaches start current visited =
                        aliasDependencies
                        |> Map.tryFind current
                        |> Option.defaultValue Set.empty
                        |> Seq.exists (fun dependency ->
                            String.Equals(dependency, start, StringComparison.Ordinal)
                            || (not (Set.contains dependency visited)
                                && reaches start dependency (Set.add dependency visited)))

                    aliasDependencies
                    |> Map.keys
                    |> Seq.filter (fun aliasName -> reaches aliasName aliasName (Set.singleton aliasName))
                    |> Seq.distinct
                    |> Seq.map (fun aliasName ->
                        makeDiagnostic DiagnosticCode.RecursiveTypeAlias $"Type alias '{aliasName}' recursively depends on itself.")
                    |> Seq.toList

                let malformedConstructorDiagnostics =
                    let declarationKeywordNames =
                        Set.ofList [ "data"; "expect"; "export"; "import"; "instance"; "let"; "module"; "opaque"; "private"; "projection"; "public"; "trait"; "type" ]

                    let exposesRuntimeTypeField (constructor: DataConstructor) =
                        let exposedFieldTypes =
                            match constructor.Parameters with
                            | Some parameters ->
                                parameters
                                |> List.choose (fun parameter ->
                                    if parameter.ParameterIsImplicit || parameter.ParameterQuantity = Some QuantityZero then
                                        None
                                    else
                                        TypeSignatures.parseType parameter.ParameterTypeTokens)
                            | None ->
                                TypeSignatures.constructorParameterTokenGroups constructor
                                |> List.choose (fun parameterTokens ->
                                    match parameterTokens with
                                    | { Kind = AtSign } :: _ ->
                                        None
                                    | { Kind = IntegerLiteral; Text = "0" } :: _ ->
                                        None
                                    | _ ->
                                        let typeTokens =
                                            match parameterTokens |> List.tryFindIndex (fun token -> token.Kind = Colon) with
                                            | Some colonIndex when colonIndex + 1 < parameterTokens.Length ->
                                                parameterTokens |> List.skip (colonIndex + 1)
                                            | _ ->
                                                parameterTokens

                                        TypeSignatures.parseType typeTokens)

                        exposedFieldTypes
                        |> List.exists (function
                            | TypeUniverse _ -> true
                            | TypeIntrinsic UniverseClassifier -> true
                            | TypeName([ "Type" ], _) -> true
                            | _ -> false)

                    let constructorHasMalformedShape (constructor: DataConstructor) =
                        let significant = significantTokens constructor.Tokens

                        let hasUnbalancedDelimiters tokens =
                            let mutable parenDepth = 0
                            let mutable braceDepth = 0
                            let mutable bracketDepth = 0
                            let mutable setBraceDepth = 0

                            for token in tokens do
                                match token.Kind with
                                | LeftParen -> parenDepth <- parenDepth + 1
                                | RightParen -> parenDepth <- max 0 (parenDepth - 1)
                                | LeftBrace -> braceDepth <- braceDepth + 1
                                | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
                                | LeftBracket -> bracketDepth <- bracketDepth + 1
                                | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
                                | LeftSetBrace -> setBraceDepth <- setBraceDepth + 1
                                | RightSetBrace -> setBraceDepth <- max 0 (setBraceDepth - 1)
                                | _ -> ()

                            parenDepth <> 0 || braceDepth <> 0 || bracketDepth <> 0 || setBraceDepth <> 0

                        if hasUnbalancedDelimiters significant then
                            false
                        else
                            let stripConstructorName tokens =
                                let isSymbolToken token =
                                    match token.Kind with
                                    | Operator
                                    | Colon
                                    | Equals -> true
                                    | _ -> false

                                match tokens with
                                | { Kind = LeftParen } :: rest ->
                                    let rec loop remaining =
                                        match remaining with
                                        | { Kind = RightParen } :: tail ->
                                            tail
                                        | token :: tail when isSymbolToken token ->
                                            loop tail
                                        | _ ->
                                            tokens

                                    loop rest
                                | _nameToken :: rest ->
                                    rest
                                | [] ->
                                    []

                            let remainingTokens =
                                match significant with
                                | { Kind = Operator; Text = "|" } :: rest -> stripConstructorName rest
                                | _ -> stripConstructorName significant

                            match constructor.Parameters, remainingTokens with
                            | Some _, _ ->
                                false
                            | None, [] ->
                                false
                            | None, { Kind = Colon } :: typeTokens ->
                                TypeSignatures.parseScheme typeTokens |> Option.isNone
                            | None, _ ->
                                List.isEmpty (TypeSignatures.constructorFieldTypes constructor)

                    frontendModule.Declarations
                    |> List.collect (function
                        | DataDeclarationNode declaration ->
                            declaration.Constructors
                            |> List.choose (fun constructor ->
                                if Set.contains constructor.Name declarationKeywordNames then
                                    Some(makeDiagnostic DiagnosticCode.MalformedConstructorDeclaration $"Constructor declaration in data type '{declaration.Name}' starts with declaration keyword '{constructor.Name}'.")
                                elif exposesRuntimeTypeField constructor then
                                    Some(makeDiagnostic DiagnosticCode.MalformedConstructorDeclaration $"Constructor '{constructor.Name}' exposes runtime field metadata of type 'Type'.")
                                elif constructorHasMalformedShape constructor then
                                    Some(makeDiagnostic DiagnosticCode.MalformedConstructorDeclaration $"Constructor declaration '{constructor.Name}' in data type '{declaration.Name}' is malformed.")
                                else
                                    None)
                        | _ ->
                            [])

                let patternDuplicateDiagnostics pattern =
                    let duplicateNames current =
                        collectPatternNames current
                        |> List.countBy id
                        |> List.choose (fun (name, count) ->
                            if count > 1 then
                                Some(makeDiagnostic DiagnosticCode.DuplicatePatternBinder $"Pattern binder '{name}' is bound more than once in the same pattern.")
                            else
                                None)

                    let rec loop current =
                        match current with
                        | AsPattern(_, inner) ->
                            duplicateNames current @ loop inner
                        | TypedPattern(inner, _) ->
                            duplicateNames current @ loop inner
                        | OrPattern alternatives ->
                            alternatives |> List.collect loop
                        | ConstructorPattern(_, arguments) ->
                            duplicateNames current @ (arguments |> List.collect loop)
                        | NamedConstructorPattern(_, fields) ->
                            duplicateNames current @ (fields |> List.collect (fun field -> loop field.Pattern))
                        | TuplePattern elements ->
                            duplicateNames current @ (elements |> List.collect loop)
                        | VariantPattern _ ->
                            duplicateNames current
                        | AnonymousRecordPattern(fields, _) ->
                            duplicateNames current @ (fields |> List.collect (fun field -> loop field.Pattern))
                        | WildcardPattern
                        | NamePattern _
                        | LiteralPattern _ ->
                            []

                    loop pattern |> List.distinctBy (fun diagnostic -> diagnostic.Message)

                let extendPatternLocalsWithoutMutation locals expectedType pattern =
                    let localCounter = ref 0
                    extendPatternLocalTypes environment localCounter locals expectedType pattern

                let orPatternBinderTypeDiagnostics expectedType pattern =
                    let normalize = normalizeTypeAliases environment.VisibleTypeAliases

                    let typedBindingsForAlternative currentExpected alternative =
                        let boundNames =
                            collectPatternNames alternative |> Set.ofList

                        let inferredBindings =
                            extendPatternLocalsWithoutMutation Map.empty currentExpected alternative

                        boundNames
                        |> Seq.choose (fun name -> inferredBindings |> Map.tryFind name |> Option.map (fun bindingType -> name, bindingType))
                        |> Map.ofSeq

                    let rec loop expected currentPattern =
                        let currentDiagnostics =
                            match currentPattern with
                            | OrPattern alternatives ->
                                match alternatives with
                                | [] ->
                                    []
                                | firstAlternative :: restAlternatives ->
                                    let firstNames = collectPatternNames firstAlternative |> Set.ofList
                                    let firstBindings = typedBindingsForAlternative expected firstAlternative

                                    restAlternatives
                                    |> List.collect (fun alternative ->
                                        let alternativeNames = collectPatternNames alternative |> Set.ofList
                                        let alternativeBindings = typedBindingsForAlternative expected alternative

                                        if alternativeNames <> firstNames then
                                            []
                                        else
                                            let comparableNames =
                                                Set.intersect
                                                    (firstBindings |> Map.keys |> Set.ofSeq)
                                                    (alternativeBindings |> Map.keys |> Set.ofSeq)

                                            comparableNames
                                            |> Seq.choose (fun name ->
                                                let firstType = firstBindings[name] |> normalize
                                                let alternativeType = alternativeBindings[name] |> normalize

                                                if TypeSignatures.definitionallyEqual firstType alternativeType then
                                                    None
                                                else
                                                    Some(
                                                        makeDiagnostic
                                                            DiagnosticCode.OrPatternBinderTypeMismatch
                                                            $"Binder '{name}' has type '{TypeSignatures.toText firstType}' in one or-pattern alternative but '{TypeSignatures.toText alternativeType}' in another."
                                                    ))
                                            |> Seq.toList)
                            | _ ->
                                []

                        let nestedDiagnostics =
                            match currentPattern with
                            | AsPattern(_, inner) ->
                                loop expected inner
                            | TypedPattern(inner, typeTokens) ->
                                let ascribedType =
                                    TypeSignatures.parseType typeTokens
                                    |> Option.map (qualifyVisibleTypeNames environment)
                                    |> Option.orElse expected

                                loop ascribedType inner
                            | TuplePattern elements ->
                                let tupleFields =
                                    elements
                                    |> List.mapi (fun index element ->
                                        { Name = $"_{index + 1}"
                                          IsImplicit = false
                                          Pattern = element })

                                loop expected (AnonymousRecordPattern(tupleFields, None))
                            | AnonymousRecordPattern(fields, _) ->
                                match expected |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                                | Some(TypeRecord recordFields) ->
                                    fields
                                    |> List.collect (fun field ->
                                        let fieldType =
                                            recordFields
                                            |> List.tryFind (fun recordField -> String.Equals(recordField.Name, field.Name, StringComparison.Ordinal))
                                            |> Option.map (fun recordField -> recordField.Type)

                                        loop fieldType field.Pattern)
                                | _ ->
                                    fields |> List.collect (fun field -> loop None field.Pattern)
                            | ConstructorPattern(nameSegments, arguments) ->
                                let argumentTypes =
                                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                                    | Some expectedResultType, Some constructorInfo ->
                                        let localCounter = ref 0
                                        let instantiated = TypeSignatures.instantiate "t" !localCounter constructorInfo.Scheme
                                        localCounter.Value <- !localCounter + instantiated.Forall.Length

                                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                                        if List.length parameterTypes = List.length arguments then
                                            match
                                                TypeSignatures.tryUnifyMany
                                                    [
                                                        qualifyVisibleTypeNames environment constructorResultType,
                                                        qualifyVisibleTypeNames environment expectedResultType
                                                    ]
                                            with
                                            | Some substitution ->
                                                parameterTypes
                                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                                            | None ->
                                                List.replicate arguments.Length None
                                        else
                                            List.replicate arguments.Length None
                                    | _ ->
                                        List.replicate arguments.Length None

                                List.zip arguments argumentTypes
                                |> List.collect (fun (argumentPattern, argumentType) -> loop argumentType argumentPattern)
                            | NamedConstructorPattern(nameSegments, fields) ->
                                let argumentTypes =
                                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                                    | Some expectedResultType, Some constructorInfo ->
                                        let localCounter = ref 0
                                        let instantiated = TypeSignatures.instantiate "t" !localCounter constructorInfo.Scheme
                                        localCounter.Value <- !localCounter + instantiated.Forall.Length

                                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                                        let fieldTypeMap =
                                            constructorInfo.ParameterLayouts
                                            |> Option.map (fun layouts ->
                                                layouts
                                                |> List.filter (fun parameter -> not parameter.IsImplicit)
                                                |> List.map (fun parameter -> parameter.Name)
                                                |> List.zip parameterTypes
                                                |> List.map (fun (fieldType, fieldName) -> fieldName, fieldType)
                                                |> Map.ofList)
                                            |> Option.defaultValue Map.empty

                                        match
                                            TypeSignatures.tryUnifyMany
                                                [
                                                    qualifyVisibleTypeNames environment constructorResultType,
                                                    qualifyVisibleTypeNames environment expectedResultType
                                                ]
                                        with
                                        | Some substitution ->
                                            fieldTypeMap
                                            |> Map.map (fun _ fieldType -> TypeSignatures.applySubstitution substitution fieldType)
                                        | None ->
                                            Map.empty
                                    | _ ->
                                        Map.empty

                                fields
                                |> List.collect (fun field ->
                                    let fieldType = argumentTypes |> Map.tryFind field.Name
                                    loop fieldType field.Pattern)
                            | OrPattern alternatives ->
                                alternatives |> List.collect (loop expected)
                            | VariantPattern _
                            | WildcardPattern
                            | NamePattern _
                            | LiteralPattern _ ->
                                []

                        currentDiagnostics @ nestedDiagnostics

                    loop expectedType pattern

                let unsignedRecursiveBindingDiagnostics =
                    let signatureNames =
                        frontendModule.Declarations
                        |> List.choose (function
                            | SignatureDeclaration declaration -> Some declaration.Name
                            | _ -> None)
                        |> Set.ofList

                    let patternNames pattern =
                        collectPatternNames pattern |> Set.ofList

                    let parameterNames (parameters: Parameter list) =
                        parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList

                    let rec expressionReferences target shadowed expression =
                        let references = expressionReferences target shadowed

                        match expression with
                        | Name [ name ] ->
                            String.Equals(name, target, StringComparison.Ordinal)
                            && not (Set.contains name shadowed)
                        | TypeSyntaxTokens _ ->
                            false
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner ->
                            references inner
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            references label
                            || references body
                            || references returnClause.Body
                            || (operationClauses |> List.exists (fun clause -> references clause.Body))
                        | Apply(callee, arguments) ->
                            references callee || (arguments |> List.exists references)
                        | LocalLet(binding, value, body) ->
                            references value
                            || expressionReferences target (Set.union shadowed (patternNames binding.Pattern)) body
                        | LocalSignature(declaration, body) ->
                            if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                                false
                            else
                                expressionReferences target (Set.add declaration.Name shadowed) body
                        | LocalTypeAlias(_, body) ->
                            references body
                        | LocalScopedEffect(_, body) ->
                            references body
                        | Lambda(parameters, body) ->
                            expressionReferences target (Set.union shadowed (parameterNames parameters)) body
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            references condition || references whenTrue || references whenFalse
                        | Match(scrutinee, cases) ->
                            references scrutinee
                            || (cases
                                |> List.exists (fun caseClause ->
                                    let caseShadowed = Set.union shadowed (patternNames caseClause.Pattern)
                                    (caseClause.Guard |> Option.exists (expressionReferences target caseShadowed))
                                    || expressionReferences target caseShadowed caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.exists (fun field -> references field.Value)
                        | Seal(value, _) ->
                            references value
                        | RecordUpdate(receiver, fields) ->
                            references receiver || (fields |> List.exists (fun field -> references field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            references receiver || (arguments |> List.exists references)
                        | SafeNavigation(receiver, navigation) ->
                            references receiver || (navigation.Arguments |> List.exists references)
                        | TagTest(receiver, _) ->
                            references receiver
                        | Do statements ->
                            doStatementsReference target shadowed statements
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner) ->
                            references inner
                        | NamedApplicationBlock fields ->
                            fields |> List.exists (fun field -> references field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            references left || references right
                        | Comprehension comprehension ->
                            references comprehension.Lowered
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.exists (function
                                | StringText _ -> false
                                | StringInterpolation(inner, _) -> references inner)
                        | Literal _
                        | NumericLiteral _
                        | KindQualifiedName _
                        | Name _ ->
                            false

                    and doStatementsReference target shadowed statements =
                        match statements with
                        | [] ->
                            false
                        | statement :: rest ->
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target (Set.union shadowed (patternNames binding.Pattern)) rest
                            | DoLetQuestion(binding, expression, failure) ->
                                let failureReferences =
                                    failure
                                    |> Option.exists (fun block ->
                                        doStatementsReference target (Set.union shadowed (patternNames block.ResiduePattern.Pattern)) block.Body)

                                expressionReferences target shadowed expression
                                || failureReferences
                                || doStatementsReference target (Set.union shadowed (patternNames binding.Pattern)) rest
                            | DoVar(name, expression) ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target (Set.add name shadowed) rest
                            | DoAssign(_, expression)
                            | DoDefer expression
                            | DoExpression expression
                            | DoReturn expression ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target shadowed rest
                            | DoIf(condition, whenTrue, whenFalse) ->
                                expressionReferences target shadowed condition
                                || doStatementsReference target shadowed whenTrue
                                || doStatementsReference target shadowed whenFalse
                                || doStatementsReference target shadowed rest
                            | DoWhile(condition, body) ->
                                expressionReferences target shadowed condition
                                || doStatementsReference target shadowed body
                                || doStatementsReference target shadowed rest

                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition
                            when definition.Name.IsSome
                                 && definition.Body.IsSome
                                 && not (Set.contains definition.Name.Value signatureNames) ->
                            let name = definition.Name.Value
                            let shadowed = parameterNames definition.Parameters

                            if expressionReferences name shadowed definition.Body.Value then
                                Some(makeDiagnostic DiagnosticCode.RecursionRequiresSignature $"Top-level binding '{name}' is recursive but has no preceding signature declaration.")
                            else
                                None
                        | _ ->
                            None)

                let trivialRecursiveCycleDiagnostics =
                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition
                            when definition.Name.IsSome
                                 && definition.Body.IsSome
                                 && List.isEmpty definition.Parameters ->
                            let name = definition.Name.Value

                            match definition.Body.Value with
                            | Name [ referencedName ] when String.Equals(referencedName, name, StringComparison.Ordinal) ->
                                Some(
                                    makeDiagnostic
                                        DiagnosticCode.RecursionRequiresSignature
                                        $"Recursive cycle for binding '{name}' is not total and must be rejected."
                                )
                            | _ ->
                                None
                        | _ ->
                            None)

                let expressionPatternDiagnostics initialLocalTypes expression =
                    let extendParameterLocalTypes locals (parameters: Parameter list) =
                        parameters
                        |> List.fold
                            (fun current parameter ->
                                match parameter.TypeTokens |> Option.bind TypeSignatures.parseType with
                                | Some parameterType ->
                                    Map.add parameter.Name (qualifyVisibleTypeNames environment parameterType) current
                                | None ->
                                    current)
                            locals

                    let inferExpectedType localTypes expression =
                        inferValidationExpressionType environment (ref 0) localTypes expression

                    let rec validateExpression localTypes current =
                        match current with
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner ->
                            validateExpression localTypes inner
                        | TypeSyntaxTokens _ ->
                            []
                        | LocalLet(binding, value, body) ->
                            let valueType = inferExpectedType localTypes value
                            let nextLocals = extendPatternLocalsWithoutMutation localTypes valueType binding.Pattern

                            patternDuplicateDiagnostics binding.Pattern
                            @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                            @ validateExpression localTypes value
                            @ validateExpression nextLocals body
                        | LocalSignature(_, body) ->
                            validateExpression localTypes body
                        | LocalTypeAlias(_, body) ->
                            validateExpression localTypes body
                        | LocalScopedEffect(_, body) ->
                            validateExpression localTypes body
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            validateExpression localTypes label
                            @ validateExpression localTypes body
                            @ validateExpression localTypes returnClause.Body
                            @ (operationClauses |> List.collect (fun clause -> validateExpression localTypes clause.Body))
                        | Lambda(parameters, body) ->
                            validateExpression (extendParameterLocalTypes localTypes parameters) body
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            validateExpression localTypes condition
                            @ validateExpression localTypes whenTrue
                            @ validateExpression localTypes whenFalse
                        | Match(scrutinee, cases) ->
                            let scrutineeType = inferExpectedType localTypes scrutinee

                            validateExpression localTypes scrutinee
                            @ (cases
                               |> List.collect (fun caseClause ->
                                   let caseLocals =
                                       extendPatternLocalsWithoutMutation localTypes scrutineeType caseClause.Pattern

                                   patternDuplicateDiagnostics caseClause.Pattern
                                   @ orPatternBinderTypeDiagnostics scrutineeType caseClause.Pattern
                                   @ (caseClause.Guard |> Option.map (validateExpression caseLocals) |> Option.defaultValue [])
                                   @ validateExpression caseLocals caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.collect (fun field -> validateExpression localTypes field.Value)
                        | Seal(value, _) ->
                            validateExpression localTypes value
                        | RecordUpdate(receiver, fields) ->
                            validateExpression localTypes receiver
                            @ (fields |> List.collect (fun field -> validateExpression localTypes field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            validateExpression localTypes receiver @ (arguments |> List.collect (validateExpression localTypes))
                        | SafeNavigation(receiver, navigation) ->
                            validateExpression localTypes receiver
                            @ (navigation.Arguments |> List.collect (validateExpression localTypes))
                        | TagTest(receiver, _) ->
                            validateExpression localTypes receiver
                        | Comprehension comprehension ->
                            validateExpression localTypes comprehension.Lowered
                        | Do statements ->
                            validateDo localTypes statements
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner) ->
                            validateExpression localTypes inner
                        | NamedApplicationBlock fields ->
                            fields |> List.collect (fun field -> validateExpression localTypes field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            validateExpression localTypes left @ validateExpression localTypes right
                        | Apply(callee, arguments) ->
                            validateExpression localTypes callee @ (arguments |> List.collect (validateExpression localTypes))
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.collect (function
                                | StringText _ -> []
                                | StringInterpolation(inner, _) -> validateExpression localTypes inner)
                        | Literal _
                        | NumericLiteral _
                        | KindQualifiedName _
                        | Name _ ->
                            []

                    and validateDo localTypes statements =
                        statements
                        |> List.collect (function
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                let valueType = inferExpectedType localTypes expression

                                patternDuplicateDiagnostics binding.Pattern
                                @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                                @ validateExpression localTypes expression
                                @ []
                            | DoLetQuestion(binding, expression, failure) ->
                                let valueType = inferExpectedType localTypes expression

                                patternDuplicateDiagnostics binding.Pattern
                                @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                                @ validateExpression localTypes expression
                                @ (failure
                                   |> Option.map (fun block ->
                                       patternDuplicateDiagnostics block.ResiduePattern.Pattern
                                       @ orPatternBinderTypeDiagnostics valueType block.ResiduePattern.Pattern
                                       @ validateDo localTypes block.Body)
                                   |> Option.defaultValue [])
                            | DoVar(_, expression)
                            | DoAssign(_, expression)
                            | DoDefer expression
                            | DoExpression expression
                            | DoReturn expression ->
                                validateExpression localTypes expression
                            | DoIf(condition, whenTrue, whenFalse) ->
                                validateExpression localTypes condition
                                @ validateDo localTypes whenTrue
                                @ validateDo localTypes whenFalse
                            | DoWhile(condition, body) ->
                                validateExpression localTypes condition @ validateDo localTypes body)

                    validateExpression initialLocalTypes expression

                let expressionNameResolutionDiagnostics (definition: LetDefinition) expression =
                    let ordinaryNameAmbiguityDiagnostic name candidates =
                        makeDiagnostic
                            DiagnosticCode.NameAmbiguous
                            (ordinaryNameAmbiguityMessage name candidates)

                    let simpleClauseBinderName (tokens: Token list) =
                        match significantTokens tokens with
                        | [ token ] when Token.isName token ->
                            Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                        | _ ->
                            None

                    let clauseBoundNames (clause: SurfaceEffectHandlerClause) =
                        let argumentNames =
                            clause.ArgumentTokens
                            |> List.choose simpleClauseBinderName

                        match clause.ResumptionName with
                        | Some name -> name :: argumentNames
                        | None -> argumentNames
                        |> Set.ofList

                    let ordinaryNameAmbiguityDiagnostics name =
                        environment.AmbiguousVisibleOrdinaryTerms
                        |> Map.tryFind name
                        |> Option.bind (fun candidates ->
                            let admissible =
                                candidates
                                |> List.filter (function
                                    | OrdinaryVisibleBindingCandidate _
                                    | OrdinaryVisibleExportedBindingCandidate _
                                    | OrdinaryVisibleConstructorCandidate _
                                    | OrdinaryVisibleModuleCandidate _ -> true)

                            if List.length admissible > 1 then Some admissible else None)
                        |> Option.map (fun candidates -> [ ordinaryNameAmbiguityDiagnostic name candidates ])
                        |> Option.defaultValue []

                    let rec walk shadowed current =
                        match current with
                        | Name [ name ] when not (Set.contains name shadowed) ->
                            ordinaryNameAmbiguityDiagnostics name
                        | Name _
                        | KindQualifiedName _
                        | Literal _
                        | NumericLiteral _ ->
                            []
                        | TypeSyntaxTokens _ ->
                            []
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner)
                        | Seal(inner, _) ->
                            walk shadowed inner
                        | LocalLet(binding, value, body) ->
                            let nextShadowed =
                                Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            walk shadowed value @ walk nextShadowed body
                        | LocalSignature(declaration, body) ->
                            walk (Set.add declaration.Name shadowed) body
                        | LocalTypeAlias(_, body) ->
                            walk shadowed body
                        | LocalScopedEffect(declaration, body) ->
                            walk (Set.add declaration.Name shadowed) body
                        | Lambda(parameters, body) ->
                            let nextShadowed =
                                parameters
                                |> List.map (fun parameter -> parameter.Name)
                                |> Set.ofList
                                |> Set.union shadowed

                            walk nextShadowed body
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            walk shadowed label
                            @ walk shadowed body
                            @ walk (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                            @ (operationClauses
                               |> List.collect (fun clause ->
                                   walk (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            walk shadowed condition @ walk shadowed whenTrue @ walk shadowed whenFalse
                        | Match(scrutinee, cases) ->
                            walk shadowed scrutinee
                            @ (cases
                               |> List.collect (fun caseClause ->
                                   let caseShadowed =
                                       Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                                   (caseClause.Guard |> Option.map (walk caseShadowed) |> Option.defaultValue [])
                                   @ walk caseShadowed caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.collect (fun field -> walk shadowed field.Value)
                        | RecordUpdate(receiver, fields) ->
                            walk shadowed receiver
                            @ (fields |> List.collect (fun field -> walk shadowed field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            walk shadowed receiver @ (arguments |> List.collect (walk shadowed))
                        | SafeNavigation(receiver, navigation) ->
                            walk shadowed receiver @ (navigation.Arguments |> List.collect (walk shadowed))
                        | TagTest(receiver, _) ->
                            walk shadowed receiver
                        | Do statements ->
                            walkDo shadowed statements
                        | Apply(callee, arguments) ->
                            walk shadowed callee @ (arguments |> List.collect (walk shadowed))
                        | NamedApplicationBlock fields ->
                            fields |> List.collect (fun field -> walk shadowed field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            walk shadowed left @ walk shadowed right
                        | Comprehension comprehension ->
                            walkComprehension shadowed comprehension
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.collect (function
                                | StringText _ -> []
                                | StringInterpolation(inner, _) -> walk shadowed inner)

                    and walkComprehension shadowed (comprehension: SurfaceComprehension) =
                        let walkYield currentShadowed =
                            match comprehension.Yield with
                            | YieldValue value ->
                                walk currentShadowed value
                            | YieldKeyValue(key, value) ->
                                walk currentShadowed key @ walk currentShadowed value

                        let rec loop currentShadowed clauses =
                            match clauses with
                            | [] ->
                                walkYield currentShadowed
                            | clause :: rest ->
                                match clause with
                                | ForClause(_, _, binding, source) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source @ loop nextShadowed rest
                                | JoinClause(binding, source, condition) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source
                                    @ walk nextShadowed condition
                                    @ loop nextShadowed rest
                                | LetClause(_, binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed value @ loop nextShadowed rest
                                | IfClause condition ->
                                    walk currentShadowed condition @ loop currentShadowed rest
                                | GroupByClause(key, aggregations, intoName) ->
                                    walk currentShadowed key
                                    @ (aggregations |> List.collect (fun field -> walk currentShadowed field.Value))
                                    @ loop (Set.singleton intoName) rest
                                | OrderByClause(_, key)
                                | DistinctByClause key
                                | SkipClause key
                                | TakeClause key ->
                                    walk currentShadowed key @ loop currentShadowed rest
                                | DistinctClause ->
                                    loop currentShadowed rest
                                | LeftJoinClause(binding, source, condition, intoName) ->
                                    let joinShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source
                                    @ walk joinShadowed condition
                                    @ loop (Set.add intoName currentShadowed) rest

                        loop shadowed comprehension.Clauses

                    and walkDo shadowed statements =
                        let rec loop currentShadowed remaining =
                            match remaining with
                            | [] ->
                                []
                            | statement :: rest ->
                                match statement with
                                | DoLet(binding, value)
                                | DoBind(binding, value)
                                | DoUsing(binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed value @ loop nextShadowed rest
                                | DoLetQuestion(binding, value, failure) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    let failureDiagnostics =
                                        failure
                                        |> Option.map (fun block ->
                                            let failureShadowed =
                                                Set.union currentShadowed (collectPatternNames block.ResiduePattern.Pattern |> Set.ofList)

                                            walkDo failureShadowed block.Body)
                                        |> Option.defaultValue []

                                    walk currentShadowed value @ failureDiagnostics @ loop nextShadowed rest
                                | DoVar(name, value) ->
                                    walk currentShadowed value @ loop (Set.add name currentShadowed) rest
                                | DoAssign(_, value)
                                | DoDefer value
                                | DoExpression value
                                | DoReturn value ->
                                    walk currentShadowed value @ loop currentShadowed rest
                                | DoIf(condition, whenTrue, whenFalse) ->
                                    walk currentShadowed condition
                                    @ walkDo currentShadowed whenTrue
                                    @ walkDo currentShadowed whenFalse
                                    @ loop currentShadowed rest
                                | DoWhile(condition, body) ->
                                    walk currentShadowed condition
                                    @ walkDo currentShadowed body
                                    @ loop currentShadowed rest

                        loop shadowed statements

                    let initialShadowed =
                        definition.Parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList

                    walk initialShadowed expression

                let constructorDefaultDiagnostics =
                    let topLevelNames =
                        frontendModule.Declarations
                        |> List.collect (function
                            | SignatureDeclaration declaration -> [ declaration.Name ]
                            | LetDeclaration declaration -> declaration.Name |> Option.toList
                            | ProjectionDeclarationNode declaration -> [ declaration.Name ]
                            | DataDeclarationNode declaration ->
                                declaration.Name :: (declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                            | TypeAliasNode declaration -> [ declaration.Name ]
                            | TraitDeclarationNode declaration -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> [ declaration.Name ]
                            | _ -> [])
                        |> Set.ofList

                    let baseVisibleNames =
                        let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()

                        [ topLevelNames
                          preludeContract.TermNames
                          preludeContract.TypeNames
                          preludeContract.TraitNames
                          Set.ofList Stdlib.FixedPreludeConstructors
                          environment.VisibleBindings |> Map.keys |> Set.ofSeq
                          environment.VisibleConstructors |> Map.keys |> Set.ofSeq
                          environment.VisibleModules
                          environment.VisibleStaticObjects |> Map.keys |> Set.ofSeq
                          environment.VisibleTypeFacets |> Map.keys |> Set.ofSeq
                          environment.VisibleTraits |> Map.keys |> Set.ofSeq ]
                        |> Set.unionMany
                        |> Set.remove "<anonymous>"

                    let diagnosticsForDefault parameters index parameterName parameterTypeTokens defaultValue =
                        let earlierParameters = parameters |> List.take index
                        let forbiddenNames =
                            parameters
                            |> List.skip index
                            |> List.choose (fun candidate -> candidate.ParameterName)
                            |> Set.ofList

                        let localTypes =
                            earlierParameters
                            |> List.choose (fun earlier ->
                                match earlier.ParameterName, TypeSignatures.parseType earlier.ParameterTypeTokens with
                                | Some name, Some parameterType -> Some(name, parameterType)
                                | _ -> None)
                            |> Map.ofList

                        let visibleNames =
                            earlierParameters
                            |> List.choose (fun earlier -> earlier.ParameterName)
                            |> Set.ofList
                            |> Set.union baseVisibleNames

                        let nameDiagnostics =
                            ResourceCheckingSurface.expressionNames defaultValue
                            |> Seq.distinct
                            |> Seq.choose (fun referencedName ->
                                if Set.contains referencedName forbiddenNames then
                                    Some(
                                        makeDiagnostic
                                            DiagnosticCode.NameUnresolved
                                            $"Default expression for constructor parameter '{parameterName}' cannot reference '{referencedName}' before it is bound."
                                    )
                                elif not (Set.contains referencedName visibleNames) then
                                    Some(makeDiagnostic DiagnosticCode.NameUnresolved $"Name '{referencedName}' is not in scope.")
                                else
                                    None)
                            |> Seq.toList

                        let typeDiagnostics =
                            match TypeSignatures.parseType parameterTypeTokens, inferValidationExpressionType environment (ref 0) localTypes defaultValue with
                            | Some expectedType, Some actualType
                                when not (
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                                        (normalizeTypeAliases environment.VisibleTypeAliases actualType)
                                ) ->
                                [ makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"Default expression for constructor parameter '{parameterName}' has type '{TypeSignatures.toText actualType}', but '{TypeSignatures.toText expectedType}' was expected." ]
                            | Some _, None when List.isEmpty nameDiagnostics ->
                                [ makeDiagnostic
                                    DiagnosticCode.TypeEqualityMismatch
                                    $"Default expression for constructor parameter '{parameterName}' could not be checked against its declared type." ]
                            | _ ->
                                []

                        nameDiagnostics @ typeDiagnostics

                    let diagnosticsForConstructor (constructor: DataConstructor) =
                        match constructor.Parameters with
                        | Some parameters ->
                            parameters
                            |> List.mapi (fun index parameter -> index, parameter)
                            |> List.collect (fun (index, parameter) ->
                                match parameter.ParameterName, parameter.DefaultValue with
                                | Some parameterName, Some defaultValue ->
                                    diagnosticsForDefault parameters index parameterName parameter.ParameterTypeTokens defaultValue
                                | _ ->
                                    [])
                        | None ->
                            []

                    frontendModule.Declarations
                    |> List.collect (function
                        | DataDeclarationNode declaration ->
                            declaration.Constructors |> List.collect diagnosticsForConstructor
                        | _ ->
                            [])

                let instanceMemberSignatureDiagnostics =
                    let traitInfoByName =
                        environment.VisibleTraits

                    frontendModule.Declarations
                    |> List.collect (function
                        | InstanceDeclarationNode declaration ->
                            tryParseInstanceHeader declaration
                            |> Option.toList
                            |> List.collect (fun (traitName, _, headTypes) ->
                                traitInfoByName
                                |> Map.tryFind traitName
                                |> Option.toList
                                |> List.collect (fun traitInfo ->
                                    let traitSubstitution =
                                        if List.length traitInfo.TypeParameters = List.length headTypes then
                                            List.zip traitInfo.TypeParameters headTypes |> Map.ofList
                                        else
                                            Map.empty

                                    declaration.Members
                                    |> List.collect (fun memberDeclaration ->
                                        match memberDeclaration.Name with
                                        | None ->
                                            []
                                        | Some memberName ->
                                            match traitInfo.Members |> Map.tryFind memberName with
                                            | None ->
                                                []
                                            | Some memberInfo ->
                                                match memberDeclaration.ReturnTypeTokens |> Option.bind TypeSignatures.parseType with
                                                | None ->
                                                    []
                                                | Some declaredReturnType ->
                                                    let expectedReturnType =
                                                        memberInfo.Scheme
                                                        |> TypeSignatures.applySchemeSubstitution traitSubstitution
                                                        |> TypeSignatures.schemeParts
                                                        |> snd

                                                    if
                                                        TypeSignatures.definitionallyEqual
                                                            (normalizeTypeAliases environment.VisibleTypeAliases declaredReturnType)
                                                            (normalizeTypeAliases environment.VisibleTypeAliases expectedReturnType)
                                                    then
                                                        []
                                                    else
                                                        [
                                                            makeDiagnostic
                                                                DiagnosticCode.TypeEqualityMismatch
                                                                $"Instance member '{memberName}' for trait '{traitName}' must return '{TypeSignatures.toText expectedReturnType}', but declares '{TypeSignatures.toText declaredReturnType}'."
                                                        ])))
                        | _ ->
                            [])

                let instanceSupertraitDiagnostics =
                    let traitInfoByName =
                        environment.VisibleTraits

                    let constraintMatches (expected: TraitConstraint) (actual: TraitConstraint) =
                        String.Equals(expected.TraitName, actual.TraitName, StringComparison.Ordinal)
                        && List.length expected.Arguments = List.length actual.Arguments
                        && List.forall2
                            (fun left right ->
                                TypeSignatures.definitionallyEqual
                                    (normalizeTypeAliases environment.VisibleTypeAliases left)
                                    (normalizeTypeAliases environment.VisibleTypeAliases right))
                            expected.Arguments
                            actual.Arguments

                    let premisesSatisfy (premises: TraitConstraint list) (requiredConstraint: TraitConstraint) =
                        premises
                        |> List.exists (fun (premise: TraitConstraint) ->
                            reachableTraitConstraints environment premise
                            |> List.exists (constraintMatches requiredConstraint))

                    frontendModule.Declarations
                    |> List.collect (function
                        | InstanceDeclarationNode declaration ->
                            tryParseInstanceHeader declaration
                            |> Option.toList
                            |> List.collect (fun (traitName, constraints, headTypes) ->
                                traitInfoByName
                                |> Map.tryFind traitName
                                |> Option.toList
                                |> List.collect (fun traitInfo ->
                                    tryInstantiateTraitSupertraits traitInfo headTypes
                                    |> Option.defaultValue []
                                    |> List.choose (fun requiredConstraint ->
                                        let satisfied =
                                            premisesSatisfy constraints requiredConstraint
                                            || (resolveConstraintInstance environment requiredConstraint |> Option.isSome)

                                        if satisfied then
                                            None
                                        else
                                            Some(
                                                makeDiagnostic
                                                    DiagnosticCode.TraitSupertraitUnsatisfied
                                                    $"Instance for trait '{traitName}' requires declared supertrait '{renderTraitConstraint environment requiredConstraint}', but that evidence is not satisfied by the instance premises or visible instances."
                                            ))))
                        | _ ->
                            [])

                let effectDeclarationDiagnostics =
                    frontendModule.Declarations
                    |> List.collect (function
                        | EffectDeclarationNode declaration ->
                            borrowedEffectResumptionQuantityDiagnostics makeDiagnostic declaration
                        | _ ->
                            [])

                let structuralDiagnostics =
                    moduleAttributeDiagnostics
                    @ totalityAssertionDiagnostics
                    @ typeAliasCycleDiagnostics
                    @ malformedConstructorDiagnostics
                    @ unsignedRecursiveBindingDiagnostics
                    @ trivialRecursiveCycleDiagnostics
                    @ constructorDefaultDiagnostics
                    @ effectDeclarationDiagnostics
                    @ instanceSupertraitDiagnostics
                    @ instanceMemberSignatureDiagnostics

                let multishotBackendCapabilityDiagnostics =
                    if backendSupportsMultishotEffects backendProfile then
                        []
                    else
                        let normalizedBackendProfile = BackendProfile.toPortableName backendProfile
                        let privateByDefault = isPrivateByDefault frontendModule

                        let multishotInvocationMessage context effectName operationName =
                            $"Backend profile '{normalizedBackendProfile}' does not provide capability 'rt-multishot-effects' required by multi-shot operation '{effectName}.{operationName}' {context}."

                        let rec rewriteEffectLabelAliasUse aliasName effectName current =
                            let rewrite = rewriteEffectLabelAliasUse aliasName effectName

                            match current with
                            | Name [ name ] when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                                KindQualifiedName(EffectLabelKind, [ effectName ])
                            | Name(root :: path) when String.Equals(root, aliasName, StringComparison.Ordinal) ->
                                Name(effectName :: path)
                            | Name _ ->
                                current
                            | TypeSyntaxTokens _ ->
                                current
                            | SyntaxQuote inner ->
                                SyntaxQuote(rewrite inner)
                            | SyntaxSplice inner ->
                                SyntaxSplice(rewrite inner)
                            | TopLevelSyntaxSplice inner ->
                                TopLevelSyntaxSplice(rewrite inner)
                            | CodeQuote inner ->
                                CodeQuote(rewrite inner)
                            | CodeSplice inner ->
                                CodeSplice(rewrite inner)
                            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                                    { clause with Body = rewrite clause.Body }

                                Handle(isDeep, rewrite label, rewrite body, rewriteClause returnClause, operationClauses |> List.map rewriteClause)
                            | LocalLet(binding, value, body) ->
                                let shadowsAlias =
                                    collectPatternNames binding.Pattern
                                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
                            | LocalSignature(declaration, body) ->
                                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then current else LocalSignature(declaration, rewrite body)
                            | LocalTypeAlias(declaration, body) ->
                                LocalTypeAlias(declaration, rewrite body)
                            | LocalScopedEffect(declaration, body) ->
                                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then current else LocalScopedEffect(declaration, rewrite body)
                            | Lambda(parameters, body) ->
                                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then current else Lambda(parameters, rewrite body)
                            | IfThenElse(condition, whenTrue, whenFalse) ->
                                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                            | Match(scrutinee, cases) ->
                                Match(
                                    rewrite scrutinee,
                                    cases
                                    |> List.map (fun caseClause ->
                                        let shadowsAlias =
                                            collectPatternNames caseClause.Pattern
                                            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                                        { caseClause with
                                            Guard = caseClause.Guard |> Option.map rewrite
                                            Body = if shadowsAlias then caseClause.Body else rewrite caseClause.Body })
                                )
                            | RecordLiteral fields ->
                                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | Seal(value, ascriptionTokens) ->
                                Seal(rewrite value, ascriptionTokens)
                            | RecordUpdate(receiver, fields) ->
                                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | MemberAccess(receiver, segments, arguments) ->
                                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                            | SafeNavigation(receiver, navigation) ->
                                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                            | TagTest(receiver, constructorName) ->
                                TagTest(rewrite receiver, constructorName)
                            | Do statements ->
                                Do(statements)
                            | MonadicSplice inner ->
                                MonadicSplice(rewrite inner)
                            | ExplicitImplicitArgument inner ->
                                ExplicitImplicitArgument(rewrite inner)
                            | NamedApplicationBlock fields ->
                                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | InoutArgument inner ->
                                InoutArgument(rewrite inner)
                            | Unary(operatorName, inner) ->
                                Unary(operatorName, rewrite inner)
                            | Apply(callee, arguments) ->
                                Apply(rewrite callee, arguments |> List.map rewrite)
                            | Binary(left, operatorName, right) ->
                                Binary(rewrite left, operatorName, rewrite right)
                            | Elvis(left, right) ->
                                Elvis(rewrite left, rewrite right)
                            | Comprehension comprehension ->
                                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                            | PrefixedString(prefix, parts) ->
                                PrefixedString(
                                    prefix,
                                    parts
                                    |> List.map (function
                                        | StringText text -> StringText text
                                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                                )
                            | Literal _
                            | NumericLiteral _
                            | KindQualifiedName _ ->
                                current

                        let tryMatchMultishotInvocation expression =
                            match expression with
                            | Apply(Name [ effectName; operationName ], _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | Apply(MemberAccess(Name [ effectName ], [ operationName ], []), _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | Apply(MemberAccess(KindQualifiedName(EffectLabelKind, [ effectName ]), [ operationName ], []), _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | _ ->
                                None

                        let rec collectMultishotInvocations expression =
                            let nested =
                                match expression with
                                | SyntaxQuote _
                                | SyntaxSplice _
                                | TopLevelSyntaxSplice _
                                | CodeQuote _
                                | CodeSplice _ ->
                                    []
                                | TypeSyntaxTokens _ ->
                                    []
                                | LocalLet(binding, value, body) ->
                                    let bodyForCollection =
                                        match binding.Pattern, value with
                                        | NamePattern aliasName, Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                                            rewriteEffectLabelAliasUse aliasName effectName body
                                        | NamePattern aliasName, KindQualifiedName(EffectLabelKind, [ effectName ])
                                            when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                                            rewriteEffectLabelAliasUse aliasName effectName body
                                        | _ ->
                                            body

                                    collectMultishotInvocations value @ collectMultishotInvocations bodyForCollection
                                | LocalSignature(_, body)
                                | LocalTypeAlias(_, body) ->
                                    collectMultishotInvocations body
                                | LocalScopedEffect(declaration, body) ->
                                    withScopedEffectDeclaration declaration (fun () -> collectMultishotInvocations body)
                                | Lambda(_, body) ->
                                    collectMultishotInvocations body
                                | Handle(_, label, body, returnClause, operationClauses) ->
                                    collectMultishotInvocations label
                                    @ collectMultishotInvocations body
                                    @ collectMultishotInvocations returnClause.Body
                                    @ (operationClauses |> List.collect (fun clause -> collectMultishotInvocations clause.Body))
                                | Match(scrutinee, cases) ->
                                    collectMultishotInvocations scrutinee
                                    @ (cases
                                       |> List.collect (fun caseClause ->
                                           (caseClause.Guard
                                            |> Option.map collectMultishotInvocations
                                            |> Option.defaultValue [])
                                           @ collectMultishotInvocations caseClause.Body))
                                | IfThenElse(condition, whenTrue, whenFalse) ->
                                    collectMultishotInvocations condition
                                    @ collectMultishotInvocations whenTrue
                                    @ collectMultishotInvocations whenFalse
                                | RecordLiteral fields ->
                                    fields |> List.collect (fun field -> collectMultishotInvocations field.Value)
                                | Seal(value, _) ->
                                    collectMultishotInvocations value
                                | RecordUpdate(receiver, fields) ->
                                    collectMultishotInvocations receiver
                                    @ (fields |> List.collect (fun field -> collectMultishotInvocations field.Value))
                                | MemberAccess(receiver, _, arguments) ->
                                    collectMultishotInvocations receiver
                                    @ (arguments |> List.collect collectMultishotInvocations)
                                | SafeNavigation(receiver, navigation) ->
                                    collectMultishotInvocations receiver
                                    @ (navigation.Arguments |> List.collect collectMultishotInvocations)
                                | TagTest(receiver, _) ->
                                    collectMultishotInvocations receiver
                                | Do statements ->
                                    let rec collectDo statements =
                                        match statements with
                                        | [] ->
                                            []
                                        | statement :: rest ->
                                            let restInvocations = collectDo rest

                                            match statement with
                                            | DoLet(_, value)
                                            | DoBind(_, value)
                                            | DoUsing(_, value)
                                            | DoVar(_, value)
                                            | DoAssign(_, value)
                                            | DoDefer value
                                            | DoExpression value
                                            | DoReturn value ->
                                                collectMultishotInvocations value @ restInvocations
                                            | DoLetQuestion(_, value, failure) ->
                                                let failureInvocations =
                                                    failure
                                                    |> Option.map (fun block -> collectDo block.Body)
                                                    |> Option.defaultValue []

                                                collectMultishotInvocations value @ failureInvocations @ restInvocations
                                            | DoIf(condition, whenTrue, whenFalse) ->
                                                collectMultishotInvocations condition
                                                @ collectDo whenTrue
                                                @ collectDo whenFalse
                                                @ restInvocations
                                            | DoWhile(condition, body) ->
                                                collectMultishotInvocations condition @ collectDo body @ restInvocations

                                    collectDo statements
                                | MonadicSplice inner
                                | ExplicitImplicitArgument inner
                                | InoutArgument inner
                                | Unary(_, inner) ->
                                    collectMultishotInvocations inner
                                | NamedApplicationBlock fields ->
                                    fields |> List.collect (fun field -> collectMultishotInvocations field.Value)
                                | Apply(callee, arguments) ->
                                    collectMultishotInvocations callee
                                    @ (arguments |> List.collect collectMultishotInvocations)
                                | Binary(left, _, right)
                                | Elvis(left, right) ->
                                    collectMultishotInvocations left @ collectMultishotInvocations right
                                | Comprehension comprehension ->
                                    collectMultishotInvocations comprehension.Lowered
                                | PrefixedString(_, parts) ->
                                    parts
                                    |> List.collect (function
                                        | StringText _ -> []
                                        | StringInterpolation(inner, _) -> collectMultishotInvocations inner)
                                | Literal _
                                | NumericLiteral _
                                | KindQualifiedName _
                                | Name _ ->
                                    []

                            match tryMatchMultishotInvocation expression with
                            | Some invocation -> invocation :: nested
                            | None -> nested

                        let uniqueMultishotInvocations expression =
                            collectMultishotInvocations expression
                            |> List.distinct

                        let exportedDeclarationDiagnostics =
                            frontendModule.Declarations
                            |> List.choose (function
                                | LetDeclaration definition when definition.Name.IsSome && definition.Body.IsSome ->
                                    let bindingName = definition.Name.Value

                                    if isExportedVisibility privateByDefault definition.Visibility then
                                        uniqueMultishotInvocations definition.Body.Value
                                        |> List.tryHead
                                        |> Option.map (fun (effectName, operationName) ->
                                            makeDiagnostic
                                                DiagnosticCode.MultishotEffectUnsupportedBackend
                                                (multishotInvocationMessage
                                                    $"from exported declaration '{bindingName}'"
                                                    effectName
                                                    operationName))
                                    else
                                        None
                                | _ ->
                                    None)

                        exportedDeclarationDiagnostics

                if not (List.isEmpty typeAliasCycleDiagnostics) then
                    structuralDiagnostics @ multishotBackendCapabilityDiagnostics
                else
                    structuralDiagnostics
                    @ multishotBackendCapabilityDiagnostics
                    @ (frontendModule.Declarations
                    |> List.collect (function
                        | TypeAliasNode declaration ->
                            declaration.BodyTokens
                            |> Option.bind tryParseRecordSurfaceInfo
                            |> Option.map (fun recordInfo ->
                                let duplicateDiagnostics =
                                    recordInfo.Fields
                                    |> List.countBy (fun field -> field.Name)
                                    |> List.choose (fun (name, count) ->
                                        if count > 1 then
                                            Some(makeDiagnostic DiagnosticCode.RecordDuplicateField $"Record field '{name}' is declared more than once.")
                                        else
                                            None)

                                let cycleDiagnostics =
                                    let parsedFields =
                                        recordInfo.Fields
                                        |> List.map (fun field ->
                                            parseType field.TypeTokens
                                            |> Option.map (fun parsedType ->
                                                { Name = field.Name
                                                  Quantity = QuantityOmega
                                                  Type = parsedType }))

                                    if parsedFields |> List.forall Option.isSome then
                                        let typeExpr = TypeRecord(parsedFields |> List.choose id)

                                        if hasCyclicRecordDependencies typeExpr then
                                            [ makeDiagnostic DiagnosticCode.RecordDependencyCycle "Record type field dependencies must be acyclic." ]
                                        else
                                            []
                                    else
                                        []

                                duplicateDiagnostics @ cycleDiagnostics)
                            |> Option.defaultValue []
                        | LetDeclaration definition ->
                            let scheme =
                                definition.Name
                                |> Option.bind (fun name -> Map.tryFind name environment.VisibleBindings)
                                |> Option.map (fun bindingInfo -> bindingInfo.Scheme)

                            let bodyEnvironment =
                                match scheme with
                                | Some scheme ->
                                    let schemeConstrainedMembers =
                                        if List.isEmpty scheme.Constraints then
                                            Map.empty
                                        else
                                            buildConstrainedMembers environment scheme.Constraints

                                    let schemeConstraintDictionaries =
                                        scheme.Constraints
                                        |> List.mapi (fun index constraintInfo ->
                                            constraintInfo, KCoreName [ $"__kappa_dict_{constraintInfo.TraitName}_{index}" ])
                                        |> buildConstraintDictionaries environment

                                    let parameterConstrainedMembers =
                                        buildParameterConstrainedMembers environment scheme definition.Parameters

                                    let parameterConstraintDictionaries =
                                        buildParameterConstraintDictionaries environment scheme definition.Parameters

                                    { environment with
                                        ConstraintDictionaries =
                                            parameterConstraintDictionaries
                                            |> Map.fold (fun state key value ->
                                                if Map.containsKey key state then
                                                    state
                                                else
                                                    Map.add key value state) schemeConstraintDictionaries
                                        ConstrainedMembers =
                                            parameterConstrainedMembers
                                            |> Map.fold (fun state memberName route ->
                                                if Map.containsKey memberName state then
                                                    state
                                                else
                                                    Map.add memberName route state) schemeConstrainedMembers }
                                | _ ->
                                    environment

                            let moduleTopLevelDefinitionsByName =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | LetDeclaration candidate ->
                                        match candidate.Name, candidate.Body with
                                        | Some name, Some _ -> Some(name, candidate)
                                        | _ -> None
                                    | _ ->
                                        None)
                                |> Map.ofList

                            let explicitSignatureNames =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | SignatureDeclaration declaration -> Some declaration.Name
                                    | _ -> None)
                                |> Set.ofList

                            let sourceSignatureSchemesByName =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | SignatureDeclaration declaration ->
                                        TypeSignatures.parseScheme declaration.TypeTokens
                                        |> Option.map (fun parsedScheme -> declaration.Name, parsedScheme)
                                    | _ ->
                                        None)
                                |> Map.ofList

                            let sourceSignatureScheme =
                                definition.Name
                                |> Option.bind (fun name -> Map.tryFind name sourceSignatureSchemesByName)

                            validateBuiltInExpressionsForBinding
                                bodyEnvironment
                                knownSurfaceTermNames
                                allowUnresolvedCallDiagnostics
                                explicitSignatureNames
                                sourceSignatureScheme
                                moduleTopLevelDefinitionsByName
                                definition
                                scheme
                            @
                                (let initialParameterLocals =
                                     let annotatedParameterLocals =
                                         definition.Parameters
                                         |> List.choose (fun parameter ->
                                             parameter.TypeTokens
                                             |> Option.bind TypeSignatures.parseType
                                             |> Option.map (fun parsedType ->
                                                 parameter.Name, qualifyVisibleTypeNames bodyEnvironment parsedType))
                                         |> Map.ofList

                                     let hiddenConstraintLocals =
                                         match scheme with
                                         | Some bindingScheme ->
                                             bindingScheme.Constraints
                                             |> List.mapi (fun index constraintInfo ->
                                                 let dictionaryParameterName = $"__kappa_dict_{constraintInfo.TraitName}_{index}"
                                                 dictionaryParameterName,
                                                 TypeName([ constraintInfo.TraitName ], constraintInfo.Arguments))
                                             |> Map.ofList
                                         | None ->
                                             Map.empty

                                     match scheme with
                                     | Some bindingScheme ->
                                         let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                                         if List.length parameterTypes = List.length definition.Parameters then
                                             List.zip definition.Parameters parameterTypes
                                             |> List.map (fun (parameter, parameterType) -> parameter.Name, parameterType)
                                             |> Map.ofList
                                             |> Map.fold (fun state name parameterType -> Map.add name parameterType state) hiddenConstraintLocals
                                         else
                                             annotatedParameterLocals
                                             |> Map.fold (fun state name parameterType -> Map.add name parameterType state) hiddenConstraintLocals
                                     | None ->
                                         annotatedParameterLocals
                                         |> Map.fold (fun state name parameterType -> Map.add name parameterType state) hiddenConstraintLocals

                                 definition.Body
                                 |> Option.map (fun body ->
                                     expressionPatternDiagnostics initialParameterLocals body
                                     @ expressionNameResolutionDiagnostics definition body)
                                 |> Option.defaultValue [])
                        | ProjectionDeclarationNode declaration ->
                            validateProjectionDeclaration declaration
                        | _ ->
                            [])))

        duplicateDeclarationDiagnostics @ (frontendModules |> List.collect validateFrontendModule)

    let private makeSyntheticBindingDeclaration
        (name: string)
        (parameters: KCoreParameter list)
        (returnType: TypeExpr option)
        (body: KCoreExpression)
        (provenance: KCoreOrigin)
        =
        { Source = syntheticLetSource name
          Binding =
            Some
                { Visibility = Some Visibility.Private
                  IsOpaque = false
                  Name = Some name
                  Parameters = parameters
                  ReturnType = returnType
                  ReturnTypeText = returnType |> Option.map typeTextOf
                  Body = Some body
                  BodyText = Some ""
                  Provenance = provenance }
          Provenance = provenance }

    let private lowerBindingBody
        (environment: BindingLoweringEnvironment)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (extraLocalTypes: (string * TypeExpr) list)
        (body: SurfaceExpression)
        =
        let freshCounter = ref 0
        let doScopeCounter = ref 0
        let usingCounter = ref 0

        let sanitizeInternalName (value: string) =
            if String.IsNullOrWhiteSpace value then
                "resource"
            else
                let characters =
                    value
                    |> Seq.map (fun character ->
                        if Char.IsLetterOrDigit character || character = '_' then
                            character
                        else
                            '_')
                    |> Seq.toArray

                String(characters)

        let freshDoScopeLabel () =
            let label = $"S{doScopeCounter.Value}"
            doScopeCounter.Value <- doScopeCounter.Value + 1
            label

        let freshUsingOwnedName bindingName =
            let index = usingCounter.Value
            usingCounter.Value <- usingCounter.Value + 1
            $"__kappa_using_{sanitizeInternalName bindingName}_{index}"

        let freshSyntheticName prefix =
            let index = freshCounter.Value
            freshCounter.Value <- freshCounter.Value + 1
            $"{prefix}{index}"

        let rec substituteZeroArityLocalTypeAliasInExpression (alias: TypeAlias) expression =
            let substituteTypeTokens tokens =
                let aliasBodyTokens = alias.BodyTokens |> Option.defaultValue []
                let tokenArray = tokens |> List.toArray
                let rewritten = ResizeArray<Token>()

                let isStandaloneAlias index =
                    let token = tokenArray[index]
                    let previousIsDot = index > 0 && tokenArray[index - 1].Kind = Dot
                    let nextIsDot = index + 1 < tokenArray.Length && tokenArray[index + 1].Kind = Dot

                    Token.isName token
                    && String.Equals(SyntaxFacts.trimIdentifierQuotes token.Text, alias.Name, StringComparison.Ordinal)
                    && not previousIsDot
                    && not nextIsDot

                for index = 0 to tokenArray.Length - 1 do
                    if isStandaloneAlias index then
                        rewritten.AddRange(aliasBodyTokens)
                    else
                        rewritten.Add(tokenArray[index])

                List.ofSeq rewritten

            let substituteParameter (parameter: Parameter) =
                { parameter with
                    TypeTokens = parameter.TypeTokens |> Option.map substituteTypeTokens }

            let substituteBinding (binding: SurfaceBindPattern) =
                { binding with
                    TypeTokens = binding.TypeTokens |> Option.map substituteTypeTokens }

            let rec substitute current =
                match current with
                | SyntaxQuote inner ->
                    SyntaxQuote(substitute inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(substitute inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(substitute inner)
                | TypeSyntaxTokens _ ->
                    current
                | CodeQuote inner ->
                    CodeQuote(substitute inner)
                | CodeSplice inner ->
                    CodeSplice(substitute inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let substituteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = substitute clause.Body }

                    Handle(
                        isDeep,
                        substitute label,
                        substitute body,
                        substituteClause returnClause,
                        operationClauses |> List.map substituteClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(substituteBinding binding, substitute value, substitute body)
                | LocalSignature(declaration, body) ->
                    LocalSignature({ declaration with TypeTokens = substituteTypeTokens declaration.TypeTokens }, substitute body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(
                        { declaration with
                            HeaderTokens = substituteTypeTokens declaration.HeaderTokens
                            BodyTokens = declaration.BodyTokens |> Option.map substituteTypeTokens },
                        substitute body
                    )
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, substitute body)
                | Lambda(parameters, body) ->
                    Lambda(parameters |> List.map substituteParameter, substitute body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(substitute condition, substitute whenTrue, substitute whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        substitute scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map substitute
                                Body = substitute caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(substitute value, substituteTypeTokens ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(substitute receiver, fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(substitute receiver, segments, arguments |> List.map substitute)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(substitute receiver, { navigation with Arguments = navigation.Arguments |> List.map substitute })
                | TagTest(receiver, constructorName) ->
                    TagTest(substitute receiver, constructorName)
                | Do statements ->
                    Do(statements |> List.map substituteDoStatement)
                | MonadicSplice inner ->
                    MonadicSplice(substitute inner)
                | Apply(callee, arguments) ->
                    Apply(substitute callee, arguments |> List.map substitute)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(substitute inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | InoutArgument inner ->
                    InoutArgument(substitute inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, substitute inner)
                | Binary(left, operatorName, right) ->
                    Binary(substitute left, operatorName, substitute right)
                | Elvis(left, right) ->
                    Elvis(substitute left, substitute right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = substitute comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(substitute inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    current

            and substituteDoStatement statement =
                match statement with
                | DoLet(binding, expression) ->
                    DoLet(substituteBinding binding, substitute expression)
                | DoLetQuestion(binding, expression, failure) ->
                    let substitutedFailure =
                        failure
                        |> Option.map (fun failure ->
                            { failure with
                                ResiduePattern = substituteBinding failure.ResiduePattern
                                Body = failure.Body |> List.map substituteDoStatement })

                    DoLetQuestion(substituteBinding binding, substitute expression, substitutedFailure)
                | DoBind(binding, expression) ->
                    DoBind(substituteBinding binding, substitute expression)
                | DoVar(name, expression) ->
                    DoVar(name, substitute expression)
                | DoAssign(name, expression) ->
                    DoAssign(name, substitute expression)
                | DoUsing(binding, expression) ->
                    DoUsing(substituteBinding binding, substitute expression)
                | DoDefer expression ->
                    DoDefer(substitute expression)
                | DoIf(condition, whenTrue, whenFalse) ->
                    DoIf(substitute condition, whenTrue |> List.map substituteDoStatement, whenFalse |> List.map substituteDoStatement)
                | DoWhile(condition, body) ->
                    DoWhile(substitute condition, body |> List.map substituteDoStatement)
                | DoReturn expression ->
                    DoReturn(substitute expression)
                | DoExpression expression ->
                    DoExpression(substitute expression)

            substitute expression

        let annotateLambdaFromSignature (declaration: BindingSignature) value =
            annotateLambdaWithTypeTokens declaration.TypeTokens value

        let mergeVisibleAndLocalTypeAliases localAliases =
            environment.VisibleTypeAliases
            |> Map.fold (fun state name info -> Map.add name info state) localAliases

        let renderLocalSchemeTokens (scheme: TypeScheme) =
            let binderText (binder: TypeSignatures.ForallBinder) =
                let quantityPrefix =
                    match binder.Quantity with
                    | QuantityZero -> ""
                    | quantity -> Quantity.toSurfaceText quantity + " "

                $"({quantityPrefix}{binder.Name} : {TypeSignatures.toText binder.Sort})"

            let constraintText (constraintInfo: TypeSignatures.TraitConstraint) =
                match constraintInfo.Arguments with
                | [] -> constraintInfo.TraitName
                | arguments ->
                    String.concat " " (constraintInfo.TraitName :: (arguments |> List.map TypeSignatures.toText))

            let forallPrefix =
                match scheme.Forall with
                | [] -> ""
                | binders ->
                    "forall " + (binders |> List.map binderText |> String.concat " ") + ". "

            let constraintsPrefix =
                match scheme.Constraints with
                | [] -> ""
                | constraints ->
                    (constraints |> List.map constraintText |> String.concat ", ") + " => "

            typeTextTokens (forallPrefix + constraintsPrefix + TypeSignatures.toText scheme.Body)

        let expandTypeTokensWithLocalAliases localAliases tokens =
            let aliases = mergeVisibleAndLocalTypeAliases localAliases

            match TypeSignatures.parseScheme tokens with
            | Some scheme ->
                { scheme with
                    Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = normalizeTypeAliases aliases binder.Sort })
                    Constraints =
                        scheme.Constraints
                        |> List.map (fun constraintInfo ->
                            { constraintInfo with
                                Arguments = constraintInfo.Arguments |> List.map (normalizeTypeAliases aliases) })
                    Body = normalizeTypeAliases aliases scheme.Body }
                |> renderLocalSchemeTokens
            | None ->
                tokens
                |> TypeSignatures.parseType
                |> Option.map (normalizeTypeAliases aliases)
                |> Option.map TypeSignatures.toText
                |> Option.map typeTextTokens
                |> Option.defaultValue tokens

        let expandTypeTokenOptionWithLocalAliases localAliases tokens =
            tokens |> Option.map (expandTypeTokensWithLocalAliases localAliases)

        let expandParameterTypeTokens localAliases (parameter: Parameter) =
            { parameter with
                TypeTokens = expandTypeTokenOptionWithLocalAliases localAliases parameter.TypeTokens }

        let expandBindingTypeTokens localAliases (binding: SurfaceBindPattern) =
            { binding with
                TypeTokens = expandTypeTokenOptionWithLocalAliases localAliases binding.TypeTokens }

        let expandEffectDeclarationTypeTokens localAliases (declaration: EffectDeclaration) =
            { declaration with
                HeaderTokens = expandTypeTokensWithLocalAliases localAliases declaration.HeaderTokens
                Operations =
                    declaration.Operations
                    |> List.map (fun operation ->
                        { operation with
                            SignatureTokens = expandTypeTokensWithLocalAliases localAliases operation.SignatureTokens }) }

        let expandTypeAliasTokens localAliases (declaration: TypeAlias) =
            { declaration with
                HeaderTokens = expandTypeTokensWithLocalAliases localAliases declaration.HeaderTokens
                BodyTokens = expandTypeTokenOptionWithLocalAliases localAliases declaration.BodyTokens }

        let rec normalizeLocalDeclarationsWithAliases localAliases expression =
            match expression with
            | SyntaxQuote inner ->
                SyntaxQuote(normalizeLocalDeclarationsWithAliases localAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | TypeSyntaxTokens _ ->
                expression
            | CodeQuote inner ->
                CodeQuote(normalizeLocalDeclarationsWithAliases localAliases inner)
            | CodeSplice inner ->
                CodeSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let normalizeClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = normalizeLocalDeclarationsWithAliases localAliases clause.Body }

                Handle(
                    isDeep,
                    normalizeLocalDeclarationsWithAliases localAliases label,
                    normalizeLocalDeclarationsWithAliases localAliases body,
                    normalizeClause returnClause,
                    operationClauses |> List.map normalizeClause
                )
            | LocalTypeAlias(declaration, body) ->
                let expandedDeclaration = expandTypeAliasTokens localAliases declaration

                match tryParseTypeAliasInfo environment.CurrentModuleName expandedDeclaration with
                | Some(_, aliasInfo) ->
                    let nextLocalAliases = Map.add declaration.Name aliasInfo localAliases
                    normalizeLocalDeclarationsWithAliases nextLocalAliases body
                | None ->
                    LocalTypeAlias(expandedDeclaration, normalizeLocalDeclarationsWithAliases localAliases body)
            | LocalSignature(declaration, LocalLet(binding, value, body))
                when binding.Pattern = NamePattern declaration.Name ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokensWithLocalAliases localAliases declaration.TypeTokens }

                LocalLet(
                    expandBindingTypeTokens localAliases binding,
                    annotateLambdaFromSignature expandedDeclaration (normalizeLocalDeclarationsWithAliases localAliases value),
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | LocalSignature(declaration, body) ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokensWithLocalAliases localAliases declaration.TypeTokens }

                LocalSignature(expandedDeclaration, normalizeLocalDeclarationsWithAliases localAliases body)
            | LocalLet(binding, value, body) ->
                LocalLet(
                    expandBindingTypeTokens localAliases binding,
                    normalizeLocalDeclarationsWithAliases localAliases value,
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(
                    expandEffectDeclarationTypeTokens localAliases declaration,
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | Lambda(parameters, body) ->
                Lambda(parameters |> List.map (expandParameterTypeTokens localAliases), normalizeLocalDeclarationsWithAliases localAliases body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    normalizeLocalDeclarationsWithAliases localAliases whenTrue,
                    normalizeLocalDeclarationsWithAliases localAliases whenFalse
                )
            | Match(scrutinee, cases) ->
                Match(
                    normalizeLocalDeclarationsWithAliases localAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map (normalizeLocalDeclarationsWithAliases localAliases)
                            Body = normalizeLocalDeclarationsWithAliases localAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(
                    normalizeLocalDeclarationsWithAliases localAliases value,
                    expandTypeTokensWithLocalAliases localAliases ascriptionTokens
                )
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(
                    receiver |> normalizeLocalDeclarationsWithAliases localAliases,
                    fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value })
                )
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(
                    normalizeLocalDeclarationsWithAliases localAliases receiver,
                    segments,
                    arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases)
                )
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    normalizeLocalDeclarationsWithAliases localAliases receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases) }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(normalizeLocalDeclarationsWithAliases localAliases receiver, constructorName)
            | Do statements ->
                Do(statements |> List.map (normalizeLocalDoStatementWithAliases localAliases))
            | MonadicSplice inner ->
                MonadicSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Apply(callee, arguments) ->
                Apply(
                    normalizeLocalDeclarationsWithAliases localAliases callee,
                    arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases)
                )
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(normalizeLocalDeclarationsWithAliases localAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value }))
            | InoutArgument inner ->
                InoutArgument(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, normalizeLocalDeclarationsWithAliases localAliases inner)
            | Binary(left, operatorName, right) ->
                Binary(
                    normalizeLocalDeclarationsWithAliases localAliases left,
                    operatorName,
                    normalizeLocalDeclarationsWithAliases localAliases right
                )
            | Elvis(left, right) ->
                Elvis(
                    normalizeLocalDeclarationsWithAliases localAliases left,
                    normalizeLocalDeclarationsWithAliases localAliases right
                )
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = normalizeLocalDeclarationsWithAliases localAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(normalizeLocalDeclarationsWithAliases localAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                expression

        and normalizeLocalDoStatementWithAliases localAliases statement =
            match statement with
            | DoLet(binding, expression) ->
                DoLet(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoLetQuestion(binding, expression, failure) ->
                let normalizedFailure =
                    failure
                    |> Option.map (fun failure ->
                        { failure with
                            ResiduePattern = expandBindingTypeTokens localAliases failure.ResiduePattern
                            Body = failure.Body |> List.map (normalizeLocalDoStatementWithAliases localAliases) })

                DoLetQuestion(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression, normalizedFailure)
            | DoBind(binding, expression) ->
                DoBind(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoVar(name, expression) ->
                DoVar(name, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoAssign(name, expression) ->
                DoAssign(name, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoUsing(binding, expression) ->
                DoUsing(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoDefer expression ->
                DoDefer(normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoIf(condition, whenTrue, whenFalse) ->
                DoIf(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    whenTrue |> List.map (normalizeLocalDoStatementWithAliases localAliases),
                    whenFalse |> List.map (normalizeLocalDoStatementWithAliases localAliases)
                )
            | DoWhile(condition, body) ->
                DoWhile(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    body |> List.map (normalizeLocalDoStatementWithAliases localAliases)
                )
            | DoReturn expression ->
                DoReturn(normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoExpression expression ->
                DoExpression(normalizeLocalDeclarationsWithAliases localAliases expression)

        let body = normalizeLocalDeclarationsWithAliases Map.empty body

        let rec inferExpressionType localTypes expression =
            let normalizeVisibleType typeExpr =
                typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases
            let visibleTypeEquals left right =
                TypeSignatures.definitionallyEqual (normalizeVisibleType left) (normalizeVisibleType right)

            match expression with
            | Literal literal ->
                Some(inferLiteralType literal)
            | NumericLiteral literal ->
                match SurfaceNumericLiteral.suffix literal with
                | Some suffixName ->
                    inferExpressionType localTypes (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
                | None ->
                    Some(inferSurfaceNumericLiteralType literal)
            | TypeSyntaxTokens tokens ->
                TypeSignatures.parseType tokens |> Option.map (fun _ -> TypeName([ "Type" ], []))
            | SyntaxQuote inner ->
                inferExpressionType localTypes inner
                |> Option.map syntaxType
            | SyntaxSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName([ "Syntax" ], [ innerType ]) -> Some innerType
                    | _ -> None)
            | TopLevelSyntaxSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName([ "Syntax" ], [ innerType ]) -> Some innerType
                    | _ -> None)
            | CodeQuote inner ->
                inferExpressionType localTypes inner
                |> Option.map codeType
            | CodeSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName([ "Code" ], [ innerType ]) -> Some innerType
                    | _ -> None)
            | Name [ "True" ]
            | Name [ "False" ] ->
                Some boolType
            | KindQualifiedName _ ->
                tryResolveScopedStaticObject environment expression
                |> Option.bind (fun staticObject -> staticObject.Scheme)
                |> Option.map (fun scheme -> scheme.Body)
            | Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                Some(TypeIntrinsic EffLabelClassifier)
            | Name(root :: path) ->
                let resolvedStaticObjectType =
                    tryResolveScopedStaticObject environment expression
                    |> Option.bind (fun staticObject ->
                        match staticObject.ObjectKind with
                        | StaticEffectLabelObject ->
                            staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                        | _ ->
                            None)

                let scopedEffectOperationType =
                    match path with
                    | [ operationName ] ->
                        tryFindScopedEffectOperation root operationName
                        |> Option.bind (fun (_, operation) ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment))
                    | _ ->
                        None

                let resolvedEffectOperationType =
                    tryResolveEffectOperationNamePath environment (root :: path)
                    |> Option.bind (fun (_, _, operation) ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment))

                let ordinaryResolution =
                    localTypes
                    |> Map.tryFind root
                    |> Option.orElseWith (fun () ->
                        environment.VisibleConstructors
                        |> Map.tryFind root
                        |> Option.bind (fun constructorInfo ->
                            if List.isEmpty path then
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    constructorInfo
                                    (Some localTypes)
                                    (inferExpressionType localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    []
                                |> Option.map (fun preparedCall -> preparedCall.ResultType)
                            else
                                None))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind root
                        |> Option.bind (fun bindingInfo ->
                            if List.isEmpty path then
                                (if bindingHasResolvableLocalRuntimeImplicitParameter environment localTypes bindingInfo then
                                     tryPrepareVisibleBindingCall
                                         environment
                                         freshCounter
                                         bindingInfo
                                         (Some localTypes)
                                         (inferExpressionType localTypes)
                                         (tryResolveUniqueLocalImplicitByType environment localTypes)
                                         []
                                     |> Option.map (fun preparedCall -> preparedCall.ResultType)
                                 else
                                     None)
                                |> Option.orElseWith (fun () -> instantiateVisibleBindingResultType environment freshCounter root)
                            else
                                None))
                    |> Option.orElseWith (fun () ->
                        tryResolveScopedStaticObject environment (Name [ root ])
                        |> Option.bind (fun staticObject ->
                            if List.isEmpty path then
                                staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                            else
                                None))
                    |> Option.bind (fun rootType -> tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)

                match path with
                | [ memberName ] ->
                    scopedEffectOperationType
                    |> Option.orElse resolvedStaticObjectType
                    |> Option.orElse resolvedEffectOperationType
                    |> Option.orElseWith (fun () -> tryReceiverProjection environment localTypes root memberName |> Option.map (fun projectionInfo -> projectionInfo.ReturnType))
                    |> Option.orElseWith (fun () ->
                        tryInferStaticConstructorCall
                            environment
                            freshCounter
                            (inferExpressionType localTypes)
                            (Name [ root ])
                            memberName
                            [])
                    |> Option.orElse ordinaryResolution
                | _ ->
                    resolvedStaticObjectType
                    |> Option.orElse resolvedEffectOperationType
                    |> Option.orElse ordinaryResolution
            | Name [] ->
                None
            | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
                match
                    tryResolveHandledEffectDeclaration environment receiver
                    |> Option.bind (fun declaration ->
                        EffectSemantics.tryFindOperation memberName declaration
                        |> Option.bind (fun operation ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.map TypeSignatures.functionParts
                            |> Option.map (fun (parameterTypes, resultType) -> declaration, parameterTypes, resultType)))
                with
                | Some(declaration, parameterTypes, resultType) when List.length parameterTypes = List.length arguments ->
                    Some(effType (scopedEffectRowType declaration) resultType)
                | _ ->
                    match tryInferQueryCarrierType environment freshCounter localTypes inferExpressionType expression with
                    | Some queryCarrierType ->
                        Some queryCarrierType
                    | None ->
                        inferApplicationType localTypes expression
            | Apply(Name nameSegments, arguments) ->
                match
                    tryResolveEffectOperationNamePath environment nameSegments
                    |> Option.bind (fun (_, declaration, operation) ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.map (fun signature -> declaration, TypeSignatures.functionParts signature))
                with
                | Some(declaration, (parameterTypes, resultType)) when List.length parameterTypes = List.length arguments ->
                    Some(effType (scopedEffectRowType declaration) resultType)
                | _ ->
                    match tryInferQueryCarrierType environment freshCounter localTypes inferExpressionType expression with
                    | Some queryCarrierType ->
                        Some queryCarrierType
                    | None ->
                        inferApplicationType localTypes expression
            | LocalSignature(_, body) ->
                inferExpressionType localTypes body
            | LocalTypeAlias(_, body) ->
                inferExpressionType localTypes body
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let bindingNames = collectPatternNames binding.Pattern

                let bindingDeclaredType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)

                let valueLocals =
                    match binding.Pattern, bindingDeclaredType, value with
                    | NamePattern bindingName, Some declaredType, Lambda _ ->
                        Map.add bindingName declaredType localTypes
                    | _ ->
                        localTypes

                let nextLocals =
                    match inferExpressionType valueLocals value with
                    | Some valueType ->
                        extendBindingLocalTypes environment freshCounter localTypes binding (Some valueType)
                    | None ->
                        extendBindingLocalTypes
                            environment
                            freshCounter
                            localTypes
                            binding
                            (Some(inferFallbackLocalType freshCounter value))

                let bodyForInference =
                    match bindingNames, tryResolveScopedStaticObject environment value with
                    | [ aliasName ], Some staticObject ->
                        rewriteStaticObjectAliasUse aliasName staticObject body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases environment binding.Pattern value
                let bodyForInference = rewriteStaticObjectPathAliasUses localStaticAliases bodyForInference
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForInference = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForInference

                inferExpressionType nextLocals bodyForInference
            | LocalScopedEffect(declaration, body) ->
                withScopedEffectDeclaration declaration (fun () -> inferExpressionType localTypes body)
            | Handle(_, label, body, returnClause, _) ->
                let handledResultType =
                    match
                        tryResolveHandledEffectDeclaration environment label,
                        inferExpressionType localTypes body |> Option.bind tryUnwrapEffType
                    with
                    | Some declaration, Some(effectRow, payloadType) ->
                        match trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow with
                        | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                        | _ -> None
                    | _ ->
                        None

                handledResultType
                |> Option.orElseWith (fun () -> inferExpressionType localTypes returnClause.Body)
            | Lambda(lambdaParameters, lambdaBody) ->
                let parameterTypes =
                    lambdaParameters
                    |> List.map (fun parameter ->
                        tryParseParameterType parameter
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

                let parameterQuantities =
                    lambdaParameters
                    |> List.map (fun parameter -> parameter.Quantity |> Option.defaultValue QuantityOmega)

                let lambdaLocals =
                    List.zip lambdaParameters parameterTypes
                    |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) localTypes

                inferExpressionType lambdaLocals lambdaBody
                |> Option.map (fun resultType ->
                    List.zip parameterTypes parameterQuantities
                    |> List.rev
                    |> List.fold (fun state (parameterType, quantity) -> TypeArrow(quantity, parameterType, state)) resultType)
            | IfThenElse(_, whenTrue, whenFalse) ->
                match inferExpressionType localTypes whenTrue, inferExpressionType localTypes whenFalse with
                | Some trueType, Some falseType when trueType = falseType ->
                    Some trueType
                | _ ->
                    None
            | Match(scrutinee, cases) ->
                let scrutineeType = inferExpressionType localTypes scrutinee

                cases
                |> List.choose (fun caseClause ->
                    let caseLocals =
                        extendPatternLocalTypes environment freshCounter localTypes scrutineeType caseClause.Pattern

                    inferExpressionType caseLocals caseClause.Body)
                |> function
                    | first :: rest when rest |> List.forall ((=) first) -> Some first
                    | _ -> None
            | RecordLiteral fields ->
                let inferredFields =
                    fields
                    |> List.map (fun field ->
                        inferExpressionType localTypes field.Value
                        |> Option.map (fun fieldType ->
                            ({ Name = field.Name
                               Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                               Type = fieldType }: TypeSignatures.RecordField)))

                if inferredFields |> List.forall Option.isSome then
                    inferredFields
                    |> List.choose id
                    |> TypeRecord
                    |> Some
                else
                    None
            | Seal(value, _) ->
                inferExpressionType localTypes value
            | RecordUpdate(receiver, _) ->
                inferExpressionType localTypes receiver
            | MemberAccess(receiver, segments, arguments) ->
                match segments with
                | [] ->
                    inferExpressionType localTypes receiver
                    |> Option.bind (fun receiverType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            receiverType
                            arguments)
                | [ memberName ] ->
                    (tryResolveHandledEffectDeclaration environment receiver
                     |> Option.bind (fun declaration ->
                         EffectSemantics.tryFindOperation memberName declaration
                         |> Option.bind (fun operation ->
                             operation.SignatureTokens
                             |> TypeSignatures.parseType
                             |> Option.map (qualifyVisibleTypeNames environment)
                             |> Option.bind (fun operationType ->
                                 let parameterTypes, resultType = TypeSignatures.functionParts operationType

                                 if List.length arguments = List.length parameterTypes then
                                     Some(effType (scopedEffectRowType declaration) resultType)
                                 else
                                     tryInferVisibleAppliedType
                                         environment.VisibleTypeAliases
                                         (qualifyVisibleTypeNames environment)
                                         (inferExpressionType localTypes)
                                         operationType
                                         arguments))))
                    |> Option.orElseWith (fun () ->
                        tryInferStaticConstructorCall
                            environment
                            freshCounter
                            (inferExpressionType localTypes)
                            receiver
                            memberName
                            arguments)
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind memberName
                        |> Option.bind (fun bindingInfo ->
                            tryBuildReceiverMethodArguments bindingInfo receiver arguments
                            |> Option.bind (fun receiverArguments ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferExpressionType localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    receiverArguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType))))
                    |> Option.orElseWith (fun () ->
                        inferExpressionType localTypes receiver
                        |> Option.bind (fun receiverType ->
                            tryProjectVisibleRecordType environment.VisibleTypeAliases receiverType [ memberName ]
                            |> Option.bind (fun memberType ->
                                tryInferVisibleAppliedType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferExpressionType localTypes)
                                    memberType
                                    arguments)))
                | memberName :: rest ->
                    inferExpressionType localTypes (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))
            | SafeNavigation(receiver, navigation) ->
                inferExpressionType localTypes receiver
                |> Option.bind (fun receiverType ->
                    tryOptionPayloadType environment.VisibleTypeAliases receiverType
                    |> Option.bind (fun payloadType ->
                        tryInferSafeNavigationMemberType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            payloadType
                            navigation
                        |> Option.map (fun memberType ->
                            match tryOptionPayloadType environment.VisibleTypeAliases memberType with
                            | Some _ -> memberType
                            | None -> TypeName([ "Option" ], [ memberType ]))))
            | TagTest _ ->
                Some boolType
            | Do statements ->
                inferDoResultType localTypes statements
            | MonadicSplice inner ->
                inferExpressionType localTypes inner |> Option.map unwrapIoType
            | ExplicitImplicitArgument inner ->
                inferExpressionType localTypes inner
            | NamedApplicationBlock _ ->
                None
            | InoutArgument inner ->
                inferExpressionType localTypes inner
            | Apply _ as application ->
                inferApplicationType localTypes application
            | Unary("not", _) ->
                Some boolType
            | Unary(("negate" | "-"), operand) ->
                inferExpressionType localTypes operand
            | Unary _ ->
                None
            | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                match inferExpressionType localTypes left, inferExpressionType localTypes right with
                | Some leftType, Some rightType when visibleTypeEquals leftType intType && visibleTypeEquals rightType intType ->
                    Some intType
                | Some leftType, Some rightType when visibleTypeEquals leftType floatType && visibleTypeEquals rightType floatType ->
                    Some floatType
                | _ ->
                    None
            | Binary(_, ("==" | "!=" | "<" | ">" | "<=" | ">=" | "&&" | "||"), _) ->
                Some boolType
            | Binary(left, operatorName, right) ->
                inferExpressionType localTypes (Apply(Name [ operatorName ], [ left; right ]))
            | Elvis(left, right) ->
                match inferExpressionType localTypes left, inferExpressionType localTypes right with
                | Some leftType, Some defaultType ->
                    tryOptionPayloadType environment.VisibleTypeAliases leftType
                    |> Option.bind (fun payloadType ->
                        tryUnifyVisibleTypes environment.VisibleTypeAliases [ payloadType, defaultType ]
                        |> Option.map (fun substitution ->
                            TypeSignatures.applySubstitution substitution payloadType)
                        |> Option.orElseWith (fun () ->
                            if
                                TypeSignatures.definitionallyEqual
                                    (normalizeTypeAliases environment.VisibleTypeAliases payloadType)
                                    (normalizeTypeAliases environment.VisibleTypeAliases defaultType)
                            then
                                Some payloadType
                            else
                                None))
                | _ ->
                    None
            | Comprehension comprehension ->
                inferExpressionType localTypes comprehension.Lowered
            | PrefixedString(prefix, _) ->
                tryInferPrefixedStringMacroResultType environment freshCounter localTypes prefix

        and inferApplicationType localTypes application =
            tryInferQueryCarrierType
                environment
                freshCounter
                localTypes
                (fun currentLocals currentExpression -> inferExpressionType currentLocals currentExpression)
                application
            |> Option.orElseWith (fun () ->
                match application with
                | Apply(Name [ receiverName; memberName ], arguments) ->
                    tryInferStaticConstructorCall
                        environment
                        freshCounter
                        (inferExpressionType localTypes)
                        (Name [ receiverName ])
                        memberName
                        arguments
                    |> Option.orElseWith (fun () ->
                        tryPrepareResolvedTraitProjectionCall
                            environment
                            freshCounter
                            localTypes
                            [ receiverName; memberName ]
                            (inferExpressionType localTypes)
                            arguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind memberName
                        |> Option.bind (fun bindingInfo ->
                            tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments
                            |> Option.bind (fun receiverArguments ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferExpressionType localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    receiverArguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType))))
                | Apply(Name [ calleeName ], arguments) ->
                    localTypes
                    |> Map.tryFind calleeName
                    |> Option.bind (fun localType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            localType
                            arguments)
                    |> Option.orElseWith (fun () ->
                        environment.VisibleConstructors
                        |> Map.tryFind calleeName
                        |> Option.bind (fun constructorInfo ->
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                constructorInfo
                                (Some localTypes)
                                (inferExpressionType localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                arguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind calleeName
                        |> Option.bind (fun bindingInfo ->
                            let preparedResultType =
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferExpressionType localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    arguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType)

                            preparedResultType
                            |> Option.orElseWith (fun () ->
                                instantiateVisibleBindingBodyType environment freshCounter calleeName
                                |> Option.bind (fun bodyType ->
                                    tryInferVisibleAppliedType
                                        environment.VisibleTypeAliases
                                        (qualifyVisibleTypeNames environment)
                                        (inferExpressionType localTypes)
                                        bodyType
                                        arguments))))
                    |> Option.orElseWith (fun () ->
                        tryPrepareVisibleTraitMemberCall
                            environment
                            freshCounter
                            calleeName
                            (inferExpressionType localTypes)
                            arguments
                        |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleProjections
                        |> Map.tryFind calleeName
                        |> Option.bind (fun projectionInfo ->
                            tryInferProjectionCallResultType localTypes projectionInfo arguments))
                | _ ->
                    None)

        and tryInferProjectionCallResultType localTypes (projectionInfo: ProjectionInfo) arguments =
            if List.length projectionInfo.Binders <> List.length arguments then
                None
            else
                let tryUnifyExpected expectedType actualType substitution =
                    let expectedType = TypeSignatures.applySubstitution substitution expectedType

                    tryUnifyVisibleTypes environment.VisibleTypeAliases [ expectedType, actualType ]
                    |> Option.map (composeTypeSubstitution substitution)
                    |> Option.orElseWith (fun () ->
                        if
                            TypeSignatures.definitionallyEqual
                                (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                                (normalizeTypeAliases environment.VisibleTypeAliases actualType)
                        then
                            Some substitution
                        else
                            None)

                let rec tryInferPlaceExpressionType expression =
                    match expression with
                    | Name(root :: path) ->
                        localTypes
                        |> Map.tryFind root
                        |> Option.bind (fun rootType ->
                            tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)
                    | Apply(Name [ projectionName ], projectionArguments) ->
                        environment.VisibleProjections
                        |> Map.tryFind projectionName
                        |> Option.bind (fun nestedProjectionInfo ->
                            tryInferProjectionCallResultType localTypes nestedProjectionInfo projectionArguments)
                    | _ ->
                        None

                (Some Map.empty, List.zip projectionInfo.Binders arguments)
                ||> List.fold (fun current (binder, argument) ->
                    current
                    |> Option.bind (fun substitution ->
                        match binder with
                        | ProjectionPlaceBinder placeBinder ->
                            match TypeSignatures.parseType placeBinder.TypeTokens, tryInferPlaceExpressionType argument with
                            | Some expectedType, Some actualType ->
                                tryUnifyExpected expectedType actualType substitution
                            | _ ->
                                None
                        | ProjectionValueBinder valueBinder ->
                            match tryParseParameterType valueBinder, inferExpressionType localTypes argument with
                            | Some expectedType, Some actualType ->
                                tryUnifyExpected expectedType actualType substitution
                            | _ ->
                                None))
                |> Option.map (fun substitution ->
                    TypeSignatures.applySubstitution substitution projectionInfo.ReturnType)

        and inferDoResultType localTypes statements =
            let tryMergeBranchResultTypes leftType rightType =
                tryUnifyVisibleTypes environment.VisibleTypeAliases [ leftType, rightType ]
                |> Option.map (fun substitution ->
                    TypeSignatures.applySubstitution substitution leftType)
                |> Option.orElseWith (fun () ->
                    if
                        TypeSignatures.definitionallyEqual
                            (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                            (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                    then
                        Some leftType
                    else
                        None)

            match statements with
            | [] ->
                Some unitType
            | DoExpression expression :: [] ->
                inferExpressionType localTypes expression
            | DoExpression _ :: rest ->
                inferDoResultType localTypes rest
            | DoLet(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                    |> Option.defaultValue localTypes

                failure
                |> Option.iter (fun failure -> inferDoResultType localTypes failure.Body |> ignore)

                inferDoResultType nextLocals rest
            | DoBind(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            freshCounter
                            localTypes
                            (Some(unwrapBindPayloadType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoUsing(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            freshCounter
                            localTypes
                            (Some(unwrapIoType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoVar(bindingName, expression) :: rest ->
                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                inferDoResultType nextLocals rest
            | DoAssign _ :: rest ->
                inferDoResultType localTypes rest
            | DoDefer _ :: rest ->
                inferDoResultType localTypes rest
            | DoIf(_, whenTrue, whenFalse) :: [] ->
                match inferDoResultType localTypes whenTrue, inferDoResultType localTypes whenFalse with
                | Some whenTrueType, Some whenFalseType ->
                    tryMergeBranchResultTypes whenTrueType whenFalseType
                | _ ->
                    None
            | DoIf(_, _, _) :: rest ->
                inferDoResultType localTypes rest
            | DoWhile _ :: rest ->
                inferDoResultType localTypes rest
            | DoReturn expression :: _ ->
                inferExpressionType localTypes expression

        and buildUsingReleaseAction localTypes expression hiddenOwnedName =
            let defaultRelease =
                KCoreRelease(None, KCoreName [ "release" ], KCoreName [ hiddenOwnedName ])

            match inferExpressionType localTypes expression with
            | Some(TypeName(monadName, [ resourceType ])) ->
                let monadType = TypeName(monadName, [])

                let releasableConstraint =
                    { TraitName = "Releasable"
                      Arguments = [ monadType; resourceType ] }

                match tryLowerResolvedDictionaryValue environment releasableConstraint with
                | Some dictionaryValue ->
                    KCoreRelease(
                        Some(TypeSignatures.toText resourceType),
                        KCoreTraitCall("Releasable", "release", dictionaryValue, []),
                        KCoreName [ hiddenOwnedName ]
                    )
                | None ->
                    defaultRelease
            | _ ->
                defaultRelease

        and buildPlaceWritebackExpression rootName path replacement =
            let rec loop currentSegments remainingPath =
                match remainingPath with
                | [] ->
                    replacement
                | fieldName :: rest ->
                    let nestedValue = loop (currentSegments @ [ fieldName ]) rest

                    RecordUpdate(
                        Name currentSegments,
                        [
                            { Name = fieldName
                              IsImplicit = false
                              IsExtension = false
                              Path =
                                  [ { Name = fieldName
                                      IsImplicit = false } ]
                              Value = nestedValue }
                        ]
                    )

            loop [ rootName ] path

        and tryExpressionPlace expression =
            match expression with
            | Name(root :: path) ->
                Some(root, path)
            | _ ->
                None

        and unwrapRefLikeType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName([ "Ref" ], [ inner ]) -> Some inner
            | _ -> None

        and substituteProjectionExpression
            (placeArguments: Map<string, string * string list>)
            (valueArguments: Map<string, SurfaceExpression>)
            expression
            =
            let rec loop current =
                match current with
                | Name(root :: path) ->
                    match Map.tryFind root placeArguments with
                    | Some(actualRoot, actualPath) ->
                        Name(actualRoot :: (actualPath @ path))
                    | None ->
                        match Map.tryFind root valueArguments with
                        | Some replacement when List.isEmpty path ->
                            replacement
                        | Some(Name replacementSegments) ->
                            Name(replacementSegments @ path)
                        | _ ->
                            current
                | Name [] ->
                    current
                | TypeSyntaxTokens _ ->
                    current
                | SyntaxQuote inner ->
                    SyntaxQuote(loop inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(loop inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(loop inner)
                | CodeQuote inner ->
                    CodeQuote(loop inner)
                | CodeSplice inner ->
                    CodeSplice(loop inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let loopClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = loop clause.Body }

                    Handle(
                        isDeep,
                        loop label,
                        loop body,
                        loopClause returnClause,
                        operationClauses |> List.map loopClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(binding, loop value, loop body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, loop body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, loop body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, loop body)
                | Lambda(parameters, body) ->
                    Lambda(parameters, loop body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(loop condition, loop whenTrue, loop whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        loop scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map loop
                                Body = loop caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(loop value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(receiver |> loop, fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(receiver |> loop, segments, arguments |> List.map loop)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(receiver |> loop, { navigation with Arguments = navigation.Arguments |> List.map loop })
                | TagTest(receiver, constructorName) ->
                    TagTest(loop receiver, constructorName)
                | Do statements ->
                    let rec substituteDoStatement statement =
                        match statement with
                        | DoLet(binding, value) -> DoLet(binding, loop value)
                        | DoLetQuestion(binding, value, failure) ->
                            DoLetQuestion(
                                binding,
                                loop value,
                                failure
                                |> Option.map (fun failure ->
                                    { failure with
                                        Body = failure.Body |> List.map substituteDoStatement })
                            )
                        | DoBind(binding, value) -> DoBind(binding, loop value)
                        | DoVar(name, value) -> DoVar(name, loop value)
                        | DoAssign(name, value) -> DoAssign(name, loop value)
                        | DoUsing(binding, value) -> DoUsing(binding, loop value)
                        | DoDefer value -> DoDefer(loop value)
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(
                                loop condition,
                                whenTrue |> List.map substituteDoStatement,
                                whenFalse |> List.map substituteDoStatement
                            )
                        | DoWhile(condition, body) ->
                            DoWhile(loop condition, body |> List.map substituteDoStatement)
                        | DoReturn value -> DoReturn(loop value)
                        | DoExpression value -> DoExpression(loop value)

                    Do(statements |> List.map substituteDoStatement)
                | MonadicSplice inner ->
                    MonadicSplice(loop inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(loop inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | Apply(callee, arguments) ->
                    Apply(loop callee, arguments |> List.map loop)
                | InoutArgument inner ->
                    InoutArgument(loop inner)
                | Unary(operatorName, operand) ->
                    Unary(operatorName, loop operand)
                | Binary(left, operatorName, right) ->
                    Binary(loop left, operatorName, loop right)
                | Elvis(left, right) ->
                    Elvis(loop left, loop right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = loop comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(loop inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _ ->
                    current

            loop expression

        and tryProjectionCallExpression expression =
            match expression with
            | Apply(Name [ projectionName ], projectionArguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.map (fun projectionInfo -> projectionInfo, projectionArguments)
            | _ ->
                None

        and tryProjectionArgumentBindings (projectionInfo: ProjectionInfo) projectionArguments =
            if List.length projectionInfo.Binders <> List.length projectionArguments then
                None
            else
                (Some(Map.empty, Map.empty), List.zip projectionInfo.Binders projectionArguments)
                ||> List.fold (fun state (binder, argument) ->
                    state
                    |> Option.bind (fun (placeArguments, valueArguments) ->
                        match binder with
                        | ProjectionPlaceBinder placeBinder ->
                            tryExpressionPlace argument
                            |> Option.map (fun place ->
                                Map.add placeBinder.Name place placeArguments, valueArguments)
                        | ProjectionValueBinder valueBinder ->
                            Some(placeArguments, Map.add valueBinder.Name argument valueArguments)))

        and lowerPatternBinding
            (localTypes: Map<string, TypeExpr>)
            valueType
            (binding: SurfaceBindPattern)
            valueExpression
            continueWith
            =
            let nextLocals =
                extendPatternLocalTypes environment freshCounter localTypes valueType binding.Pattern

            let loweredBody = continueWith nextLocals

            match binding.Pattern with
            | NamePattern bindingName ->
                KCoreLet(bindingName, valueExpression, loweredBody)
            | _ ->
                let tempBindingName = freshSyntheticName "__kappa_bind_"

                KCoreLet(
                    tempBindingName,
                    valueExpression,
                    KCoreMatch(
                        KCoreName [ tempBindingName ],
                        [
                            { Pattern = lowerPattern nextLocals valueType binding.Pattern
                              Guard = None
                              Body = loweredBody }
                        ]
                    )
                )

        and tryLowerProjectionInoutDoSite
            scopeLabel
            (localTypes: Map<string, TypeExpr>)
            (binding: SurfaceBindPattern option)
            calleeName
            explicitParameters
            targetExplicitIndex
            (projectionInfo: ProjectionInfo)
            projectionArguments
            rest
            isMonadicSite
            =
            tryProjectionArgumentBindings projectionInfo projectionArguments
            |> Option.bind (fun (placeArguments, valueArguments) ->
                let substitute =
                    substituteProjectionExpression placeArguments valueArguments

                let rec lowerProjectionBody bodyLocals body =
                    match body with
                    | ProjectionYield yielded ->
                        let yieldedPlace = substitute yielded

                        match tryExpressionPlace yieldedPlace with
                        | Some _ ->
                            let rewrittenArguments =
                                explicitParameters
                                |> List.map (fun (explicitIndex, _, _, argument) ->
                                    if explicitIndex = targetExplicitIndex then
                                        InoutArgument yieldedPlace
                                    else
                                        argument)

                            tryLowerInoutDoSite
                                scopeLabel
                                bodyLocals
                                binding
                                (Apply(Name [ calleeName ], rewrittenArguments))
                                rest
                                isMonadicSite
                        | None ->
                            None
                    | ProjectionIfThenElse(condition, whenTrue, whenFalse) ->
                        match lowerProjectionBody bodyLocals whenTrue, lowerProjectionBody bodyLocals whenFalse with
                        | Some loweredTrue, Some loweredFalse ->
                            Some(KCoreIfThenElse(lowerExpression bodyLocals (substitute condition), loweredTrue, loweredFalse))
                        | _ ->
                            None
                    | ProjectionMatch(scrutinee, cases) ->
                        let loweredScrutinee = substitute scrutinee
                        let scrutineeType = inferExpressionType bodyLocals loweredScrutinee

                        let loweredCases : KCoreMatchCase option list =
                            cases
                            |> List.map (fun caseClause ->
                                let caseLocals =
                                    extendPatternLocalTypes environment freshCounter bodyLocals scrutineeType caseClause.Pattern

                                lowerProjectionBody caseLocals caseClause.Body
                                |> Option.map (fun loweredBody ->
                                    ({ Pattern = lowerPattern caseLocals scrutineeType caseClause.Pattern
                                       Guard = caseClause.Guard |> Option.map (substitute >> lowerExpression caseLocals)
                                       Body = loweredBody }
                                     : KCoreMatchCase)))

                        if loweredCases |> List.forall Option.isSome then
                            Some(
                                KCoreMatch(
                                    lowerExpression bodyLocals loweredScrutinee,
                                    loweredCases |> List.choose id
                                )
                            )
                        else
                            None
                    | ProjectionAccessors _ ->
                        None

                projectionInfo.Body |> Option.bind (lowerProjectionBody localTypes))

        and tryLowerInoutDoSite
            scopeLabel
            (localTypes: Map<string, TypeExpr>)
            (binding: SurfaceBindPattern option)
            expression
            rest
            isMonadicSite
            =
            match expression with
            | Apply(Name [ calleeName ], arguments) ->
                environment.VisibleBindings
                |> Map.tryFind calleeName
                |> Option.bind (fun bindingInfo ->
                    tryPrepareVisibleBindingCall
                        environment
                        freshCounter
                        bindingInfo
                        (Some localTypes)
                        (inferExpressionType localTypes)
                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                        arguments
                    |> Option.bind (fun preparedCall ->
                        let explicitParameters =
                            preparedCall.Parameters
                            |> List.choose (fun parameter ->
                                match parameter.Layout, parameter.AssignedArgument with
                                | Some layout, Some(ExplicitArgument argument) ->
                                    Some(layout, parameter.ParameterType, argument)
                                | _ ->
                                    None)
                            |> List.mapi (fun explicitIndex (layout, parameterType, argument) ->
                                explicitIndex, layout, parameterType, argument)

                        let inoutParameters =
                            explicitParameters
                            |> List.choose (fun (explicitIndex, layout, parameterType, argument) ->
                                match layout.IsInout, argument with
                                | true, InoutArgument inner -> Some(explicitIndex, layout, parameterType, inner)
                                | _ -> None)

                        if List.isEmpty inoutParameters then
                            None
                        else
                            let siteResultType =
                                if isMonadicSite then
                                    unwrapIoType preparedCall.ResultType
                                else
                                    preparedCall.ResultType

                            match tryCanonicalRecordType environment.VisibleTypeAliases siteResultType with
                            | Some(TypeRecord resultFields as resultRecordType) ->
                                let inoutNames =
                                    inoutParameters |> List.map (fun (_, layout, _, _) -> layout.Name) |> Set.ofList

                                let residualFields =
                                    resultFields
                                    |> List.filter (fun field -> not (Set.contains field.Name inoutNames))

                                let projectionInoutParameter =
                                    inoutParameters
                                    |> List.tryPick (fun (explicitIndex, _, _, inner) ->
                                        tryProjectionCallExpression inner
                                        |> Option.map (fun (projectionInfo, projectionArguments) ->
                                            explicitIndex, projectionInfo, projectionArguments))

                                match projectionInoutParameter with
                                | Some(targetExplicitIndex, projectionInfo, projectionArguments) ->
                                    tryLowerProjectionInoutDoSite
                                        scopeLabel
                                        localTypes
                                        binding
                                        calleeName
                                        explicitParameters
                                        targetExplicitIndex
                                        projectionInfo
                                        projectionArguments
                                        rest
                                        isMonadicSite
                                | None ->
                                    let layout =
                                        ensureSyntheticRecordLayout environment.CurrentModuleName "<binding>" recordLayouts resultRecordType

                                    let mutable rewrittenArguments = ResizeArray<SurfaceExpression>()
                                    let mutable callLocalTypes = localTypes
                                    let preludeBindings = ResizeArray<string * TypeExpr * KCoreExpression>()
                                    let restorePlans = ResizeArray<string * string * string list * bool>()

                                    for _, parameterLayout, _, argument in explicitParameters do
                                        match parameterLayout.IsInout, argument with
                                        | true, InoutArgument inner ->
                                            match tryExpressionPlace inner with
                                            | Some(rootName, path) ->
                                                match localTypes |> Map.tryFind rootName |> Option.bind unwrapRefLikeType with
                                                | Some refInnerType ->
                                                    let hiddenRootName = freshSyntheticName $"__kappa_inout_{rootName}_"
                                                    preludeBindings.Add(
                                                        hiddenRootName,
                                                        refInnerType,
                                                        KCoreExecute(
                                                            KCoreAppSpine(
                                                                KCoreName [ "readRef" ],
                                                                [ explicitKCoreArgument (KCoreName [ rootName ]) ]
                                                            )
                                                        )
                                                    )

                                                    callLocalTypes <- Map.add hiddenRootName refInnerType callLocalTypes
                                                    restorePlans.Add(parameterLayout.Name, rootName, path, true)
                                                    rewrittenArguments.Add(InoutArgument(Name(hiddenRootName :: path)))
                                                | None ->
                                                    restorePlans.Add(parameterLayout.Name, rootName, path, false)
                                                    rewrittenArguments.Add(argument)
                                            | None ->
                                                rewrittenArguments.Add(argument)
                                        | _ ->
                                            rewrittenArguments.Add(argument)

                                    let rewrittenCallExpression =
                                        Apply(Name [ calleeName ], List.ofSeq rewrittenArguments)

                                    let resultBindingName = freshSyntheticName "__kappa_inout_result_"
                                    let fieldBindingNames =
                                        layout.Fields
                                        |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_inout_field_{field.Name}_")
                                        |> Map.ofList

                                    let pattern =
                                        KCoreConstructorPattern(
                                            [ layout.ConstructorName ],
                                            layout.Fields
                                            |> List.map (fun field -> KCoreNamePattern fieldBindingNames[field.Name])
                                        )

                                    let matchLocalTypes =
                                        let withPrelude =
                                            preludeBindings
                                            |> Seq.fold (fun state (name, fieldType, _) -> Map.add name fieldType state) callLocalTypes

                                        layout.Fields
                                        |> List.fold (fun state field ->
                                            Map.add fieldBindingNames[field.Name] field.Type state) withPrelude

                                    let restLocalTypes =
                                        restorePlans
                                        |> Seq.fold (fun state (formalName, rootName, path, isVarRoot) ->
                                            match resultFields |> List.tryFind (fun field -> String.Equals(field.Name, formalName, StringComparison.Ordinal)) with
                                            | Some field when List.isEmpty path ->
                                                if isVarRoot then
                                                    Map.add rootName (refType field.Type) state
                                                else
                                                    Map.add rootName field.Type state
                                            | _ ->
                                                state) localTypes

                                    let residualResultType =
                                        match residualFields with
                                        | [] -> unitType
                                        | _ -> TypeRecord residualFields

                                    let loweredContinuation =
                                        match binding with
                                        | None ->
                                            if List.isEmpty residualFields then
                                                Some(lowerDoStatements scopeLabel restLocalTypes rest)
                                            else
                                                None
                                        | Some residualBinding ->
                                            let residualValueExpression =
                                                match residualFields with
                                                | [] ->
                                                    KCoreLiteral LiteralValue.Unit
                                                | _ ->
                                                    let residualLayout =
                                                        ensureSyntheticRecordLayout
                                                            environment.CurrentModuleName
                                                            "<binding>"
                                                            recordLayouts
                                                            residualResultType

                                                    KCoreAppSpine(
                                                        KCoreName [ residualLayout.ConstructorName ],
                                                        residualLayout.Fields
                                                        |> List.map (fun field ->
                                                            explicitKCoreArgument (KCoreName [ fieldBindingNames[field.Name] ]))
                                                    )

                                            Some(
                                                lowerPatternBinding
                                                    restLocalTypes
                                                    (Some residualResultType)
                                                    residualBinding
                                                    residualValueExpression
                                                    (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
                                            )

                                    loweredContinuation
                                    |> Option.map (fun continuationBody ->
                                        let restoredBody =
                                            restorePlans
                                            |> Seq.toList
                                            |> List.rev
                                            |> List.fold (fun current (formalName, rootName, path, isVarRoot) ->
                                                let replacement = Name [ fieldBindingNames[formalName] ]

                                                let rebuiltValue =
                                                    if isVarRoot then
                                                        let hiddenRootName, hiddenRootType =
                                                            preludeBindings
                                                            |> Seq.find (fun (name, _, _) ->
                                                                name.StartsWith($"__kappa_inout_{rootName}_", StringComparison.Ordinal))
                                                            |> fun (name, fieldType, _) -> name, fieldType

                                                        if List.isEmpty path then
                                                            KCoreName [ fieldBindingNames[formalName] ]
                                                        else
                                                            lowerExpression
                                                                (Map.add hiddenRootName hiddenRootType matchLocalTypes)
                                                                (buildPlaceWritebackExpression hiddenRootName path replacement)
                                                    elif List.isEmpty path then
                                                        KCoreName [ fieldBindingNames[formalName] ]
                                                    else
                                                        lowerExpression
                                                            matchLocalTypes
                                                            (buildPlaceWritebackExpression rootName path replacement)

                                                if isVarRoot then
                                                    KCoreSequence(
                                                        KCoreExecute(
                                                            KCoreAppSpine(
                                                                KCoreName [ "writeRef" ],
                                                                [ explicitKCoreArgument (KCoreName [ rootName ])
                                                                  explicitKCoreArgument rebuiltValue ]
                                                            )
                                                        ),
                                                        current
                                                    )
                                                else
                                                    KCoreLet(rootName, rebuiltValue, current))
                                                continuationBody

                                        let matchBody =
                                            KCoreMatch(
                                                KCoreName [ resultBindingName ],
                                                [
                                                    { Pattern = pattern
                                                      Guard = None
                                                      Body = restoredBody }
                                                ]
                                            )

                                        let callValue =
                                            if isMonadicSite then
                                                KCoreExecute(lowerExpression callLocalTypes rewrittenCallExpression)
                                            else
                                                lowerExpression callLocalTypes rewrittenCallExpression

                                        let callBody =
                                            KCoreLet(
                                                resultBindingName,
                                                callValue,
                                                matchBody
                                            )

                                        preludeBindings
                                        |> Seq.toList
                                        |> List.rev
                                        |> List.fold (fun current (bindingName, _, valueExpression) ->
                                            KCoreLet(bindingName, valueExpression, current)) callBody)
                            | _ ->
                                None))
            | _ ->
                None

        and lowerDoStatements scopeLabel localTypes statements =
            let bindPatternName (binding: SurfaceBindPattern) =
                match binding.Pattern with
                | NamePattern name -> name
                | _ -> "__pattern"

            match statements with
            | [] ->
                KCoreLiteral LiteralValue.Unit
            | [ DoExpression expression ] ->
                match tryLowerInoutDoSite scopeLabel localTypes None expression [] true with
                | Some lowered ->
                    lowered
                | None ->
                    KCoreExecute(lowerExpression localTypes expression)
            | DoExpression expression :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes None expression rest true with
                | Some lowered ->
                    lowered
                | None ->
                    KCoreSequence(KCoreExecute(lowerExpression localTypes expression), lowerDoStatements scopeLabel localTypes rest)
            | DoLet(binding, expression) :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes (Some binding) expression rest false with
                | Some lowered ->
                    lowered
                | None ->
                    let loweredValue = lowerExpression localTypes expression
                    let valueType = inferExpressionType localTypes expression

                    lowerPatternBinding
                        localTypes
                        valueType
                        binding
                        loweredValue
                        (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let valueType = inferExpressionType localTypes expression
                let successLocals =
                    extendPatternLocalTypes environment freshCounter localTypes valueType binding.Pattern

                let successCase: KCoreMatchCase =
                    { Pattern = lowerPattern localTypes valueType binding.Pattern
                      Guard = None
                      Body = lowerDoStatements scopeLabel successLocals rest }

                let failureCase: KCoreMatchCase =
                    match failure with
                    | Some failure ->
                        let failureLocals =
                            extendPatternLocalTypes environment freshCounter localTypes valueType failure.ResiduePattern.Pattern

                        { Pattern = lowerPattern localTypes valueType failure.ResiduePattern.Pattern
                          Guard = None
                          Body = lowerDoStatements scopeLabel failureLocals failure.Body }
                    | None ->
                        { Pattern = KCoreWildcardPattern
                          Guard = None
                          Body = KCoreExecute(KCoreName [ "empty" ]) }

                KCoreMatch(lowerExpression localTypes expression, [ successCase; failureCase ])
            | DoBind(binding, expression) :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes (Some binding) expression rest true with
                | Some lowered ->
                    lowered
                | None ->
                    let loweredValue = KCoreExecute(lowerExpression localTypes expression)
                    let valueType = inferExpressionType localTypes expression |> Option.map unwrapBindPayloadType

                    lowerPatternBinding
                        localTypes
                        valueType
                        binding
                        loweredValue
                        (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
            | DoUsing(binding, expression) :: rest ->
                let bindingName =
                    match binding.Pattern with
                    | NamePattern name -> name
                    | _ -> "__using"

                let hiddenOwnedName = freshUsingOwnedName bindingName
                let loweredValue = KCoreExecute(lowerExpression localTypes expression)

                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (unwrapIoType valueType) localTypes
                    | None -> localTypes

                KCoreLet(
                    hiddenOwnedName,
                    loweredValue,
                    KCoreScheduleExit(
                        scopeLabel,
                        buildUsingReleaseAction localTypes expression hiddenOwnedName,
                        KCoreLet(bindingName, KCoreName [ hiddenOwnedName ], lowerDoStatements scopeLabel nextLocals rest)
                    )
                )
            | DoVar(bindingName, expression) :: rest ->
                let loweredValue =
                    KCoreExecute(
                        KCoreAppSpine(
                            KCoreName [ "newRef" ],
                            [ explicitKCoreArgument (lowerExpression localTypes expression) ]
                        )
                    )

                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                KCoreLet(bindingName, loweredValue, lowerDoStatements scopeLabel nextLocals rest)
            | DoAssign(bindingName, expression) :: rest ->
                KCoreSequence(
                    KCoreExecute(
                        KCoreAppSpine(
                            KCoreName [ "writeRef" ],
                            [ explicitKCoreArgument (KCoreName [ bindingName ])
                              explicitKCoreArgument (lowerExpression localTypes expression) ]
                        )
                    ),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoDefer expression :: rest ->
                KCoreScheduleExit(
                    scopeLabel,
                    KCoreDeferred(lowerExpression localTypes expression),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | [ DoIf(condition, whenTrue, whenFalse) ] ->
                KCoreIfThenElse(
                    lowerExpression localTypes condition,
                    lowerDoStatements scopeLabel localTypes whenTrue,
                    lowerDoStatements scopeLabel localTypes whenFalse
                )
            | DoIf(condition, whenTrue, whenFalse) :: rest ->
                KCoreSequence(
                    KCoreIfThenElse(
                        lowerExpression localTypes condition,
                        lowerDoStatements scopeLabel localTypes whenTrue,
                        lowerDoStatements scopeLabel localTypes whenFalse
                    ),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoWhile(condition, body) :: rest ->
                KCoreSequence(
                    KCoreWhile(lowerExpression localTypes condition, lowerDoStatements scopeLabel localTypes body),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoReturn expression :: _ ->
                KCoreExecute(
                    KCoreAppSpine(
                        KCoreName [ "return" ],
                        [ explicitKCoreArgument (lowerExpression localTypes expression) ]
                    )
                )

        and lowerPattern localTypes expectedType pattern =
            match pattern with
            | WildcardPattern ->
                KCoreWildcardPattern
            | NamePattern name ->
                KCoreNamePattern name
            | AsPattern(_, inner) ->
                lowerPattern localTypes expectedType inner
            | TypedPattern(inner, typeTokens) ->
                let narrowedExpected =
                    TypeSignatures.parseType typeTokens
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.orElse expectedType

                lowerPattern localTypes narrowedExpected inner
            | LiteralPattern literal ->
                KCoreLiteralPattern literal
            | ConstructorPattern(name, arguments) ->
                let argumentTypes =
                    match expectedType, tryResolveVisibleConstructorInfo environment name with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                        if List.length parameterTypes = List.length arguments then
                            match
                                TypeSignatures.tryUnifyMany
                                    [
                                        qualifyVisibleTypeNames environment constructorResultType,
                                        qualifyVisibleTypeNames environment expectedResultType
                                    ]
                            with
                            | Some substitution ->
                                parameterTypes
                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                            | None ->
                                List.replicate arguments.Length None
                        else
                            List.replicate arguments.Length None
                    | _ ->
                        List.replicate arguments.Length None

                KCoreConstructorPattern(
                    name,
                    List.zip arguments argumentTypes
                    |> List.map (fun (argumentPattern, argumentType) -> lowerPattern localTypes argumentType argumentPattern)
                )
            | NamedConstructorPattern(name, fields) ->
                let positionalPatterns =
                    match tryResolveVisibleConstructorInfo environment name with
                    | Some constructorInfo ->
                        let fieldMap =
                            fields
                            |> List.map (fun field -> field.Name, field.Pattern)
                            |> Map.ofList

                        constructorInfo.ParameterLayouts
                        |> Option.map (fun layouts ->
                            layouts
                            |> List.filter (fun parameter -> not parameter.IsImplicit)
                            |> List.map (fun parameter ->
                                fieldMap |> Map.tryFind parameter.Name |> Option.defaultValue WildcardPattern))
                        |> Option.defaultValue (fields |> List.map (fun field -> field.Pattern))
                    | None ->
                        fields |> List.map (fun field -> field.Pattern)

                lowerPattern localTypes expectedType (ConstructorPattern(name, positionalPatterns))
            | TuplePattern elements ->
                let tupleFields =
                    elements
                    |> List.mapi (fun index element ->
                        { Name = $"_{index + 1}"
                          IsImplicit = false
                          Pattern = element })

                lowerPattern localTypes expectedType (AnonymousRecordPattern(tupleFields, None))
            | VariantPattern(BoundVariantPattern(name, _)) ->
                KCoreNamePattern name
            | VariantPattern(RestVariantPattern name) ->
                KCoreNamePattern name
            | VariantPattern(WildcardVariantPattern _) ->
                KCoreWildcardPattern
            | OrPattern alternatives ->
                KCoreOrPattern(alternatives |> List.map (lowerPattern localTypes expectedType))
            | AnonymousRecordPattern(fields, _) ->
                match expectedType |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some recordType ->
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleName "<binding>" recordLayouts recordType

                    let fieldPatterns =
                        fields
                        |> List.map (fun field -> field.Name, field.Pattern)
                        |> Map.ofList

                    KCoreConstructorPattern(
                        [ layout.ConstructorName ],
                        layout.Fields
                        |> List.map (fun field ->
                            fieldPatterns
                            |> Map.tryFind field.Name
                            |> Option.map (lowerPattern localTypes (Some field.Type))
                            |> Option.defaultValue KCoreWildcardPattern)
                    )
                | None ->
                    KCoreWildcardPattern

        and lowerStaticObject staticObject =
            match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
            | StaticEffectLabelObject, Some declaration, _ ->
                scopedKCoreEffectLabel declaration
            | StaticEffectLabelObject, None, [ effectName ] ->
                match tryFindScopedEffectDeclaration effectName with
                | Some declaration ->
                    scopedKCoreEffectLabel declaration
                | None ->
                    KCoreStaticObject
                        { ObjectKind = KCoreEffectLabelObject
                          Name = staticObject.NameSegments
                          Type = staticObjectTypeText staticObject |> Option.bind tryParseTypeText
                          TypeText = staticObjectTypeText staticObject }
            | _ ->
                let kind =
                    match staticObject.ObjectKind with
                    | StaticTypeObject -> KCoreTypeObject
                    | StaticTraitObject -> KCoreTraitObject
                    | StaticEffectLabelObject -> KCoreEffectLabelObject
                    | StaticModuleObject -> KCoreModuleObject

                KCoreStaticObject
                    { ObjectKind = kind
                      Name = staticObject.NameSegments
                      Type = staticObjectTypeText staticObject |> Option.bind tryParseTypeText
                      TypeText = staticObjectTypeText staticObject }

        and tryLowerRecordProjectionPath
            localTypes
            receiverValue
            receiverType
            path
            =
            match tryCanonicalRecordType environment.VisibleTypeAliases receiverType, path with
            | Some(TypeRecord fields), fieldName :: rest ->
                let layout =
                    ensureSyntheticRecordLayout environment.CurrentModuleName "<binding>" recordLayouts (TypeRecord fields)

                let boundFields =
                    layout.Fields
                    |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_record_{field.Name}_")

                match
                    fields |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal)),
                    boundFields |> List.tryFind (fun (name, _) -> String.Equals(name, fieldName, StringComparison.Ordinal))
                with
                | Some field, Some(_, bindingName) ->
                    let fieldValue = KCoreName [ bindingName ]

                    let body =
                        match rest with
                        | [] ->
                            fieldValue
                        | _ ->
                            tryLowerRecordProjectionPath
                                (Map.add bindingName field.Type localTypes)
                                fieldValue
                                field.Type
                                rest
                            |> Option.defaultValue fieldValue

                    Some(
                        KCoreMatch(
                            receiverValue,
                            [
                                { Pattern =
                                    KCoreConstructorPattern(
                                        [ layout.ConstructorName ],
                                        boundFields
                                        |> List.map (fun (_, localName) -> KCoreNamePattern localName)
                                    )
                                  Guard = None
                                  Body = body }
                            ]
                        )
                    )
                | _ ->
                    None
            | _ ->
                None

        and lowerExpression localTypes expression =
            lowerExpressionWithExpectedType localTypes None expression

        and lowerExpressionWithExpectedType localTypes expectedType expression =
            let lowerArguments arguments =
                arguments
                |> List.map (function
                    | InoutArgument inner -> inoutKCoreArgument (lowerExpressionWithExpectedType localTypes None inner)
                    | argument -> explicitKCoreArgument (lowerExpressionWithExpectedType localTypes None argument))

            let lowerArgumentExpressions arguments =
                arguments
                |> List.map (function
                    | InoutArgument inner -> lowerExpressionWithExpectedType localTypes None inner
                    | argument -> lowerExpressionWithExpectedType localTypes None argument)

            let lowerPreparedArguments preparedArguments =
                preparedArguments
                |> List.map (function
                    | ExplicitArgument argument -> explicitKCoreArgument (lowerExpressionWithExpectedType localTypes None argument)
                    | ImplicitArgument implicitArgument -> implicitKCoreArgument implicitArgument)

            let lowerPreparedArgumentExpressions preparedArguments =
                preparedArguments
                |> List.map (function
                    | ExplicitArgument argument -> lowerExpressionWithExpectedType localTypes None argument
                    | ImplicitArgument implicitArgument -> implicitArgument)

            let lowerStaticConstructorCallee receiverExpression memberName =
                let receiverSegments =
                    match receiverExpression with
                    | Name segments
                    | KindQualifiedName(_, segments) ->
                        Some segments
                    | _ ->
                        tryResolveScopedStaticObject environment receiverExpression
                        |> Option.map (fun staticObject -> staticObject.NameSegments)

                KCoreName((receiverSegments |> Option.defaultValue []) @ [ memberName ])

            let lowerInterpolatedMacroTypeArgument inner =
                match inferExpressionType localTypes inner |> Option.map (normalizeTypeAliases environment.VisibleTypeAliases) with
                | Some(TypeName(nameSegments, [])) ->
                    KCoreStaticObject
                        { ObjectKind = KCoreTypeObject
                          Name = nameSegments
                          Type = Some(TypeName([ "Type" ], []))
                          TypeText = Some "Type" }
                | _ ->
                    KCoreLiteral LiteralValue.Unit

            let interpolatedFragmentConstructor name arguments =
                KCoreAppSpine(KCoreName [ name ], arguments |> List.map explicitKCoreArgument)

            let fragmentListExpression fragments =
                let cons head tail =
                    KCoreAppSpine(
                        KCoreName [ "Cons" ],
                        [ explicitKCoreArgument head
                          explicitKCoreArgument tail ]
                    )

                fragments
                |> List.rev
                |> List.fold (fun tail head -> cons head tail) (KCoreName [ "Nil" ])

            let lowerPrefixedStringFragments parts =
                let flushText pending acc =
                    match pending with
                    | Some text when not (String.IsNullOrEmpty(text)) ->
                        interpolatedFragmentConstructor "Lit" [ KCoreLiteral(LiteralValue.String text) ] :: acc
                    | _ ->
                        acc

                let interpolationFragment inner format =
                    let typeArgument = lowerInterpolatedMacroTypeArgument inner
                    let quoted = KCoreSyntaxQuote(lowerExpressionWithExpectedType localTypes None inner)

                    match format with
                    | None ->
                        interpolatedFragmentConstructor "Interp" [ typeArgument; quoted ]
                    | Some formatText ->
                        interpolatedFragmentConstructor
                            "InterpFmt"
                            [ typeArgument
                              quoted
                              KCoreLiteral(LiteralValue.String formatText) ]

                let rec loop pendingText acc remainingParts =
                    match remainingParts with
                    | [] ->
                        let completed = flushText pendingText acc |> List.rev

                        if List.isEmpty completed then
                            [ interpolatedFragmentConstructor "Lit" [ KCoreLiteral(LiteralValue.String "") ] ]
                        else
                            completed
                    | StringText text :: rest ->
                        let mergedText =
                            pendingText
                            |> Option.map (fun pending -> pending + text)
                            |> Option.defaultValue text

                        loop (Some mergedText) acc rest
                    | StringInterpolation(inner, format) :: rest ->
                        let nextAcc =
                            flushText pendingText acc
                            |> fun fragments -> interpolationFragment inner format :: fragments

                        loop None nextAcc rest

                loop None [] parts

            let lowerPrefixedString prefix parts =
                let fragments = lowerPrefixedStringFragments parts |> fragmentListExpression

                KCoreTopLevelSyntaxSplice(
                    KCoreTraitCall(
                        "InterpolatedMacro",
                        "buildInterpolated",
                        KCoreName [ prefix ],
                        [ fragments ]
                    )
                )

            let tryLowerEffectHandlerArgument tokens =
                match significantEffectHandlerTokens tokens with
                | [ leftParen; rightParen ] when leftParen.Kind = LeftParen && rightParen.Kind = RightParen ->
                    Some KCoreEffectUnitArgument
                | [ nameToken ] when Token.isName nameToken ->
                    let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

                    if String.Equals(name, "_", StringComparison.Ordinal) then
                        Some KCoreEffectWildcardArgument
                    else
                        Some(KCoreEffectNameArgument name)
                | leftParen :: nameToken :: colonToken :: _
                    when leftParen.Kind = LeftParen && Token.isName nameToken && colonToken.Kind = Colon ->
                    let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

                    if String.Equals(name, "_", StringComparison.Ordinal) then
                        Some KCoreEffectWildcardArgument
                    else
                        Some(KCoreEffectNameArgument name)
                | _ ->
                    None

            let effectHandlerArgumentName argument =
                match argument with
                | KCoreEffectNameArgument name -> Some name
                | _ -> None

            let asEffectComputation currentLocals innerExpression =
                let lowered = lowerExpression currentLocals innerExpression

                let inferredComputationType =
                    tryInferLocalAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferExpressionType currentLocals)
                        currentLocals
                        innerExpression
                    |> Option.orElseWith (fun () -> inferExpressionType currentLocals innerExpression)

                match inferredComputationType |> Option.bind tryUnwrapComputationPayloadType with
                | Some _ ->
                    lowered
                | None ->
                    KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument lowered ])

            let rec tryLowerEffectfulDoStatements currentLocals statements =
                match statements with
                | [] ->
                    Some(KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument (KCoreLiteral LiteralValue.Unit) ]))
                | [ DoReturn expression ] ->
                    Some(KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument (lowerExpression currentLocals expression) ]))
                | [ DoExpression expression ] ->
                    Some(asEffectComputation currentLocals expression)
                | DoExpression expression :: rest ->
                    tryLowerEffectfulDoStatements currentLocals rest
                    |> Option.map (fun loweredRest ->
                        KCoreAppSpine(
                            KCoreName [ ">>" ],
                            [
                                explicitKCoreArgument (asEffectComputation currentLocals expression)
                                explicitKCoreArgument loweredRest
                            ]
                        ))
                | DoReturn expression :: rest ->
                    tryLowerEffectfulDoStatements currentLocals rest
                    |> Option.map (fun loweredRest ->
                        KCoreAppSpine(
                            KCoreName [ ">>" ],
                            [
                                explicitKCoreArgument
                                    (KCoreAppSpine(
                                        KCoreName [ "pure" ],
                                        [ explicitKCoreArgument (lowerExpression currentLocals expression) ]
                                    ))
                                explicitKCoreArgument loweredRest
                            ]
                        ))
                | DoLet(binding, value) :: rest ->
                    match tryLowerEffectfulDoStatements currentLocals rest with
                    | Some loweredRest ->
                        let bindingExpectedType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)

                        let loweredValue = lowerExpressionWithExpectedType currentLocals bindingExpectedType value
                        let valueType = bindingExpectedType |> Option.orElseWith (fun () -> inferExpressionType currentLocals value)

                        Some(
                            lowerPatternBinding
                                currentLocals
                                valueType
                                binding
                                loweredValue
                                (fun _ -> loweredRest))
                    | None ->
                        None
                | DoBind(binding, expression) :: rest ->
                    let payloadType = inferExpressionType currentLocals expression |> Option.map unwrapBindPayloadType
                    let parameterName = freshSyntheticName "__kappa_eff_bind_"

                    let parameter =
                        { Name = parameterName
                          Quantity = Some QuantityOne
                          IsImplicit = false
                          Type = payloadType
                          TypeText = payloadType |> Option.map TypeSignatures.toText }

                    let parameterLocals =
                        payloadType
                        |> Option.map (fun typeExpr -> Map.add parameterName typeExpr currentLocals)
                        |> Option.defaultValue currentLocals

                    let restLocals =
                        extendBindingLocalTypes environment freshCounter currentLocals binding payloadType

                    match tryLowerEffectfulDoStatements restLocals rest with
                    | Some loweredRest ->
                        let lambdaBody =
                            lowerPatternBinding
                                parameterLocals
                                payloadType
                                binding
                                (KCoreName [ parameterName ])
                                (fun _ -> loweredRest)

                        Some(
                            KCoreAppSpine(
                                KCoreName [ ">>=" ],
                                [
                                    explicitKCoreArgument (asEffectComputation currentLocals expression)
                                    explicitKCoreArgument (KCoreLambda([ parameter ], lambdaBody))
                                ]
                            ))
                    | None ->
                        None
                | DoIf(condition, whenTrue, whenFalse) :: rest ->
                    match tryLowerEffectfulDoStatements currentLocals whenTrue, tryLowerEffectfulDoStatements currentLocals whenFalse with
                    | Some loweredWhenTrue, Some loweredWhenFalse ->
                        let loweredIf = KCoreIfThenElse(lowerExpression currentLocals condition, loweredWhenTrue, loweredWhenFalse)

                        match rest with
                        | [] ->
                            Some loweredIf
                        | _ ->
                            match tryLowerEffectfulDoStatements currentLocals rest with
                            | Some loweredRest ->
                                Some(
                                    KCoreAppSpine(
                                        KCoreName [ ">>" ],
                                        [
                                            explicitKCoreArgument loweredIf
                                            explicitKCoreArgument loweredRest
                                        ]
                                    ))
                            | None ->
                                None
                    | _ ->
                        None
                | DoLetQuestion _ :: _
                | DoVar _ :: _
                | DoAssign _ :: _
                | DoUsing _ :: _
                | DoDefer _ :: _
                | DoWhile _ :: _ ->
                    None

            let rec hasEffectfulDoFlow currentLocals statements =
                statements
                |> List.exists (function
                    | DoBind(_, innerExpression) ->
                        inferExpressionType currentLocals innerExpression
                        |> Option.bind tryUnwrapEffType
                        |> Option.isSome
                    | DoExpression innerExpression ->
                        inferExpressionType currentLocals innerExpression
                        |> Option.bind tryUnwrapEffType
                        |> Option.isSome
                    | DoIf(_, whenTrue, whenFalse) ->
                        hasEffectfulDoFlow currentLocals whenTrue || hasEffectfulDoFlow currentLocals whenFalse
                    | DoWhile(_, body) ->
                        hasEffectfulDoFlow currentLocals body
                    | DoLet _
                    | DoLetQuestion _
                    | DoVar _
                    | DoAssign _
                    | DoUsing _
                    | DoDefer _
                    | DoReturn _ ->
                        false)

            let tryInferSeededLambdaParameterTypes helperName parameters bodyExpression =
                let rec tryFind shadowed expression =
                    match expression with
                    | Apply(Name [ name ], arguments)
                        when String.Equals(name, helperName, StringComparison.Ordinal)
                             && not (Set.contains helperName shadowed)
                             && List.length arguments = List.length parameters ->
                        let argumentTypes = arguments |> List.map (inferExpressionType localTypes)

                        if argumentTypes |> List.forall Option.isSome then
                            Some(argumentTypes |> List.choose id)
                        else
                            None
                    | Apply(callee, arguments) ->
                        tryFind shadowed callee
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick (tryFind shadowed))
                    | LocalLet(binding, value, body) ->
                        tryFind shadowed value
                        |> Option.orElseWith (fun () ->
                            let nextShadowed =
                                if collectPatternNames binding.Pattern |> List.exists (fun name -> String.Equals(name, helperName, StringComparison.Ordinal)) then
                                    Set.add helperName shadowed
                                else
                                    shadowed

                            tryFind nextShadowed body)
                    | LocalSignature(declaration, body) ->
                        if String.Equals(declaration.Name, helperName, StringComparison.Ordinal) then
                            None
                        else
                            tryFind shadowed body
                    | LocalTypeAlias(_, body) ->
                        tryFind shadowed body
                    | LocalScopedEffect(_, body) ->
                        tryFind shadowed body
                    | TypeSyntaxTokens _ ->
                        None
                    | Lambda(nestedParameters, body) ->
                        let nextShadowed =
                            if nestedParameters |> List.exists (fun parameter -> String.Equals(parameter.Name, helperName, StringComparison.Ordinal)) then
                                Set.add helperName shadowed
                            else
                                shadowed

                        tryFind nextShadowed body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        tryFind shadowed condition
                        |> Option.orElseWith (fun () -> tryFind shadowed whenTrue)
                        |> Option.orElseWith (fun () -> tryFind shadowed whenFalse)
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        tryFind shadowed label
                        |> Option.orElseWith (fun () -> tryFind shadowed body)
                        |> Option.orElseWith (fun () -> tryFind shadowed returnClause.Body)
                        |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> tryFind shadowed clause.Body))
                    | Match(scrutinee, cases) ->
                        tryFind shadowed scrutinee
                        |> Option.orElseWith (fun () ->
                            cases
                            |> List.tryPick (fun caseClause ->
                                caseClause.Guard
                                |> Option.bind (tryFind shadowed)
                                |> Option.orElseWith (fun () -> tryFind shadowed caseClause.Body)))
                    | RecordLiteral fields ->
                        fields |> List.tryPick (fun field -> tryFind shadowed field.Value)
                    | RecordUpdate(receiver, fields) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> tryFind shadowed field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick (tryFind shadowed))
                    | SafeNavigation(receiver, navigation) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick (tryFind shadowed))
                    | TagTest(receiver, _) ->
                        tryFind shadowed receiver
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner)
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | Seal(inner, _) ->
                        tryFind shadowed inner
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        tryFind shadowed left
                        |> Option.orElseWith (fun () -> tryFind shadowed right)
                    | Comprehension comprehension ->
                        tryFind shadowed comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.tryPick (function
                            | StringText _ -> None
                            | StringInterpolation(inner, _) -> tryFind shadowed inner)
                    | NamedApplicationBlock fields ->
                        fields |> List.tryPick (fun field -> tryFind shadowed field.Value)
                    | Do _
                    | Literal _
                    | NumericLiteral _
                    | Name _
                    | KindQualifiedName _ ->
                        None

                tryFind Set.empty bodyExpression

            let lowerLambdaExpression baseLocals parameterTypeHints lambdaParameters lambdaBody =
                let resolvedParameterTypes =
                    lambdaParameters
                    |> List.mapi (fun index parameter ->
                        tryParseParameterType parameter
                        |> Option.orElseWith (fun () ->
                            parameterTypeHints |> Option.bind (List.tryItem index))
                        |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

                let lambdaLocals =
                    List.zip lambdaParameters resolvedParameterTypes
                    |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) baseLocals

                KCoreLambda(
                    List.zip lambdaParameters resolvedParameterTypes
                    |> List.map (fun (parameter, parameterType) -> lowerKCoreParameter parameter (Some parameterType)),
                    lowerExpressionWithExpectedType lambdaLocals expectedType lambdaBody
                )

            let rec substituteKCoreNames substitutions current =
                match current with
                | KCoreName [ name ] ->
                    substitutions |> Map.tryFind name |> Option.defaultValue current
                | KCoreName _ ->
                    current
                | KCoreSyntaxQuote inner ->
                    KCoreSyntaxQuote(substituteKCoreNames substitutions inner)
                | KCoreSyntaxSplice inner ->
                    KCoreSyntaxSplice(substituteKCoreNames substitutions inner)
                | KCoreTopLevelSyntaxSplice inner ->
                    KCoreTopLevelSyntaxSplice(substituteKCoreNames substitutions inner)
                | KCoreCodeQuote inner ->
                    KCoreCodeQuote(substituteKCoreNames substitutions inner)
                | KCoreCodeSplice inner ->
                    KCoreCodeSplice(substituteKCoreNames substitutions inner)
                | KCoreLiteral _
                | KCoreDictionaryValue _
                | KCoreStaticObject _ ->
                    current
                | KCoreEffectLabel(labelName, interfaceId, labelId, operations) ->
                    KCoreEffectLabel(labelName, interfaceId, labelId, operations)
                | KCoreEffectOperation(label, operationId, operationName) ->
                    KCoreEffectOperation(substituteKCoreNames substitutions label, operationId, operationName)
                | KCoreLambda(parameters, body) ->
                    let nextSubstitutions =
                        parameters
                        |> List.fold (fun state parameter -> Map.remove parameter.Name state) substitutions

                    KCoreLambda(parameters, substituteKCoreNames nextSubstitutions body)
                | KCoreIfThenElse(condition, whenTrue, whenFalse) ->
                    KCoreIfThenElse(
                        substituteKCoreNames substitutions condition,
                        substituteKCoreNames substitutions whenTrue,
                        substituteKCoreNames substitutions whenFalse
                    )
                | KCoreHandle(isDeep, label, body, returnClause, operationClauses) ->
                    let lowerClause (clause: KCoreEffectHandlerClause) =
                        let nextSubstitutions =
                            clause.Arguments
                            |> List.choose effectHandlerArgumentName
                            |> List.fold (fun state name -> Map.remove name state) substitutions
                            |> fun state ->
                                clause.ResumptionName
                                |> Option.map (fun name -> Map.remove name state)
                                |> Option.defaultValue state

                        { clause with
                            Body = substituteKCoreNames nextSubstitutions clause.Body }

                    KCoreHandle(
                        isDeep,
                        substituteKCoreNames substitutions label,
                        substituteKCoreNames substitutions body,
                        lowerClause returnClause,
                        operationClauses |> List.map lowerClause
                    )
                | KCoreMatch(scrutinee, cases) ->
                    KCoreMatch(
                        substituteKCoreNames substitutions scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { Pattern = caseClause.Pattern
                              Guard = caseClause.Guard |> Option.map (substituteKCoreNames substitutions)
                              Body = substituteKCoreNames substitutions caseClause.Body })
                    )
                | KCoreExecute inner ->
                    KCoreExecute(substituteKCoreNames substitutions inner)
                | KCoreLet(bindingName, value, body) ->
                    let nextSubstitutions = Map.remove bindingName substitutions
                    KCoreLet(
                        bindingName,
                        substituteKCoreNames substitutions value,
                        substituteKCoreNames nextSubstitutions body
                    )
                | KCoreDoScope(scopeLabel, body) ->
                    KCoreDoScope(scopeLabel, substituteKCoreNames substitutions body)
                | KCoreScheduleExit(scopeLabel, action, body) ->
                    let loweredAction =
                        match action with
                        | KCoreDeferred deferred -> KCoreDeferred(substituteKCoreNames substitutions deferred)
                        | KCoreRelease(typeText, release, resource) ->
                            KCoreRelease(
                                typeText,
                                substituteKCoreNames substitutions release,
                                substituteKCoreNames substitutions resource
                            )

                    KCoreScheduleExit(scopeLabel, loweredAction, substituteKCoreNames substitutions body)
                | KCoreSequence(first, second) ->
                    KCoreSequence(substituteKCoreNames substitutions first, substituteKCoreNames substitutions second)
                | KCoreWhile(condition, body) ->
                    KCoreWhile(substituteKCoreNames substitutions condition, substituteKCoreNames substitutions body)
                | KCoreAppSpine(callee, arguments) ->
                    KCoreAppSpine(
                        substituteKCoreNames substitutions callee,
                        arguments
                        |> List.map (fun argument ->
                            { argument with
                                Expression = substituteKCoreNames substitutions argument.Expression })
                    )
                | KCoreTraitCall(traitName, memberName, dictionary, arguments) ->
                    KCoreTraitCall(
                        traitName,
                        memberName,
                        substituteKCoreNames substitutions dictionary,
                        arguments |> List.map (substituteKCoreNames substitutions)
                    )
                | KCoreUnary(operatorName, operand) ->
                    KCoreUnary(operatorName, substituteKCoreNames substitutions operand)
                | KCoreBinary(left, operatorName, right) ->
                    KCoreBinary(
                        substituteKCoreNames substitutions left,
                        operatorName,
                        substituteKCoreNames substitutions right
                    )
                | KCorePrefixedString(prefix, parts) ->
                    KCorePrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | KCoreStringText text -> KCoreStringText text
                            | KCoreStringInterpolation inner -> KCoreStringInterpolation(substituteKCoreNames substitutions inner))
                    )

            let eraseIntrinsicPreludeDictionaryArguments
                (bindingInfo: BindingSchemeInfo)
                (dictionaryArguments: KCoreArgument list)
                =
                let isIntrinsicPreludeDictionary expression =
                    match expression with
                    | KCoreDictionaryValue(moduleName, _, instanceKey, _) ->
                        String.Equals(moduleName, Stdlib.PreludeModuleText, StringComparison.Ordinal)
                        && instanceKey.StartsWith("builtin-prelude:", StringComparison.Ordinal)
                    | _ ->
                        false

                if IntrinsicCatalog.erasesBuiltinPreludeConstraintEvidence bindingInfo.ModuleName bindingInfo.Name then
                    dictionaryArguments
                    |> List.filter (fun argument -> not (isIntrinsicPreludeDictionary argument.Expression))
                else
                    dictionaryArguments

            let lowerPreparedBindingCallArguments
                (bindingInfo: BindingSchemeInfo)
                (preparedCall: PreparedBindingCall)
                =
                let isIntrinsicPreludeDictionary expression =
                    match expression with
                    | KCoreDictionaryValue(moduleName, _, instanceKey, _) ->
                        String.Equals(moduleName, Stdlib.PreludeModuleText, StringComparison.Ordinal)
                        && instanceKey.StartsWith("builtin-prelude:", StringComparison.Ordinal)
                    | _ ->
                        false

                let eraseIntrinsicPreludeImplicitDictionaries preparedArguments =
                    if IntrinsicCatalog.erasesBuiltinPreludeConstraintEvidence bindingInfo.ModuleName bindingInfo.Name then
                        preparedArguments
                        |> List.filter (function
                            | ImplicitArgument implicitArgument -> not (isIntrinsicPreludeDictionary implicitArgument)
                            | ExplicitArgument _ -> true)
                    else
                        preparedArguments

                let eraseIntrinsicPreludeDictionaryArguments dictionaryArguments =
                    if IntrinsicCatalog.erasesBuiltinPreludeConstraintEvidence bindingInfo.ModuleName bindingInfo.Name then
                        dictionaryArguments
                        |> List.filter (fun argument -> not (isIntrinsicPreludeDictionary argument.Expression))
                    else
                        dictionaryArguments

                if List.isEmpty preparedCall.Parameters then
                    preparedCall.Arguments
                    |> eraseIntrinsicPreludeImplicitDictionaries
                    |> lowerPreparedArguments
                else
                    let rec loop substitutions parameters =
                        match parameters with
                        | [] ->
                            []
                        | parameter :: rest ->
                            let runtimeArgument, nextSubstitutions =
                                match parameter.Layout, parameter.AssignedArgument with
                                | _, Some(ExplicitArgument argument) ->
                                    let loweredArgument = lowerExpressionWithExpectedType localTypes (Some parameter.ParameterType) argument
                                    let substitutions =
                                        match parameter.Layout with
                                        | Some layout -> Map.add layout.Name loweredArgument substitutions
                                        | None -> substitutions

                                    Some(explicitKCoreArgument loweredArgument), substitutions
                                | Some layout, Some(ImplicitArgument implicitArgument) ->
                                    Some(implicitKCoreArgument implicitArgument), Map.add layout.Name implicitArgument substitutions
                                | Some layout, None when bindingInfo.DefaultArguments.ContainsKey(layout.Name) ->
                                    let loweredDefault =
                                        lowerExpressionWithExpectedType localTypes (Some parameter.ParameterType) bindingInfo.DefaultArguments[layout.Name]
                                        |> substituteKCoreNames substitutions

                                    Some(explicitKCoreArgument loweredDefault), Map.add layout.Name loweredDefault substitutions
                                | _ ->
                                    None, substitutions

                            match runtimeArgument with
                            | Some runtimeArgument -> runtimeArgument :: loop nextSubstitutions rest
                            | None -> loop nextSubstitutions rest

                    loop Map.empty preparedCall.Parameters

            match expression with
            | Literal literal ->
                KCoreLiteral literal
            | NumericLiteral literal ->
                match SurfaceNumericLiteral.suffix literal with
                | Some suffixName ->
                    lowerExpressionWithExpectedType
                        localTypes
                        expectedType
                        (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
                | None ->
                    let contextualType =
                        expectedType
                        |> Option.bind (fun expectedResultType ->
                            tryResolveNumericLiteralContext environment expectedResultType literal)

                    match contextualType with
                    | Some(_, None) ->
                        tryLowerNumericLiteralForRuntime literal
                        |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
                    | Some(targetType, Some instanceInfo) ->
                        let literalConstraint =
                            { TraitName = numericLiteralConstraintName literal
                              Arguments = [ targetType ] }

                        let semanticArgument =
                            tryLowerNumericLiteralForRuntime literal
                            |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)

                        KCoreTraitCall(
                            literalConstraint.TraitName,
                            (if literalConstraint.TraitName = "FromInteger" then
                                 "fromInteger"
                             else
                                 "fromFloat"),
                            (tryLowerResolvedDictionaryValue environment literalConstraint
                             |> Option.defaultValue (
                                 KCoreDictionaryValue(instanceInfo.ModuleName, instanceInfo.TraitName, instanceInfo.InstanceKey, [])
                             )),
                            [ semanticArgument ]
                        )
                    | None ->
                        tryLowerNumericLiteralForRuntime literal
                        |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
            | TypeSyntaxTokens _ ->
                KCoreLiteral LiteralValue.Unit
            | SyntaxQuote inner ->
                KCoreSyntaxQuote(lowerExpressionWithExpectedType localTypes None inner)
            | SyntaxSplice inner ->
                KCoreSyntaxSplice(lowerExpressionWithExpectedType localTypes None inner)
            | TopLevelSyntaxSplice inner ->
                KCoreTopLevelSyntaxSplice(lowerExpressionWithExpectedType localTypes None inner)
            | CodeQuote inner ->
                KCoreCodeQuote(lowerExpressionWithExpectedType localTypes None inner)
            | CodeSplice inner ->
                KCoreCodeSplice(lowerExpressionWithExpectedType localTypes None inner)
            | Comprehension comprehension ->
                lowerExpressionWithExpectedType localTypes expectedType comprehension.Lowered
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let handledType =
                    expectedType
                    |> Option.orElseWith (fun () -> inferExpressionType localTypes expression)

                let handledBodyType =
                    inferExpressionType localTypes body

                let handledPayloadType =
                    handledBodyType
                    |> Option.bind tryUnwrapEffType
                    |> Option.map snd
                    |> Option.defaultValue (TypeVariable $"handlePayload{freshCounter.Value}")

                let handledEffectDeclaration =
                    tryResolveHandledEffectDeclaration environment label

                let lowerClause
                    (argumentTypes: TypeExpr list)
                    (resumptionType: TypeExpr option)
                    (clause: SurfaceEffectHandlerClause)
                    =
                    let loweredArguments =
                        clause.ArgumentTokens
                        |> List.map (fun tokens ->
                            tryLowerEffectHandlerArgument tokens
                            |> Option.defaultValue KCoreEffectWildcardArgument)

                    let clauseLocals =
                        (localTypes, loweredArguments |> List.mapi (fun index argument -> argument, argumentTypes |> List.tryItem index))
                        ||> List.fold (fun state (argument, argumentType) ->
                            match argument, argumentType with
                            | KCoreEffectNameArgument name, Some currentArgumentType -> Map.add name currentArgumentType state
                            | _ -> state)
                        |> fun state ->
                            match clause.ResumptionName, resumptionType with
                            | Some resumptionName, Some currentResumptionType ->
                                Map.add resumptionName currentResumptionType state
                            | _ ->
                                state

                    { OperationName = clause.OperationName
                      Arguments = loweredArguments
                      ResumptionName = clause.ResumptionName
                      Body = lowerExpressionWithExpectedType clauseLocals handledType clause.Body }

                let loweredReturnClause =
                    lowerClause [ handledPayloadType ] None returnClause

                let loweredOperationClauses =
                    operationClauses
                    |> List.map (fun clause ->
                        let parameterTypes, resultType =
                            handledEffectDeclaration
                            |> Option.bind (fun declaration ->
                                EffectSemantics.tryFindOperation clause.OperationName declaration
                                |> Option.bind (fun operation ->
                                    operation.SignatureTokens
                                    |> TypeSignatures.parseType
                                    |> Option.map (qualifyVisibleTypeNames environment)
                                    |> Option.map TypeSignatures.functionParts
                                    |> Option.map (fun (parameterTypes, resultType) -> parameterTypes, resultType)))
                            |> Option.defaultValue ([], TypeVariable $"opResult{freshCounter.Value}")

                        let resumptionResultType =
                            if isDeep then
                                handledType
                            else
                                handledBodyType

                        let resumptionType =
                            resumptionResultType
                            |> Option.map (fun currentHandledType -> TypeArrow(QuantityOne, resultType, currentHandledType))

                        lowerClause parameterTypes resumptionType clause, resultType)

                let loweredLabel = lowerExpressionWithExpectedType localTypes None label
                let loweredBody = lowerExpressionWithExpectedType localTypes handledType body

                if not isDeep then
                    KCoreHandle(
                        false,
                        loweredLabel,
                        loweredBody,
                        loweredReturnClause,
                        loweredOperationClauses |> List.map fst
                    )
                else
                    let goName = $"__kappa_deep_go_{freshCounter.Value}"
                    freshCounter.Value <- freshCounter.Value + 1
                    let compName = $"__kappa_deep_comp_{freshCounter.Value}"
                    freshCounter.Value <- freshCounter.Value + 1

                    let lowerDeepClause ((clause: KCoreEffectHandlerClause), resultType: TypeExpr) =
                        match clause.ResumptionName with
                        | Some resumptionName ->
                            let shallowResumptionName = $"__kappa_deep_shallow_k_{freshCounter.Value}"
                            freshCounter.Value <- freshCounter.Value + 1
                            let resultName = $"__kappa_deep_res_{freshCounter.Value}"
                            freshCounter.Value <- freshCounter.Value + 1

                            let wrapperParameter =
                                { Name = resultName
                                  Quantity = Some QuantityOne
                                  IsImplicit = false
                                  Type = Some resultType
                                  TypeText = Some(TypeSignatures.toText resultType) }

                            let wrapperBody =
                                KCoreAppSpine(
                                    KCoreName [ goName ],
                                    [
                                        explicitKCoreArgument
                                            (KCoreAppSpine(
                                                KCoreName [ shallowResumptionName ],
                                                [ explicitKCoreArgument(KCoreName [ resultName ]) ]
                                            ))
                                    ]
                                )

                            { clause with
                                ResumptionName = Some shallowResumptionName
                                Body =
                                    KCoreLet(
                                        resumptionName,
                                        KCoreLambda([ wrapperParameter ], wrapperBody),
                                        clause.Body
                                    ) }
                        | None ->
                            clause

                    let driverParameter =
                        { Name = compName
                          Quantity = None
                          IsImplicit = false
                          Type = handledBodyType
                          TypeText = handledBodyType |> Option.map TypeSignatures.toText }

                    let driverBody =
                        KCoreHandle(
                            false,
                            loweredLabel,
                            KCoreName [ compName ],
                            loweredReturnClause,
                            loweredOperationClauses |> List.map lowerDeepClause
                        )

                    KCoreLet(
                        goName,
                        KCoreLambda([ driverParameter ], driverBody),
                        KCoreAppSpine(KCoreName [ goName ], [ explicitKCoreArgument loweredBody ])
                    )
            | KindQualifiedName _ ->
                tryResolveScopedStaticObject environment expression
                |> Option.map lowerStaticObject
                |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
            | Name [ bindingName ]
                when not (Map.containsKey bindingName localTypes)
                     && environment.VisibleBindings.ContainsKey(bindingName) ->
                let bindingInfo = environment.VisibleBindings[bindingName]
                match
                    tryPrepareVisibleBindingCall
                        environment
                        freshCounter
                        bindingInfo
                        (Some localTypes)
                        (inferExpressionType localTypes)
                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                        []
                with
                | Some preparedCall when not (List.isEmpty preparedCall.Arguments) ->
                    KCoreAppSpine(KCoreName [ bindingName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                | _ ->
                    KCoreName [ bindingName ]
            | Name [ bindingName ]
                when not (Map.containsKey bindingName localTypes) ->
                match tryFindScopedEffectDeclaration bindingName with
                | Some declaration ->
                    scopedKCoreEffectLabel declaration
                | None ->
                    match tryResolveScopedStaticObject environment expression with
                    | Some staticObject ->
                        lowerStaticObject staticObject
                    | None ->
                        KCoreName [ bindingName ]
            | Name [ bindingName ] ->
                KCoreName [ bindingName ]
            | Name (receiverName :: path) when not (List.isEmpty path) ->
                match tryResolveScopedStaticObject environment expression with
                | Some staticObject when staticObject.ObjectKind = StaticEffectLabelObject ->
                    lowerStaticObject staticObject
                | Some _
                | None ->
                    match tryResolveEffectOperationNamePath environment (receiverName :: path) with
                    | Some(effectName, declaration, operation) ->
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        )
                    | None ->
                        match path with
                        | [ operationName ] ->
                            match tryFindScopedEffectOperation receiverName operationName with
                            | Some(declaration, operation) ->
                                KCoreEffectOperation(
                                    scopedKCoreEffectLabel declaration,
                                    operation.OperationId,
                                    operation.Name
                                )
                            | None ->
                                let loweredReceiver = lowerExpression localTypes (Name [ receiverName ])

                                let recordProjection =
                                    inferExpressionType localTypes (Name [ receiverName ])
                                    |> Option.bind (fun receiverType ->
                                        tryLowerRecordProjectionPath localTypes loweredReceiver receiverType path)

                                match tryResolveStaticConstructor environment (Name [ receiverName ]) operationName with
                                | Some _ ->
                                    lowerStaticConstructorCallee (Name [ receiverName ]) operationName
                                | None ->
                                    match tryReceiverProjection environment localTypes receiverName operationName with
                                    | Some _ ->
                                        KCoreAppSpine(KCoreName [ operationName ], [ explicitKCoreArgument loweredReceiver ])
                                    | None ->
                                        recordProjection
                                        |> Option.defaultValue (KCoreName [ receiverName; operationName ])
                        | _ ->
                            let loweredReceiver = lowerExpression localTypes (Name [ receiverName ])

                            let recordProjection =
                                inferExpressionType localTypes (Name [ receiverName ])
                                |> Option.bind (fun receiverType ->
                                    tryLowerRecordProjectionPath localTypes loweredReceiver receiverType path)

                            recordProjection
                            |> Option.defaultValue (KCoreName(receiverName :: path))
            | Name segments ->
                KCoreName segments
            | LocalSignature(_, body) ->
                lowerExpressionWithExpectedType localTypes expectedType body
            | LocalTypeAlias(_, body) ->
                lowerExpressionWithExpectedType localTypes expectedType body
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let bindingNames = collectPatternNames binding.Pattern
                let bindingExpectedType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)

                let valueLocals =
                    match binding.Pattern, bindingExpectedType, value with
                    | NamePattern bindingName, Some declaredType, Lambda _ ->
                        Map.add bindingName declaredType localTypes
                    | _ ->
                        localTypes

                let loweredValue =
                    match binding.Pattern, value with
                    | NamePattern bindingName, Lambda(lambdaParameters, lambdaBody) ->
                        lowerLambdaExpression
                            valueLocals
                            (tryInferSeededLambdaParameterTypes bindingName lambdaParameters body)
                            lambdaParameters
                            lambdaBody
                    | _ ->
                        lowerExpressionWithExpectedType valueLocals bindingExpectedType value
                let bodyForLowering =
                    match bindingNames, tryResolveScopedStaticObject environment value with
                    | [ aliasName ], Some staticObject ->
                        rewriteStaticObjectAliasUse aliasName staticObject body
                    | [ aliasName ], _ ->
                        match value with
                        | Name [ targetName ]
                            when (environment.VisibleBindings
                                  |> Map.tryFind targetName
                                  |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind targetName))
                                 |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts)
                                 |> Option.isSome ->
                            rewriteDirectAliasUse aliasName targetName body
                        | Lambda(parameters, _) ->
                            rewriteNamedApplicationAliasUse aliasName parameters body
                        | _ ->
                            body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases environment binding.Pattern value
                let bodyForLowering = rewriteStaticObjectPathAliasUses localStaticAliases bodyForLowering
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForLowering = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForLowering

                let valueType = bindingExpectedType |> Option.orElseWith (fun () -> inferExpressionType valueLocals value)

                lowerPatternBinding
                    localTypes
                    valueType
                    binding
                    loweredValue
                    (fun loweredLocals -> lowerExpression loweredLocals bodyForLowering)
            | LocalScopedEffect(declaration, body) ->
                withScopedEffectDeclaration declaration (fun () -> lowerExpressionWithExpectedType localTypes expectedType body)
            | Lambda(lambdaParameters, lambdaBody) ->
                lowerLambdaExpression localTypes None lambdaParameters lambdaBody
            | IfThenElse(condition, whenTrue, whenFalse) ->
                KCoreIfThenElse(
                    lowerExpressionWithExpectedType localTypes None condition,
                    lowerExpressionWithExpectedType localTypes expectedType whenTrue,
                    lowerExpressionWithExpectedType localTypes expectedType whenFalse
                )
            | Match(scrutinee, cases) ->
                let scrutineeType = inferExpressionType localTypes scrutinee

                let loweredCases : KCoreMatchCase list =
                    cases
                    |> List.collect (fun caseClause ->
                        let alternatives =
                            match caseClause.Pattern with
                            | OrPattern options -> options
                            | other -> [ other ]

                        alternatives
                        |> List.map (fun pattern ->
                            let caseLocals =
                                extendPatternLocalTypes environment freshCounter localTypes scrutineeType pattern

                            ({ Pattern = lowerPattern caseLocals scrutineeType pattern
                               Guard = caseClause.Guard |> Option.map (lowerExpression caseLocals)
                               Body = lowerExpression caseLocals caseClause.Body }
                             : KCoreMatchCase)))

                KCoreMatch(
                    lowerExpression localTypes scrutinee,
                    loweredCases
                )
            | RecordLiteral fields ->
                let inferredFields =
                    fields
                    |> List.map (fun field ->
                        inferExpressionType localTypes field.Value
                        |> Option.map (fun fieldType ->
                            { Name = field.Name
                              Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                              Type = fieldType }))

                if inferredFields |> List.forall Option.isSome then
                    let recordType = TypeRecord(inferredFields |> List.choose id)
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleName "<binding>" recordLayouts recordType

                    let fieldValues =
                        fields
                        |> List.map (fun field -> field.Name, field.Value)
                        |> Map.ofList

                    KCoreAppSpine(
                        KCoreName [ layout.ConstructorName ],
                        layout.Fields
                        |> List.map (fun field ->
                            fieldValues
                            |> Map.tryFind field.Name
                            |> Option.map (lowerExpression localTypes >> explicitKCoreArgument)
                            |> Option.defaultValue (explicitKCoreArgument (KCoreLiteral LiteralValue.Unit)))
                    )
                else
                    KCoreLiteral LiteralValue.Unit
            | Seal(value, _) ->
                lowerExpressionWithExpectedType localTypes expectedType value
            | RecordUpdate(receiver, fields) ->
                let loweredReceiver = lowerExpression localTypes receiver

                match inferExpressionType localTypes receiver |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some recordType ->
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleName "<binding>" recordLayouts recordType

                    let boundFields =
                        layout.Fields
                        |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_record_{field.Name}_")

                    let receiverSegments =
                        match receiver with
                        | Name segments -> Some segments
                        | _ -> None

                    let ordinaryUpdateValue topLevelName (group: SurfaceRecordUpdateField list) =
                        match group |> List.tryFind (fun field -> List.length field.Path = 1) with
                        | Some directField ->
                            directField.Value
                        | None ->
                            match receiverSegments with
                            | Some segments ->
                                let nestedFields =
                                    group
                                    |> List.choose (fun field ->
                                        match field.Path with
                                        | _ :: child :: rest ->
                                            Some
                                                { field with
                                                    Name = child.Name
                                                    IsImplicit = child.IsImplicit
                                                    IsExtension = false
                                                    Path = child :: rest }
                                        | _ ->
                                            None)

                                RecordUpdate(Name(segments @ [ topLevelName ]), nestedFields)
                            | None ->
                                group
                                |> List.tryHead
                                |> Option.map (fun field -> field.Value)
                                |> Option.defaultValue (Literal LiteralValue.Unit)

                    let updatedFields =
                        fields
                        |> List.filter (fun field -> not field.IsExtension)
                        |> List.groupBy (fun field -> field.Name)
                        |> List.map (fun (name, group) -> name, ordinaryUpdateValue name group)
                        |> Map.ofList

                    let pattern =
                        KCoreConstructorPattern(
                            [ layout.ConstructorName ],
                            boundFields
                            |> List.map (fun (_, bindingName) -> KCoreNamePattern bindingName)
                        )

                    let rebuiltFields =
                        layout.Fields
                        |> List.map (fun field ->
                            updatedFields
                            |> Map.tryFind field.Name
                            |> Option.map (lowerExpression localTypes)
                            |> Option.defaultValue (
                                boundFields
                                |> List.find (fun (name, _) -> String.Equals(name, field.Name, StringComparison.Ordinal))
                                |> snd
                                |> fun bindingName -> KCoreName [ bindingName ]))

                    KCoreMatch(
                        loweredReceiver,
                        [
                            { Pattern = pattern
                              Guard = None
                              Body =
                                KCoreAppSpine(
                                    KCoreName [ layout.ConstructorName ],
                                    rebuiltFields |> List.map explicitKCoreArgument
                                ) }
                        ]
                    )
                | None ->
                    loweredReceiver
            | MemberAccess(receiver, segments, arguments) ->
                match segments with
                | [] ->
                    KCoreAppSpine(lowerExpression localTypes receiver, lowerArguments arguments)
                | [ memberName ] ->
                    match
                        tryResolveHandledEffectDeclaration environment receiver
                        |> Option.bind (fun declaration ->
                            EffectSemantics.tryFindOperation memberName declaration
                            |> Option.map (fun operation -> declaration.VisibleName, declaration, operation))
                    with
                    | Some(effectName, declaration, operation) ->
                        let loweredOperation =
                            KCoreEffectOperation(
                                scopedKCoreEffectLabel declaration,
                                operation.OperationId,
                                operation.Name
                            )

                        if List.isEmpty arguments then
                            loweredOperation
                        else
                            KCoreAppSpine(loweredOperation, lowerArguments arguments)
                    | None ->
                        match tryResolveStaticConstructor environment receiver memberName with
                        | Some _ ->
                            KCoreAppSpine(lowerStaticConstructorCallee receiver memberName, lowerArguments arguments)
                        | None ->
                            match environment.VisibleBindings |> Map.tryFind memberName with
                            | Some bindingInfo ->
                                match tryBuildReceiverMethodArguments bindingInfo receiver arguments with
                                | Some receiverArguments ->
                                    match
                                        tryPrepareVisibleBindingCall
                                            environment
                                            freshCounter
                                            bindingInfo
                                            (Some localTypes)
                                            (inferExpressionType localTypes)
                                            (tryResolveUniqueLocalImplicitByType environment localTypes)
                                            receiverArguments
                                    with
                                    | Some preparedCall ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                                    | None ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerArguments receiverArguments)
                                | None ->
                                    if List.isEmpty arguments then
                                        KCoreName [ memberName ]
                                    else
                                        KCoreAppSpine(KCoreName [ memberName ], lowerArguments arguments)
                            | None ->
                                let loweredReceiver = lowerExpression localTypes receiver

                                match inferExpressionType localTypes receiver with
                                | Some receiverType ->
                                    tryLowerRecordProjectionPath localTypes loweredReceiver receiverType [ memberName ]
                                    |> Option.map (fun projected ->
                                        if List.isEmpty arguments then
                                            projected
                                        else
                                            KCoreAppSpine(projected, lowerArguments arguments))
                                    |> Option.defaultValue (KCoreName [ memberName ])
                                | None ->
                                    KCoreName [ memberName ]
                | memberName :: rest ->
                    lowerExpression localTypes (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))
            | SafeNavigation(receiver, navigation) ->
                let loweredReceiver = lowerExpression localTypes receiver
                let binderName = freshSyntheticName "__kappa_safe_"

                let loweredMember =
                    let callee = KCoreName(binderName :: navigation.Segments)

                    match navigation.Arguments with
                    | [] ->
                        callee
                    | arguments ->
                        KCoreAppSpine(callee, arguments |> List.map (lowerExpression localTypes >> explicitKCoreArgument))

                let wrapsResult =
                    inferExpressionType localTypes receiver
                    |> Option.bind (fun receiverType ->
                        tryOptionPayloadType environment.VisibleTypeAliases receiverType
                        |> Option.bind (fun payloadType ->
                            tryInferSafeNavigationMemberType
                                environment.VisibleTypeAliases
                                (qualifyVisibleTypeNames environment)
                                (inferExpressionType localTypes)
                                payloadType
                                navigation))
                    |> Option.bind (tryOptionPayloadType environment.VisibleTypeAliases)
                    |> Option.isNone

                let successBody =
                    if wrapsResult then
                        KCoreAppSpine(KCoreName [ "Some" ], [ explicitKCoreArgument loweredMember ])
                    else
                        loweredMember

                KCoreMatch(
                    loweredReceiver,
                    [
                        { Pattern = KCoreConstructorPattern([ "Some" ], [ KCoreNamePattern binderName ])
                          Guard = None
                          Body = successBody }
                        { Pattern = KCoreConstructorPattern([ "None" ], [])
                          Guard = None
                          Body = KCoreName [ "None" ] }
                    ]
                )
            | TagTest(receiver, constructorName) ->
                KCoreBinary(lowerExpression localTypes receiver, "is", KCoreName constructorName)
            | Do statements ->
                match
                    expectedType |> Option.bind tryUnwrapEffType |> Option.isSome
                    || hasEffectfulDoFlow localTypes statements
                with
                | true ->
                    match tryLowerEffectfulDoStatements localTypes statements with
                    | Some loweredEffectBody ->
                        loweredEffectBody
                    | None ->
                        let scopeLabel = freshDoScopeLabel ()
                        KCoreDoScope(scopeLabel, lowerDoStatements scopeLabel localTypes statements)
                | false ->
                    let scopeLabel = freshDoScopeLabel ()
                    KCoreDoScope(scopeLabel, lowerDoStatements scopeLabel localTypes statements)
            | MonadicSplice inner ->
                KCoreExecute(lowerExpressionWithExpectedType localTypes None inner)
            | ExplicitImplicitArgument inner ->
                lowerExpressionWithExpectedType localTypes None inner
            | NamedApplicationBlock _ ->
                KCoreLiteral LiteralValue.Unit
            | InoutArgument inner ->
                lowerExpressionWithExpectedType localTypes None inner
            | Apply _ as application when tryMatchQueryCarrierShape application |> Option.isSome ->
                let carrier = tryMatchQueryCarrierShape application |> Option.get
                lowerExpressionWithExpectedType localTypes expectedType carrier.Comprehension.Lowered
            | Apply(Name [ receiverName; memberName ], arguments) ->
                match tryResolveEffectOperationNamePath environment [ receiverName; memberName ] with
                | Some(effectName, declaration, operation) ->
                    KCoreAppSpine(
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        ),
                        lowerArguments arguments
                    )
                | None ->
                    match tryResolveStaticConstructor environment (Name [ receiverName ]) memberName with
                    | Some _ ->
                        KCoreAppSpine(lowerStaticConstructorCallee (Name [ receiverName ]) memberName, lowerArguments arguments)
                    | None ->
                        match tryResolveTraitMemberProjection environment localTypes [ receiverName; memberName ] with
                        | Some(traitInfo, resolvedMemberName, _, resolvedReceiverName) ->
                                KCoreTraitCall(
                                    traitInfo.Name,
                                    resolvedMemberName,
                                    lowerExpressionWithExpectedType localTypes None (Name [ resolvedReceiverName ]),
                                    lowerArgumentExpressions arguments
                                )
                        | None ->
                            match environment.VisibleBindings |> Map.tryFind memberName with
                            | Some bindingInfo ->
                                match tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments with
                                | Some receiverArguments ->
                                    match
                                        tryPrepareVisibleBindingCall
                                            environment
                                            freshCounter
                                            bindingInfo
                                            (Some localTypes)
                                            (inferExpressionType localTypes)
                                            (tryResolveUniqueLocalImplicitByType environment localTypes)
                                            receiverArguments
                                    with
                                    | Some preparedCall ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                                    | None ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerArguments receiverArguments)
                                | None ->
                                    KCoreAppSpine(lowerExpression localTypes (Name [ receiverName; memberName ]), lowerArguments arguments)
                            | None ->
                                KCoreAppSpine(lowerExpression localTypes (Name [ receiverName; memberName ]), lowerArguments arguments)
            | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
                match tryResolveStaticConstructor environment receiver memberName with
                | Some _ ->
                    KCoreAppSpine(lowerStaticConstructorCallee receiver memberName, lowerArguments arguments)
                | None ->
                    KCoreAppSpine(
                        lowerExpressionWithExpectedType localTypes None (MemberAccess(receiver, [ memberName ], [])),
                        lowerArguments arguments
                    )
            | Apply(Name nameSegments, arguments) ->
                match tryResolveEffectOperationNamePath environment nameSegments with
                | Some(effectName, declaration, operation) ->
                    KCoreAppSpine(
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        ),
                        lowerArguments arguments
                    )
                | None ->
                    match tryResolveTraitMemberProjection environment localTypes nameSegments with
                    | Some(traitInfo, memberName, _, receiverName) ->
                        KCoreTraitCall(
                            traitInfo.Name,
                            memberName,
                            lowerExpressionWithExpectedType localTypes None (Name [ receiverName ]),
                            lowerArgumentExpressions arguments
                        )
                    | None ->
                        match nameSegments with
                        | [ calleeName ]
                            when not (Map.containsKey calleeName localTypes)
                                 && not (Map.containsKey calleeName environment.VisibleBindings)
                                 && environment.ConstrainedMembers.ContainsKey calleeName ->
                            let traitName, dictionaryParameterName = environment.ConstrainedMembers[calleeName]

                            KCoreTraitCall(
                                traitName,
                                calleeName,
                                KCoreName [ dictionaryParameterName ],
                                lowerArgumentExpressions arguments
                            )
                        | [ calleeName ] when environment.VisibleConstructors.ContainsKey calleeName ->
                            let constructorInfo = environment.VisibleConstructors[calleeName]
                            match
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    constructorInfo
                                    (Some localTypes)
                                    (inferExpressionType localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    arguments
                            with
                            | Some preparedCall ->
                                KCoreAppSpine(
                                    KCoreName [ calleeName ],
                                    lowerPreparedBindingCallArguments constructorInfo preparedCall
                                )
                            | None ->
                                KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | [ calleeName ] when environment.VisibleBindings.ContainsKey calleeName ->
                            let bindingInfo = environment.VisibleBindings[calleeName]
                            let preferredTraitDispatch =
                                if IntrinsicCatalog.prefersTraitDispatchForNonBuiltinInstances bindingInfo.ModuleName calleeName then
                                    let tryPrepareLocalDictionaryTraitDispatch () =
                                        environment.ConstrainedMembers
                                        |> Map.tryFind calleeName
                                        |> Option.bind (fun (traitName, dictionaryParameterName) ->
                                            environment.VisibleTraits
                                            |> Map.tryFind traitName
                                            |> Option.bind (fun traitInfo ->
                                                traitInfo.Members
                                                |> Map.tryFind calleeName
                                                |> Option.bind (fun memberInfo ->
                                                    let probeCounter = ref freshCounter.Value

                                                    let overloadedScheme =
                                                        { memberInfo.Scheme with
                                                            Constraints =
                                                                { TraitName = traitInfo.Name
                                                                  Arguments = traitInfo.TypeParameters |> List.map TypeVariable }
                                                                :: memberInfo.Scheme.Constraints }

                                                    let memberBindingInfo =
                                                        { ModuleName = traitInfo.ModuleName
                                                          Name = calleeName
                                                          IsPattern = false
                                                          Scheme = overloadedScheme
                                                          TypeTokens = []
                                                          ParameterLayouts = None
                                                          ConstructorTypeName = None
                                                          DefaultArguments = Map.empty }

                                                    tryPrepareVisibleBindingCall
                                                        environment
                                                        probeCounter
                                                        memberBindingInfo
                                                        None
                                                        (inferExpressionType localTypes)
                                                        noLocalImplicit
                                                        arguments
                                                    |> Option.bind (fun preparedCall ->
                                                        match preparedCall.InstantiatedScheme.Constraints with
                                                        | owningConstraint :: []
                                                            when String.Equals(owningConstraint.TraitName, traitInfo.Name, StringComparison.Ordinal) ->
                                                            freshCounter.Value <- probeCounter.Value

                                                            Some(
                                                                KCoreTraitCall(
                                                                    traitInfo.Name,
                                                                    calleeName,
                                                                    KCoreName [ dictionaryParameterName ],
                                                                    lowerPreparedArgumentExpressions preparedCall.Arguments
                                                                )
                                                            )
                                                        | _ ->
                                                            None))))

                                    tryPrepareLocalDictionaryTraitDispatch ()
                                    |> Option.orElseWith (fun () ->
                                        let probeCounter = ref freshCounter.Value

                                        tryPrepareVisibleTraitMemberCall
                                            environment
                                            probeCounter
                                            calleeName
                                            (inferExpressionType localTypes)
                                            arguments
                                        |> Option.bind (fun (traitInfo, _, preparedCall, instanceInfo) ->
                                            if String.Equals(instanceInfo.ModuleName, Stdlib.PreludeModuleText, StringComparison.Ordinal)
                                               && instanceInfo.InstanceKey.StartsWith("builtin-prelude:", StringComparison.Ordinal) then
                                                None
                                            else
                                                freshCounter.Value <- probeCounter.Value

                                                Some(
                                                    KCoreTraitCall(
                                                        traitInfo.Name,
                                                        calleeName,
                                                        lowerResolvedOwningDictionaryValue
                                                            environment
                                                            traitInfo.Name
                                                            preparedCall
                                                            instanceInfo,
                                                        lowerPreparedArgumentExpressions preparedCall.Arguments
                                                    )
                                                )))
                                else
                                    None

                            match preferredTraitDispatch with
                            | Some traitCall ->
                                traitCall
                            | None ->
                                match
                                    tryPrepareVisibleBindingCall
                                        environment
                                        freshCounter
                                        bindingInfo
                                        (Some localTypes)
                                        (inferExpressionType localTypes)
                                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                                        arguments
                                with
                                | Some preparedCall ->
                                    let dictionaryArguments =
                                        preparedCall.InstantiatedScheme.Constraints
                                        |> List.choose (fun constraintInfo ->
                                            tryLowerResolvedDictionaryValue environment constraintInfo
                                            |> Option.map explicitKCoreArgument)
                                        |> eraseIntrinsicPreludeDictionaryArguments bindingInfo

                                    KCoreAppSpine(
                                        KCoreName [ calleeName ],
                                        dictionaryArguments @ lowerPreparedBindingCallArguments bindingInfo preparedCall
                                    )
                                | None ->
                                    KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | [ calleeName ] ->
                            match
                                tryPrepareVisibleTraitMemberCall
                                    environment
                                    freshCounter
                                    calleeName
                                    (inferExpressionType localTypes)
                                    arguments
                            with
                            | Some(traitInfo, _, preparedCall, instanceInfo) ->
                                KCoreTraitCall(
                                    traitInfo.Name,
                                    calleeName,
                                    lowerResolvedOwningDictionaryValue
                                        environment
                                        traitInfo.Name
                                        preparedCall
                                        instanceInfo,
                                    lowerPreparedArgumentExpressions preparedCall.Arguments
                                )
                            | None ->
                                KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | _ ->
                            KCoreAppSpine(lowerExpression localTypes (Name nameSegments), lowerArguments arguments)
            | Apply(callee, arguments) ->
                KCoreAppSpine(lowerExpressionWithExpectedType localTypes None callee, lowerArguments arguments)
            | Unary(operatorName, operand) ->
                let operandExpectedType =
                    if operatorName = "-" || operatorName = "negate" then expectedType else None

                KCoreUnary(operatorName, lowerExpressionWithExpectedType localTypes operandExpectedType operand)
            | Binary(left, operatorName, right) ->
                KCoreBinary(lowerExpression localTypes left, operatorName, lowerExpression localTypes right)
            | Elvis(left, right) ->
                let binderName = freshSyntheticName "__kappa_elvis_"

                KCoreMatch(
                    lowerExpression localTypes left,
                    [
                        { Pattern = KCoreConstructorPattern([ "Some" ], [ KCoreNamePattern binderName ])
                          Guard = None
                          Body = KCoreName [ binderName ] }
                        { Pattern = KCoreConstructorPattern([ "None" ], [])
                          Guard = None
                          Body = lowerExpression localTypes right }
                    ]
                )
            | PrefixedString(prefix, parts) ->
                lowerPrefixedString prefix parts

        let localTypes =
            (buildLocalTypes scheme parameters, extraLocalTypes)
            ||> List.fold (fun state (name, parameterType) -> Map.add name parameterType state)

        let bodyForLowering =
            match parameters, scheme, body with
            | [], Some scheme, Lambda(lambdaParameters, lambdaBody) ->
                let parameterTypes, _ = TypeSignatures.schemeParts scheme

                if List.length parameterTypes = List.length lambdaParameters then
                    let annotatedParameters =
                        List.zip lambdaParameters parameterTypes
                        |> List.map (fun (parameter, parameterType) ->
                            if parameter.TypeTokens.IsSome then
                                parameter
                            else
                                { parameter with
                                    TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })

                    Lambda(annotatedParameters, lambdaBody)
                else
                    body
            | _ ->
                body

        lowerExpressionWithExpectedType localTypes (lowerBindingReturnTypeExpr scheme parameters None) bodyForLowering

    let private lowerUserBinding
        (environment: BindingLoweringEnvironment)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (moduleTopLevelDefinitionsByName: Map<string, LetDefinition>)
        (filePath: string)
        (moduleName: string)
        (definition: LetDefinition)
        (sourceSignature: BindingSignature option)
        (bindingInfo: BindingSchemeInfo option)
        =
        let sourceSignatureScheme =
            sourceSignature
            |> Option.bind (fun declaration -> TypeSignatures.parseScheme declaration.TypeTokens)

        let sourceSignatureParameterLayouts =
            sourceSignature
            |> Option.bind (fun declaration ->
                declaration.TypeTokens
                |> splitSignatureParameterTokens
                |> function
                    | [] -> None
                    | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout))

        let scheme =
            sourceSignatureScheme
            |> Option.orElseWith (fun () -> bindingInfo |> Option.map (fun info -> info.Scheme))

        let synthesizedOmittedImplicitParameters =
            let isAnonymousSignatureLayoutName name =
                String.IsNullOrWhiteSpace name
                || String.Equals(name, "_", StringComparison.Ordinal)
                || name.StartsWith("__kappa_signature_wildcard_", StringComparison.Ordinal)

            let signatureLayoutMatchesExplicitParameter (layout: Parameter) (explicitParameter: Parameter) =
                layout.IsImplicit = explicitParameter.IsImplicit
                && layout.IsInout = explicitParameter.IsInout
                && layout.IsReceiver = explicitParameter.IsReceiver
                &&
                (if isAnonymousSignatureLayoutName layout.Name then
                     true
                 else
                     String.Equals(layout.Name, explicitParameter.Name, StringComparison.Ordinal))

            let synthesizeParameter (layout: Parameter) parameterType synthesizedIndex : Parameter =
                let parameterName =
                    if String.IsNullOrWhiteSpace layout.Name
                       || String.Equals(layout.Name, "_", StringComparison.Ordinal)
                       || layout.Name.StartsWith("__kappa_signature_wildcard_", StringComparison.Ordinal) then
                        $"__kappa_implicit_{synthesizedIndex}"
                    else
                        layout.Name

                { Name = parameterName
                  TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType))
                  Quantity = layout.Quantity
                  IsImplicit = true
                  IsInout = layout.IsInout
                  IsReceiver = layout.IsReceiver }

            let synthesizeImplicitParameter parameterType synthesizedIndex : Parameter =
                synthesizeParameter
                    { Name = $"__kappa_implicit_{synthesizedIndex}"
                      TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType))
                      Quantity = None
                      IsImplicit = true
                      IsInout = false
                      IsReceiver = false }
                    parameterType
                    synthesizedIndex

            let synthesizedFromSchemePrefix =
                match scheme with
                | Some bindingScheme ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme
                    let omittedLeadingCount = parameterTypes.Length - definition.Parameters.Length

                    if omittedLeadingCount <= 0 then
                        []
                    else
                        parameterTypes
                        |> List.take omittedLeadingCount
                        |> List.mapi (fun index parameterType ->
                            if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                None
                            elif tryTraitConstraintFromType environment parameterType |> Option.isSome then
                                Some(synthesizeImplicitParameter parameterType index)
                            else
                                None)
                        |> List.choose id
                | None ->
                    []

            let synthesizedFromSignatureLayouts =
                match scheme, sourceSignatureParameterLayouts with
                | Some bindingScheme, Some signatureLayouts ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                    if List.length signatureLayouts <> List.length parameterTypes then
                        []
                    else
                        let rec collectOmitted
                            (layouts: Parameter option list)
                            (types: TypeExpr list)
                            (explicitParameters: Parameter list)
                            (synthesized: Parameter list)
                            synthesizedIndex
                            =
                            match layouts, types with
                            | layoutOpt :: restLayouts, parameterType :: restTypes ->
                                match layoutOpt, explicitParameters with
                                | Some layout, explicitParameter :: restExplicit
                                    when signatureLayoutMatchesExplicitParameter layout explicitParameter ->
                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        restExplicit
                                        synthesized
                                        synthesizedIndex
                                | Some layout, _
                                    when layout.IsImplicit
                                         && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) ->
                                    let synthesizedParameter = synthesizeParameter layout parameterType synthesizedIndex

                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        explicitParameters
                                        (synthesizedParameter :: synthesized)
                                        (synthesizedIndex + 1)
                                | Some _, _ :: restExplicit ->
                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        restExplicit
                                        synthesized
                                        synthesizedIndex
                                | Some _, [] ->
                                    collectOmitted restLayouts restTypes [] synthesized synthesizedIndex
                                | None, _ :: restExplicit ->
                                    collectOmitted restLayouts restTypes restExplicit synthesized synthesizedIndex
                                | None, [] ->
                                    collectOmitted restLayouts restTypes [] synthesized synthesizedIndex
                            | _ ->
                                List.rev synthesized

                        collectOmitted signatureLayouts parameterTypes definition.Parameters [] 0
                | _, _ ->
                    []

            match scheme, sourceSignatureParameterLayouts |> Option.orElseWith (fun () -> bindingInfo |> Option.bind (fun info -> info.ParameterLayouts |> Option.map (List.map Some))) with
            | Some bindingScheme, Some parameterLayouts ->
                let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                let resolvedParameterLayouts =
                    if parameterLayouts |> List.forall Option.isSome then
                        Some(parameterLayouts |> List.choose id)
                    else
                        None

                match resolvedParameterLayouts |> Option.bind (fun layouts -> tryAlignParameterTypesWithLayouts environment layouts parameterTypes) with
                | Some(alignedParameterTypes, _) ->
                    let synthesized =
                        if List.isEmpty synthesizedFromSignatureLayouts then
                            let rec collectOmitted
                                (layouts: Parameter list)
                                alignedTypes
                                (explicitParameters: Parameter list)
                                (synthesized: Parameter list)
                                synthesizedIndex
                                =
                                match layouts, alignedTypes with
                                | layout :: restLayouts, parameterType :: restTypes ->
                                    let nextExplicitParameter =
                                        explicitParameters |> List.tryHead

                                    let matchesExplicitParameter =
                                        nextExplicitParameter
                                        |> Option.exists (fun explicitParameter ->
                                            signatureLayoutMatchesExplicitParameter layout explicitParameter)

                                    if matchesExplicitParameter then
                                        collectOmitted restLayouts restTypes (explicitParameters |> List.tail) synthesized synthesizedIndex
                                    elif layout.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                                        let synthesizedParameter = synthesizeParameter layout parameterType synthesizedIndex

                                        collectOmitted
                                            restLayouts
                                            restTypes
                                            explicitParameters
                                            (synthesizedParameter :: synthesized)
                                            (synthesizedIndex + 1)
                                    elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        collectOmitted restLayouts restTypes explicitParameters synthesized synthesizedIndex
                                    else
                                        List.rev synthesized
                                | _ ->
                                    List.rev synthesized

                            collectOmitted (resolvedParameterLayouts.Value) alignedParameterTypes definition.Parameters [] 0
                        else
                            synthesizedFromSignatureLayouts

                    if List.isEmpty synthesized then
                        synthesizedFromSchemePrefix
                    else
                        synthesized
                | None ->
                    if List.isEmpty synthesizedFromSignatureLayouts then
                        synthesizedFromSchemePrefix
                    else
                        synthesizedFromSignatureLayouts
            | _, _ ->
                if List.isEmpty synthesizedFromSignatureLayouts then
                    synthesizedFromSchemePrefix
                else
                    synthesizedFromSignatureLayouts

        let effectiveDefinitionParameters =
            synthesizedOmittedImplicitParameters @ definition.Parameters

        let constrainedMembers, hiddenParameters =
            match scheme with
            | Some scheme ->
                let memberEntries =
                    scheme.Constraints
                    |> List.mapi (fun index constraintInfo ->
                        let dictionaryParameterName = $"__kappa_dict_{constraintInfo.TraitName}_{index}"
                        constraintInfo, dictionaryParameterName)

                let schemeConstrainedMembers =
                    if List.isEmpty scheme.Constraints then
                        Map.empty
                    else
                        buildConstrainedMembers environment scheme.Constraints

                let parameterConstrainedMembers =
                    buildParameterConstrainedMembers environment scheme effectiveDefinitionParameters

                let constrainedMembers =
                    parameterConstrainedMembers
                    |> Map.fold (fun state memberName route ->
                        if Map.containsKey memberName state then
                            state
                        else
                            Map.add memberName route state) schemeConstrainedMembers

                constrainedMembers, memberEntries
            | _ ->
                Map.empty, []

        let constraintDictionaries =
            match scheme with
            | Some currentScheme ->
                let schemeConstraintDictionaries =
                    hiddenParameters
                    |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                        constraintInfo, KCoreName [ dictionaryParameterName ])
                    |> buildConstraintDictionaries environment

                let parameterConstraintDictionaries =
                    buildParameterConstraintDictionaries environment currentScheme effectiveDefinitionParameters

                parameterConstraintDictionaries
                |> Map.fold (fun state key value ->
                    if Map.containsKey key state then
                        state
                    else
                        Map.add key value state) schemeConstraintDictionaries
            | None ->
                Map.empty

        let bodyEnvironment =
            { environment with
                ConstraintDictionaries = constraintDictionaries
                ConstrainedMembers = constrainedMembers }

        let hiddenParameters =
            hiddenParameters
            |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    true
                    (Some(dictionaryType constraintInfo.TraitName constraintInfo.Arguments)))

        let tryInferLambdaParameterTypesFromTopLevelCalls (lambdaParameters: Parameter list) =
            definition.Name
            |> Option.bind (fun bindingName ->
                let inferArgumentType argument =
                    inferValidationExpressionType bodyEnvironment (ref 0) Map.empty argument

                let rec findCall expression =
                    match expression with
                    | Apply(Name [ calleeName ], arguments)
                        when String.Equals(calleeName, bindingName, StringComparison.Ordinal)
                             && List.length arguments = List.length lambdaParameters ->
                        let argumentTypes = arguments |> List.map inferArgumentType

                        if argumentTypes |> List.forall Option.isSome then
                            Some(argumentTypes |> List.choose id)
                        else
                            None
                    | Apply(callee, arguments) ->
                        findCall callee
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick findCall)
                    | LocalLet(_, value, body) ->
                        findCall value |> Option.orElseWith (fun () -> findCall body)
                    | LocalSignature(_, body)
                    | LocalTypeAlias(_, body)
                    | LocalScopedEffect(_, body)
                    | Lambda(_, body)
                    | SyntaxQuote body
                    | SyntaxSplice body
                    | TopLevelSyntaxSplice body
                    | CodeQuote body
                    | CodeSplice body
                    | MonadicSplice body
                    | ExplicitImplicitArgument body
                    | InoutArgument body
                    | Unary(_, body)
                    | Seal(body, _)
                    | TagTest(body, _) ->
                        findCall body
                    | TypeSyntaxTokens _ ->
                        None
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        findCall label
                        |> Option.orElseWith (fun () -> findCall body)
                        |> Option.orElseWith (fun () -> findCall returnClause.Body)
                        |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> findCall clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        findCall condition
                        |> Option.orElseWith (fun () -> findCall whenTrue)
                        |> Option.orElseWith (fun () -> findCall whenFalse)
                    | Match(scrutinee, cases) ->
                        findCall scrutinee
                        |> Option.orElseWith (fun () ->
                            cases
                            |> List.tryPick (fun caseClause ->
                                caseClause.Guard
                                |> Option.bind findCall
                                |> Option.orElseWith (fun () -> findCall caseClause.Body)))
                    | RecordLiteral fields ->
                        fields |> List.tryPick (fun field -> findCall field.Value)
                    | RecordUpdate(receiver, fields) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> findCall field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick findCall)
                    | SafeNavigation(receiver, navigation) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick findCall)
                    | Do statements ->
                        statements
                        |> List.tryPick (function
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                findCall value
                            | DoLetQuestion(_, value, failure) ->
                                findCall value
                                |> Option.orElseWith (fun () ->
                                    failure |> Option.bind (fun block -> block.Body |> List.tryPick (function
                                        | DoLet(_, nestedValue)
                                        | DoBind(_, nestedValue)
                                        | DoUsing(_, nestedValue)
                                        | DoVar(_, nestedValue)
                                        | DoAssign(_, nestedValue)
                                        | DoDefer nestedValue
                                        | DoExpression nestedValue
                                        | DoReturn nestedValue -> findCall nestedValue
                                        | _ -> None)))
                            | DoIf(condition, whenTrue, whenFalse) ->
                                findCall condition
                                |> Option.orElseWith (fun () -> whenTrue |> List.tryPick (fun statement ->
                                    match statement with
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None))
                                |> Option.orElseWith (fun () -> whenFalse |> List.tryPick (fun statement ->
                                    match statement with
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None))
                            | DoWhile(condition, body) ->
                                findCall condition
                                |> Option.orElseWith (fun () -> body |> List.tryPick (function
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None)))
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        findCall left |> Option.orElseWith (fun () -> findCall right)
                    | Comprehension comprehension ->
                        findCall comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.tryPick (function
                            | StringText _ -> None
                            | StringInterpolation(inner, _) -> findCall inner)
                    | NamedApplicationBlock fields ->
                        fields |> List.tryPick (fun field -> findCall field.Value)
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        None

                moduleTopLevelDefinitionsByName
                |> Map.toList
                |> List.filter (fun (candidateName, _) -> not (String.Equals(candidateName, bindingName, StringComparison.Ordinal)))
                |> List.tryPick (fun (_, candidateDefinition) ->
                    candidateDefinition.Body |> Option.bind findCall))

        let tryResolveManifestStaticFieldFromFunctionResult
            calleeName
            (arguments: SurfaceExpression list)
            fieldName
            =
            let rec tryResolveStaticValue parameterStaticObjects expression =
                match expression with
                | Name [ name ] ->
                    parameterStaticObjects
                    |> Map.tryFind name
                    |> Option.orElseWith (fun () -> tryResolveScopedStaticObject environment expression)
                | Seal(inner, _) ->
                    tryResolveStaticValue parameterStaticObjects inner
                | _ ->
                    tryResolveScopedStaticObject environment expression

            let rec tryResolveField parameterStaticObjects expression =
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                    |> Option.bind (fun field -> tryResolveStaticValue parameterStaticObjects field.Value)
                | Seal(inner, _) ->
                    tryResolveField parameterStaticObjects inner
                | _ ->
                    None

            moduleTopLevelDefinitionsByName
            |> Map.tryFind calleeName
            |> Option.bind (fun calleeDefinition ->
                if List.length calleeDefinition.Parameters <> List.length arguments then
                    None
                else
                    let parameterStaticObjects =
                        List.zip calleeDefinition.Parameters arguments
                        |> List.choose (fun (parameter, argument) ->
                            tryResolveScopedStaticObject environment argument
                            |> Option.map (fun staticObject -> parameter.Name, staticObject))
                        |> Map.ofList

                    calleeDefinition.Body
                    |> Option.bind (tryResolveField parameterStaticObjects))

        let rec rewriteManifestStaticFieldUses expression =
            let rewrite = rewriteManifestStaticFieldUses

            match expression with
            | MemberAccess(Apply(Name [ calleeName ], callArguments), [ fieldName ], [])
                when moduleTopLevelDefinitionsByName.ContainsKey(calleeName) ->
                match tryResolveManifestStaticFieldFromFunctionResult calleeName callArguments fieldName with
                | Some staticObject ->
                    Name staticObject.NameSegments
                | None ->
                    MemberAccess(
                        Apply(Name [ calleeName ], callArguments |> List.map rewrite),
                        [ fieldName ],
                        []
                    )
            | TypeSyntaxTokens _ ->
                expression
            | LocalLet(binding, value, body) ->
                LocalLet(binding, rewrite value, rewrite body)
            | LocalSignature(signature, body) ->
                LocalSignature(signature, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    { returnClause with Body = rewrite returnClause.Body },
                    operationClauses
                    |> List.map (fun clause ->
                        { clause with
                            Body = rewrite clause.Body })
                )
            | Lambda(parameters, body) ->
                Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewrite receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map rewrite }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteDoStatement statement =
                    match statement with
                    | DoLet(binding, inner) -> DoLet(binding, rewrite inner)
                    | DoLetQuestion(binding, inner, failure) ->
                        let rewrittenFailure =
                            failure
                            |> Option.map (fun block ->
                                { block with
                                    Body = block.Body |> List.map rewriteDoStatement })

                        DoLetQuestion(binding, rewrite inner, rewrittenFailure)
                    | DoBind(binding, inner) -> DoBind(binding, rewrite inner)
                    | DoVar(name, inner) -> DoVar(name, rewrite inner)
                    | DoAssign(name, inner) -> DoAssign(name, rewrite inner)
                    | DoUsing(binding, inner) -> DoUsing(binding, rewrite inner)
                    | DoDefer inner -> DoDefer(rewrite inner)
                    | DoIf(condition, whenTrue, whenFalse) ->
                        DoIf(rewrite condition, whenTrue |> List.map rewriteDoStatement, whenFalse |> List.map rewriteDoStatement)
                    | DoWhile(condition, body) ->
                        DoWhile(rewrite condition, body |> List.map rewriteDoStatement)
                    | DoReturn inner -> DoReturn(rewrite inner)
                    | DoExpression inner -> DoExpression(rewrite inner)

                Do(statements |> List.map rewriteDoStatement)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                expression

        let tryRewriteLegacyRecordDestructuringParameters
            (bindingScheme: TypeScheme)
            (parameters: Parameter list)
            (body: SurfaceExpression option)
            =
            let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

            match parameterTypes, parameters, body with
            | [ recordType ], firstParameter :: remainingParameters, Some body ->
                match normalizeTypeAliases environment.VisibleTypeAliases recordType with
                | TypeRecord fields when not (List.isEmpty fields) ->
                    let parameterCountMatches = List.length fields = List.length parameters
                    let collapsedLegacyRecordParameter = List.length parameters = 1 && List.length fields > 1

                    let trailingParametersMatchFieldTypes =
                        if parameterCountMatches then
                            remainingParameters
                            |> List.zip (fields |> List.skip 1)
                            |> List.forall (fun (field, parameter) ->
                                String.Equals(parameter.Name, field.Name, StringComparison.Ordinal)
                                && (parameter.TypeTokens
                                    |> Option.bind TypeSignatures.parseType
                                    |> Option.map (fun parameterType ->
                                        TypeSignatures.definitionallyEqual
                                            (normalizeTypeAliases environment.VisibleTypeAliases parameterType)
                                            (normalizeTypeAliases environment.VisibleTypeAliases field.Type))
                                    |> Option.defaultValue false))
                        else
                            false

                    let firstParameterMatchesFirstField =
                        String.Equals(firstParameter.Name, fields.Head.Name, StringComparison.Ordinal)

                    if not firstParameterMatchesFirstField
                       || not (collapsedLegacyRecordParameter || (parameterCountMatches && trailingParametersMatchFieldTypes)) then
                        None
                    else
                        let syntheticParameterName = "__kappa_record_param_0"
                        let recordTypeText = TypeSignatures.toText recordType

                        let syntheticParameter =
                            { Name = syntheticParameterName
                              TypeTokens = Some(typeTextTokens recordTypeText)
                              Quantity = None
                              IsImplicit = false
                              IsInout = false
                              IsReceiver = false }

                        let destructuringBinding =
                            { Pattern =
                                AnonymousRecordPattern(
                                    fields
                                    |> List.map (fun field ->
                                        { Name = field.Name
                                          IsImplicit = false
                                          Pattern = NamePattern field.Name }),
                                    None
                                )
                              Quantity = None
                              IsImplicit = false
                              TypeTokens = Some(typeTextTokens recordTypeText)
                              BinderSpans = Map.empty }

                        Some([ syntheticParameter ], Some(LocalLet(destructuringBinding, Name [ syntheticParameterName ], body)))
                | _ ->
                    None
            | _ ->
                None

        let rewrittenDefinitionBody =
            definition.Body
            |> Option.map (rewriteTopLevelManifestStaticFieldUses environment moduleTopLevelDefinitionsByName)

        let effectiveParameters, effectiveBody =
            match effectiveDefinitionParameters, rewrittenDefinitionBody, scheme with
            | parameters, body, Some bindingScheme ->
                match
                    tryRewriteLegacyRecordDestructuringParametersForBinding
                        environment.VisibleTypeAliases
                        bindingScheme
                        parameters
                        body
                with
                | Some rewritten ->
                    rewritten
                | None ->
                    match definition.Parameters, rewrittenDefinitionBody, scheme with
                    | [], Some(Lambda(lambdaParameters, lambdaBody)), bindingScheme ->
                        let callInferredParameterTypes =
                            if bindingScheme.IsSome then
                                None
                            else
                                tryInferLambdaParameterTypesFromTopLevelCalls lambdaParameters

                        let annotatedParameters =
                            match bindingScheme with
                            | Some bindingScheme ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                                if List.length parameterTypes = List.length lambdaParameters then
                                    lambdaParameters
                                    |> List.zip parameterTypes
                                    |> List.map (fun (parameterType, parameter) ->
                                        if parameter.TypeTokens.IsSome then
                                            parameter
                                        else
                                            { parameter with
                                                TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })
                                else
                                    lambdaParameters
                            | None ->
                                lambdaParameters
                                |> List.mapi (fun index parameter ->
                                    if parameter.TypeTokens.IsSome then
                                        parameter
                                    else
                                        match callInferredParameterTypes |> Option.bind (List.tryItem index) with
                                        | Some inferredType ->
                                            { parameter with
                                                TypeTokens = Some(typeTextTokens (TypeSignatures.toText inferredType)) }
                                        | None ->
                                            parameter)

                        annotatedParameters, Some lambdaBody
                    | _ ->
                        parameters, rewrittenDefinitionBody
            | [], Some(Lambda(lambdaParameters, lambdaBody)), bindingScheme ->
                let callInferredParameterTypes =
                    if bindingScheme.IsSome then
                        None
                    else
                        tryInferLambdaParameterTypesFromTopLevelCalls lambdaParameters

                let annotatedParameters =
                    match bindingScheme with
                    | Some bindingScheme ->
                        let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                        if List.length parameterTypes = List.length lambdaParameters then
                            lambdaParameters
                            |> List.zip parameterTypes
                            |> List.map (fun (parameterType, parameter) ->
                                if parameter.TypeTokens.IsSome then
                                    parameter
                                else
                                    { parameter with
                                        TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })
                        else
                            lambdaParameters
                    | None ->
                        lambdaParameters
                        |> List.mapi (fun index parameter ->
                            if parameter.TypeTokens.IsSome then
                                parameter
                            else
                                match callInferredParameterTypes |> Option.bind (List.tryItem index) with
                                | Some inferredType ->
                                    { parameter with
                                        TypeTokens = Some(typeTextTokens (TypeSignatures.toText inferredType)) }
                                | None ->
                                    parameter)

                annotatedParameters, Some lambdaBody
            | _ ->
                effectiveDefinitionParameters, rewrittenDefinitionBody

        let loweredBody =
            effectiveBody
            |> Option.map (lowerBindingBody bodyEnvironment recordLayouts scheme effectiveParameters [])

        let parameters =
            hiddenParameters @ buildBindingParameters environment.VisibleTypeAliases scheme effectiveParameters

        let provenance = declarationOrigin filePath moduleName (LetDeclaration definition)

        { Source = LetDeclaration definition
          Binding =
            Some
                { Visibility = definition.Visibility
                  IsOpaque = definition.IsOpaque
                  Name = definition.Name
                  Parameters = parameters
                  ReturnType = lowerBindingReturnTypeExpr scheme effectiveParameters definition.ReturnTypeTokens
                  ReturnTypeText = lowerBindingReturnType scheme effectiveParameters definition.ReturnTypeTokens
                  Body = loweredBody
                  BodyText = loweredBody |> Option.map (fun _ -> "")
                  Provenance = provenance }
          Provenance = provenance }

    let private synthesizeTraitDispatchBindings
        (filePath: string)
        (moduleName: string)
        (traitInfo: TraitInfo)
        =
        traitInfo.Members
        |> Map.toList
        |> List.map (fun (memberName, memberInfo) ->
            let parameterTypes, resultType = TypeSignatures.schemeParts memberInfo.Scheme
            let dictionaryParameterName = "__kappa_dict"
            let dictionaryArgumentTypes =
                traitInfo.TypeParameters |> List.map TypeVariable

            let valueParameterNames =
                parameterTypes
                |> List.mapi (fun index _ -> $"arg{index}")

            let parameters =
                lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    false
                    (Some(dictionaryType traitInfo.Name dictionaryArgumentTypes))
                :: (List.zip valueParameterNames parameterTypes
                    |> List.map (fun (parameterName, parameterType) ->
                        lowerSyntheticKCoreParameter parameterName None false (Some parameterType)))

            let body =
                KCoreTraitCall(
                    traitInfo.Name,
                    memberName,
                    KCoreName [ dictionaryParameterName ],
                    valueParameterNames |> List.map (fun parameterName -> KCoreName [ parameterName ])
                )

            let provenance =
                syntheticOrigin
                    filePath
                    moduleName
                    (TraitRuntime.dispatchBindingName traitInfo.Name memberName)
                    "trait-dispatch"

            makeSyntheticBindingDeclaration
                (TraitRuntime.dispatchBindingName traitInfo.Name memberName)
                (lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    false
                    (Some(dictionaryType traitInfo.Name dictionaryArgumentTypes))
                 :: (List.zip valueParameterNames parameterTypes
                     |> List.map (fun (parameterName, parameterType) ->
                         lowerSyntheticKCoreParameter parameterName None false (Some parameterType))))
                (Some resultType)
                body
                provenance)

    let private synthesizeInstanceBindings
        (surfaceIndex: Map<string, ModuleSurfaceInfo>)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (filePath: string)
        (moduleName: string)
        (instanceInfo: InstanceInfo)
        =
        let selfDictionaryName = "__kappa_self_dict"

        let traitInfo =
            mergeVisibleTraits surfaceIndex moduleName
            |> Map.tryFind instanceInfo.TraitName

        let substitution =
            match traitInfo with
            | Some traitInfo when List.length traitInfo.TypeParameters = List.length instanceInfo.HeadTypes ->
                List.zip traitInfo.TypeParameters instanceInfo.HeadTypes |> Map.ofList
            | _ ->
                Map.empty

        let visibleBindings = mergeVisibleBindings surfaceIndex moduleName
        let visibleTraits = mergeVisibleTraits surfaceIndex moduleName
        let visibleTypeAliases = mergeVisibleTypeAliases surfaceIndex moduleName
        let visibleTypeFacets = mergeVisibleTypeFacets surfaceIndex moduleName
        let visibleProjections = mergeVisibleProjections surfaceIndex moduleName

        let environment =
            { CurrentModuleName = moduleName
              SurfaceIndex = surfaceIndex
              VisibleTypeAliases = visibleTypeAliases
              VisibleTypeFacets = visibleTypeFacets
              VisibleStaticObjects = Map.empty
              VisibleModules = mergeVisibleModules surfaceIndex moduleName
              VisibleRecordTypes = mergeVisibleRecordTypes surfaceIndex moduleName
              VisibleBindings = visibleBindings
              VisibleConstructors = mergeVisibleConstructors surfaceIndex moduleName
              AmbiguousVisibleOrdinaryTerms = mergeAmbiguousVisibleOrdinaryTerms surfaceIndex moduleName
              VisibleProjections = visibleProjections
              VisibleTraits = visibleTraits
              VisibleInstances = visibleInstances surfaceIndex moduleName
              ElaborationAvailableBindings =
                visibleBindings
                |> Map.keys
                |> Set.ofSeq
                |> Set.intersect (IntrinsicCatalog.elaborationAvailableIntrinsicTermNames ())
              ConstraintDictionaries = Map.empty
              ConstrainedMembers = Map.empty }

        let instanceConstraints = instanceInfo.Constraints

        let hiddenConstraintEntries =
            instanceConstraints
            |> List.mapi (fun index constraintInfo ->
                let dictionaryParameterName = $"__kappa_dict_{constraintInfo.TraitName}_{index}"
                constraintInfo, dictionaryParameterName)

        let selfConstrainedMembers =
            traitInfo
            |> Option.map (fun currentTraitInfo ->
                currentTraitInfo.Members
                |> Map.toList
                |> List.map (fun (memberName, _) -> memberName, (instanceInfo.TraitName, selfDictionaryName))
                |> Map.ofList)
            |> Option.defaultValue Map.empty

        let bodyEnvironment =
            let premiseConstrainedMembers = buildConstrainedMembers environment instanceConstraints
            let premiseConstraintDictionaries =
                hiddenConstraintEntries
                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                    constraintInfo, KCoreName [ dictionaryParameterName ])
                |> buildConstraintDictionaries environment

            let selfConstraintDictionaries =
                buildConstraintDictionaries
                    environment
                    [ { TraitName = instanceInfo.TraitName
                        Arguments = instanceInfo.HeadTypes },
                      KCoreName [ selfDictionaryName ] ]

            { environment with
                ConstraintDictionaries =
                    premiseConstraintDictionaries
                    |> Map.fold (fun state key value ->
                        if Map.containsKey key state then
                            state
                        else
                            Map.add key value state) selfConstraintDictionaries
                ConstrainedMembers =
                    premiseConstrainedMembers
                    |> Map.fold (fun state memberName route ->
                        if Map.containsKey memberName state then
                            state
                        else
                            Map.add memberName route state) selfConstrainedMembers }

        let memberBindings =
            traitInfo
            |> Option.map (fun traitInfo ->
                traitInfo.Members
                |> Map.toList
                |> List.choose (fun (memberName, memberInfo) ->
                    let memberDefinition =
                        instanceInfo.Members
                        |> Map.tryFind memberName
                        |> Option.map (fun definition -> definition, false)
                        |> Option.orElseWith (fun () ->
                            memberInfo.DefaultDefinition
                            |> Option.map (fun definition -> definition, true))

                    memberDefinition
                    |> Option.map (fun (definition, isDefaultDefinition) ->
                        let specializedScheme =
                            memberInfo.Scheme |> TypeSignatures.applySchemeSubstitution substitution

                        let extraLocalTypes =
                            [ selfDictionaryName, TypeName([ instanceInfo.TraitName ], instanceInfo.HeadTypes) ]
                            @ (hiddenConstraintEntries
                               |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                                   dictionaryParameterName, TypeName([ constraintInfo.TraitName ], constraintInfo.Arguments)))

                        let loweredBody =
                            definition.Body
                            |> Option.map (
                                lowerBindingBody
                                    bodyEnvironment
                                    recordLayouts
                                    (Some specializedScheme)
                                    definition.Parameters
                                    extraLocalTypes
                            )

                        let parameters =
                            lowerSyntheticKCoreParameter
                                selfDictionaryName
                                None
                                true
                                (Some(dictionaryType instanceInfo.TraitName instanceInfo.HeadTypes))
                            :: (hiddenConstraintEntries
                                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                                    lowerSyntheticKCoreParameter
                                        dictionaryParameterName
                                        None
                                        true
                                        (Some(dictionaryType constraintInfo.TraitName constraintInfo.Arguments))))
                            @ buildBindingParameters environment.VisibleTypeAliases (Some specializedScheme) definition.Parameters

                        let provenance =
                            syntheticOrigin
                                filePath
                                moduleName
                                (TraitRuntime.instanceMemberBindingName instanceInfo.TraitName instanceInfo.InstanceKey memberName)
                                (if isDefaultDefinition then "instance-default-member" else "instance-member")

                        makeSyntheticBindingDeclaration
                            (TraitRuntime.instanceMemberBindingName instanceInfo.TraitName instanceInfo.InstanceKey memberName)
                            parameters
                            (lowerBindingReturnTypeExpr (Some specializedScheme) definition.Parameters definition.ReturnTypeTokens)
                            (loweredBody |> Option.defaultValue (KCoreLiteral LiteralValue.Unit))
                            provenance)))
            |> Option.defaultValue []

        let dictionaryBinding =
            let dictionaryParameters =
                hiddenConstraintEntries
                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                    lowerSyntheticKCoreParameter
                        dictionaryParameterName
                        None
                        true
                        (Some(dictionaryType constraintInfo.TraitName constraintInfo.Arguments)))

            let dictionaryCaptures =
                hiddenConstraintEntries
                |> List.map (fun (_, dictionaryParameterName) -> KCoreName [ dictionaryParameterName ])

            let provenance =
                syntheticOrigin
                    filePath
                    moduleName
                    (TraitRuntime.instanceDictionaryBindingName instanceInfo.TraitName instanceInfo.InstanceKey)
                    "instance-dictionary"

            makeSyntheticBindingDeclaration
                (TraitRuntime.instanceDictionaryBindingName instanceInfo.TraitName instanceInfo.InstanceKey)
                dictionaryParameters
                (Some(dictionaryType instanceInfo.TraitName instanceInfo.HeadTypes))
                (KCoreDictionaryValue(
                    moduleName,
                    instanceInfo.TraitName,
                    instanceInfo.InstanceKey,
                    dictionaryCaptures
                ))
                provenance

        memberBindings @ [ dictionaryBinding ]

    let lowerKCoreModules
        backendProfile
        allowUnsafeConsume
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<string, HostBindings.HostModuleDescription>)
        =
        let surfaceIndex = buildSurfaceIndex frontendModules hostModules
        let effectDeclarationsByModule = buildEffectDeclarationIndex frontendModules

        frontendModules
        |> List.map (fun frontendModule ->
            let moduleName = moduleNameText frontendModule.ModuleIdentity
            let topLevelEffects =
                let localEffects =
                    frontendModule.Declarations
                    |> List.choose (function
                        | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleName declaration)
                        | _ -> None)

                localEffects @ importedEffectDeclarations surfaceIndex effectDeclarationsByModule moduleName

            withScopedEffectDeclarations topLevelEffects (fun () ->
                let moduleInfo = surfaceIndex[moduleName]
                let recordLayouts = ref Map.empty

                let baseEnvironment =
                    { CurrentModuleName = moduleName
                      SurfaceIndex = surfaceIndex
                      VisibleTypeAliases = mergeVisibleTypeAliases surfaceIndex moduleName
                      VisibleTypeFacets = mergeVisibleTypeFacets surfaceIndex moduleName
                      VisibleStaticObjects = Map.empty
                      VisibleModules = mergeVisibleModules surfaceIndex moduleName
                      VisibleRecordTypes = mergeVisibleRecordTypes surfaceIndex moduleName
                      VisibleBindings = mergeVisibleBindings surfaceIndex moduleName
                      VisibleConstructors = mergeVisibleConstructors surfaceIndex moduleName
                      AmbiguousVisibleOrdinaryTerms = mergeAmbiguousVisibleOrdinaryTerms surfaceIndex moduleName
                      VisibleProjections = mergeVisibleProjections surfaceIndex moduleName
                      VisibleTraits = mergeVisibleTraits surfaceIndex moduleName
                      VisibleInstances = visibleInstances surfaceIndex moduleName
                      ElaborationAvailableBindings =
                        mergeVisibleBindings surfaceIndex moduleName
                        |> Map.keys
                        |> Set.ofSeq
                        |> Set.intersect (IntrinsicCatalog.elaborationAvailableIntrinsicTermNames ())
                      ConstraintDictionaries = Map.empty
                      ConstrainedMembers = Map.empty }

                let environment =
                    let staticObjectAliases =
                        let localAliases =
                            buildStaticObjectAliasesForModule baseEnvironment frontendModule.Declarations

                        topLevelEffects
                        |> List.filter (fun declaration -> declaration.Name.Contains("."))
                        |> List.fold (fun current declaration ->
                            let semanticDeclaration =
                                declaration
                                |> EffectSemantics.ensureTopLevel moduleName
                                |> EffectSemantics.toSemantic

                            Map.add declaration.Name (scopedEffectLabelStaticObject semanticDeclaration) current) localAliases

                    { baseEnvironment with
                        VisibleStaticObjects = staticObjectAliases }

                let declarations =
                    let moduleTopLevelDefinitionsByName =
                        frontendModule.Declarations
                        |> List.choose (function
                            | LetDeclaration candidate ->
                                match candidate.Name, candidate.Body with
                                | Some name, Some _ -> Some(name, candidate)
                                | _ -> None
                            | _ ->
                                None)
                        |> Map.ofList

                    let sourceBindingInfosByName =
                        let bindingDefinitions =
                            moduleTopLevelDefinitionsByName

                        frontendModule.Declarations
                        |> List.choose (function
                            | SignatureDeclaration declaration ->
                                let signatureParameterLayouts =
                                    declaration.TypeTokens
                                    |> splitSignatureParameterTokens
                                    |> function
                                        | [] -> None
                                        | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                                TypeSignatures.parseScheme declaration.TypeTokens
                                |> Option.map (fun scheme ->
                                    let parameterLayouts =
                                        bindingDefinitions
                                        |> Map.tryFind declaration.Name
                                        |> Option.map (fun definition -> definition.Parameters)
                                        |> mergeParameterLayouts signatureParameterLayouts
                                        |> stripForallOnlyParameterLayouts scheme

                                    declaration.Name,
                                    { ModuleName = moduleName
                                      Name = declaration.Name
                                      IsPattern =
                                        bindingDefinitions
                                        |> Map.tryFind declaration.Name
                                        |> Option.exists (fun definition -> definition.IsPattern)
                                      Scheme = scheme
                                      TypeTokens = declaration.TypeTokens
                                      ParameterLayouts = parameterLayouts
                                      ConstructorTypeName = None
                                      DefaultArguments = Map.empty })
                            | _ ->
                                None)
                        |> Map.ofList

                    let sourceSignatureDeclarationsByName =
                        frontendModule.Declarations
                        |> List.choose (function
                            | SignatureDeclaration declaration -> Some(declaration.Name, declaration)
                            | _ -> None)
                        |> Map.ofList

                    frontendModule.Declarations
                    |> List.collect (fun declaration ->
                        let provenance = declarationOrigin frontendModule.FilePath moduleName declaration

                        let originalDeclaration =
                            match declaration with
                            | LetDeclaration definition when definition.Name.IsSome ->
                                let sourceSignature =
                                    sourceSignatureDeclarationsByName
                                    |> Map.tryFind definition.Name.Value

                                let bindingInfo =
                                    sourceBindingInfosByName
                                    |> Map.tryFind definition.Name.Value
                                    |> Option.orElseWith (fun () ->
                                        environment.VisibleBindings
                                        |> Map.tryFind definition.Name.Value)

                                [ lowerUserBinding
                                      environment
                                      recordLayouts
                                      moduleTopLevelDefinitionsByName
                                      frontendModule.FilePath
                                      moduleName
                                      definition
                                      sourceSignature
                                      bindingInfo ]
                            | _ ->
                                [ { Source = declaration
                                    Binding = None
                                    Provenance = provenance } ]

                        match declaration with
                        | TraitDeclarationNode declaration ->
                            originalDeclaration
                        | InstanceDeclarationNode declaration ->
                            let instanceKey = TraitRuntime.instanceKeyFromTokens declaration.HeaderTokens
                            match
                                moduleInfo.Instances
                                |> List.tryFind (fun info ->
                                    String.Equals(info.TraitName, declaration.TraitName, StringComparison.Ordinal)
                                    && String.Equals(info.InstanceKey, instanceKey, StringComparison.Ordinal))
                            with
                            | Some instanceInfo ->
                                originalDeclaration
                                @ synthesizeInstanceBindings surfaceIndex recordLayouts frontendModule.FilePath moduleName instanceInfo
                            | None ->
                                // Parse-invalid instance declarations may survive as surface nodes with diagnostics but
                                // intentionally produce no semantic instance info. Lowering must not crash on them.
                                originalDeclaration
                        | _ ->
                            originalDeclaration)

                let intrinsicTerms =
                    match frontendModule.ModuleIdentity with
                    | Some moduleNameSegments ->
                        frontendModule.Declarations
                        |> List.choose (function
                            | ExpectDeclarationNode declaration
                                when Stdlib.intrinsicallySatisfiesExpectForCompilationProfile
                                        backendProfile
                                        allowUnsafeConsume
                                        moduleNameSegments
                                        declaration ->
                                match declaration with
                                | ExpectTermDeclaration termDeclaration -> Some termDeclaration.Name
                                | _ -> None
                            | _ ->
                                None)
                    | None ->
                        []

                { Name = moduleName
                  SourceFile = frontendModule.FilePath
                  ModuleAttributes = frontendModule.ModuleAttributes
                  Imports = frontendModule.Imports
                  VisibleTraitTypeParameterCounts =
                    environment.VisibleTraits
                    |> Map.map (fun _ traitInfo -> traitInfo.TypeParameters.Length)
                  IntrinsicTerms = intrinsicTerms |> List.distinct |> List.sort
                  SyntheticDataTypes =
                    recordLayouts.Value
                    |> Map.toList
                    |> List.map snd
                    |> List.sortBy (fun layout -> layout.TypeName)
                    |> List.map (fun layout ->
                        { Name = layout.TypeName
                          TypeParameters = layout.TypeParameters
                          ConstructorName = layout.ConstructorName
                          FieldNames = layout.Fields |> List.map (fun field -> field.Name)
                          FieldTypeTexts = layout.Fields |> List.map (fun field -> TypeSignatures.toText field.Type)
                          Provenance = layout.Provenance })
                  Ownership = frontendModule.Ownership
                  Declarations = declarations }))
